window.KABAR_PACK = [{"slug": "pajak-karbon-indonesia-kemana", "topic": "Regulasi", "mood": "#0B2471", "title": "Pajak karbon Rp30 per kilogram: janji yang terus tertunda.", "dek": "UU HPP 2021 menetapkan tarif pajak karbon minimal Rp30.000 per ton untuk PLTU batu bara. Tapi tanggal berlakunya terus digeser — dan hingga kini ⚠︎ belum efektif berjalan.", "hook": "Karbon sudah punya harga di undang-undang sejak 2021. Lima tahun kemudian, tagihannya belum pernah datang.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (UU HPP, IEEFA, IISD)", "read": 4, "blocks": [{"t": "lead", "x": "Di atas kertas, Indonesia sudah punya pajak karbon sejak 2021. Undang-Undang Harmonisasi Peraturan Perpajakan menuliskannya jelas: setiap kilogram karbon dioksida punya harga. Ide besarnya menarik — memberi harga pada sesuatu yang selama ini gratis dibuang ke udara. Tapi lima tahun berselang, harga itu belum benar-benar ditagih; sebuah janji yang tanggalnya terus digeser ⚠︎."}, {"t": "p", "x": "Aturannya sendiri lugas. UU HPP menetapkan tarif <b>paling rendah Rp30 per kilogram CO2e</b> — setara Rp30.000 per ton — dan menyasar lebih dulu <b>PLTU batu bara</b> lewat skema <em>cap and tax</em>: pembangkit yang emisinya melampaui batas membayar selisihnya. Tarifnya dirancang mengambang, menyesuaikan harga pasar karbon <a href=\"https://mediakeuangan.kemenkeu.go.id/article/show/menuju-implementasi-pajak-karbon\">(Kemenkeu)</a>."}, {"t": "p", "x": "Masalahnya ada pada pelaksanaan. Pajak karbon semestinya berlaku <b>1 April 2022</b>. Tanggal itu mundur ke Juli 2022, lalu digeser ke 2025 — dan hingga pertengahan 2026 belum juga efektif berjalan ⚠︎. Alasan yang berulang: kesiapan sistem pengukuran-pelaporan-verifikasi, kekhawatiran soal inflasi, dan penolakan dari industri <a href=\"https://ieefa.org/resources/two-years-after-launch-indonesias-carbon-market-struggles-find-momentum\">(IEEFA)</a>."}, {"t": "p", "x": "Di balik penundaan itu ada ketegangan yang jujur. Pajak karbon dirancang menaikkan biaya batu bara secara bertahap, sementara pemerintah menjaga tarif listrik tetap terjangkau dan industri padat energi tetap kompetitif. Menagih karbon terlalu cepat berisiko secara politis; menundanya terlalu lama membuat sinyalnya kehilangan makna."}, {"t": "pull", "x": "Regulasi di atas kertas tidak menurunkan satu ton emisi pun. Yang menurunkan emisi adalah harga yang benar-benar ditagih."}, {"t": "stat", "n": "< US$2 ⚠︎", "l": "nilai per ton CO2e dari tarif Rp30.000 — jauh di bawah rekomendasi US$50–100 untuk 2030", "s": "IISD, 2026; High-Level Commission on Carbon Prices, 2017"}, {"t": "h2", "x": "Sinyal harga yang nyaris tak terdengar"}, {"t": "p", "x": "Bahkan seandainya berjalan, Rp30.000 per ton tergolong sangat rendah. Komisi Tingkat Tinggi soal Harga Karbon menaksir harga perlu berada di kisaran <b>US$50–100 per ton pada 2030</b> agar sejalan dengan target Perjanjian Paris. Pada nilai kurang dari US$2, sinyal untuk beralih dari batu bara nyaris tak terdengar — cukup untuk dicatat di pembukuan, belum cukup untuk mengubah keputusan investasi."}, {"t": "p", "x": "Jalur lain sempat dibuka. Bursa Karbon Indonesia (IDXCarbon) diluncurkan September 2023 di bawah pengawasan OJK, dan Perpres 110/2025 ⚠︎ menata ulang kerangka nilai ekonomi karbon nasional. Namun sepanjang 2025 alokasi izin emisi tertunda, tak ada izin yang diterbitkan, dan praktis belum ada perdagangan yang berjalan. Pajak maupun pasar karbon sama-sama masih menunggu."}, {"t": "p", "x": "Bagi perusahaan, menunggu regulasi bukanlah strategi. Ketika tarif akhirnya ditagih — sementara CBAM Uni Eropa sudah menagih lebih dulu di perbatasan — yang siap adalah mereka yang jejak karbonnya sudah <b>terlacak</b> per lini produk, bukan yang baru mulai menghitung saat tagihan datang. Sistem pelaporan yang dapat diaudit tidak dibangun dalam semalam; kesiapan data adalah bagian termurah dari transisi ini, dan justru menunda yang mahal."}], "story": [{"kind": "cover", "title": "Pajak karbon Rp30/kg: janji yang tertunda", "text": "UU HPP 2021 menetapkan tarif pajak karbon minimal Rp30.000 per ton untuk PLTU batu bara. Tapi tanggal berlakunya terus digeser — dan hingga kini ⚠︎ belum efektif berjalan."}, {"kind": "hook", "title": "Sudah di undang-undang, belum di dompet", "text": "Karbon punya harga di UU sejak 2021. Lima tahun kemudian, tagihannya belum pernah datang."}, {"kind": "point", "title": "Apa isinya", "text": "Tarif minimal Rp30/kg CO2e (= Rp30.000/ton), untuk PLTU batu bara lebih dulu, lewat skema cap and tax."}, {"kind": "point", "title": "Terus mundur", "text": "Harusnya 1 April 2022 → digeser Juli 2022 → 2025 → hingga pertengahan 2026 belum efektif berjalan ⚠︎."}, {"kind": "stat", "title": "Terlalu murah untuk didengar", "big": "< US$2 ⚠︎", "label": "nilai per ton dari tarif Rp30.000 — vs rekomendasi US$50–100 (2030)", "source": "IISD 2026; HLC Carbon Prices 2017"}, {"kind": "quote", "title": "Inti persoalannya", "text": "Regulasi di atas kertas tidak menurunkan satu ton emisi pun. Yang menurunkan emisi adalah harga yang benar-benar ditagih."}, {"kind": "end", "title": "Jangan tunggu tagihan", "text": "Ketika tarif akhirnya ditagih — dan CBAM sudah menagih di perbatasan — yang siap adalah yang jejak karbonnya sudah terlacak. Baca selengkapnya di Glyiv Kabar."}], "sources": [{"a": "Republik Indonesia (2021). Undang-Undang No. 7 Tahun 2021 tentang Harmonisasi Peraturan Perpajakan (UU HPP), Pasal 13 — pajak karbon.", "u": "https://mediakeuangan.kemenkeu.go.id/article/show/menuju-implementasi-pajak-karbon"}, {"a": "IEEFA (2025). Two years after launch, Indonesia's carbon market struggles to find momentum.", "u": "https://ieefa.org/resources/two-years-after-launch-indonesias-carbon-market-struggles-find-momentum"}, {"a": "IISD (2026). Carbon Pricing in Southeast Asia — Policy Brief (tarif efektif setara ~US$2/ton, implementasi tertunda).", "u": "https://www.iisd.org/system/files/2026-03/carbon-pricing-southeast-asia.pdf"}, {"a": "High-Level Commission on Carbon Prices / World Bank (2017). Rekomendasi harga karbon US$50–100 per ton CO2e pada 2030 untuk selaras dengan target Paris.", "u": "https://www.carbonpricingleadership.org/report-of-the-highlevel-commission-on-carbon-prices"}]}, {"slug": "idxcarbon-dua-tahun", "topic": "Regulasi", "mood": "#B0894F", "title": "Bursa Karbon Indonesia: dua tahun setelah lonceng pertama.", "dek": "IDXCarbon dibuka 26 September 2023 dengan lonceng dan optimisme; dua tahun kemudian sekitar 1,6 juta ton CO2e tercatat berpindah tangan — angka nyata, tapi sebagian besar terjadi hanya dalam hitungan hari, dan likuiditas hariannya masih tipis.", "hook": "Bursa Karbon Indonesia baru berusia dua tahun. Hampir sepertiga dari seluruh yang pernah diperdagangkan terjadi di hari pertama. Ini artinya.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data BEI/IDXCarbon, IEEFA & World Bank", "read": 4, "blocks": [{"t": "lead", "x": "Pada 26 September 2023, lonceng pembukaan Bursa Karbon Indonesia — IDXCarbon — dibunyikan, dan hari itu terasa seperti awal sesuatu yang besar: 459.914 ton CO2e berpindah tangan hanya dalam beberapa jam pertama perdagangan. Dua tahun kemudian, gambarannya jauh lebih tenang. Infrastrukturnya sudah berdiri kokoh, tapi pasarnya belum benar-benar ramai."}, {"t": "p", "x": "Sejak lonceng itu hingga 29 Desember 2025, total volume yang <b>terlacak</b> diperdagangkan di IDXCarbon mencapai sekitar <b>1,6 juta ton CO2e</b> senilai Rp80,75 miliar, <a href=\"https://www.idxchannel.com/market-news/dua-tahun-idx-carbon-nilai-transaksi-capai-rp8075-miliar-per-29-desember-2025\">menurut data Bursa Efek Indonesia</a>. Angka itu terdengar besar sampai kita letakkan di sebelah emisi Indonesia yang sekitar <b>1,26 miliar ton</b> setara CO2 per tahun (<a href=\"https://data.worldbank.org/indicator/EN.ATM.GHGT.KT.CE?locations=ID\">World Bank, 2023</a>) — dua tahun perdagangan setara kira-kira 0,1% dari emisi satu tahun saja."}, {"t": "p", "x": "Yang lebih menjelaskan soal likuiditas adalah sebarannya. Hampir 30% dari seluruh volume dua tahun itu terjadi pada hari pembukaan. Setelah euforia awal, perdagangan kerap sepi berminggu-minggu; pada Juni 2025 nilai transaksi bahkan <a href=\"https://www.idnfinancials.com/news/55927/carbon-trading-plunges-98-5-in-june-2025-idx-chief-responds\">anjlok sekitar 98,5% dibanding bulan sebelumnya</a>. Lonjakan besar biasanya datang saat entitas tertentu menuntaskan kewajiban atau target, bukan dari arus jual-beli harian yang stabil."}, {"t": "pull", "x": "Pasar sudah berdiri, tapi 'terlacak diperdagangkan' belum sama dengan 'likuid'. Sebagian besar volume dua tahun terjadi dalam hitungan hari."}, {"t": "stat", "n": "±1,6 juta ton", "l": "total CO2e terlacak diperdagangkan di IDXCarbon selama dua tahun pertama (26 Sep 2023–29 Des 2025)", "s": "Bursa Efek Indonesia, 2025"}, {"t": "h2", "x": "Kenapa likuiditasnya masih tipis"}, {"t": "p", "x": "Akarnya struktural. Sebagian besar perdagangan masih bersifat <b>sukarela</b>: belum ada penalti tegas yang memaksa pengemisi besar membeli unit karbon, sehingga permintaan lemah sementara pasokan proyek terus bertambah. Analisis IEEFA menilai ekosistemnya <a href=\"https://ieefa.org/resources/two-years-after-launch-indonesias-carbon-market-struggles-find-momentum\">belum sepenuhnya matang</a> — kurang insentif bagi pembeli dan belum ada batas-atas emisi (cap) yang mengikat. Tanpa 'kelangkaan' yang diciptakan aturan, harga dan volume sulit bergerak."}, {"t": "p", "x": "Pemerintah berencana memperketat lewat skema wajib berbasis batas-emisi untuk sektor pembangkit dan industri, yang seharusnya menciptakan permintaan struktural ⚠︎ — namun cakupan dan jadwal pastinya masih bergerak. Sisi pasokan pun butuh kepercayaan: pembeli serius menuntut kredit yang bisa ditelusuri sampai ke proyeknya, bukan sekadar sertifikat di atas kertas. Selama permintaan belum wajib dan pasokan belum sepenuhnya kredibel, likuiditas kemungkinan tetap tipis."}, {"t": "p", "x": "Dua tahun ini bukan kegagalan — membangun bursa, registri, dan aturan main adalah pekerjaan berat yang sudah selesai separuhnya. Yang belum datang adalah alasan ekonomi bagi ribuan perusahaan untuk benar-benar bertransaksi setiap hari. Di situlah pekerjaan berikutnya: mengubah karbon dari kewajiban pelaporan menjadi angka yang terlacak per produk dan per fasilitas — cukup kredibel untuk diperdagangkan, bukan sekadar dilaporkan."}], "story": [{"kind": "cover", "title": "Bursa Karbon Indonesia: dua tahun setelah lonceng pertama.", "text": "IDXCarbon dibuka 26 September 2023 dengan lonceng dan optimisme; dua tahun kemudian sekitar 1,6 juta ton CO2e tercatat berpindah tangan — angka nyata, tapi likuiditas hariannya masih tipis.", "label": "Regulasi"}, {"kind": "hook", "title": "Sepertiga di hari pertama", "text": "Bursa karbon kita baru berusia dua tahun. Hampir sepertiga dari seluruh yang pernah diperdagangkan terjadi di hari pembukaan."}, {"kind": "point", "title": "Ramai sehari, lalu sepi", "text": "459.914 ton CO2e berpindah tangan di hari pembukaan. Sesudahnya, perdagangan kerap sepi berminggu-minggu — Juni 2025 bahkan anjlok ~98,5%."}, {"kind": "stat", "title": "Volume dua tahun", "big": "±1,6 juta ton", "label": "CO2e diperdagangkan dalam 2 tahun — sekitar 0,1% dari emisi Indonesia setahun", "source": "BEI 2025 · World Bank 2023"}, {"kind": "point", "title": "Kenapa masih tipis", "text": "Perdagangan masih sukarela: belum ada penalti bagi pengemisi besar, belum ada batas-atas emisi yang mengikat. Tanpa kelangkaan, harga dan volume sulit bergerak."}, {"kind": "quote", "title": "Berdiri, belum ramai", "text": "Pasar sudah berdiri; yang belum datang adalah alasan bagi ribuan perusahaan untuk bertransaksi tiap hari."}, {"kind": "end", "title": "Ikuti Glyiv Kabar", "text": "Kami menelusuri karbon dari kewajiban pelaporan menjadi angka yang bisa diperdagangkan. Baca versi lengkapnya dan gabung ekosistem Glyiv."}], "sources": [{"a": "IEEFA (2025). Two years after launch, Indonesia's carbon market struggles to find momentum.", "u": "https://ieefa.org/resources/two-years-after-launch-indonesias-carbon-market-struggles-find-momentum"}, {"a": "IDX Channel / Bursa Efek Indonesia (2025). Dua Tahun IDX Carbon, Nilai Transaksi Capai Rp80,75 Miliar per 29 Desember 2025.", "u": "https://www.idxchannel.com/market-news/dua-tahun-idx-carbon-nilai-transaksi-capai-rp8075-miliar-per-29-desember-2025"}, {"a": "ANTARA (2025). IDXCarbon catat volume transaksi 1.599.516 ton CO2e per 8 Agustus 2025.", "u": "https://www.antaranews.com/berita/5029353/idxcarbon-catat-volume-transaksi-1599516-ton-co2e-per-8-agustus-2025"}, {"a": "World Bank. Total greenhouse gas emissions (kt of CO2 equivalent) — Indonesia (data 2023).", "u": "https://data.worldbank.org/indicator/EN.ATM.GHGT.KT.CE?locations=ID"}]}, {"slug": "perpres-nek-spe-grk", "topic": "Regulasi", "mood": "#0B2471", "title": "Perpres NEK dan SPE-GRK: tulang punggung pasar karbon kita.", "dek": "Perpres 98/2021 tentang Nilai Ekonomi Karbon adalah dasar hukum yang membuat sebuah pengurangan emisi bisa menjadi sertifikat SPE-GRK yang diakui negara — kami runut alurnya, dari lahan sampai registri, tanpa jargon.", "hook": "Kenapa sebuah pohon bisa berubah jadi \"sertifikat\"? Jawabannya ada di satu Peraturan Presiden — dan sebuah sistem registri yang jarang dibicarakan.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Perpres 98/2021 & sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Sebuah pengurangan emisi hanya bernilai kalau ada yang menjamin ia nyata, tidak dihitung dua kali, dan diakui negara. Di Indonesia, jaminan itu punya nama dan nomor: Peraturan Presiden Nomor 98 Tahun 2021 tentang Nilai Ekonomi Karbon. Pasar karbon kita berdiri di atas dasar hukum ini — bukan sekadar niat baik."}, {"t": "p", "x": "Nilai Ekonomi Karbon (NEK) intinya sederhana: memberi <b>harga</b> pada setiap ton emisi. Perpres 98/2021 — ditetapkan 29 Oktober 2021 — mengatur beberapa cara memberi harga itu: <b>perdagangan karbon</b>, pembayaran berbasis kinerja, dan pungutan atas karbon (termasuk pajak karbon, yang jadwal berlakunya sudah beberapa kali bergeser ⚠︎). Semuanya diarahkan ke satu tujuan: membantu Indonesia mencapai target iklim dalam NDC-nya. <a href=\"https://peraturan.bpk.go.id/details/187122/perpres-no-98-tahun-2021\">Teks lengkapnya ada di sini</a>."}, {"t": "p", "x": "Dari kerangka itu lahir sertifikatnya: <b>SPE-GRK</b>, Sertifikat Pengurangan Emisi Gas Rumah Kaca. Ini bukan sekadar surat pernyataan. Sebuah usaha atau proyek baru bisa memegangnya setelah melewati <b>MRV</b> — pengukuran, pelaporan, dan verifikasi oleh pihak independen — lalu teregistrasi resmi dengan nomor di sistem registri nasional. Satu SPE-GRK mewakili satu ton CO₂ ekuivalen yang pengurangannya sudah dibuktikan, bukan sekadar dijanjikan. Nomor registrasi itulah yang mencegah satu ton dihitung dua kali oleh dua pihak berbeda."}, {"t": "pull", "x": "Tanpa MRV dan registri, sebuah klaim pengurangan emisi hanyalah cerita. SPE-GRK adalah cara negara mengubah cerita itu menjadi bukti yang bisa ditelusuri."}, {"t": "h2", "x": "Dari lahan ke sertifikat"}, {"t": "p", "x": "Alurnya kira-kira begini. Aksi mitigasi beserta sumber dayanya didaftarkan lebih dulu di <b>SRN-PPI</b> — Sistem Registri Nasional Pengendalian Perubahan Iklim, pangkalan data resmi milik pemerintah. Proyek dijalankan, hasilnya di-MRV dan diverifikasi. Bila lolos, SPE-GRK diterbitkan dan tercatat, sehingga bisa ditelusuri: proyek mana, tahun berapa, siapa yang memverifikasi. Sertifikat yang sudah tercatat inilah yang boleh diperdagangkan — antara lain lewat <a href=\"https://www.idxcarbon.co.id/\">Bursa Karbon Indonesia (IDXCarbon)</a>, yang diluncurkan 26 September 2023."}, {"t": "stat", "n": "117.455 tCO₂e", "l": "Volume tercatat diperdagangkan di Bursa Karbon Indonesia sepanjang Januari 2026 (152 peserta, 9 proyek)", "s": "IDXCarbon, Laporan Bulanan Januari 2026"}, {"t": "h2", "x": "Yang jujur perlu dicatat"}, {"t": "p", "x": "Punya lahan atau menanam pohon tidak otomatis berarti Anda memegang SPE-GRK. Sertifikat itu baru lahir setelah MRV, verifikasi, dan pencatatan — sebuah proses, bukan status bawaan. Kerangkanya pun masih terus berkembang: aturan turunan dan tata kelola registri unit karbon diperbarui dari waktu ke waktu ⚠︎, termasuk yang menyangkut perdagangan lintas negara."}, {"t": "p", "x": "Di sinilah posisi Glyiv kami buat sejujur mungkin. Kami bukan penerbit sertifikat dan bukan bursa. Kami membantu pemilik usaha dan proyek <b>melacak</b> data karbonnya secara rapi dan bisa diaudit — bahan baku yang justru dibutuhkan proses MRV — supaya ketika saatnya masuk jalur SPE-GRK, datanya sudah siap. Yang kami tawarkan bukan janji 'netral karbon', melainkan kontribusi yang terlacak, langkah demi langkah."}], "story": [{"kind": "cover", "title": "Perpres NEK & SPE-GRK", "text": "Perpres 98/2021 tentang Nilai Ekonomi Karbon adalah dasar hukum yang membuat sebuah pengurangan emisi bisa menjadi sertifikat SPE-GRK yang diakui negara — kami runut alurnya, dari lahan sampai registri, tanpa jargon."}, {"kind": "hook", "title": "Bukan sekadar niat baik", "text": "Kenapa sebuah pohon bisa berubah jadi 'sertifikat'? Jawabannya ada di satu Peraturan Presiden — dan sebuah sistem registri yang jarang dibicarakan."}, {"kind": "point", "title": "Apa itu NEK?", "text": "Nilai Ekonomi Karbon = memberi harga pada tiap ton emisi. Perpres 98/2021 mengaturnya lewat perdagangan karbon, pembayaran berbasis kinerja, dan pungutan."}, {"kind": "point", "title": "Apa itu SPE-GRK?", "text": "Sertifikat Pengurangan Emisi GRK. Terbit hanya setelah melewati MRV (ukur, lapor, verifikasi) dan tercatat resmi di registri. Satu sertifikat = satu ton CO₂e, dibuktikan."}, {"kind": "point", "title": "Alurnya singkat", "text": "Daftar di SRN-PPI → proyek berjalan → MRV & verifikasi → SPE-GRK terbit & tercatat → boleh diperdagangkan di Bursa Karbon Indonesia (IDXCarbon)."}, {"kind": "stat", "title": "Skalanya hari ini", "big": "117.455 tCO₂e", "label": "Volume di Bursa Karbon Indonesia, Januari 2026", "source": "IDXCarbon, Laporan Bulanan Jan 2026"}, {"kind": "end", "title": "Data dulu, sertifikat kemudian", "text": "Glyiv membantu Anda melacak data karbon secara rapi dan bisa diaudit — siap saat masuk jalur SPE-GRK. Baca artikel lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Peraturan Presiden Republik Indonesia Nomor 98 Tahun 2021 tentang Penyelenggaraan Nilai Ekonomi Karbon (ditetapkan 29 Oktober 2021).", "u": "https://peraturan.bpk.go.id/details/187122/perpres-no-98-tahun-2021"}, {"a": "Sistem Registri Nasional Pengendalian Perubahan Iklim (SRN-PPI), KLHK — definisi SPE-GRK dan alur registrasi/MRV.", "u": "https://srn.menlhk.go.id/"}, {"a": "IDXCarbon (Bursa Karbon Indonesia), Laporan Bulanan Perdagangan Karbon Januari 2026; peluncuran bursa 26 September 2023.", "u": "https://www.idxcarbon.co.id/"}]}, {"slug": "cbam-nilai-default-mahal", "topic": "Regulasi", "mood": "#B0894F", "title": "Kenapa 'nilai default' CBAM bisa jadi jebakan tarif.", "dek": "Sejak CBAM masuk fase bayar pada 2026, eksportir yang tak menyertakan data emisi terverifikasi dihitung memakai nilai default yang sengaja dibuat tinggi — dan karbon yang tertelusur bisa memangkas selisih tagihan itu.", "hook": "Diam soal emisi Anda? CBAM akan mengisi angkanya sendiri — dan tebakannya selalu mahal.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen Komisi Eropa & sumber publik", "read": 5, "blocks": [{"t": "lead", "x": "Bayangkan dua pabrik baja mengirim produk yang sama ke Eropa. Yang satu melampirkan data emisi yang terlacak dan terverifikasi; yang lain tidak. Mulai 2026, pabrik kedua bisa membayar tarif CBAM lebih besar — bukan karena produknya lebih kotor, tapi karena ia membiarkan otoritas UE yang menebak angkanya. Dan tebakan itu, sesuai desainnya, dibuat tinggi."}, {"t": "p", "x": "CBAM menagih selisih harga karbon di perbatasan Uni Eropa. Ketika eksportir tak bisa membuktikan intensitas karbon barangnya dengan data terverifikasi, otoritas memakai <b>nilai default</b> — angka acuan yang, menurut regulasinya, dirancang konservatif alias cenderung tinggi (<a href=\"https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en\">Komisi Eropa</a>). Logikanya sederhana: default tak boleh lebih murah daripada memberi data asli, supaya tak ada insentif untuk sekadar 'diam saja'."}, {"t": "p", "x": "Selama fase transisi (Okt 2023–Des 2025), nilai default masih boleh dipakai relatif longgar untuk pelaporan. Tapi penggunaannya diperketat sejak 2025, dan mulai <b>1 Januari 2026</b> saat CBAM masuk fase bayar, data emisi aktual yang terverifikasi menjadi kunci untuk menghindari tarif berbasis default. Metodologi persis nilai default periode definitif masih dituangkan lewat aturan pelaksana Komisi ⚠︎."}, {"t": "pull", "x": "Nilai default bukan hukuman acak — ia dirancang agar 'tidak melapor' selalu lebih mahal daripada melapor jujur."}, {"t": "stat", "n": "≈1,9 t", "l": "CO₂ per ton baja kasar — rata-rata dunia; rute tungku busur listrik (scrap) bisa jauh di bawahnya", "s": "worldsteel, Sustainability Indicators 2023"}, {"t": "p", "x": "Di sinilah jebakannya terlihat. Produsen yang sudah relatif bersih — misalnya pabrik baja rute scrap dengan intensitas jauh di bawah rata-rata — justru paling dirugikan bila dihitung memakai default, karena default menyamaratakannya dengan yang paling boros. Data yang tertelusur bukan sekadar urusan kepatuhan; ia selisih tagihan yang nyata."}, {"t": "h2", "x": "Cara keluar dari jebakan"}, {"t": "p", "x": "Langkahnya bukan buru-buru membeli offset, melainkan <b>mengukur lalu memverifikasi</b>: memetakan emisi tertanam per produk dengan metodologi yang selaras standar global (GHG Protocol, ISO 14064), lengkap dengan jejak data yang bisa diaudit. UE menyediakan template komunikasi data emisi dari produsen ke importir — dan angka terverifikasi itulah yang menggantikan default yang mahal (<a href=\"https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en\">Komisi Eropa</a>)."}, {"t": "p", "x": "CBAM tidak hanya menghukum produk yang kotor; ia menghukum data yang hilang. Bagi eksportir Indonesia, kabar baiknya sederhana: karbon yang terlacak dengan rapi adalah kontribusi nyata pada iklim sekaligus pertahanan terbaik terhadap tarif yang sebenarnya bisa dihindari."}], "story": [{"kind": "cover", "title": "Nilai default CBAM: jebakan tarif yang bisa dihindari", "text": "Sejak CBAM masuk fase bayar pada 2026, eksportir tanpa data emisi terverifikasi dihitung memakai nilai default yang sengaja dibuat tinggi — dan karbon yang tertelusur bisa memangkas tagihan itu."}, {"kind": "hook", "title": "Diam = mahal", "text": "Tak melapor emisi? CBAM akan mengisi angkanya sendiri. Dan tebakannya tak pernah murah."}, {"kind": "point", "title": "Apa itu 'nilai default'?", "text": "Kalau eksportir tak kirim data emisi terverifikasi, CBAM memakai angka acuan bawaan untuk menghitung tarif."}, {"kind": "point", "title": "Kenapa selalu tinggi?", "text": "Regulasinya dirancang agar default tak pernah lebih murah dari data asli — supaya tak ada yang untung dari diam. ⚠︎"}, {"kind": "stat", "title": "Default menyamaratakan", "big": "≈1,9 t", "label": "CO₂ per ton baja — rata-rata dunia. Pabrik bersih bisa jauh di bawahnya.", "source": "worldsteel, 2023"}, {"kind": "quote", "title": "Intinya", "text": "Nilai default bukan hukuman acak — ia dirancang agar 'tidak melapor' selalu lebih mahal daripada melapor jujur."}, {"kind": "end", "title": "Karbon terlacak = tarif lebih ringan", "text": "Baca ulasan lengkapnya, atau telusuri bareng Glyiv bagaimana data emisi terverifikasi menurunkan tagihan CBAM Anda."}], "sources": [{"a": "European Commission (2023). Regulation (EU) 2023/956 — Carbon Border Adjustment Mechanism.", "u": "https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en"}, {"a": "European Commission, DG TAXUD (2023). Guidance & default values for the CBAM transitional period.", "u": "https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en"}, {"a": "worldsteel (2023). Sustainability Indicators — CO₂ emissions intensity per tonne of crude steel.", "u": "https://worldsteel.org/data/sustainability-indicators/"}]}, {"slug": "eudr-sawit-kopi-karet", "topic": "Regulasi", "mood": "#4F7A3A", "title": "EUDR: bebas-deforestasi jadi syarat masuk pasar Eropa.", "dek": "Regulasi Anti-Deforestasi UE mewajibkan uji tuntas geolokasi untuk sawit, kopi, kakao, karet, dan kayu — \"bebas deforestasi\" berubah dari nilai tambah menjadi tiket masuk. Pemberlakuan penuh bagi pelaku besar ditunda hingga akhir 2025 ⚠︎.", "hook": "Eropa kini menolak sawit, kopi, dan kakao yang lahir dari hutan yang ditebang — dan meminta koordinat lahannya.", "cover": "https://images.unsplash.com/photo-1625246333195-78d9c38ad449?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen Komisi Eropa", "read": 5, "blocks": [{"t": "lead", "x": "Selama ini pintu masuk ke pasar Eropa dijaga oleh dua hal: harga dan mutu. Mulai akhir 2025, ada penjaga ketiga — bukti bahwa komoditas Anda tidak lahir dari hutan yang ditebang. Regulasi Anti-Deforestasi Uni Eropa (EUDR) mengubah 'bebas-deforestasi' dari sekadar nilai tambah menjadi syarat yang tak bisa ditawar."}, {"t": "p", "x": "EUDR — <a href=\"https://environment.ec.europa.eu/topics/forests/deforestation/regulation-deforestation-free-products_en\">Regulasi (UE) 2023/1115</a> — melarang penjualan di pasar UE untuk tujuh komoditas bila diproduksi di lahan yang mengalami deforestasi. Lima di antaranya menyangkut Indonesia secara langsung: <b>sawit, kopi, kakao, karet, dan kayu</b> (ditambah sapi dan kedelai). Setiap pelaku wajib melakukan <b>uji tuntas</b>: mengumpulkan koordinat geolokasi petak lahan tempat komoditas ditanam, lalu membuktikan lahan itu tidak dibuka dari hutan."}, {"t": "p", "x": "Batasnya tegas. Komoditas harus berasal dari lahan yang tidak mengalami deforestasi <b>setelah 31 Desember 2020</b>. Artinya satu titik koordinat yang jatuh di bekas tutupan hutan pasca-tanggal itu bisa menutup akses satu kiriman. Bukan lagi sertifikat di atas kertas — melainkan titik di peta yang bisa dicocokkan dengan citra satelit."}, {"t": "stat", "n": "31 Des 2020", "l": "Tanggal batas — komoditas harus bebas deforestasi setelah tanggal ini", "s": "Regulasi (UE) 2023/1115, Komisi Eropa"}, {"t": "pull", "x": "Eropa tak lagi hanya bertanya berapa harganya, tapi dari lahan mana asalnya."}, {"t": "h2", "x": "Beban terberat jatuh ke petani kecil"}, {"t": "p", "x": "Indonesia adalah produsen minyak sawit terbesar dunia, dan sekitar 40% ⚠︎ kebun sawitnya digarap petani swadaya — jutaan keluarga yang sering belum punya sertifikat lahan, apalagi peta poligon kebunnya <a href=\"https://fas.usda.gov/\">(USDA FAS)</a>. Bagi mereka, uji tuntas geolokasi bukan urusan administrasi ringan: tanpa data asal-usul yang terlacak, hasil panen mereka berisiko tersingkir dari rantai pasok yang menuju Eropa."}, {"t": "p", "x": "Justru karena kesiapan yang belum merata itulah pemberlakuan penuh ditunda. Semula berlaku 30 Desember 2024, EUDR digeser satu tahun lewat <a href=\"https://eur-lex.europa.eu/eli/reg/2024/3234/oj\">Regulasi (UE) 2024/3234</a>: <b>30 Desember 2025</b> bagi pelaku besar, dan 30 Juni 2026 bagi usaha mikro dan kecil. ⚠︎ Menjelang akhir 2025 masih beredar usulan penundaan dan penyederhanaan lanjutan — jadwal final sebaiknya dicek langsung ke sumber resmi UE."}, {"t": "h2", "x": "Yang bisa disiapkan sekarang"}, {"t": "p", "x": "Langkahnya bukan menunggu tenggat, tapi membangun <b>keterlacakan</b>: memetakan poligon kebun, menautkan setiap panen ke koordinatnya, dan menyimpan jejak itu agar bisa diaudit. Data yang sama yang membuka pintu Eropa juga memperkuat posisi tawar produsen — dari sekadar pemasok komoditas menjadi pemasok yang asal-usulnya bisa dibuktikan. Di situlah 'bebas-deforestasi' berhenti menjadi beban dan mulai menjadi keunggulan."}], "story": [{"kind": "cover", "title": "EUDR: bebas-deforestasi jadi tiket masuk Eropa", "text": "Regulasi Anti-Deforestasi UE mewajibkan uji tuntas geolokasi untuk sawit, kopi, kakao, karet, dan kayu — 'bebas deforestasi' kini syarat, bukan bonus. Pelaku besar: ditunda hingga akhir 2025 ⚠︎."}, {"kind": "hook", "title": "Penjaga baru di perbatasan", "text": "Eropa tak lagi hanya menanyakan harga dan mutu. Kini ia minta bukti: dari lahan mana komoditas Anda berasal?"}, {"kind": "point", "title": "Apa itu EUDR", "text": "Regulasi (UE) 2023/1115: tujuh komoditas dilarang masuk bila lahannya bekas hutan. Untuk Indonesia — sawit, kopi, kakao, karet, kayu. Wajib koordinat geolokasi tiap petak."}, {"kind": "point", "title": "Garis batasnya tegas", "text": "Lahan tak boleh dideforestasi setelah 31 Des 2020. Satu titik di bekas hutan bisa menutup satu kiriman. Dicocokkan dengan citra satelit — bukan sertifikat kertas."}, {"kind": "stat", "title": "Tanggal batas EUDR", "big": "31 Des 2020", "label": "Lahan harus bebas deforestasi setelah tanggal ini", "source": "Regulasi (UE) 2023/1115, Komisi Eropa"}, {"kind": "point", "title": "Petani kecil paling terdampak", "text": "Sekitar 40% ⚠︎ kebun sawit Indonesia digarap petani swadaya — banyak yang belum punya peta poligon kebun. Tanpa data terlacak, mereka bisa tersingkir dari pasar Eropa."}, {"kind": "end", "title": "Keterlacakan = keunggulan", "text": "Petakan poligon, tautkan panen ke koordinatnya, simpan jejak yang bisa diaudit. Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Komisi Eropa (2023). Regulation (EU) 2023/1115 on deforestation-free products (EUDR).", "u": "https://environment.ec.europa.eu/topics/forests/deforestation/regulation-deforestation-free-products_en"}, {"a": "Parlemen & Dewan Eropa (2024). Regulation (EU) 2024/3234 — penundaan penerapan EUDR selama 12 bulan.", "u": "https://eur-lex.europa.eu/eli/reg/2024/3234/oj"}, {"a": "USDA Foreign Agricultural Service (2024). Indonesia: Oilseeds and Products Annual — Indonesia produsen minyak sawit terbesar dunia.", "u": "https://fas.usda.gov/"}]}, {"slug": "ifrs-s2-laporan-iklim", "topic": "Regulasi", "mood": "#0B2471", "title": "IFRS S2: laporan iklim yang mulai diminta investor.", "dek": "Standar iklim ISSB (IFRS S1 & S2) membuat risiko iklim dan emisi Scope 1–3 dibaca sekritis neraca — dan investor global mulai memintanya sebagai syarat, bukan bonus.", "hook": "Dulu laporan iklim dibuat untuk citra. Sekarang investor memintanya dengan bahasa yang sama seperti neraca.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen IFRS Foundation & IOSCO", "read": 5, "blocks": [{"t": "lead", "x": "Selama ini laporan iklim dan laporan keuangan hidup di dua dunia terpisah — satu untuk citra, satu untuk angka. Kini investor mulai menuntut keduanya bicara bahasa yang sama: risiko iklim yang bisa dibaca sekritis neraca."}, {"t": "p", "x": "Pergeseran itu punya nama. Pada 26 Juni 2023, ISSB (International Sustainability Standards Board) — bagian dari IFRS Foundation, badan yang sama di balik standar akuntansi global — menerbitkan <b>IFRS S1</b> (kerangka umum pengungkapan keberlanjutan) dan <b>IFRS S2</b> (khusus iklim). Keduanya berlaku untuk periode pelaporan yang dimulai pada atau setelah 1 Januari 2024 <a href=\"https://www.ifrs.org/issued-standards/ifrs-sustainability-standards-navigator/ifrs-s2-climate-related-disclosures/\">IFRS Foundation</a>."}, {"t": "p", "x": "IFRS S2 meminta perusahaan mengungkap risiko dan peluang iklim lewat empat pilar yang sudah dikenal dari TCFD — tata kelola, strategi, manajemen risiko, serta metrik dan target. Bagian paling menuntut: pengungkapan emisi gas rumah kaca <b>Scope 1, 2, dan 3</b>, dihitung mengikuti GHG Protocol. Ada kelonggaran transisi — Scope 3 boleh ditunda pada tahun pertama penerapan — tapi justru di sanalah emisi terbesar sering bersembunyi."}, {"t": "p", "x": "Risiko iklim yang dimaksud punya dua wajah: <b>risiko fisik</b> — banjir, kekeringan, gelombang panas yang mengganggu aset dan rantai pasok — dan <b>risiko transisi</b> — perubahan kebijakan, harga karbon, serta selera pasar saat dunia bergerak rendah-karbon. IFRS S2 meminta perusahaan menjelaskan bagaimana keduanya bisa memengaruhi arus kas, akses pendanaan, dan nilai aset dari waktu ke waktu."}, {"t": "stat", "n": "11,4×", "l": "Emisi Scope 3 rata-rata sekian kali lebih besar daripada emisi operasional (Scope 1 & 2)", "s": "CDP, 2022"}, {"t": "pull", "x": "Investor tak lagi bertanya 'apakah Anda peduli iklim', tapi 'tunjukkan angkanya — dengan metode yang bisa saya bandingkan'."}, {"t": "h2", "x": "Kenapa dorongan datang dari investor"}, {"t": "p", "x": "IFRS S2 dirancang sebagai <b>baseline global</b>: dasar minimum yang bisa dipakai investor lintas negara untuk membandingkan perusahaan setara. IOSCO, organisasi payung regulator pasar modal dunia yang menaungi lebih dari 95% pasar sekuritas global, mendukung standar ini pada Juli 2023 dan mendorong anggotanya mempertimbangkan adopsi <a href=\"https://www.iosco.org/news/pdf/IOSCONEWS703.pdf\">IOSCO</a>. Sejak 2024, ISSB juga mengambil alih pemantauan pengungkapan iklim dari TCFD yang dibubarkan — satu bahasa, bukan puluhan format."}, {"t": "h2", "x": "Apa artinya bagi perusahaan Indonesia"}, {"t": "p", "x": "Indonesia belum mewajibkannya penuh, tapi arahnya jelas. OJK sudah menuntut Laporan Keberlanjutan lewat <b>POJK 51/2017</b> dan menyusun Taksonomi Keuangan Berkelanjutan sebagai acuan; adopsi resmi IFRS S1/S2 sebagai standar nasional masih berproses ⚠︎. Bagi eksportir dan perusahaan pemburu modal asing, tuntutan justru datang lebih dulu dari investor dan pembeli, bukan regulator. Benang merahnya sama seperti CBAM: yang menentukan bukan niat, tapi <b>data yang bisa ditelusuri hingga sumbernya</b>. Memetakan emisi Scope 1–3 hari ini — tertelusur, selaras GHG Protocol, siap diaudit — bukan soal mengejar tenggat, tapi bersiap untuk saat pertanyaan itu datang dari orang yang memegang cek."}], "story": [{"kind": "cover", "title": "IFRS S2: laporan iklim yang mulai diminta investor", "text": "Standar iklim ISSB membuat risiko iklim dan emisi Scope 1–3 dibaca sekritis neraca — dan investor global mulai memintanya sebagai syarat, bukan bonus."}, {"kind": "hook", "title": "Dua dunia menyatu", "text": "Dulu laporan iklim untuk citra. Sekarang investor memintanya dengan bahasa yang sama seperti neraca."}, {"kind": "point", "title": "Apa itu IFRS S1 & S2", "text": "Standar ISSB — bagian dari IFRS Foundation. Terbit 26 Juni 2023, berlaku sejak 1 Januari 2024. Satu bahasa global untuk pengungkapan iklim."}, {"kind": "point", "title": "Yang diminta", "text": "Empat pilar TCFD — tata kelola, strategi, risiko, target — plus emisi Scope 1, 2, dan 3 (GHG Protocol). Scope 3 paling sulit dilacak, sekaligus paling besar."}, {"kind": "stat", "title": "Beban tersembunyi di Scope 3", "big": "11,4×", "label": "Emisi Scope 3 rata-rata sekian kali lebih besar dari emisi operasional", "source": "CDP, 2022"}, {"kind": "point", "title": "Dorongan dari investor, bukan regulator", "text": "IFRS S2 = baseline global, didukung IOSCO (Juli 2023). Yang menuntut lebih dulu: pemegang modal dan pembeli, bukan aturan."}, {"kind": "end", "title": "Bersiap sebelum ditanya", "text": "Di Indonesia, OJK sudah menuntut Laporan Keberlanjutan (POJK 51/2017). Mulai petakan emisi Scope 1–3 Anda — tertelusur, siap diaudit — bersama Glyiv."}], "sources": [{"a": "IFRS Foundation (2023). IFRS S2 Climate-related Disclosures.", "u": "https://www.ifrs.org/issued-standards/ifrs-sustainability-standards-navigator/ifrs-s2-climate-related-disclosures/"}, {"a": "IFRS Foundation (2023). IFRS S1 General Requirements for Disclosure of Sustainability-related Financial Information.", "u": "https://www.ifrs.org/issued-standards/ifrs-sustainability-standards-navigator/ifrs-s1-general-requirements/"}, {"a": "IOSCO (2023). IOSCO endorses the ISSB's Sustainability-related Financial Disclosures Standards.", "u": "https://www.iosco.org/news/pdf/IOSCONEWS703.pdf"}, {"a": "CDP (2022). Scope 3 emissions rata-rata 11,4x lebih besar dari emisi operasional (CDP Global Supply Chain / Technical Note).", "u": "https://www.cdp.net/en/research"}]}, {"slug": "pcaf-emisi-yang-dibiayai", "topic": "Sektor", "mood": "#0B2471", "title": "Emisi yang dibiayai: jejak karbon tersembunyi di balik pinjaman bank.", "dek": "Standar PCAF menghitung emisi dari setiap pinjaman dan investasi sebuah bank. Hasilnya kerap ratusan kali lebih besar dari emisi kantor, listrik, dan perjalanan dinasnya — dan selama ini jarang masuk laporan.", "hook": "Jejak karbon terbesar sebuah bank bukan di kantornya — tapi di setiap pinjaman yang ia cairkan.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan standar PCAF & sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Jejak karbon sebuah bank tampak kecil bila hanya dihitung dari kantor, pendingin ruangan, dan perjalanan dinas. Tapi itu bukan bagian terbesarnya. Dampak iklim paling nyata dari sebuah bank justru berada di luar temboknya — di setiap pinjaman yang ia cairkan dan setiap saham yang ia pegang."}, {"t": "p", "x": "Standar yang memberi nama pada dampak itu menyebutnya <b>financed emissions</b> — emisi yang dibiayai. Dikembangkan oleh <a href=\"https://carbonaccountingfinancials.com/\">PCAF</a> (Partnership for Carbon Accounting Financials), metode ini menghitung emisi dari portofolio pinjaman dan investasi, lalu memetakannya sebagai Cakupan 3 Kategori 15 — 'Investasi' — dalam <a href=\"https://ghgprotocol.org/standards/scope-3-standard\">GHG Protocol</a>. Logikanya sederhana: bila sebuah pabrik melepas emisi dan bank membiayai sebagian nilainya, porsi emisi itu ikut tercatat di buku bank."}, {"t": "stat", "n": "≈700×", "l": "rata-rata emisi portofolio lembaga keuangan dibanding emisi operasionalnya sendiri", "s": "CDP, The Time to Green Finance, 2021"}, {"t": "pull", "x": "Bagi banyak bank, emisi yang dibiayai bisa ratusan kali lebih besar dari emisi operasionalnya sendiri — dan selama ini nyaris tak pernah masuk laporan."}, {"t": "h2", "x": "Bagaimana angkanya disusun"}, {"t": "p", "x": "Inti metodenya adalah <b>faktor atribusi</b>: porsi emisi debitur yang menjadi tanggung jawab bank dihitung dari nilai pinjaman dibagi nilai perusahaan (utang ditambah ekuitas). Karena data emisi debitur kerap tak lengkap, PCAF menyertakan <b>skor kualitas data</b> berskala 1–5 — dari angka terverifikasi hingga estimasi berbasis rata-rata sektor. Artinya angka pertama hampir selalu kasar, lalu menajam seiring membaiknya data debitur. Ini terlacak, belum tentu presisi."}, {"t": "h2", "x": "Apa artinya bagi bank di Indonesia"}, {"t": "p", "x": "Arah regulasi di Indonesia sudah terbentuk. <a href=\"https://www.ojk.go.id/\">OJK</a> menerbitkan Taksonomi untuk Keuangan Berkelanjutan Indonesia pada 2024, kelanjutan dari POJK 51/2017 tentang keuangan berkelanjutan. ⚠︎ Kewajiban pelaporan financed emissions yang spesifik dan mengikat bagi seluruh bank belum final — sebagian besar masih bergerak sebagai komitmen sukarela dan roadmap. Namun tekanannya datang dari dua sisi: investor global yang menuntut keselarasan dengan target net-zero, dan bank sendiri yang mulai melihat betapa terkonsentrasinya risiko iklim di portofolionya."}, {"t": "p", "x": "Yang berubah bukan sekadar kewajiban lapor, melainkan cara bank memandang portofolionya. Pinjaman ke sektor intensif-karbon kini membawa risiko transisi — nilai aset bisa tergerus bila kebijakan iklim mengetat. Menghitung emisi yang dibiayai adalah langkah pertama untuk melihat risiko itu sebelum ia menjadi kerugian. Bukan soal mengklaim hijau, tapi soal tahu persis di mana portofolio Anda berdiri."}], "story": [{"kind": "cover", "title": "Emisi yang dibiayai", "text": "Standar PCAF menghitung emisi dari setiap pinjaman dan investasi sebuah bank. Hasilnya kerap ratusan kali lebih besar dari emisi kantor, listrik, dan perjalanan dinasnya — dan selama ini jarang masuk laporan."}, {"kind": "hook", "title": "Di luar tembok", "text": "Jejak karbon terbesar sebuah bank bukan di kantornya — tapi di setiap pinjaman yang ia cairkan."}, {"kind": "point", "title": "Jejak yang sebenarnya", "text": "Emisi terbesar sebuah bank datang bukan dari operasinya, tapi dari pabrik, tambang, dan proyek yang ia biayai."}, {"kind": "point", "title": "Namanya: emisi yang dibiayai", "text": "Standar PCAF memetakannya sebagai Cakupan 3 Kategori 15 GHG Protocol — porsi emisi debitur yang menjadi tanggung jawab pemberi pinjaman."}, {"kind": "stat", "title": "Selisih yang mengejutkan", "big": "≈700×", "label": "emisi portofolio vs emisi operasional lembaga keuangan", "source": "CDP, The Time to Green Finance, 2021"}, {"kind": "point", "title": "Indonesia mulai bergerak", "text": "OJK sudah menerbitkan taksonomi keuangan berkelanjutan. ⚠︎ Kewajiban pelaporan yang mengikat belum final — tekanan kini datang dari investor dan risiko transisi."}, {"kind": "end", "title": "Lihat di mana portofolio Anda berdiri", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan telusuri bagaimana karbon menjadi lensa risiko, bukan sekadar laporan."}], "sources": [{"a": "PCAF (2022). The Global GHG Accounting and Reporting Standard for the Financial Industry, Part A, Second Edition.", "u": "https://carbonaccountingfinancials.com/standard"}, {"a": "CDP (2021). The Time to Green Finance: CDP Financial Services Disclosure Report 2020.", "u": "https://www.cdp.net/en/research/global-reports/financial-services-disclosure-report-2020"}, {"a": "GHG Protocol (2013). Corporate Value Chain (Scope 3) Standard, Category 15: Investments.", "u": "https://ghgprotocol.org/standards/scope-3-standard"}, {"a": "Otoritas Jasa Keuangan (2024). Taksonomi untuk Keuangan Berkelanjutan Indonesia (TKBI).", "u": "https://www.ojk.go.id/"}]}, {"slug": "pasal-6-paris-perdagangan", "topic": "Global", "mood": "#1E5F8C", "title": "Pasal 6 Paris: bagaimana Indonesia menjual kredit karbon lintas negara", "dek": "Perjanjian Paris membuka jalan agar satu ton pengurangan emisi bisa berpindah tangan antarnegara — tapi hanya jika 'corresponding adjustment' memastikan ton itu tidak diklaim dua kali.", "hook": "Satu ton karbon, dua negara yang sama-sama ingin mengklaimnya. Pasal 6 Paris menentukan siapa yang berhak.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Bayangkan satu proyek panas bumi di Sulawesi menurunkan emisi setara satu ton CO₂. Ton itu bisa tetap tercatat di neraca iklim Indonesia — atau dijual ke Jepang, Swiss, atau Singapura yang perlu menutup targetnya sendiri. Yang menentukan bukan harganya, melainkan satu aturan akuntansi bernama Pasal 6 Perjanjian Paris."}, {"t": "p", "x": "Pasal 6 adalah bagian <a href=\"https://unfccc.int/process-and-meetings/the-paris-agreement/paris-agreement-article-6\">Perjanjian Paris</a> yang mengizinkan negara bekerja sama menurunkan emisi lintas batas. Lewat <b>Pasal 6.2</b>, sebuah negara boleh mengalihkan hasil pengurangan emisinya — disebut ITMO, <i>Internationally Transferred Mitigation Outcome</i> — kepada negara lain untuk dihitung ke dalam target iklim (NDC) pembeli. Sederhananya: satu ton yang diturunkan di sini bisa berpindah klaim ke sana. Pembeli mendapat 'kredit' untuk targetnya; penjual melepas haknya atas ton itu."}, {"t": "h2", "x": "Corresponding adjustment: agar tak dihitung dua kali"}, {"t": "p", "x": "Di sinilah aturan main yang paling menentukan. Ketika Indonesia mengotorisasi lalu mentransfer satu ton ke luar negeri, ia wajib melakukan <b>corresponding adjustment</b> — menambahkan kembali ton itu ke inventarisasi emisinya sendiri. Angka yang dijual harus benar-benar hilang dari satu sisi buku besar dan muncul di sisi lain. Konsekuensinya, negara penjual tidak boleh ikut mengklaim pengurangan yang sudah dilepas. Prosedur ini ditetapkan dalam panduan COP26 (Keputusan 2/CMA.3) dan menjadi syarat agar transfer benar-benar kredibel, bukan sekadar tukar sertifikat."}, {"t": "pull", "x": "Tanpa penyesuaian itu, satu ton yang sama bisa diklaim dua negara sekaligus — dan janji iklim keduanya jadi separuh nyata."}, {"t": "p", "x": "Indonesia menaruh mekanisme ini di dalam kerangka Nilai Ekonomi Karbon (NEK). Aturan terbarunya, <a href=\"https://peraturan.bpk.go.id/Details/334733/perpres-no-110-tahun-2025\">Peraturan Presiden No. 110 Tahun 2025</a> yang terbit Oktober 2025, menggantikan regulasi 2021 sekaligus membuka kembali perdagangan karbon internasional yang sempat dijeda empat tahun. Perpres itu menegaskan bahwa transfer di bawah Pasal 6.2 dan 6.4 membutuhkan <b>otorisasi Menteri Lingkungan Hidup</b> (dulu KLHK) plus corresponding adjustment sebelum dieksekusi, dengan pencatatan lewat registri nasional SRN-PPI dan SRUK."}, {"t": "stat", "n": "4 tahun", "l": "jeda perdagangan karbon internasional Indonesia sebelum dibuka lagi (Okt 2025)", "s": "Reuters, 2025"}, {"t": "h2", "x": "Apa artinya bagi penjual di Indonesia"}, {"t": "p", "x": "Otorisasi menjadi gerbang: tidak semua kredit boleh keluar negeri. IDXCarbon bahkan memisahkan produk yang 'diotorisasi untuk perdagangan internasional' dari yang hanya untuk pasar domestik. Pemerintah juga menandatangani pengakuan bersama (MRA) dengan beberapa standar global — seperti Gold Standard, Plan Vivo, dan Global Carbon Council — dan di COP29 (2024) menyepakati kerja sama bilateral dengan Jepang untuk perdagangan di bawah Pasal 6.2. Meski begitu, jumlah transfer berotorisasi penuh yang benar-benar rampung masih sedikit ⚠︎ — kerangkanya baru dan banyak detail teknis terus disusun."}, {"t": "p", "x": "Untuk Glyiv, pelajaran intinya sederhana: nilai sebuah kredit bukan cuma harganya, melainkan seberapa jujur ia dicatat. Satu ton yang <b>terlacak</b> rapi, berotorisasi, dan disesuaikan dengan benar adalah kontribusi iklim yang bisa dipertanggungjawabkan. Yang tidak, hanyalah kertas. Pasal 6 memaksa setiap pihak — termasuk Indonesia — memilih yang pertama."}], "story": [{"kind": "cover", "title": "Pasal 6 Paris", "text": "Perjanjian Paris membuka jalan agar satu ton pengurangan emisi bisa berpindah tangan antarnegara — tapi hanya jika 'corresponding adjustment' memastikan ton itu tidak diklaim dua kali."}, {"kind": "hook", "title": "Satu ton, dua negara", "text": "Siapa yang berhak mengklaim pengurangan emisi yang sama? Pasal 6 Paris yang menjawab."}, {"kind": "point", "title": "Apa itu Pasal 6.2", "text": "Sebuah negara boleh mengalihkan hasil pengurangan emisinya (ITMO) untuk dihitung ke target iklim negara lain."}, {"kind": "point", "title": "Corresponding adjustment", "text": "Penjual wajib menambahkan kembali ton yang dijual ke neracanya sendiri — supaya tak dihitung dua kali."}, {"kind": "point", "title": "Aturan Indonesia", "text": "Perpres 110/2025 + otorisasi Menteri Lingkungan Hidup jadi syarat setiap transfer lintas negara."}, {"kind": "stat", "title": "Empat tahun jeda", "big": "4 tahun", "label": "jeda sebelum perdagangan internasional dibuka lagi (Okt 2025)", "source": "Reuters, 2025"}, {"kind": "end", "title": "Baca versi lengkapnya", "text": "Kredit yang jujur dicatat adalah kontribusi nyata. Selami intelijen karbon bersama Glyiv."}], "sources": [{"a": "UNFCCC, 'Paris Agreement, Article 6' (2015)", "u": "https://unfccc.int/process-and-meetings/the-paris-agreement/paris-agreement-article-6"}, {"a": "UNFCCC, Keputusan 2/CMA.3, 'Guidance on cooperative approaches referred to in Article 6, paragraph 2, of the Paris Agreement', Glasgow (2021)"}, {"a": "Peraturan Presiden No. 110 Tahun 2025 tentang Penyelenggaraan Instrumen Nilai Ekonomi Karbon dan Pengendalian Emisi Gas Rumah Kaca Nasional", "u": "https://peraturan.bpk.go.id/Details/334733/perpres-no-110-tahun-2025"}, {"a": "SSEK Law Firm, 'Indonesia Introduces New Carbon Trading Framework Under Presidential Regulation No. 110 of 2025' (2025)", "u": "https://ssek.com/blog/indonesia-introduces-new-carbon-trading-framework-under-presidential-regulation-no-110-of-2025/"}]}, {"slug": "idxcarbon-pembeli-internasional", "topic": "Regulasi", "mood": "#B0894F", "title": "Bursa Karbon Indonesia kini terbuka bagi pembeli internasional.", "dek": "Sejak 20 Januari 2025, IDXCarbon membuka perdagangan unit karbon bagi pembeli luar negeri — langkah yang bisa menebalkan permintaan, sekaligus menaikkan taruhan atas kejujuran setiap kredit.", "hook": "Untuk pertama kalinya, kredit karbon Indonesia bisa dibeli dari luar negeri. Yang berubah bukan cuma volume — tapi standar buktinya.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan siaran pers OJK/KLH/BEI & laporan publik", "read": 4, "blocks": [{"t": "lead", "x": "Selama lebih dari setahun, unit karbon di Bursa Karbon Indonesia hanya boleh berpindah tangan di dalam negeri. Sejak 20 Januari 2025, pintu itu terbuka — pembeli dari luar negeri kini bisa membeli kredit karbon Indonesia langsung lewat IDXCarbon, dan itu mengubah siapa saja yang ikut menetapkan harganya."}, {"t": "p", "x": "Peresmian dilakukan bersama oleh Kementerian Lingkungan Hidup, Otoritas Jasa Keuangan, dan Bursa Efek Indonesia. Pada hari pertama, IDXCarbon mencatat <b>1,78 juta unit karbon</b> dari lima proyek energi — termasuk pembangkit hidro dan gas — dengan harga pembuka Rp96.000 per ton untuk kategori berbasis teknologi dan Rp144.000 untuk kategori energi terbarukan <a href=\"https://www.spglobal.com/energy/en/news-research/latest-news/energy-transition/012025-indonesia-launches-international-carbon-trading-on-idx-with-five-power-plants\">(S&P Global)</a>."}, {"t": "p", "x": "Bursa ini sendiri masih muda. Sejak diluncurkan pada 26 September 2023, jumlah pengguna jasanya tumbuh dari 16 menjadi sekitar 100 pada akhir 2024, dan ditargetkan menembus 200 pada 2025 <a href=\"https://ojk.go.id/id/berita-dan-kegiatan/siaran-pers/Pages/Peresmian-Perdagangan-Karbon-Luar-Negeri.aspx\">(OJK)</a>. Membuka pasar internasional adalah cara mempercepat kurva itu — mengundang modal dan pembeli yang selama ini menunggu di luar pagar."}, {"t": "p", "x": "Untuk menarik minat, IDXCarbon membebaskan peserta internasional dari biaya registrasi, biaya pencatatan, iuran keanggotaan, dan biaya tahunan <a href=\"https://lestari.kompas.com/read/2025/01/21/090000286/pembeli-karbon-dari-luar-negeri-dapat-sederet-insentif\">(Kompas)</a>. Logikanya sederhana: lebih banyak pembeli berarti permintaan lebih tebal — dan harga yang lebih mendekati nilai sebenarnya dari satu ton yang tak jadi terlepas ke atmosfer."}, {"t": "pull", "x": "Membuka pasar memang menaikkan permintaan. Tapi permintaan besar hanya bermakna bila setiap unit benar-benar mewakili satu ton nyata — dan tak dihitung dua kali."}, {"t": "h2", "x": "Permintaan naik, tuntutan integritas ikut naik"}, {"t": "p", "x": "Di sinilah taruhannya. Begitu unit karbon Indonesia bisa dipakai menutup target negara atau perusahaan lain, risiko <b>penghitungan ganda</b> menjadi nyata. Kerangka Pasal 6 Perjanjian Paris menuntut adanya <i>corresponding adjustment</i> — setiap pengurangan yang dijual ke luar negeri harus dikurangkan dari neraca NDC Indonesia, agar tak diklaim dua pihak sekaligus. Sepanjang 2025, pemerintah juga menjalin pengakuan bersama dengan standar seperti Verra dan Gold Standard ⚠︎."}, {"t": "stat", "n": "1,78 juta", "l": "unit karbon terjual pada hari pertama perdagangan internasional, dari lima proyek energi", "s": "S&P Global, 20 Jan 2025"}, {"t": "p", "x": "Antusiasme itu perlu ditimbang dengan kenyataan. Sepanjang 2025, volume di IDXCarbon masih tipis — sekitar 0,6 juta ton CO₂e ⚠︎, dengan peserta yang masih didominasi BUMN sektor listrik <a href=\"https://ieefa.org/resources/two-years-after-launch-indonesias-carbon-market-struggles-find-momentum\">(IEEFA)</a>. Membuka keran internasional adalah undangan, bukan jaminan bahwa uang akan mengalir masuk."}, {"t": "p", "x": "Yang pada akhirnya menentukan bukan sekadar akses pasar, melainkan <b>bukti</b>. Pembeli internasional yang serius akan menuntut jejak yang bisa ditelusuri — dari petak lahan hingga tanda tangan registri — sebelum menaruh namanya pada sebuah kredit. Bagi proyek Indonesia, keterbukaan ini adalah peluang; bagi yang datanya rapuh, ia adalah ujian."}], "story": [{"kind": "cover", "title": "Bursa karbon kini terbuka bagi pembeli internasional", "text": "Sejak 20 Januari 2025, IDXCarbon membuka perdagangan unit karbon bagi pembeli luar negeri — menebalkan permintaan, sekaligus menaikkan taruhan atas kejujuran setiap kredit."}, {"kind": "hook", "title": "Pintu yang lama tertutup", "text": "Untuk pertama kalinya, kredit karbon Indonesia bisa dibeli dari luar negeri."}, {"kind": "point", "title": "Apa yang berubah", "text": "IDXCarbon membuka perdagangan bagi pembeli asing — lengkap dengan pembebasan biaya registrasi dan keanggotaan."}, {"kind": "point", "title": "Kenapa penting", "text": "Lebih banyak pembeli berarti permintaan lebih tebal — dan harga yang lebih dekat ke nilai sebenarnya satu ton."}, {"kind": "stat", "title": "Sinyal permintaan", "big": "1,78 juta", "label": "unit karbon terjual di hari pertama, dari lima proyek energi", "source": "S&P Global, 20 Jan 2025"}, {"kind": "point", "title": "Syaratnya: integritas", "text": "Begitu kredit bisa menutup target pihak lain, penghitungan ganda jadi risiko nyata. Pasal 6 Paris menuntut corresponding adjustment."}, {"kind": "end", "title": "Peluang, sekaligus ujian", "text": "Akses pasar hanya bermakna bila setiap unit bisa ditelusuri. Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "OJK, KLH/BPLH & PT Bursa Efek Indonesia (2025). Siaran Pers Bersama: Peresmian Perdagangan Karbon Luar Negeri, 20 Januari 2025.", "u": "https://ojk.go.id/id/berita-dan-kegiatan/siaran-pers/Pages/Peresmian-Perdagangan-Karbon-Luar-Negeri.aspx"}, {"a": "S&P Global Commodity Insights (2025). Indonesia launches international carbon trading on IDX with five power plants.", "u": "https://www.spglobal.com/energy/en/news-research/latest-news/energy-transition/012025-indonesia-launches-international-carbon-trading-on-idx-with-five-power-plants"}, {"a": "Kompas Lestari (2025). Pembeli Karbon dari Luar Negeri Dapat Sederet Insentif.", "u": "https://lestari.kompas.com/read/2025/01/21/090000286/pembeli-karbon-dari-luar-negeri-dapat-sederet-insentif"}, {"a": "IEEFA (2025). Two years after launch, Indonesia's carbon market struggles to find momentum.", "u": "https://ieefa.org/resources/two-years-after-launch-indonesias-carbon-market-struggles-find-momentum"}]}, {"slug": "icvcm-core-carbon-principles", "topic": "Offset", "mood": "#1cae6b", "title": "Menyaring kredit 'zombie': apa itu Core Carbon Principles.", "dek": "Pasar karbon sukarela dibanjiri kredit yang tak jelas asalnya; ICVCM dan VCMI memasang dua rambu — satu menyaring mutu kredit, satu menjaga kejujuran klaim — untuk memisahkan offset bermakna dari sekadar label.", "hook": "Ada 'kredit zombie' yang beredar bertahun-tahun tanpa karbon nyata di baliknya. Kini dua rambu mulai menyaringnya.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen ICVCM & VCMI", "read": 4, "blocks": [{"t": "lead", "x": "Pasar karbon sukarela punya penyakit lama: kredit yang beredar bertahun-tahun tanpa jaminan ada karbon nyata di baliknya. Sebagian lahir dari proyek usang yang didaur ulang, sebagian dari klaim yang tak pernah lolos standar. Pembeli serius menyebutnya 'kredit zombie' — dan sulit membedakan yang bermakna dari yang sekadar berlabel."}, {"t": "p", "x": "Kekhawatiran ini bukan retorika. Analisis independen atas sejumlah kredit hutan menemukan mayoritas tak mewakili pengurangan emisi nyata — proyek melebih-lebihkan ancaman deforestasi yang seolah dicegah <a href=\"https://www.science.org/doi/10.1126/science.ade3535\">(West dkk., <em>Science</em>, 2023)</a>. Temuan semacam itulah yang mendorong lahirnya rambu mutu yang lebih ketat."}, {"t": "p", "x": "Untuk itu <b>ICVCM</b> (Integrity Council for the Voluntary Carbon Market) menerbitkan <b>Core Carbon Principles</b> pada 2023 — sepuluh prinsip yang menjadi ambang mutu bagi kredit sukarela. Prinsip-prinsip itu dikelompokkan ke tiga pilar: tata kelola, dampak emisi, dan pembangunan berkelanjutan. Program serta metodologi yang lolos penilaian independen berhak menyandang <b>label CCP</b> — penanda bahwa kreditnya memenuhi standar minimum, bukan sekadar diperdagangkan. <a href=\"https://icvcm.org/core-carbon-principles/\">(ICVCM)</a>"}, {"t": "p", "x": "Tiga prinsip menyaring paling banyak kredit zombie. <b>Adisionalitas</b>: penyerapan karbon benar terjadi karena kreditnya, bukan sesuatu yang toh akan terjadi tanpa dana itu. <b>Permanensi</b>: karbon yang diserap tak lepas kembali dalam waktu dekat. Dan <b>tanpa penghitungan ganda</b>: satu ton hanya boleh diklaim satu pihak, satu kali. Banyak kredit lama gugur justru di tiga titik ini."}, {"t": "pull", "x": "CCP menilai mutu kreditnya; VCMI menilai kejujuran klaimnya. Satu menyaring pasokan, satu menjaga bagaimana kredit itu boleh disebut."}, {"t": "stat", "n": "10 prinsip", "l": "Core Carbon Principles ICVCM — di 3 pilar: tata kelola, dampak emisi, pembangunan berkelanjutan", "s": "ICVCM, 2023"}, {"t": "h2", "x": "Sisi permintaan: siapa yang boleh mengklaim apa"}, {"t": "p", "x": "Kalau ICVCM menjaga sisi pasokan, <b>VCMI</b> (Voluntary Carbon Markets Integrity Initiative) menjaga sisi permintaan lewat <b>Claims Code of Practice</b> (2023). Aturannya membalik urutan yang biasa: perusahaan tak boleh sekadar membeli kredit lalu mengaku bersih. Ia harus lebih dulu menghitung emisinya, menetapkan target pengurangan berbasis sains, dan menurunkan emisi itu — baru boleh menyebut kontribusinya pada tingkat Silver, Gold, atau Platinum, bergantung seberapa besar sisa emisi yang ia tanggung. <a href=\"https://vcmintegrity.org/vcmi-claims-code-of-practice/\">(VCMI)</a>"}, {"t": "p", "x": "Dua rambu ini penting karena saling menutup celah. Label CCP tak berarti bila perusahaan memakainya untuk klaim berlebihan; klaim VCMI tak berarti bila kreditnya zombie. Penilaian keduanya pun masih berjalan — cakupan metodologi yang sudah lolos label CCP terus bertambah dan sebaiknya dicek langsung ke registri ⚠︎. Bagi Glyiv, arahnya jelas: bukti yang terlacak sampai ke petak lahan, bukan sekadar label yang menenangkan hati."}], "story": [{"kind": "cover", "title": "Menyaring kredit 'zombie'", "text": "ICVCM dan VCMI memasang dua rambu untuk memisahkan offset bermakna dari sekadar label."}, {"kind": "hook", "title": "Kredit 'zombie'", "text": "Beredar bertahun-tahun tanpa jaminan ada karbon nyata di baliknya. Sulit dibedakan dari yang asli."}, {"kind": "point", "title": "Rambu 1 — ICVCM", "text": "Core Carbon Principles: 10 prinsip mutu untuk kredit. Lolos penilaian independen, dapat label CCP."}, {"kind": "point", "title": "Tiga saringan inti", "text": "Adisionalitas, permanensi, dan tanpa penghitungan ganda. Di sinilah kebanyakan kredit zombie gugur."}, {"kind": "stat", "title": "Ukuran mutunya", "big": "10", "label": "prinsip di 3 pilar Core Carbon Principles", "source": "ICVCM, 2023"}, {"kind": "point", "title": "Rambu 2 — VCMI", "text": "Mengatur klaim perusahaan: hitung dan kurangi emisi dulu, baru boleh mengaku kontribusi (Silver/Gold/Platinum)."}, {"kind": "end", "title": "Bukti, bukan label", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan ikut kami membangun karbon yang terlacak sampai ke petak lahan."}], "sources": [{"a": "ICVCM (2023). The Core Carbon Principles, Assessment Framework and Assessment Procedure. Integrity Council for the Voluntary Carbon Market.", "u": "https://icvcm.org/core-carbon-principles/"}, {"a": "VCMI (2023). Claims Code of Practice. Voluntary Carbon Markets Integrity Initiative.", "u": "https://vcmintegrity.org/vcmi-claims-code-of-practice/"}, {"a": "West, T.A.P., dkk. (2023). Action needed to make carbon offsets from tropical forest conservation work for climate change mitigation. Science, 381(6660).", "u": "https://www.science.org/doi/10.1126/science.ade3535"}]}, {"slug": "ndc-kedua-indonesia", "topic": "Regulasi", "mood": "#0B2471", "title": "NDC kedua Indonesia: dari target ke bukti penurunan.", "dek": "Indonesia sudah menaruh angkanya di atas meja — 31,89% mandiri, hingga 43,20% bersyarat pada 2030 — tapi pencapaiannya nyaris seluruhnya bergantung pada dua sektor: hutan-lahan dan energi.", "hook": "Targetnya sudah ada. Pertanyaannya: siapa yang benar-benar akan menurunkan emisinya — dan bagaimana kita tahu itu nyata?", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Enhanced NDC & dokumen publik", "read": 4, "blocks": [{"t": "lead", "x": "Menetapkan target iklim itu mudah; membuktikan penurunannya jauh lebih sulit. Indonesia sudah menaruh angkanya di atas meja — 31,89 persen dengan usaha sendiri, hingga 43,20 persen bila ada dukungan internasional, dipotong dari proyeksi emisi 2030. Sejak itu, pertanyaan yang menentukan bukan lagi 'berapa targetnya', melainkan 'sektor mana yang benar-benar akan mengantar ke sana — dan bagaimana kita tahu itu terjadi'."}, {"t": "p", "x": "Angka itu berasal dari <b>Enhanced NDC</b> yang diserahkan Indonesia ke UNFCCC pada September 2022 <a href=\"https://unfccc.int/sites/default/files/NDC/2022-09/23.09.2022_Enhanced%20NDC%20Indonesia.pdf\">(dokumen resmi)</a>. Keduanya diukur terhadap skenario tanpa-intervensi (BAU) sebesar <b>2,869 GtCO₂e</b> pada 2030 — naik dari komitmen sebelumnya, 29 persen dan 41 persen. NDC kedua berhorizon 2035 masih dalam penyusunan ⚠︎, sehingga kerangka 2030 inilah tolok ukur terdekat yang bisa dipegang."}, {"t": "h2", "x": "Dua sektor yang menentukan"}, {"t": "p", "x": "Bila dibedah per sektor, ceritanya mengejutkan dalam kesederhanaannya. Dari target mandiri 31,89 persen, sektor <b>kehutanan dan lahan (FOLU)</b> menyumbang 17,57 poin dan <b>energi</b> 12,50 poin — bersama-sama hampir <b>94 persen</b> dari seluruh penurunan yang direncanakan. Limbah, pertanian, dan industri, digabung sekalipun, hanya menyumbang sisa yang tipis. Artinya: pencapaian NDC nyaris sepenuhnya adalah soal dua sektor ini."}, {"t": "bars", "h": [1, 0.71, 0.08, 0.02, 0.01], "cap": "Kontribusi tiap sektor pada target mandiri 31,89% (CM1): FOLU, energi, limbah, pertanian, industri. Sumber: Enhanced NDC Indonesia, 2022."}, {"t": "p", "x": "FOLU adalah tuas terbesar sekaligus paling rapuh. Rencananya bernama <b>FOLU Net Sink 2030</b>: menjadikan hutan dan lahan menyerap lebih banyak karbon daripada yang dilepas, hingga posisi bersih −140 MtCO₂e pada 2030 <a href=\"https://www.menlhk.go.id/\">(KLHK, 2022)</a>. Itu hanya mungkin bila laju deforestasi ditekan, lahan gambut direstorasi, dan mangrove dijaga — pekerjaan bertahun-tahun, bukan janji yang ditandatangani sekali lalu selesai."}, {"t": "pull", "x": "Target menutup satu baris di atas kertas. Bukti penurunan menuntut setiap hektar hutan dan setiap megawatt bersih benar-benar terlacak."}, {"t": "p", "x": "Sektor energi lebih pelan dan lebih mahal. Kemitraan <b>JETP</b> menjanjikan dana US$20 miliar pada 2022 untuk mempercepat transisi kelistrikan, dengan sasaran sekitar 34 persen pembangkitan terbarukan pada 2030 ⚠︎ <a href=\"https://jetp-id.org/\">(CIPP, 2023)</a>. Namun pencairannya berjalan lambat dan ketergantungan pada batu bara belum benar-benar berbalik — jarak antara komitmen dan realisasi di sini justru paling lebar."}, {"t": "h2", "x": "Dari target ke bukti"}, {"t": "p", "x": "Di sinilah selisih antara mengumumkan dan membuktikan terasa. Climate Action Tracker masih menilai keseluruhan langkah Indonesia 'sangat tidak memadai' terhadap jalur 1,5°C ⚠︎ <a href=\"https://climateactiontracker.org/countries/indonesia/\">(CAT, 2024)</a> — bukan karena targetnya rendah, melainkan karena bukti pelaksanaannya belum konsisten. Untuk FOLU dan energi, konsekuensinya satu: setiap penurunan harus <b>terlacak</b> hingga ke petak lahan dan titik sambung jaringan, terverifikasi, dan tak terhitung dua kali. Target memberi arah; bukti yang bisa diaudit yang akhirnya dihitung."}], "story": [{"kind": "cover", "title": "NDC kedua Indonesia", "text": "Dari target ke bukti penurunan: 31,89% mandiri, 43,20% bersyarat pada 2030 — tapi ditentukan oleh dua sektor saja."}, {"kind": "hook", "title": "Targetnya sudah ada.", "text": "Pertanyaannya: siapa yang benar-benar akan menurunkan emisinya — dan bagaimana kita tahu itu nyata?"}, {"kind": "point", "title": "Angkanya", "text": "31,89% mandiri, hingga 43,20% bersyarat pada 2030 — dipotong dari proyeksi 2,869 GtCO₂e. (Enhanced NDC, 2022)"}, {"kind": "point", "title": "Dua sektor menentukan", "text": "FOLU (hutan-lahan) + energi = hampir 94% target mandiri. Sisanya tipis."}, {"kind": "stat", "title": "Porsi penentu", "big": "≈94%", "label": "Penurunan dari FOLU + energi (target mandiri)", "source": "Enhanced NDC Indonesia, 2022"}, {"kind": "quote", "title": "Intinya", "text": "Target menutup satu baris di kertas. Bukti butuh tiap hektar hutan dan tiap megawatt bersih terlacak."}, {"kind": "end", "title": "Baca telaah lengkapnya", "text": "Kupas sektor mana yang paling menentukan NDC Indonesia — bersama Glyiv, intelijen karbon Indonesia."}], "sources": [{"a": "Republik Indonesia (2022). Enhanced Nationally Determined Contribution. UNFCCC NDC Registry.", "u": "https://unfccc.int/sites/default/files/NDC/2022-09/23.09.2022_Enhanced%20NDC%20Indonesia.pdf"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan (2022). Rencana Operasional Indonesia's FOLU Net Sink 2030 (SK.168/MENLHK/2022).", "u": "https://www.menlhk.go.id/"}, {"a": "JETP Secretariat (2023). Comprehensive Investment and Policy Plan (CIPP) — Indonesia Just Energy Transition Partnership.", "u": "https://jetp-id.org/"}, {"a": "Climate Action Tracker (2024). Indonesia — Country assessment.", "u": "https://climateactiontracker.org/countries/indonesia/"}]}, {"slug": "net-zero-2060-realistis", "topic": "Ekonomi", "mood": "#0F2E22", "title": "Net zero 2060: seberapa realistis peta jalan kita?", "dek": "Indonesia berjanji nol bersih pada 2060 atau lebih cepat. Satu tumpuannya — hutan sebagai penyerap — bisa berbalik dalam hitungan tahun; tumpuan lain, listrik yang masih ~60% batu bara, terkunci dalam aset berumur puluhan tahun.", "hook": "Kita janji nol bersih 2060. Tapi 60% listrik kita masih dari batu bara ⚠︎ — dan PLTU-nya masih muda. Seberapa realistis?", "cover": "https://images.unsplash.com/photo-1509391366360-2e959784a276?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (LTS-LCCR, KLHK, IEA)", "read": 4, "blocks": [{"t": "lead", "x": "Indonesia sudah menaruh angka di atas meja: emisi nol bersih pada 2060 — atau lebih cepat. Janjinya berani. Persoalannya bukan pada niat, melainkan pada jarak antara garis akhir di atas kertas dan kenyataan jaringan listrik hari ini, yang sebagian besar masih menyala dari batu bara."}, {"t": "p", "x": "Target itu tertuang dalam strategi jangka panjang Indonesia, <b>LTS-LCCR 2021</b>, yang diserahkan ke sekretariat iklim PBB: emisi memuncak lalu menurun menuju nol bersih pada 2060 atau lebih awal bila dukungan internasional memadai <a href=\"https://unfccc.int/sites/default/files/resource/Indonesia_LTS-LCCR_2021.pdf\">[1]</a>. Peta jalannya bertumpu pada dua kaki — dan keduanya melangkah dengan kecepatan yang sangat berbeda."}, {"t": "p", "x": "Di antara sekarang dan 2060 ada tenggat lebih dekat yang menentukan: <b>2030</b>. Lewat NDC-nya, Indonesia menjanjikan penurunan emisi 31,9% dengan upaya sendiri, hingga 43,2% dengan bantuan internasional, dibanding skenario tanpa intervensi ⚠︎ <a href=\"https://unfccc.int/sites/default/files/resource/Indonesia_LTS-LCCR_2021.pdf\">[1]</a>. Tenggat inilah yang menguji apakah 2060 sekadar retorika atau lintasan yang benar-benar dimulai."}, {"t": "h2", "x": "Dua tumpuan, dua kecepatan"}, {"t": "p", "x": "Kaki pertama adalah <b>FOLU Net Sink 2030</b>: menjadikan sektor kehutanan dan penggunaan lahan — selama ini sumber emisi terbesar Indonesia — berbalik menjadi <b>penyerap bersih</b> pada 2030. Sasarannya serapan bersih −140 juta ton CO₂e ⚠︎, dan itu bergantung penuh pada berhentinya deforestasi serta kebakaran gambut <a href=\"https://www.menlhk.go.id/\">[2]</a>. Di atas kertas inilah bagian yang paling cepat berbuah — sekaligus paling rapuh terhadap satu musim kering yang buruk."}, {"t": "stat", "n": "−140 juta ton CO₂e", "l": "Target serapan bersih sektor kehutanan & lahan (FOLU) pada 2030 ⚠︎", "s": "KLHK, Rencana Operasional FOLU Net Sink 2030 (2022)"}, {"t": "p", "x": "Kaki kedua jauh lebih berat: <b>listrik</b>. Sekitar 60% pembangkitan listrik nasional masih bersumber dari batu bara ⚠︎ <a href=\"https://www.iea.org/countries/indonesia\">[3]</a>, dan sebagian besar PLTU-nya berusia muda — dibangun satu-dua dekade terakhir, jauh dari pensiun alami. Banyak di antaranya terikat kontrak pembelian jangka panjang, sehingga menutupnya bukan sekadar soal teknis, tapi soal siapa menanggung biayanya. Di sinilah kemitraan <b>JETP</b> senilai ~US$20 miliar (2022) semestinya masuk, meski pencairan dan proyek nyatanya berjalan lebih lambat dari janji ⚠︎ <a href=\"https://jetp-id.org/\">[4]</a>."}, {"t": "pull", "x": "Kaki hutan bisa berbalik dalam hitungan tahun; kaki listrik terkunci dalam aset yang berumur puluhan tahun. Peta jalan yang jujur mengakui kedua jam ini berdetak berbeda."}, {"t": "h2", "x": "Yang membedakan janji dari peta jalan"}, {"t": "p", "x": "Jadi, realistis atau tidak? Jawabannya tidak tunggal. FOLU 2030 masuk akal bila penegakan deforestasi konsisten dan cuaca berpihak; nol bersih 2060 masuk akal hanya bila transisi listrik dimulai serius pada dekade ini — bukan ditunda hingga menjelang tenggat, saat PLTU muda hari ini justru sedang di puncak usianya. Yang memisahkan janji dari peta jalan adalah bukti yang bisa ditelusuri: emisi yang <b>terlacak</b> per sektor, per tahun, terbuka untuk diperiksa dan dikoreksi saat melenceng. Tanpa itu, 2060 hanya sebuah angka; dengan itu, setiap ton yang benar-benar terlacak menjadi kontribusi yang bisa dipertanggungjawabkan — bukan klaim menenangkan hati yang tak terbukti."}], "story": [{"kind": "cover", "title": "Net zero 2060: seberapa realistis peta jalan kita?", "text": "Indonesia berjanji nol bersih pada 2060 atau lebih cepat. Satu tumpuannya — hutan sebagai penyerap — bisa berbalik dalam hitungan tahun; tumpuan lain, listrik yang masih ~60% batu bara, terkunci puluhan tahun."}, {"kind": "hook", "title": "Janji besar, jaringan lama", "text": "Kita janji nol bersih 2060. Tapi 60% listrik kita masih dari batu bara ⚠︎ — dan PLTU-nya masih muda. Seberapa realistis?"}, {"kind": "point", "title": "Dua tumpuan", "text": "Peta jalan bersandar pada dua kaki: hutan (FOLU Net Sink 2030) dan listrik. Keduanya bergerak dengan kecepatan yang sangat berbeda."}, {"kind": "stat", "title": "Sasaran hutan 2030", "big": "−140 jt ton CO₂e", "label": "Target serapan bersih FOLU pada 2030 ⚠︎", "source": "KLHK, 2022"}, {"kind": "point", "title": "Batu bara belum lepas", "text": "Sekitar 60% listrik nasional masih dari batu bara ⚠︎. PLTU-nya muda dan terikat kontrak jangka panjang — mahal untuk dipensiunkan lebih awal."}, {"kind": "quote", "title": "Dua jam berbeda", "text": "Hutan bisa berbalik dalam hitungan tahun; listrik terkunci puluhan tahun. Kedua jam ini berdetak berbeda."}, {"kind": "end", "title": "Angka, atau lintasan?", "text": "2060 jadi lintasan nyata hanya saat emisi bisa ditelusuri. Baca versi lengkapnya — dan telusuri jejak karbon bareng Glyiv."}], "sources": [{"a": "Republik Indonesia. Dokumen iklim ke UNFCCC: Long-Term Strategy for Low Carbon and Climate Resilience 2050 (LTS-LCCR, 2021) & Enhanced NDC (2022).", "u": "https://unfccc.int/sites/default/files/resource/Indonesia_LTS-LCCR_2021.pdf"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan (KLHK). Rencana Operasional Indonesia's FOLU Net Sink 2030 (Permen LHK No. 168/2022).", "u": "https://www.menlhk.go.id/"}, {"a": "International Energy Agency (IEA). Indonesia — profil negara & bauran pembangkitan listrik.", "u": "https://www.iea.org/countries/indonesia"}, {"a": "JETP Secretariat Indonesia (2023). Just Energy Transition Partnership — Comprehensive Investment and Policy Plan (CIPP).", "u": "https://jetp-id.org/"}]}, {"slug": "folu-net-sink-2030", "topic": "Regulasi", "mood": "#4F7A3A", "title": "FOLU Net Sink 2030: saat hutan menyerap lebih dari yang dilepas.", "dek": "Untuk pertama kalinya, target iklim Indonesia bertumpu pada satu janji besar: pada 2030, hutan dan lahan kita harus menyerap lebih banyak karbon daripada yang dilepas — dan sektor inilah pilar terbesar NDC.", "hook": "Bayangkan hutan Indonesia berbalik dari sumber emisi terbesar menjadi penyerap bersih. Itu bukan angan-angan — itu target resmi pemerintah untuk 2030.", "cover": "https://images.unsplash.com/photo-1425913397330-cf8af2ff40a1?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen KLHK & NDC Indonesia", "read": 5, "blocks": [{"t": "lead", "x": "Untuk pertama kalinya, Indonesia menargetkan hutannya bukan sekadar berhenti melepas karbon, tapi menyerap lebih banyak daripada yang ia lepas. Itulah inti dari <b>Indonesia's FOLU Net Sink 2030</b>: pada 2030, sektor kehutanan dan penggunaan lahan lain harus berbalik dari sumber emisi menjadi penyerap bersih karbon."}, {"t": "p", "x": "FOLU — <b>Forestry and Other Land Uses</b> — mencakup segala hal yang terjadi pada hutan dan lahan: deforestasi, degradasi, kebakaran gambut, hingga penyerapan oleh hutan yang dibiarkan tumbuh. Dalam <a href=\"https://unfccc.int/sites/default/files/NDC/2022-09/23.09.2022_Enhanced%20NDC%20Indonesia.pdf\">Enhanced NDC 2022</a>, Indonesia berjanji menurunkan emisi <b>31,89%</b> dengan upaya sendiri dan <b>43,20%</b> dengan dukungan internasional pada 2030 — dan FOLU adalah penyumbang terbesarnya, lebih dari separuh penurunan pada skenario upaya sendiri."}, {"t": "p", "x": "Alasannya masuk akal secara hitungan: menjaga dan memulihkan hutan sering kali lebih cepat dan lebih murah ketimbang mendekarbonisasi sektor energi yang masih bertumpu pada batu bara. Solusi berbasis alam bisa memberi penurunan emisi besar dalam waktu dekat — asalkan permanen dan benar-benar terjadi <a href=\"https://www.ipcc.ch/report/ar6/wg3/\">(IPCC AR6)</a>."}, {"t": "p", "x": "Yang membuat target ini berani adalah kata <em>net sink</em>. Secara historis, FOLU justru salah satu sumber emisi terbesar Indonesia — dari pembukaan lahan, degradasi hutan, dan kebakaran gambut yang bisa melepas emisi dalam skala besar di tahun-tahun kering. 'Net sink' berarti membalik neraca itu: pada 2030, serapan harus melampaui lepasan."}, {"t": "stat", "n": "−140 juta ton CO₂e", "l": "target serapan bersih sektor FOLU pada 2030 — dari sumber emisi menjadi penyerap", "s": "KLHK, Rencana Operasional FOLU Net Sink 2030 (2022)"}, {"t": "h2", "x": "Dua tuas yang harus ditarik bersamaan"}, {"t": "p", "x": "Rencananya bertumpu pada dua gerakan sekaligus. Pertama, <b>menekan lepasan</b>: menghentikan deforestasi, memulihkan tata air gambut, dan mencegah kebakaran. Kedua, <b>menambah serapan</b>: rehabilitasi hutan dan lahan, restorasi gambut, serta rehabilitasi mangrove — sebagian dikoordinasikan lewat Badan Restorasi Gambut dan Mangrove (BRGM). Keduanya harus berjalan bersama; menanam pohon baru nyaris tak berarti bila hutan lama terus hilang."}, {"t": "pull", "x": "Sebuah target hanya sekuat data yang membuktikannya. 'Net sink' pada 2030 harus terlacak petak demi petak — bukan sekadar diklaim di atas kertas."}, {"t": "p", "x": "Di sinilah bagian tersulitnya. Target ini <b>ambisius</b>, dan keberhasilannya bergantung pada hal-hal yang belum sepenuhnya pasti: pendanaan iklim yang memadai, penegakan hukum di lapangan, dan sistem pemantauan yang bisa diaudit. ⚠︎ Sebagian besar penurunan pada skenario penuh (43,20%) masih <b>bersyarat</b> pada dukungan internasional, sehingga capaian akhirnya belum terjamin."}, {"t": "p", "x": "Bagi Glyiv, pelajaran pentingnya sederhana: kontribusi iklim sektor kehutanan hanya bermakna bila hasilnya <b>terlacak</b> — dari citra satelit, tingkat kelangsungan tegakan, hingga catatan yang bisa direkonsiliasi ke registri resmi. Itulah yang memisahkan target yang benar-benar tercapai dari target yang sekadar tertulis."}], "story": [{"kind": "cover", "title": "FOLU Net Sink 2030", "text": "Untuk pertama kalinya, target iklim Indonesia bertumpu pada satu janji besar: pada 2030, hutan dan lahan kita harus menyerap lebih banyak karbon daripada yang dilepas — pilar terbesar NDC."}, {"kind": "hook", "title": "Hutan yang membalik neraca", "text": "Bayangkan hutan Indonesia berbalik dari sumber emisi terbesar menjadi penyerap bersih. Itu target resmi pemerintah untuk 2030."}, {"kind": "point", "title": "Apa itu FOLU?", "text": "Forestry & Other Land Uses — deforestasi, degradasi, gambut, sampai serapan hutan yang tumbuh. Penyumbang terbesar target NDC Indonesia."}, {"kind": "point", "title": "Arti 'net sink'", "text": "Dari sumber emisi menjadi penyerap bersih: pada 2030, hutan harus menyerap lebih banyak daripada yang dilepas."}, {"kind": "stat", "title": "Angka yang menentukan", "big": "−140 juta ton CO₂e", "label": "Target serapan bersih sektor FOLU pada 2030", "source": "KLHK, Rencana Operasional FOLU Net Sink 2030 (2022)"}, {"kind": "quote", "title": "Inti soalnya", "text": "Target hanya sekuat data yang membuktikannya — 'net sink' harus terlacak petak demi petak, bukan diklaim di atas kertas."}, {"kind": "end", "title": "Baca versi lengkapnya", "text": "Pahami dua tuas di balik FOLU Net Sink 2030 — dan kenapa data yang bisa diaudit menentukan segalanya. Ikuti Glyiv Kabar."}], "sources": [{"a": "Kementerian Lingkungan Hidup dan Kehutanan (2022). Rencana Operasional Indonesia's FOLU Net Sink 2030 (SK.168/MENLHK/2022)."}, {"a": "Republik Indonesia (2022). Enhanced Nationally Determined Contribution (ENDC). Disampaikan ke UNFCCC, September 2022.", "u": "https://unfccc.int/sites/default/files/NDC/2022-09/23.09.2022_Enhanced%20NDC%20Indonesia.pdf"}, {"a": "IPCC (2022). AR6 Working Group III — Bab AFOLU: mitigasi berbasis lahan.", "u": "https://www.ipcc.ch/report/ar6/wg3/"}]}, {"slug": "uk-cbam-2027", "topic": "Global", "mood": "#1E5F8C", "title": "Bukan hanya Eropa: Inggris siapkan CBAM sendiri.", "dek": "Inggris mengonfirmasi CBAM-nya sendiri mulai 2027 untuk lima sektor padat karbon — pertanda bahwa harga karbon di perbatasan sedang bergeser dari pengecualian menjadi norma, dan komoditas Indonesia berada tepat di jalurnya.", "hook": "Uni Eropa memulainya, Inggris menyusul pada 2027. \"Harga karbon di perbatasan\" berhenti jadi pengecualian — dan besi-baja serta aluminium Indonesia ada di garis depannya.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen HM Treasury & Komisi Eropa", "read": 5, "blocks": [{"t": "lead", "x": "Selama ini 'harga karbon di perbatasan' mudah dianggap kekhasan Uni Eropa — satu blok, satu aturan, gampang dibaca sebagai pengecualian. Anggapan itu kini goyah. Inggris resmi mengonfirmasi akan memberlakukan CBAM versinya sendiri mulai 1 Januari 2027, dan pola yang tadinya tampak seperti anomali mulai terlihat sebagai arah."}, {"t": "p", "x": "Cara kerjanya mirip sepupunya di Eropa. <b>UK CBAM</b> menempelkan harga karbon pada barang impor padat karbon, agar produk dari luar menghadapi beban karbon yang sebanding dengan yang sudah dibayar produsen di dalam negeri Inggris. Lima sektor masuk cakupan awal: <b>besi dan baja, aluminium, semen, pupuk, dan hidrogen</b> — sektor yang dinilai paling rawan <a href=\"https://www.gov.uk/government/publications/factsheet-carbon-border-adjustment-mechanism-cbam/factsheet-carbon-border-adjustment-mechanism\">kebocoran karbon</a>."}, {"t": "stat", "n": "1 Jan 2027", "l": "UK CBAM mulai berlaku — besi-baja, aluminium, semen, pupuk, hidrogen", "s": "HM Treasury / GOV.UK, 2024"}, {"t": "h2", "x": "Bukan salinan persis Eropa"}, {"t": "p", "x": "Desain Inggris tak identik dengan UE. Cakupan awalnya justru lebih sempit: kaca dan keramik yang semula diusulkan akhirnya dikeluarkan karena dianggap kurang intensif karbon dan kurang terpapar risiko kebocoran. Listrik — yang masuk skema UE — tidak ada dalam daftar Inggris. Emisi tidak langsung baru akan dihitung paling cepat 2029 ⚠︎, dan importir kecil di bawah ambang <b>£50.000</b> per tahun dikecualikan dari kewajiban lapor. Tarifnya mengacu pada harga UK ETS dikurangi alokasi gratis — sebagian rinciannya masih menunggu peraturan turunan ⚠︎."}, {"t": "pull", "x": "Ketika dua pasar besar mematok harga karbon di perbatasan dalam dua tahun beruntun, itu bukan lagi kebijakan tunggal — itu preseden."}, {"t": "p", "x": "Dan Inggris mungkin bukan titik akhir. UE masuk fase bayar penuh pada 1 Januari 2026; Inggris <a href=\"https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en\">menyusul setahun kemudian</a>. Di luar keduanya, Australia, Kanada, dan Amerika Serikat sedang menjajaki mekanisme sejenis — sebagian besar masih di tahap kajian atau usulan ⚠︎. Arah anginnya searah: karbon yang tak terlacak makin sulit disembunyikan di rantai pasok lintas batas."}, {"t": "p", "x": "Yang menular bukan detail teknisnya — ambang, tarif, dan daftar sektor bisa berbeda-beda — melainkan prinsipnya: emisi yang tertanam dalam sebuah produk kini menjadi bagian dari harganya. Bagi pembeli global, CBAM perlahan berubah dari beban administratif menjadi <b>sinyal</b>: mana pemasok yang bisa membuktikan intensitas karbonnya, dan mana yang cuma menghindar."}, {"t": "h2", "x": "Apa artinya bagi eksportir Indonesia"}, {"t": "p", "x": "Indonesia termasuk produsen besar besi-baja dan aluminium — persis komoditas yang kini dihargai karbonnya di dua perbatasan sekaligus. Konsekuensinya sederhana tapi menuntut: satu berkas data karbon yang kredibel kini harus bisa dibaca di banyak yurisdiksi, bukan hanya satu. Eksportir yang mampu menunjukkan jejak karbon per produk — <b>terlacak</b>, terverifikasi, selaras GHG Protocol / ISO 14064 — bukan sekadar menghindari nilai default yang cenderung tinggi; mereka menjaga pintu ke pasar premium tetap terbuka. Yang tidak, berisiko membayar ketidaktahuannya dua kali."}], "story": [{"kind": "cover", "title": "Bukan hanya Eropa", "text": "Inggris mengonfirmasi CBAM-nya sendiri mulai 2027 untuk lima sektor padat karbon — pertanda harga karbon di perbatasan bergeser dari pengecualian menjadi norma."}, {"kind": "hook", "title": "Bukan pengecualian lagi", "text": "Uni Eropa memulainya. Inggris menyusul 2027. Besi-baja & aluminium Indonesia ada di garis depannya."}, {"kind": "point", "title": "Inggris menyusul", "text": "Mulai 1 Jan 2027, Inggris memberlakukan CBAM sendiri: besi-baja, aluminium, semen, pupuk, hidrogen."}, {"kind": "point", "title": "Bukan salinan persis", "text": "Kaca & keramik dikeluarkan. Listrik tak masuk. Emisi tak langsung ditunda ke 2029 ⚠︎. Ambang £50.000/tahun."}, {"kind": "stat", "title": "Tanggalnya sudah pasti", "big": "1 Jan 2027", "label": "UK CBAM mulai berlaku", "source": "HM Treasury / GOV.UK, 2024"}, {"kind": "point", "title": "Kenapa penting buat RI", "text": "Besi-baja & aluminium Indonesia kini dihargai karbonnya di dua perbatasan sekaligus — UE dan Inggris."}, {"kind": "end", "title": "Satu data, banyak pasar", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan siapkan jejak karbon yang bisa dibaca di mana pun."}], "sources": [{"a": "HM Treasury & HMRC (Oktober 2024). Introduction of a UK Carbon Border Adjustment Mechanism from January 2027: Government response to the policy design consultation.", "u": "https://assets.publishing.service.gov.uk/media/679cb194a9ee53687470a2fa/Introduction_of_a_UK_Carbon_Border_Adjustment_Mechanism_from_January_2027_-_Government_response_to_the_policy_design_consultation.pdf"}, {"a": "GOV.UK (2024). Factsheet: Carbon Border Adjustment Mechanism (cakupan sektor, ambang £50.000, emisi tidak langsung mulai 2029).", "u": "https://www.gov.uk/government/publications/factsheet-carbon-border-adjustment-mechanism-cbam/factsheet-carbon-border-adjustment-mechanism"}, {"a": "European Commission, DG TAXUD. Carbon Border Adjustment Mechanism — fase definitif mulai 1 Januari 2026.", "u": "https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en"}]}, {"slug": "sbti-target-berbasis-sains", "topic": "Regulasi", "mood": "#0B2471", "title": "Target berbasis sains: apa bedanya dengan janji hijau biasa.", "dek": "Ribuan perusahaan berjanji \"hijau\", tapi hanya sebagian yang targetnya benar-benar diuji terhadap ilmu iklim — dan di situlah SBTi menarik garis antara komitmen berbasis sains dan klaim pemasaran.", "hook": "Semua bilang \"hijau\". Hanya sebagian yang berani menaruh angkanya di jalur 1,5°C — lalu membiarkannya diperiksa orang lain.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (SBTi, IPCC, GHG Protocol)", "read": 4, "blocks": [{"t": "lead", "x": "Setiap pekan ada perusahaan baru yang menyebut dirinya 'ramah iklim'. Sebagian sungguh berbenah — mengganti mesin, memangkas energi, membenahi rantai pasok. Sebagian lain hanya memperbarui materi pemasaran. Bagi konsumen, investor, dan mitra dagang, pertanyaannya sederhana tapi menentukan: bagaimana membedakan janji yang punya dasar ilmiah dari yang sekadar terdengar hijau?"}, {"t": "p", "x": "Di sinilah <b>Science Based Targets initiative (SBTi)</b> berperan. Lembaga ini — kolaborasi CDP, UN Global Compact, World Resources Institute, dan WWF — menilai apakah target penurunan emisi sebuah perusahaan benar-benar selaras dengan jalur menahan pemanasan di <b>1,5°C</b>, bukan sekadar angka yang enak dipandang. Target yang lolos disebut 'tervalidasi', dan metodologinya terbuka untuk ditelaah siapa pun di <a href=\"https://sciencebasedtargets.org\">sciencebasedtargets.org</a>."}, {"t": "p", "x": "Bedanya terletak pada tiga hal. Pertama, <b>cakupan</b>: target harus mencakup emisi langsung (Scope 1), energi yang dibeli (Scope 2), dan sering kali rantai nilai (Scope 3) — bagian terbesar sekaligus tersulit. Kedua, <b>ambisi</b> dipatok ke ilmu iklim, bukan ke apa yang paling nyaman bagi perusahaan. Ketiga, targetnya <b>absolut dan bertenggat</b> — angka dan tahun yang jelas, bukan klaim samar 'menuju hijau' yang tak pernah bisa dinilai benar atau salah."}, {"t": "pull", "x": "Target berbasis sains menuntut penurunan emisi lebih dulu — bukan menutupinya dengan offset yang dibeli belakangan."}, {"t": "stat", "n": "≈45%", "l": "penurunan emisi CO₂ global yang dibutuhkan pada 2030 (dibanding 2010) agar jalur 1,5°C tetap terbuka", "s": "IPCC, Global Warming of 1.5°C (SR1.5), 2018"}, {"t": "h2", "x": "Bukan 'netral karbon', tapi penurunan nyata"}, {"t": "p", "x": "Standar Net-Zero SBTi menegaskan urutan yang benar: perusahaan harus <b>memangkas</b> sekitar 90% emisinya lebih dulu, baru menetralkan sisa kecil yang benar-benar sulit dihilangkan. Ini kebalikan dari banyak klaim 'netral karbon' yang bersandar pada pembelian offset murah tanpa mengubah satu pun operasi. Karena itu SBTi mendorong bahasa <b>kontribusi iklim</b> untuk pendanaan di luar rantai nilai — bukan mengklaimnya sebagai penetral emisi perusahaan itu sendiri."}, {"t": "p", "x": "Regulator bergerak ke arah yang sama. Uni Eropa telah menyetujui aturan yang membatasi klaim lingkungan generik dan klaim 'netral karbon' yang hanya bertumpu pada offset ⚠︎ (<a href=\"https://eur-lex.europa.eu/eli/dir/2024/825/oj\">Directive (EU) 2024/825</a>; tenggat penerapan oleh negara anggota masih berjalan). Artinya, klaim hijau tanpa dasar bukan lagi sekadar risiko reputasi — perlahan ia menjadi risiko hukum."}, {"t": "h2", "x": "Apa artinya bagi perusahaan Indonesia"}, {"t": "p", "x": "Implikasinya praktis. Target yang kredibel tidak dimulai dari slogan, melainkan dari <b>inventarisasi emisi yang terlacak</b> hingga bisa diaudit — data lini per lini yang bisa diverifikasi pihak ketiga dan ditelusuri sumbernya. Dari fondasi itulah target berbasis sains bisa disusun, diajukan, dan dipertanggungjawabkan di depan pembeli maupun regulator. Tanpa data yang jujur, target apa pun hanya janji; dengan data yang rapi, ia berubah menjadi rencana."}], "story": [{"kind": "cover", "title": "Target berbasis sains vs janji hijau biasa", "text": "Ribuan perusahaan berjanji 'hijau', tapi hanya sebagian yang targetnya benar-benar diuji terhadap ilmu iklim — dan di situlah SBTi menarik garis antara komitmen berbasis sains dan klaim pemasaran."}, {"kind": "hook", "title": "Hijau di brosur — bagaimana di neraca emisi?", "text": "Bagaimana membedakan janji yang punya dasar ilmiah dari yang sekadar terdengar hijau?"}, {"kind": "point", "title": "Apa itu SBTi", "text": "Kolaborasi CDP, UN Global Compact, WRI, dan WWF yang memvalidasi target emisi perusahaan agar selaras jalur 1,5°C."}, {"kind": "point", "title": "Kunci pembedanya", "text": "Cakupan luas (Scope 1–3), ambisi dipatok ke ilmu iklim, dan target yang absolut serta bertenggat — bukan slogan samar."}, {"kind": "point", "title": "Kurangi dulu, baru netralkan", "text": "Standar Net-Zero: pangkas sekitar 90% emisi lebih dulu; offset hanya untuk sisa kecil yang sulit dihilangkan."}, {"kind": "stat", "title": "Ukuran ambisinya", "big": "≈45%", "label": "penurunan emisi CO₂ global yang dibutuhkan pada 2030 (vs 2010) untuk jalur 1,5°C", "source": "IPCC SR1.5, 2018"}, {"kind": "end", "title": "Dari janji ke rencana", "text": "Target kredibel dimulai dari data emisi yang terlacak. Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Science Based Targets initiative (SBTi). Corporate Net-Zero Standard & About the initiative.", "u": "https://sciencebasedtargets.org"}, {"a": "IPCC (2018). Global Warming of 1.5°C (Special Report SR1.5), Summary for Policymakers.", "u": "https://www.ipcc.ch/sr15/"}, {"a": "GHG Protocol. Corporate Accounting and Reporting Standard (Scope 1, 2, 3).", "u": "https://ghgprotocol.org/corporate-standard"}, {"a": "Uni Eropa. Directive (EU) 2024/825 — Empowering Consumers for the Green Transition.", "u": "https://eur-lex.europa.eu/eli/dir/2024/825/oj"}]}, {"slug": "mangrove-modal-biru-indonesia", "topic": "Offset", "mood": "#1E5F8C", "title": "3,3 juta hektar mangrove: modal biru terbesar dunia ada di sini.", "dek": "Indonesia menyimpan sekitar seperlima mangrove dunia — hutan pesisir yang, hektar per hektar, mengunci karbon beberapa kali lipat lebih banyak daripada hutan daratan, sebagian besar terkubur diam di lumpurnya.", "hook": "Hutan paling padat karbon di bumi tumbuh di lumpur pantai kita — dan kebanyakan karbonnya tersembunyi di bawah kaki.", "cover": "https://images.unsplash.com/photo-1505142468610-359e7d316be0?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (Donato dkk. 2011, Murdiyarso dkk. 2015)", "read": 4, "blocks": [{"t": "lead", "x": "Bayangkan hutan yang menyimpan lebih banyak karbon di lumpur di bawahnya ketimbang di batang dan daunnya. Hutan yang tumbuh di batas antara darat dan laut, akarnya mencengkeram pasang-surut. Itulah mangrove — dan tak ada negara di dunia yang punya lebih banyak dari Indonesia."}, {"t": "p", "x": "Peta mangrove nasional mencatat sekitar <b>3,3 juta hektar</b> hutan mangrove membentang di sepanjang pesisir Nusantara — kira-kira seperlima dari seluruh mangrove dunia, hamparan terluas di planet ini ⚠︎ (angka pastinya bergeser antara 3,3–3,4 juta hektar tergantung metode pemetaan). Sebaran globalnya bisa ditelusuri lewat <a href=\"https://www.globalmangrovewatch.org/\">Global Mangrove Watch</a>."}, {"t": "p", "x": "Yang membuat mangrove istimewa bukan luasnya, melainkan kepadatan karbonnya. Studi lapangan lintas Indo-Pasifik oleh <a href=\"https://www.nature.com/articles/ngeo1123\">Donato dkk. (2011)</a> menemukan mangrove menyimpan rata-rata lebih dari <b>1.000 ton karbon per hektar</b> — beberapa kali lipat hutan tropis daratan. Rahasianya ada di tanah: lumpur pesisir yang tergenang menyimpan sisa organik selama ribuan tahun tanpa sempat membusuk, dan bagian inilah yang menampung mayoritas karbonnya."}, {"t": "pull", "x": "Sebagian besar karbon mangrove tidak berdiri di atas tanah — ia terkubur diam di lumpur, endapan ribuan tahun yang bisa terlepas dalam semalam bila dibongkar."}, {"t": "stat", "n": "3,14 miliar ton", "l": "perkiraan karbon tersimpan di mangrove Indonesia — setara sekitar 11 miliar ton CO₂", "s": "Murdiyarso dkk., Nature Climate Change, 2015"}, {"t": "h2", "x": "Aset paling padat, paling rapuh"}, {"t": "p", "x": "Justru kepadatan itu yang membuatnya rentan. Saat mangrove dibuka — kerap untuk tambak udang atau perluasan lahan — karbon tanah yang tersimpan lama ikut terlepas ke atmosfer. <a href=\"https://www.nature.com/articles/nclimate2734\">Murdiyarso dkk.</a> memperkirakan alih fungsi mangrove bisa menyumbang hingga <b>10% emisi dari deforestasi global</b>, padahal luasnya kurang dari 1% hutan tropis dunia ⚠︎."}, {"t": "p", "x": "Sisi baiknya, yang cepat hilang juga bisa dipulihkan. Pemerintah menargetkan rehabilitasi ratusan ribu hektar mangrove terdegradasi ⚠︎, dan pasar 'karbon biru' mulai melirik restorasi pesisir sebagai sumber kredit. Tapi janji itu hanya bermakna bila serapannya <b>terlacak</b> — dipantau hingga ke petak lahan, bukan sekadar diperkirakan dari balik meja. Tanpa itu, kredit karbon biru berisiko mengulang cerita lama pasar offset: bagus di atas kertas, tapi tak terbukti di lapangan."}, {"t": "p", "x": "Bagi Glyiv, mangrove adalah contoh paling jernih kenapa data karbon harus jujur. Modal biru sebesar ini pantas dihitung dengan bukti, bukan optimisme — dan setiap hektar yang dijaga adalah kontribusi nyata, selama kita benar-benar bisa membuktikannya."}], "story": [{"kind": "cover", "title": "3,3 juta hektar mangrove", "text": "Indonesia menyimpan sekitar seperlima mangrove dunia — hutan pesisir yang mengunci karbon beberapa kali lipat lebih banyak daripada hutan daratan, sebagian besar terkubur diam di lumpurnya."}, {"kind": "hook", "title": "Karbon di bawah kaki", "text": "Hutan paling padat karbon di bumi tumbuh di lumpur pantai kita — dan kebanyakan karbonnya tersembunyi di bawah kaki."}, {"kind": "point", "title": "Seperlima mangrove dunia", "text": "Sekitar 3,3 juta hektar membentang di pesisir Indonesia — hamparan mangrove terluas di planet ini. ⚠︎ angka pasti bergeser 3,3–3,4 juta ha."}, {"kind": "point", "title": "Padat luar biasa", "text": "Lebih dari 1.000 ton karbon per hektar — beberapa kali hutan daratan. Mayoritas tersimpan di tanah, bukan di batang."}, {"kind": "stat", "title": "Simpanan karbonnya", "big": "3,14 miliar ton", "label": "karbon tersimpan di mangrove Indonesia (~11 miliar ton CO₂)", "source": "Murdiyarso dkk., Nature Climate Change, 2015"}, {"kind": "quote", "title": "Rapuh justru karena padat", "text": "Endapan ribuan tahun yang bisa terlepas dalam semalam bila dibongkar untuk tambak atau lahan."}, {"kind": "end", "title": "Modal biru butuh bukti", "text": "Baca kabar lengkapnya — dan lihat kenapa Glyiv menghitung karbon dengan bukti yang terlacak, bukan optimisme. Gabung ekosistem hijau Glyiv."}], "sources": [{"a": "Donato, D.C., Kauffman, J.B., Murdiyarso, D., Kurnianto, S., Stidham, M., Kanninen, M. (2011). Mangroves among the most carbon-rich forests in the tropics. Nature Geoscience 4, 293–297.", "u": "https://www.nature.com/articles/ngeo1123"}, {"a": "Murdiyarso, D., Purbopuspito, J., Kauffman, J.B., dkk. (2015). The potential of Indonesian mangrove forests for global climate change mitigation. Nature Climate Change 5, 1089–1092.", "u": "https://www.nature.com/articles/nclimate2734"}, {"a": "Global Mangrove Watch. Data sebaran mangrove global (extent dataset).", "u": "https://www.globalmangrovewatch.org/"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan / BRGM. Peta Mangrove Nasional (PMN), 2021."}]}, {"slug": "gambut-bom-karbon", "topic": "Offset", "mood": "#B5623A", "title": "Gambut: 'bom karbon' yang lebih baik dibiarkan basah.", "dek": "Lahan gambut Indonesia mengunci karbon dalam jumlah masif selama ribuan tahun. Saat dikeringkan dan terbakar — seperti pada 2015 — ia melepasnya sekaligus. Membiarkannya basah mungkin salah satu langkah iklim termurah yang kita punya.", "hook": "Cadangan karbon terbesar Indonesia tidak berdiri di atas tanah — ia terkubur di dalamnya, dan hanya aman selama tetap basah.", "cover": "https://images.unsplash.com/photo-1505142468610-359e7d316be0?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (Page dkk., UNEP, World Bank, WRI)", "read": 5, "blocks": [{"t": "lead", "x": "Di bawah rawa-rawa Sumatra dan Kalimantan tersimpan salah satu cadangan karbon terbesar di planet ini — bukan di batang pohon, melainkan di dalam tanah itu sendiri. Selama ribuan tahun, sisa tumbuhan yang tak sempat membusuk menumpuk dalam kondisi tergenang, mengunci karbon lapis demi lapis. Selama ia tetap basah, karbon itu aman. Masalah dimulai justru saat kita mengeringkannya."}, {"t": "p", "x": "Gambut terbentuk karena air. Dalam kondisi jenuh air dan nyaris tanpa oksigen, bahan organik gagal terurai sempurna dan menumpuk sebagai gambut — proses yang berjalan ribuan tahun. Hasilnya sangat padat karbon: lahan gambut hanya menutupi sekitar <b>3% daratan dunia</b>, tetapi menyimpan kira-kira <b>dua kali lipat</b> karbon seluruh hutan dunia digabungkan <a href=\"https://www.unep.org/resources/global-peatlands-assessment-2022\">(UNEP, 2022)</a>."}, {"t": "p", "x": "Indonesia memegang porsi terbesar gambut tropis. Cadangan gambut Asia Tenggara diperkirakan menyimpan sekitar <b>68,5 gigaton karbon</b>, dan mayoritasnya ada di Indonesia <a href=\"https://doi.org/10.1111/j.1365-2486.2010.02279.x\">(Page dkk., 2011)</a>. Ketika lahan ini dikeringkan lewat kanal untuk perkebunan atau permukiman, gambut yang tadinya basah mulai terpapar udara — teroksidasi, melepas CO₂ perlahan, dan yang paling berbahaya: menjadi sangat mudah terbakar."}, {"t": "h2", "x": "Ketika 'brankas' berubah jadi bom"}, {"t": "p", "x": "Kemarau panjang 2015 menunjukkan skalanya. Kebakaran lahan — sebagian besar di gambut kering — melepas asap yang, pada puluhan hari di puncaknya, menghasilkan emisi harian <b>melebihi seluruh ekonomi Amerika Serikat</b> <a href=\"https://www.wri.org/insights/indonesias-fire-outbreaks-producing-more-daily-emissions-entire-us-economy\">(World Resources Institute, 2015)</a>. Bank Dunia kemudian menaksir kerugian ekonominya mencapai <b>US$16,1 miliar</b> — setara sekitar 1,9% PDB — dengan area terbakar kira-kira 2,6 juta hektare <a href=\"https://www.worldbank.org/en/news/press-release/2016/02/25/indonesia-fire-crisis-cost-16-billion\">(World Bank, 2016)</a>."}, {"t": "pull", "x": "Gambut kering adalah bom karbon yang menyala pelan. Gambut basah adalah brankas yang menahannya tetap terkunci."}, {"t": "stat", "n": "US$16,1 miliar", "l": "taksiran kerugian ekonomi dari krisis kebakaran Indonesia 2015; area terbakar ~2,6 juta ha", "s": "World Bank, 2016"}, {"t": "h2", "x": "Kuncinya sederhana: biarkan basah"}, {"t": "p", "x": "Solusinya bukan teknologi rumit, melainkan air. <b>Rewetting</b> — membasahi kembali gambut dengan menyekat kanal dan menaikkan muka air tanah — menghentikan oksidasi sekaligus memangkas risiko kebakaran. Indonesia menjalankannya lewat Badan Restorasi Gambut dan Mangrove (BRGM), dengan target restorasi jutaan hektare gambut ⚠︎ (angka target dan capaian masih bergerak dan perlu diverifikasi berkala)."}, {"t": "p", "x": "Bagi pasar karbon, gambut yang dibasahi kembali adalah salah satu bentuk <b>kontribusi</b> iklim paling nyata — asalkan bisa dipertanggungjawabkan. Yang penting bukan klaim 'sekian ton diselamatkan', melainkan bukti yang <b>terlacak</b>: muka air tanah yang dipantau, kanal yang tersekat, tegakan yang pulih. Membiarkan gambut basah terdengar pasif, tapi ia mungkin salah satu langkah iklim paling murah dan paling berdampak yang dimiliki Indonesia."}], "story": [{"kind": "cover", "title": "Gambut: 'bom karbon' yang lebih baik dibiarkan basah", "text": "Lahan gambut Indonesia mengunci karbon masif selama ribuan tahun. Dikeringkan dan terbakar, ia melepasnya sekaligus. Membiarkannya basah mungkin langkah iklim termurah kita."}, {"kind": "hook", "title": "Karbon terbesar Indonesia bukan di pohon", "text": "Ia terkubur di dalam tanah rawa — dan hanya aman selama tetap basah."}, {"kind": "point", "title": "Apa itu gambut?", "text": "Sisa tumbuhan yang tergenang ribuan tahun. Menutupi ~3% daratan dunia, tapi menyimpan ~2x karbon semua hutan digabung."}, {"kind": "point", "title": "Kering = bahaya", "text": "Dikeringkan lewat kanal untuk kebun, gambut teroksidasi, melepas CO₂, dan menjadi sangat mudah terbakar."}, {"kind": "stat", "title": "Harga sebuah kemarau", "big": "US$16,1 miliar", "label": "kerugian krisis kebakaran Indonesia 2015; ~2,6 juta ha terbakar", "source": "World Bank, 2016"}, {"kind": "quote", "title": "Kering vs. basah", "text": "Gambut kering adalah bom karbon. Gambut basah adalah brankas."}, {"kind": "end", "title": "Baca cerita lengkapnya", "text": "Pelajari bagaimana gambut basah bisa jadi kontribusi iklim yang terlacak — di Glyiv Kabar."}], "sources": [{"a": "Page, S.E., Rieley, J.O., & Banks, C.J. (2011). Global and regional importance of the tropical peatland carbon pool. Global Change Biology, 17(2), 798–818.", "u": "https://doi.org/10.1111/j.1365-2486.2010.02279.x"}, {"a": "UNEP (2022). Global Peatlands Assessment – The State of the World's Peatlands.", "u": "https://www.unep.org/resources/global-peatlands-assessment-2022"}, {"a": "World Bank (2016). The Cost of Fire: An Economic Analysis of Indonesia's 2015 Fire Crisis.", "u": "https://www.worldbank.org/en/news/press-release/2016/02/25/indonesia-fire-crisis-cost-16-billion"}, {"a": "World Resources Institute (2015). Indonesia's Fire Outbreaks Producing More Daily Emissions than Entire US Economy.", "u": "https://www.wri.org/insights/indonesias-fire-outbreaks-producing-more-daily-emissions-entire-us-economy"}]}, {"slug": "redd-plus-pembayaran-hasil", "topic": "Offset", "mood": "#4F7A3A", "title": "REDD+: saat menjaga hutan benar-benar dibayar.", "dek": "Indonesia sudah menerima imbalan nyata dari Green Climate Fund dan Norwegia karena menekan deforestasi — model 'hasil dulu, bayar kemudian' yang membayar bukan janji, melainkan penurunan emisi yang bisa diverifikasi.", "hook": "Ternyata membiarkan hutan tetap berdiri ada harganya — dan Indonesia sudah menerima ceknya.", "cover": "https://images.unsplash.com/photo-1511497584788-876760111969?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen GCF & pemberitaan publik", "read": 5, "blocks": [{"t": "lead", "x": "Selama puluhan tahun, ekonomi hutan bekerja satu arah: sebatang pohon paling bernilai justru pada saat ia ditebang. REDD+ mencoba membalik logika itu — memberi harga pada hutan yang dibiarkan tetap berdiri. Dan untuk pertama kalinya, angka pembayarannya bukan lagi janji di atas kertas: Indonesia sudah benar-benar menerimanya."}, {"t": "p", "x": "REDD+ — <b>Reducing Emissions from Deforestation and forest Degradation</b> — berjalan di atas satu prinsip: 'hasil dulu, bayar kemudian'. Sebuah negara tidak diberi imbalan karena berjanji menjaga hutan, melainkan karena penurunan emisi yang <b>sudah terjadi</b> dan sudah diverifikasi terhadap garis dasar historis. Tidak ada bukti, tidak ada dana yang cair."}, {"t": "p", "x": "Pada 2020, <a href=\"https://www.greenclimate.fund/project/fp130\">Green Climate Fund menyetujui pembayaran ~US$103,8 juta⚠︎</a> untuk Indonesia — imbalan atas 20,25 juta ton CO₂e penurunan emisi deforestasi periode 2014–2016. Ini menjadi pembayaran terbesar dalam program percontohan REDD+ GCF, melampaui Brasil, dan dikelola lewat <a href=\"https://www.un-redd.org/news/indonesia-receives-results-based-payments-green-climate-fund\">Badan Pengelola Dana Lingkungan Hidup (BPDLH)</a>."}, {"t": "p", "x": "Model ini menggeser risiko. Dalam hibah biasa, dana mengalir lebih dulu dan hasil diharap menyusul; dalam pembayaran berbasis hasil, negara penerima menanggung ongkos menjaga hutan lebih dulu, dan baru menerima imbalan setelah hasilnya terbukti. Konsekuensinya jelas: setiap ton yang diklaim harus benar-benar bisa dipertanggungjawabkan."}, {"t": "pull", "x": "Yang dibayar bukan pohonnya, melainkan penurunan emisi yang bisa dibuktikan. Tanpa data yang bisa diverifikasi, tak satu dolar pun mengalir."}, {"t": "stat", "n": "US$103,8 jt⚠︎", "l": "imbalan GCF atas 20,25 juta ton CO₂e penurunan deforestasi 2014–2016 (jumlah disetujui)", "s": "Green Climate Fund (FP130), 2020"}, {"t": "p", "x": "Kisah serupa datang dari Norwegia. Di bawah kemitraan iklim dengan pagu hingga US$1 miliar⚠︎ yang diteken sejak 2010, Norwegia akhirnya membayar <b>US$56 juta</b> untuk penurunan sekitar 11,2 juta ton CO₂e pada tahun hutan 2016/2017. Jalannya tidak mulus: Indonesia sempat <a href=\"https://news.mongabay.com/2022/11/in-new-climate-deal-norway-will-pay-indonesia-56-million-for-drop-in-deforestation-emissions/\">membatalkan perjanjian pada 2021</a> karena pembayaran tak kunjung datang, sebelum keduanya memperbarui kemitraan pada September 2022 dan dana itu cair."}, {"t": "h2", "x": "Bukti, bukan janji"}, {"t": "p", "x": "Di sinilah letak ketegangannya. Besar imbalan bergantung penuh pada garis dasar — berapa banyak hutan yang <b>seharusnya</b> hilang seandainya tak ada intervensi. Sejumlah peneliti <a href=\"https://news.mongabay.com/2020/09/green-climate-fund-indonesia-redd-deforestation/\">mempertanyakan klaim deforestasi yang dihindari itu⚠︎</a>, karena sebagian penurunan bertepatan dengan tahun basah dan harga komoditas yang lesu — bukan semata kebijakan. Emisi yang dihindari sifatnya <b>terlacak</b>, bukan terukur mutlak, dan itu jujur untuk diakui."}, {"t": "p", "x": "Pelajarannya jelas bagi siapa pun yang ingin masuk ke ekonomi hijau: nilai satu hektar hutan kini melekat pada kualitas bukti yang menyertainya. Pemantauan yang tertelusur — citra satelit, garis dasar yang jujur, verifikasi independen — bukan formalitas administratif, melainkan penentu apakah imbalan mengalir atau macet. Menjaga hutan memang bisa dibayar. Tapi hanya bila penjagaan itu bisa dibuktikan."}], "story": [{"kind": "cover", "title": "REDD+: menjaga hutan yang dibayar", "text": "Indonesia sudah menerima imbalan nyata dari Green Climate Fund dan Norwegia karena menekan deforestasi — model 'hasil dulu, bayar kemudian'."}, {"kind": "hook", "title": "Ternyata, tidak menebang hutan ada harganya.", "text": "Dan Indonesia sudah menerima ceknya."}, {"kind": "point", "title": "Hasil dulu, bayar kemudian", "text": "REDD+ membayar penurunan emisi yang sudah terjadi dan sudah diverifikasi — bukan janji menjaga hutan."}, {"kind": "point", "title": "Dua pembayar nyata", "text": "GCF dan Norwegia sama-sama mencairkan imbalan atas turunnya deforestasi Indonesia."}, {"kind": "stat", "title": "Angka yang benar-benar cair", "big": "US$103,8 jt⚠︎", "label": "Imbalan GCF · 20,25 juta ton CO₂e (2014–2016)", "source": "Green Climate Fund (FP130), 2020"}, {"kind": "quote", "title": "Yang sebenarnya dibayar", "text": "Yang dibayar bukan pohonnya, melainkan penurunan emisi yang bisa dibuktikan."}, {"kind": "end", "title": "Baca versi lengkapnya", "text": "Selami bagaimana bukti menentukan nilai sebuah hutan — di Glyiv Kabar."}], "sources": [{"a": "Green Climate Fund (2020). FP130: Indonesia REDD-plus RBP for results period 2014–2016.", "u": "https://www.greenclimate.fund/project/fp130"}, {"a": "UN-REDD Programme (2020). Indonesia receives Results-based Payments from the Green Climate Fund.", "u": "https://www.un-redd.org/news/indonesia-receives-results-based-payments-green-climate-fund"}, {"a": "Mongabay (2022). In new climate deal, Norway will pay Indonesia $56 million for drop in deforestation, emissions.", "u": "https://news.mongabay.com/2022/11/in-new-climate-deal-norway-will-pay-indonesia-56-million-for-drop-in-deforestation-emissions/"}, {"a": "Mongabay (2020). Experts question integrity of Indonesia's claim of avoided deforestation.", "u": "https://news.mongabay.com/2020/09/green-climate-fund-indonesia-redd-deforestation/"}]}, {"slug": "deforestasi-indonesia-menurun", "topic": "Offset", "mood": "#1cae6b", "title": "Kabar baik yang jarang dibaca: laju deforestasi kita menurun.", "dek": "Data satelit dan catatan pemerintah menunjukkan hal yang jarang jadi berita utama: laju kehilangan hutan primer Indonesia menurun beberapa tahun terakhir — capaian nyata yang masih rapuh terhadap harga komoditas.", "hook": "Untuk sekali ini, grafiknya menurun — dan itu kabar baik. Hutan primer kita hilang lebih lambat dari sebelumnya. Tapi jangan buru-buru lega.", "cover": "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data publik Global Forest Watch & KLHK", "read": 4, "blocks": [{"t": "lead", "x": "Sebagian besar kabar soal hutan datang dengan nada cemas — dan sering memang pantas. Tapi ada satu tren yang jarang dibaca sampai tuntas: laju kehilangan hutan primer Indonesia menurun beberapa tahun berturut-turut. Ini bukan optimisme kosong, melainkan pola yang terlacak dari citra satelit — dan patut dipahami dengan jujur, termasuk batasnya."}, {"t": "p", "x": "Analisis Global Forest Watch (World Resources Institute), berbasis data tutupan pohon Universitas Maryland, mencatat kehilangan hutan primer Indonesia pada 2021 turun sekitar <b>25%</b> dibanding tahun sebelumnya — melanjutkan tren penurunan multi-tahun ⚠︎. <a href=\"https://www.globalforestwatch.org/dashboards/country/IDN/\">Data resminya terbuka untuk siapa saja</a>. Kementerian Lingkungan Hidup dan Kehutanan pun mencatat deforestasi neto pada periode ini sebagai salah satu yang terendah dalam catatannya ⚠︎."}, {"t": "p", "x": "Apa yang menahannya? Beberapa faktor bertemu. Moratorium permanen izin baru di hutan primer dan lahan gambut (Inpres 5/2019); komitmen tanpa-deforestasi dari sejumlah perusahaan sawit dan bubur kertas; penegakan yang lebih tegas; serta tahun-tahun yang lebih basah sehingga kebakaran — pendorong terbesar kehilangan hutan — jauh berkurang. Tidak satu pun bekerja sendiri; justru gabungannya yang membuat kurvanya turun."}, {"t": "h2", "x": "Nyata, tetapi rapuh"}, {"t": "pull", "x": "Penurunan deforestasi Indonesia adalah capaian yang benar-benar terjadi — sekaligus capaian yang bisa berbalik hanya dalam satu musim harga sawit."}, {"t": "stat", "n": "~25%", "l": "Penurunan kehilangan hutan primer Indonesia, 2021 vs 2020", "s": "Global Forest Watch / WRI, 2022"}, {"t": "p", "x": "Kerapuhannya bersifat ekonomi. Sebagian besar deforestasi historis Indonesia terkait ekspansi komoditas — terutama sawit. Riset menunjukkan hubungan erat antara harga komoditas global dan laju pembukaan lahan <a href=\"https://iopscience.iop.org/article/10.1088/1748-9326/aaf6db\">(Austin dkk., 2019)</a> ⚠︎. Ketika harga naik, insentif membuka lahan ikut naik, dan tekanan ke hutan kembali menguat. Tren baik ini belum tentu permanen; ia perlu dijaga, bukan dirayakan lalu dilupakan."}, {"t": "p", "x": "Di sinilah pemantauan yang terlacak menjadi penting. Kawasan yang tegakannya dipantau — lewat indeks kehijauan satelit dan verifikasi lapangan — memberi bukti apakah sebuah hutan benar-benar bertahan. Bagi Glyiv, ini fondasi: kontribusi iklim yang bisa ditelusuri sampai ke petak lahan, dan imbalan yang mengalir ke pihak yang benar-benar menjaga pohonnya tetap berdiri. Tanpa jejak yang bisa diaudit, klaim 'hutan terselamatkan' hanya sebaik janji di atas kertas."}, {"t": "bars", "h": [0.95, 0.72, 0.6, 0.5, 0.42, 0.38], "cap": "Ilustrasi tren: kehilangan hutan primer Indonesia menurun sejak puncak kebakaran 2016. Pola mengacu Global Forest Watch / WRI."}, {"t": "p", "x": "Menurunnya deforestasi bukan alasan untuk lengah, melainkan bukti bahwa kebijakan, pasar, dan pemantauan bisa bergerak searah. Kabar baik hanya berarti bila bisa dipertanggungjawabkan — dan hutan yang masih berdiri layak dihitung sebagai aset, bukan sekadar latar."}], "story": [{"kind": "cover", "title": "Laju deforestasi kita menurun", "text": "Data satelit dan catatan pemerintah menunjukkan hal yang jarang jadi berita utama: laju kehilangan hutan primer Indonesia menurun beberapa tahun terakhir — capaian nyata yang masih rapuh terhadap harga komoditas."}, {"kind": "hook", "title": "Untuk sekali ini, grafiknya turun", "text": "Kabar baik yang jarang jadi headline: hutan primer kita hilang lebih lambat dari sebelumnya. Tapi jangan buru-buru lega."}, {"kind": "point", "title": "Apa datanya", "text": "Kehilangan hutan primer Indonesia turun beberapa tahun berturut-turut — terlacak dari citra satelit, bukan sekadar klaim. ⚠︎"}, {"kind": "point", "title": "Kenapa bisa turun", "text": "Moratorium 2019, komitmen tanpa-deforestasi, penegakan lebih tegas, dan tahun-tahun basah yang menekan kebakaran — bertemu sekaligus."}, {"kind": "stat", "title": "Angkanya", "big": "~25%", "label": "Penurunan kehilangan hutan primer, 2021 vs 2020", "source": "Global Forest Watch / WRI, 2022"}, {"kind": "quote", "title": "Tetapi rapuh", "text": "Capaian yang benar-benar terjadi — sekaligus bisa berbalik hanya dalam satu musim harga sawit."}, {"kind": "end", "title": "Baca selengkapnya", "text": "Kabar baik hanya berarti bila bisa dipertanggungjawabkan. Telusuri hutan sebagai aset yang bisa diaudit — bersama Glyiv."}], "sources": [{"a": "World Resources Institute / Global Forest Watch (2022). Forest Pulse: The Latest on the World's Forests — analisis kehilangan hutan primer 2021 & dasbor Indonesia.", "u": "https://research.wri.org/gfr/forest-pulse"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan (KLHK). Data deforestasi neto Indonesia (rilis tahunan).", "u": "https://www.menlhk.go.id"}, {"a": "Austin, K.G., Schwantes, A., Gu, Y., & Kasibhatla, P.S. (2019). What causes deforestation in Indonesia? Environmental Research Letters, 14(2).", "u": "https://iopscience.iop.org/article/10.1088/1748-9326/aaf6db"}]}, {"slug": "blue-carbon-lamun-terlupakan", "topic": "Offset", "mood": "#1F7A6B", "title": "Padang lamun: penyimpan karbon biru yang selalu terlupakan.", "dek": "Semua mata tertuju pada mangrove, tapi padang lamun menyimpan 'karbon biru' per hektar yang setara — dan justru paling sedikit dipetakan serta dilindungi di perairan kita.", "hook": "Menutup kurang dari 0,2% dasar laut, tapi mengubur sekitar 10% karbon yang ditelan lautan tiap tahun. Kenapa nyaris tak ada yang menjaganya?", "cover": "https://images.unsplash.com/photo-1559825481-12a05cc00344?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (Nature Geoscience, PNAS, IPCC, BRIN)", "read": 4, "blocks": [{"t": "lead", "x": "Ketika orang bicara 'karbon biru', yang terbayang hampir selalu mangrove — akar yang mencengkeram lumpur, hutan pesisir yang gagah. Padahal di bawah permukaan air yang lebih dangkal, padang lamun diam-diam menyimpan karbon per hektar yang setara, bahkan kerap lebih pekat. Ia hanya jauh lebih jarang dilihat, dipetakan, dan dilindungi."}, {"t": "p", "x": "Padang lamun adalah tumbuhan berbunga yang hidup terendam di dasar laut dangkal. Nilai iklimnya bukan terutama pada daunnya, melainkan pada sedimen di bawahnya: lumpur miskin oksigen yang mengunci karbon organik selama ratusan hingga ribuan tahun. Menurut <a href=\"https://www.nature.com/articles/ngeo1477\">Fourqurean dkk. (Nature Geoscience, 2012)</a>, satu hektar padang lamun bisa menyimpan hingga sekitar <b>140 ton karbon</b> di satu meter teratas sedimennya — berkali lipat sedimen hutan di daratan. Padahal lamun menutup kurang dari 0,2% dasar laut, namun diperkirakan mengubur sekitar 10% karbon organik yang ditelan lautan tiap tahun."}, {"t": "stat", "n": "±140 t C", "l": "karbon organik di satu meter teratas sedimen padang lamun, per hektar — berkali lipat sedimen hutan darat", "s": "Fourqurean dkk., Nature Geoscience, 2012"}, {"t": "p", "x": "Justru di sinilah ironinya: karbon yang paling pekat itu paling sedikit terpetakan. Peta lamun nasional masih tambal sulam. Pusat Riset Oseanografi BRIN memvalidasi luas padang lamun Indonesia sekitar <b>293.500 hektar</b> (Status Ekosistem Lamun 2021), sementara <em>Indonesia Blue Economy Roadmap</em> 2023 menaksir potensinya hingga ⚠︎1,8 juta hektar. Selisih sebesar itu berarti sebagian besar padang lamun kita belum pernah dipetakan dengan pasti — apalagi dijaga."}, {"t": "h2", "x": "Yang tak terpetakan sulit dilindungi"}, {"t": "p", "x": "Ketidaktahuan itu berbahaya karena lamun termasuk ekosistem yang paling cepat menyusut di dunia. <a href=\"https://www.pnas.org/doi/10.1073/pnas.0905620106\">Waycott dkk. (PNAS, 2009)</a> mencatat sekitar 29% luas padang lamun dunia yang diketahui telah lenyap sejak 1879, dengan laju kehilangan melonjak menjadi sekitar 7% per tahun sejak 1990. Ketika lamun rusak — oleh reklamasi, jangkar, limbah, atau pengerukan — sedimen yang teraduk bisa melepaskan kembali karbon yang telah dikunci selama berabad-abad."}, {"t": "pull", "x": "Karbon biru yang tak terpetakan bukan aset yang aman — ia hanya utang iklim yang belum ketahuan."}, {"t": "p", "x": "Indonesia punya taruhan besar. Pemerintah menyebut perairan kita menampung sekitar ⚠︎11,5% padang lamun dunia (angka yang dilaporkan KKP, masih perlu validasi lapangan) — modal alami yang jarang dimiliki negara lain. Tapi klaim itu baru bermakna jika luas, kondisi, dan simpanan karbonnya benar-benar <b>terlacak</b>, bukan sekadar ditaksir. Tanpa itu, lamun sulit masuk inventarisasi emisi nasional secara kredibel, meski <a href=\"https://www.ipcc.ch/publication/2013-supplement-to-the-2006-ipcc-guidelines-for-national-greenhouse-gas-inventories-wetlands/\">Panduan Lahan Basah IPCC (2013)</a> sudah membuka jalannya."}, {"t": "p", "x": "Pelajarannya sederhana dan tak seksi: sebelum bicara kredit atau <b>imbalan</b> karbon biru, pekerjaan pertama adalah memetakan dan memantau. Padang lamun tak akan menyelamatkan iklim sendirian, tapi kontribusinya nyata — dan kontribusi yang tak tercatat sama saja dengan tak ada. Di situlah data, bukan janji, yang menentukan."}], "story": [{"kind": "cover", "title": "Padang lamun: karbon biru yang terlupakan", "text": "Semua mata tertuju pada mangrove, tapi padang lamun menyimpan karbon per hektar yang setara — dan paling sedikit dipetakan serta dilindungi."}, {"kind": "hook", "title": "Karbon biru bukan cuma mangrove", "text": "Menutup <0,2% dasar laut, tapi mengubur ~10% karbon yang ditelan lautan tiap tahun. Nyaris tak ada yang menjaganya."}, {"kind": "point", "title": "Kecil tapi pekat", "text": "Nilainya ada di sedimen di bawahnya — lumpur miskin oksigen yang mengunci karbon selama ribuan tahun."}, {"kind": "stat", "title": "Serapan per hektar yang tinggi", "big": "±140 t C", "label": "per hektar, di 1 meter teratas sedimen lamun", "source": "Fourqurean dkk., Nature Geoscience, 2012"}, {"kind": "point", "title": "Paling sedikit dipetakan", "text": "Luas tervalidasi ~293.500 ha; potensi ditaksir hingga ⚠︎1,8 juta ha. Sebagian besar belum pernah dipetakan pasti."}, {"kind": "quote", "title": "Aset atau utang?", "text": "Karbon biru yang tak terpetakan bukan aset yang aman — ia utang iklim yang belum ketahuan."}, {"kind": "end", "title": "Petakan dulu, klaim belakangan", "text": "Baca ulasan lengkapnya di Glyiv Kabar, dan ikuti bagaimana data karbon biru dibuat terlacak."}], "sources": [{"a": "Fourqurean, J.W., Duarte, C.M., dkk. (2012). Seagrass ecosystems as a globally significant carbon stock. Nature Geoscience 5, 505–509.", "u": "https://www.nature.com/articles/ngeo1477"}, {"a": "Waycott, M., dkk. (2009). Accelerating loss of seagrasses across the globe threatens coastal ecosystems. PNAS 106(30), 12377–12381.", "u": "https://www.pnas.org/doi/10.1073/pnas.0905620106"}, {"a": "IPCC (2013). 2013 Supplement to the 2006 IPCC Guidelines for National Greenhouse Gas Inventories: Wetlands.", "u": "https://www.ipcc.ch/publication/2013-supplement-to-the-2006-ipcc-guidelines-for-national-greenhouse-gas-inventories-wetlands/"}, {"a": "Pusat Riset Oseanografi BRIN, Status Ekosistem Lamun Indonesia (2021); KKP, Indonesia Blue Economy Roadmap 2nd Ed. (2023) — sebagaimana diulas Mongabay (2023).", "u": "https://news.mongabay.com/2023/11/indonesia-seagrass-climate-mitigation-emissions-reduction-carbon-marine/"}]}, {"slug": "dmrv-dari-klaim-ke-bukti", "topic": "Teknologi", "mood": "#6B4E8C", "title": "dMRV: mengubah janji offset jadi data yang bisa diaudit.", "dek": "Pasar offset lama berjalan di atas kepercayaan; dMRV menggantinya dengan satelit, sensor, dan buku besar yang membuktikan pohonnya benar-benar hidup — dan hanya dihitung sekali.", "hook": "Sebuah pohon kini bisa dibuktikan hidup dari orbit — dan dipastikan tak dihitung dua kali.", "cover": "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (ICVCM, ESA, UNFCCC)", "read": 4, "blocks": [{"t": "lead", "x": "Selama bertahun-tahun, membeli offset karbon berarti memercayai sebuah janji: di suatu tempat, ada pohon yang ditanam untuk menebus emisi Anda. Masalahnya, janji sulit diaudit. Pohon bisa mati, terbakar, atau tak pernah benar-benar ada — dan kredit yang sama bisa berpindah tangan dua kali. dMRV lahir untuk satu tujuan: mengganti kepercayaan dengan bukti yang bisa diperiksa."}, {"t": "p", "x": "dMRV — kependekan dari <b>digital Monitoring, Reporting, and Verification</b> — adalah cara memantau, melaporkan, dan memverifikasi proyek iklim dengan alat digital, bukan laporan manual sekali setahun. Datanya dikumpulkan lebih sering, lebih murah, dan lebih sulit dimanipulasi. Standar integritas seperti <a href=\"https://icvcm.org/the-core-carbon-principles/\">Core Carbon Principles</a> dari ICVCM kini menjadikan kualitas pemantauan sebagai syarat kredit yang layak dipercaya, bukan sekadar pelengkap."}, {"t": "h2", "x": "Tiga mata untuk satu pohon"}, {"t": "p", "x": "Mata pertama ada di orbit. Satelit <b>Copernicus Sentinel-2</b> milik Uni Eropa memindai daratan setiap sekitar lima hari pada resolusi 10 meter, dan indeks kehijauan (NDVI) memperlihatkan apakah tegakan benar-benar hidup dan tumbuh — bukan sekadar ditanam sekali lalu ditinggalkan (<a href=\"https://sentinel.esa.int/web/sentinel/missions/sentinel-2\">ESA</a>). Sebuah foto penanaman tak lagi cukup; yang dinilai adalah kelangsungan sepanjang waktu."}, {"t": "p", "x": "Mata kedua ada di tanah. Sensor lapangan dan pengukuran petak memberi 'kebenaran dasar' untuk mengalibrasi citra satelit — piksel hijau dari luar angkasa tetap perlu dicocokkan dengan pohon nyata. Mata ketiga ada di buku besar: saat sebuah kredit 'dipensiunkan' (retired) di rantai, catatannya bersifat satu-arah dan publik, sehingga ton yang sama tak bisa dijual ulang. Inilah pertahanan terhadap <b>penghitungan ganda</b> — risiko yang di tingkat negara juga diatur lewat 'corresponding adjustment' dalam <a href=\"https://unfccc.int/process-and-meetings/the-paris-agreement/article-6-of-the-paris-agreement\">Pasal 6 Perjanjian Paris</a> ⚠︎."}, {"t": "pull", "x": "Offset yang baik bukan soal menanam pohon — tapi membuktikan pohon itu masih hidup, dan hanya dihitung sekali."}, {"t": "stat", "n": ">90%", "l": "kredit offset hutan tropis dari satu penyertifikat besar dinilai tak mewakili pengurangan emisi nyata ⚠︎ (temuan investigatif, dibantah penyertifikat)", "s": "The Guardian / SourceMaterial, 2023"}, {"t": "h2", "x": "Jujur soal batasnya"}, {"t": "p", "x": "dMRV bukan sihir. Citra satelit bisa keliru saat langit tertutup awan, dan tak ada sensor yang mampu menjamin sebuah hutan bertahan berpuluh tahun ke depan. Karena itu Glyiv memilih kata yang jujur: membeli pohon adalah sebuah <b>kontribusi</b> pada penyerapan karbon yang terlacak, bukan klaim 'netral karbon' yang instan. Bukti yang baik tahu batas dirinya."}, {"t": "p", "x": "Yang benar-benar berubah adalah rantai bukti. Dengan dMRV, siapa pun bisa menelusuri sebuah kredit hingga ke petak lahannya, tanggal pemantauannya, dan tanda tangan on-chain-nya. Itulah yang memisahkan offset yang bermakna dari yang sekadar menenangkan hati — dan itulah, pada akhirnya, jantung kredibilitas offset modern."}], "story": [{"kind": "cover", "title": "dMRV: dari janji ke bukti", "text": "Pasar offset lama berjalan di atas kepercayaan; dMRV menggantinya dengan satelit, sensor, dan buku besar yang membuktikan pohonnya benar-benar hidup — dan hanya dihitung sekali."}, {"kind": "hook", "title": "Dulu kita cuma bisa percaya", "text": "Beli offset berarti memercayai bahwa pohonnya ada di suatu tempat. dMRV membuat 'suatu tempat' itu bisa dilihat, dicek, dan diaudit."}, {"kind": "point", "title": "Apa itu dMRV?", "text": "Memantau, melaporkan, dan memverifikasi proyek iklim secara digital: satelit + sensor lapangan + buku besar on-chain. Sering, murah, sulit dimanipulasi."}, {"kind": "point", "title": "Mata di orbit", "text": "Sentinel-2 memindai tiap ~5 hari. NDVI menilai apakah pohon hidup dan tumbuh — bukan sekadar ditanam sekali lalu ditinggalkan."}, {"kind": "point", "title": "Anti hitung-ganda", "text": "Kredit yang 'dipensiunkan' di rantai bersifat satu-arah dan publik. Ton karbon yang sama tak bisa dijual dua kali."}, {"kind": "stat", "title": "Kenapa bukti itu penting", "big": ">90%", "label": "kredit hutan tropis dari satu penyertifikat besar dinilai tak mewakili pengurangan nyata ⚠︎ (dibantah penyertifikat)", "source": "The Guardian / SourceMaterial, 2023"}, {"kind": "end", "title": "Bukti, bukan janji.", "text": "Baca artikel lengkapnya di Glyiv Kabar — dan lihat bagaimana kami membangun offset yang benar-benar bisa diaudit."}], "sources": [{"a": "Integrity Council for the Voluntary Carbon Market (ICVCM) (2023). The Core Carbon Principles.", "u": "https://icvcm.org/the-core-carbon-principles/"}, {"a": "European Space Agency (ESA) / Copernicus. Sentinel-2 mission (resolusi 10 m, revisit ~5 hari).", "u": "https://sentinel.esa.int/web/sentinel/missions/sentinel-2"}, {"a": "The Guardian, Die Zeit & SourceMaterial (2023). Investigasi kualitas kredit karbon hutan tropis (berbasis riset West dkk.).", "u": "https://www.theguardian.com/environment/2023/jan/18/revealed-forest-carbon-offsets-biggest-provider-worthless-verra-aoe"}, {"a": "UNFCCC. Article 6 of the Paris Agreement — corresponding adjustments untuk mencegah penghitungan ganda.", "u": "https://unfccc.int/process-and-meetings/the-paris-agreement/article-6-of-the-paris-agreement"}]}, {"slug": "reforestasi-bukan-sekadar-menanam", "topic": "Offset", "mood": "#4F7A3A", "title": "Menanam sejuta pohon itu mudah; menjaganya yang sulit.", "dek": "Banyak proyek reforestasi gagal diam-diam karena bibitnya tak bertahan; karbon yang nyata datang dari pohon yang hidup bertahun-tahun, bukan dari seremoni tanam yang difoto.", "hook": "Sejuta bibit masuk tanah hari ini. Pertanyaan yang benar: berapa yang masih hidup lima tahun lagi?", "cover": "https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 5, "blocks": [{"t": "lead", "x": "Foto yang beredar hampir selalu mirip: barisan orang berseragam, sekop di tangan, bibit mungil masuk ke lubang tanah, lalu tepuk tangan di depan spanduk 'Sejuta Pohon'. Menanam adalah acara satu hari yang mudah difoto dan mudah dirayakan. Yang jarang masuk bingkai adalah lima tahun sesudahnya — saat bibit-bibit itu harus bertahan hidup tanpa kamera, tanpa panggung, dan sering kali tanpa perawatan."}, {"t": "p", "x": "Di titik itulah banyak proyek reforestasi diam-diam gugur. Bibit mati oleh kekeringan, terinjak dan digembalai ternak, salah dipilih spesiesnya untuk tanah setempat, atau sekadar kehabisan dana pemeliharaan begitu seremoni usai. Kajian restorasi hutan tropis berulang kali menemukan angka kematian bibit yang tinggi pada tahun-tahun pertama — di sejumlah lokasi mendekati separuh tegakan ⚠︎. Yang lebih penting dari satu angka rata-rata adalah sebarannya yang lebar: kelangsungan hidup tidak bisa diasumsikan, ia harus dibuktikan lokasi per lokasi."}, {"t": "h2", "x": "Karbon tinggal di pohon yang bertahan"}, {"t": "p", "x": "Serapan karbon bukan peristiwa penanaman, melainkan proses berpuluh tahun. Sebatang pohon justru menyerap paling banyak ketika dewasa, sehingga nilai iklimnya yang sesungguhnya baru terwujud bila tegakan itu bertahan lama. IPCC menegaskan penyerapan berbasis lahan menghadapi risiko <strong>permanensi</strong>: karbon yang sudah tersimpan bisa lepas kembali akibat kebakaran, hama, kekeringan, atau keputusan manusia (<a href='https://www.ipcc.ch/report/ar6/wg3/'>IPCC AR6, 2022</a>). Karena itu kredit yang jujur menuntut cadangan penyangga dan pemantauan bertahun-tahun — bukan sertifikat sekali cetak di hari tanam."}, {"t": "pull", "x": "Nilai karbon tidak lahir dari upacara tanam, melainkan dari pohon yang masih berdiri sepuluh tahun kemudian."}, {"t": "p", "x": "Ada jebakan kedua: jenis pohon yang ditanam. Analisis di jurnal <em>Nature</em> menemukan hampir separuh komitmen restorasi global sesungguhnya berupa kebun monokultur bernilai komersial — yang menyimpan karbon jauh lebih sedikit dan jauh lebih rapuh ketimbang hutan alam yang dibiarkan pulih (<a href='https://www.nature.com/articles/d41586-019-01026-8'>Lewis dkk., Nature, 2019</a>). Menanam dalam jumlah besar belum tentu menyimpan karbon dalam jumlah besar."}, {"t": "stat", "n": "45%", "l": "komitmen restorasi Bonn Challenge berupa kebun monokultur — simpan karbon jauh lebih sedikit & kurang tahan lama", "s": "Lewis dkk., Nature, 2019"}, {"t": "p", "x": "Konsekuensinya jelas untuk cara kita membelanjakan uang restorasi. Anggaran yang mengalir deras ke hari penanaman lalu mengering sesudahnya hampir memastikan kegagalan. Yang sebenarnya menentukan justru bagian yang membosankan: penyulaman bibit yang mati, pengendalian kebakaran, dan pelibatan warga sekitar lahan sebagai penjaga jangka panjang — bertahun-tahun setelah kamera pergi."}, {"t": "h2", "x": "Dari seremoni ke bukti"}, {"t": "p", "x": "Di sinilah pendekatan yang bisa dipertanggungjawabkan berpisah jalan dari kampanye tanam massal. Yang menentukan bukan berapa bibit masuk tanah, melainkan berapa yang <strong>terlacak hidup</strong> tahun demi tahun. Glyiv memantau kelangsungan tegakan lewat data satelit — antara lain indeks kehijauan NDVI — dan mencatat serapannya sebagai kontribusi karbon yang bisa ditelusuri hingga ke petak lahan dan tanggal pemantauannya, bukan klaim 'netral karbon' di atas kertas. Penjaga lahan yang benar-benar merawat pohonnya menerima imbalan atas tegakan yang bertahan, bukan atas foto di hari penanaman."}], "story": [{"kind": "cover", "title": "Menanam mudah. Menjaga sulit.", "text": "Banyak proyek reforestasi gagal diam-diam karena bibitnya tak bertahan; karbon yang nyata datang dari pohon yang hidup bertahun-tahun, bukan dari seremoni tanam yang difoto."}, {"kind": "hook", "title": "Seremoni sehari, ujian sepuluh tahun.", "text": "Menanam itu acara satu hari yang mudah difoto. Menjaga pohon tetap hidup adalah pekerjaan bertahun-tahun."}, {"kind": "point", "title": "Banyak yang mati diam-diam", "text": "Kekeringan, ternak, salah spesies, dana perawatan habis setelah seremoni. Di sejumlah lokasi mendekati separuh bibit tak bertahan tahun-tahun awal. ⚠︎"}, {"kind": "point", "title": "Karbon butuh waktu", "text": "Pohon menyerap paling banyak saat dewasa. Nilai iklim baru nyata bila tegakan bertahan puluhan tahun — dan tak terbakar."}, {"kind": "stat", "title": "Menanam banyak bukan berarti menyimpan banyak", "big": "45%", "label": "komitmen restorasi Bonn Challenge berupa kebun monokultur, simpan karbon jauh lebih sedikit", "source": "Lewis dkk., Nature, 2019"}, {"kind": "quote", "title": "Intinya", "text": "Nilai karbon lahir dari pohon yang masih berdiri sepuluh tahun kemudian — bukan dari upacara tanam."}, {"kind": "end", "title": "Bukti, bukan seremoni", "text": "Glyiv melacak pohon yang hidup, bukan sekadar yang ditanam. Baca versi lengkapnya, atau ikut bangun ekonomi hijau yang bisa dibuktikan."}], "sources": [{"a": "Lewis, S.L., Wheeler, C.E., Mitchard, E.T.A. & Koch, A. (2019). Restoring natural forests is the best way to remove atmospheric carbon. Nature 568, 25–28.", "u": "https://www.nature.com/articles/d41586-019-01026-8"}, {"a": "IPCC (2022). AR6 WGIII, Bab 7: Agriculture, Forestry and Other Land Uses (AFOLU) — permanensi & risiko pembalikan karbon berbasis lahan.", "u": "https://www.ipcc.ch/report/ar6/wg3/"}, {"a": "IUCN — The Bonn Challenge. Target restorasi 350 juta hektare lahan terdegradasi pada 2030.", "u": "https://www.bonnchallenge.org/"}, {"a": "Verra — VCS AFOLU Non-Permanence Risk Tool: cadangan penyangga (buffer pool) untuk risiko pembalikan.", "u": "https://verra.org/"}]}, {"slug": "keanekaragaman-hayati-30x30", "topic": "Global", "mood": "#4F7A3A", "title": "Target 30x30: Melindungi Sepertiga Bumi pada 2030", "dek": "Kerangka Kunming-Montreal menyepakati perlindungan 30% daratan dan lautan pada 2030 — dan kini kredit karbon makin dituntut ikut menjaga keanekaragaman hayati, bukan sekadar menyimpan karbon.", "hook": "Hampir 200 negara sepakat: sepertiga bumi harus terlindungi sebelum 2030.", "cover": "https://images.unsplash.com/photo-1425913397330-cf8af2ff40a1?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 3, "blocks": [{"t": "lead", "x": "Pada penghujung 2022, hampir 200 negara berkumpul di Montreal dan menyepakati satu janji yang mudah diucapkan tetapi berat dijalani: melindungi 30% daratan dan lautan dunia pada 2030. Angka itu — dikenal sebagai <b>30x30</b> — kini menjadi tolok ukur baru bagi hampir setiap klaim ramah lingkungan, termasuk kredit karbon."}, {"t": "p", "x": "Kesepakatan itu dituangkan dalam <b>Kerangka Kunming-Montreal (GBF)</b>, hasil COP15 Konvensi Keanekaragaman Hayati (CBD). Dari 23 target yang disepakati, <a href=\"https://www.cbd.int/gbf\">Target 3</a> adalah yang paling terkenal: menjamin setidaknya 30% wilayah daratan, perairan darat, pesisir, dan laut dikonservasi secara efektif pada 2030. Latarnya mendesak — <a href=\"https://www.ipbes.net/global-assessment\">IPBES (2019)</a> memperkirakan sekitar satu juta spesies terancam punah, banyak di antaranya dalam hitungan dekade."}, {"t": "h2", "x": "Jarak dari 17% ke 30%"}, {"t": "p", "x": "Hari ini dunia belum sampai di sana. Menurut <a href=\"https://www.protectedplanet.net\">Protected Planet</a> (UNEP-WCMC & IUCN), sekitar 17% daratan dan hanya 8% lautan yang saat ini berstatus kawasan lindung. Menutup jarak itu dalam waktu kurang dari satu dekade menuntut dana besar — GBF Target 19 menyerukan mobilisasi ⚠︎US$200 miliar per tahun untuk keanekaragaman hayati pada 2030 dari semua sumber."}, {"t": "stat", "n": "30%", "l": "daratan & lautan ditargetkan terlindungi pada 2030", "s": "Kerangka Kunming-Montreal (GBF), CBD COP15, 2022"}, {"t": "p", "x": "Ada satu peringatan penting: kawasan lindung 'di atas kertas' tidak selalu berarti terlindungi di lapangan. GBF menekankan konservasi yang <b>efektif</b> dan dikelola dengan baik, termasuk mengakui peran masyarakat adat dan komunitas lokal yang selama ini menjadi penjaga alam paling andal."}, {"t": "p", "x": "Di sinilah pasar karbon masuk. Banyak kredit karbon berbasis alam — misalnya proyek yang melindungi hutan agar tidak ditebang — kebetulan juga menjaga habitat satwa. Tetapi 'kebetulan' tidak lagi cukup. Standar integritas tinggi seperti <a href=\"https://icvcm.org\">Core Carbon Principles</a> menuntut proyek tidak merugikan masyarakat maupun alam, dan pembeli makin meminta bukti kontribusi bagi keanekaragaman hayati, bukan sekadar ton CO₂ yang tertahan."}, {"t": "pull", "x": "Kredit karbon kini dituntut bukan hanya menahan karbon, tetapi juga menjaga kehidupan yang tumbuh di atasnya."}, {"t": "p", "x": "Muncul pula gagasan <b>kredit keanekaragaman hayati</b> — instrumen terpisah yang membayar upaya pemulihan alam. <a href=\"https://www.biodiversitycreditalliance.org\">Biodiversity Credit Alliance</a>, yang didukung UNDP dan UNEP, tengah menyusun aturan mainnya. Namun pasar ini masih sangat muda: proyeksi nilainya beragam dan belum teruji ⚠︎, sehingga janji 'imbalan bagi penjaga hutan' perlu dibaca sebagai potensi, bukan kepastian."}, {"t": "p", "x": "Bagi Indonesia — salah satu negara paling kaya hayati di dunia, dengan hutan tropis dan mangrove yang luas — 30x30 bukan sekadar urusan konservasi, melainkan peluang ekonomi hijau yang harus dijaga kredibilitasnya. Glyiv memandang kontribusi iklim dan keanekaragaman hayati sebagai satu tarikan napas: yang terlacak, jujur dilaporkan, dan benar-benar sampai ke lapangan."}], "story": [{"kind": "cover", "title": "Target 30x30", "text": "Kerangka Kunming-Montreal menyepakati perlindungan 30% daratan dan lautan pada 2030 — dan kini kredit karbon makin dituntut ikut menjaga keanekaragaman hayati, bukan sekadar menyimpan karbon."}, {"kind": "hook", "title": "Sepertiga bumi", "text": "Hampir 200 negara sepakat: sepertiga bumi harus terlindungi sebelum 2030."}, {"kind": "point", "title": "Apa itu 30x30?", "text": "Target 3 Kerangka Kunming-Montreal: 30% daratan & lautan dikonservasi secara efektif pada 2030.", "source": "CBD COP15, 2022"}, {"kind": "point", "title": "Kita belum di sana", "text": "Baru sekitar 17% daratan dan 8% lautan yang berstatus lindung hari ini.", "source": "Protected Planet (UNEP-WCMC & IUCN)"}, {"kind": "stat", "title": "Ukuran janji", "big": "30%", "label": "daratan & lautan ditargetkan terlindungi pada 2030", "source": "GBF, CBD COP15, 2022"}, {"kind": "point", "title": "Karbon bertemu hayati", "text": "Kredit karbon berbasis alam kini dituntut ikut menjaga keanekaragaman hayati — bukan hanya menyimpan karbon.", "source": "Core Carbon Principles, ICVCM"}, {"kind": "end", "title": "Baca selengkapnya", "text": "Telusuri bagaimana Glyiv menautkan kontribusi iklim & alam yang terlacak dan jujur. Gabung Glyiv Kabar."}], "sources": [{"a": "Convention on Biological Diversity (CBD), Kunming-Montreal Global Biodiversity Framework (Decision 15/4), 2022", "u": "https://www.cbd.int/gbf"}, {"a": "UNEP-WCMC & IUCN, Protected Planet Report, 2024", "u": "https://www.protectedplanet.net"}, {"a": "IPBES, Global Assessment Report on Biodiversity and Ecosystem Services, 2019", "u": "https://www.ipbes.net/global-assessment"}, {"a": "Biodiversity Credit Alliance (didukung UNDP & UNEP), 2023", "u": "https://www.biodiversitycreditalliance.org"}]}, {"slug": "brgm-restorasi-gambut-mangrove", "topic": "Offset", "mood": "#B5623A", "title": "BRGM: badan yang bertugas 'membasahi' kembali Indonesia.", "dek": "Selama sembilan tahun, Badan Restorasi Gambut dan Mangrove ditugasi mengembalikan air ke jutaan hektar lahan yang sengaja dikeringkan — kerja lambat, penting, dan nyaris tanpa sorotan, yang kini dibubarkan sebelum benar-benar tuntas.", "hook": "Ada badan negara yang tugasnya benar-benar: membasahi kembali Indonesia. Dan hampir tak pernah masuk berita utama.", "cover": "https://images.unsplash.com/photo-1505142468610-359e7d316be0?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (Perpres 120/2020, World Bank, laporan BRGM)", "read": 5, "blocks": [{"t": "lead", "x": "Sebagian besar kerja iklim yang paling penting tidak terlihat dramatis. Tak ada gunting pita, tak ada panggung — hanya sekat kanal dari kayu, sumur bor, dan air yang perlahan dikembalikan ke tanah gambut yang selama puluhan tahun sengaja dikeringkan. Itulah inti tugas Badan Restorasi Gambut dan Mangrove (BRGM): secara harfiah, membasahi kembali Indonesia."}, {"t": "p", "x": "BRGM lahir dari asap. Setelah kebakaran gambut hebat pada 2015, pemerintah membentuk Badan Restorasi Gambut pada 2016, lalu memperluas mandatnya menjadi BRGM lewat <a href=\"https://jdih.kemenkeu.go.id/api/download/a57dbc88-719c-48fc-bf35-7cc0e459fdc2/PERPRES120TAHUN2020.pdf\">Peraturan Presiden 120/2020</a>: merestorasi <b>1,2 juta hektar</b> gambut di tujuh provinsi dan merehabilitasi <b>600.000 hektar</b> mangrove di sembilan provinsi — semuanya ditargetkan rampung akhir 2024."}, {"t": "p", "x": "Kenapa harus 'membasahi'? Gambut adalah timbunan sisa tumbuhan basah yang menyimpan karbon jauh lebih padat daripada hutan yang tumbuh di atasnya. Begitu dikeringkan lewat kanal untuk perkebunan, gambut mulai teroksidasi, melepaskan karbonnya, dan berubah menjadi bahan bakar kebakaran yang nyaris mustahil dipadamkan. Restorasi BRGM berpijak pada tiga langkah — pembasahan, penanaman ulang, dan revitalisasi ekonomi warga — dengan pembasahan sebagai jantungnya."}, {"t": "p", "x": "Praktiknya rumit. Banyak lahan gambut kritis berada di dalam konsesi atau lahan warga, sehingga restorasi menuntut negosiasi, bukan sekadar teknik. Sekat kanal harus dijaga bertahun-tahun; bila kanal dibuka lagi saat kemarau, kerja bertahun bisa lenyap dalam satu musim kebakaran. Karena itu keberhasilannya sulit dipotret dalam satu foto — ia berupa garis panjang yang landai, bukan lonjakan."}, {"t": "pull", "x": "Ini pekerjaan yang dihitung dalam tahun dan musim hujan, bukan dalam kuartal — dan hampir tak pernah jadi berita utama."}, {"t": "stat", "n": "USD 16,1 miliar", "l": "estimasi kerugian ekonomi kebakaran hutan & lahan 2015 — saat 2,6 juta hektar terbakar", "s": "World Bank, 2016"}, {"t": "h2", "x": "Angka yang jujur"}, {"t": "p", "x": "Hingga menutup tugasnya, BRGM mencatat sekitar <b>1,6 juta hektar</b> gambut direstorasi di luar konsesi dan membangun 22.349 unit infrastruktur pembasahan — sumur bor, sekat kanal, kanal timbun. Tetapi sisi mangrove jauh dari sasaran: hanya <b>84.396 hektar</b> dari target 600.000 hektar, sekitar satu per tujuh. Badan ini juga mengeklaim kebakaran gambut turun hingga 29,59% ⚠︎ — angka yang sulit diverifikasi secara independen."}, {"t": "p", "x": "Pada 2025 masa tugas BRGM berakhir dan lembaganya dibubarkan; pekerjaannya dipecah ke Kementerian Kehutanan, Kementerian Lingkungan Hidup, serta Kelautan dan Perikanan. Padahal taruhannya besar. Indonesia memegang mangrove terluas di dunia, sekitar 3,3 juta hektar ⚠︎ atau hampir seperlima total global, dan gambutnya termasuk penyimpan karbon terpadat di planet ini."}, {"t": "p", "x": "Bagi kami di Glyiv, kisah BRGM adalah pengingat bahwa restorasi karbon yang kredibel bukan soal klaim heroik, melainkan kerja panjang yang terlacak — petak demi petak, sekat demi sekat, musim demi musim. Karbon yang benar-benar tertahan di gambut basah adalah kontribusi yang nyata, asalkan bisa dibuktikan, bukan sekadar ditargetkan."}], "story": [{"kind": "cover", "title": "Membasahi kembali Indonesia", "text": "Selama sembilan tahun, sebuah badan negara ditugasi mengembalikan air ke jutaan hektar lahan yang sengaja dikeringkan — kerja lambat, penting, dan nyaris tanpa sorotan."}, {"kind": "hook", "title": "Tugas paling tak seksi di iklim", "text": "Tak ada gunting pita. Hanya sekat kanal, sumur bor, dan air yang perlahan dikembalikan ke gambut."}, {"kind": "point", "title": "Lahir dari asap", "text": "Setelah kebakaran 2015, lahir Badan Restorasi Gambut (2016), lalu menjadi BRGM lewat Perpres 120/2020 — kini plus mandat mangrove."}, {"kind": "point", "title": "Kenapa 'membasahi'?", "text": "Gambut yang dikeringkan teroksidasi, melepas karbon, dan mudah terbakar. Membasahinya kembali menahan keduanya."}, {"kind": "stat", "title": "Target yang meleset", "big": "84.396 ha", "label": "mangrove direhabilitasi — dari target 600.000 ha", "source": "Laporan BRGM, 2025"}, {"kind": "quote", "title": "Diukur dalam musim, bukan kuartal", "text": "Pekerjaan yang dihitung dalam tahun dan musim hujan, bukan dalam kuartal."}, {"kind": "end", "title": "Kerja yang belum tuntas", "text": "BRGM dibubarkan 2025, tugasnya dipecah ke tiga kementerian. Karbon di gambut basah tetap nyata — asal terlacak. Baca lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Peraturan Presiden Republik Indonesia No. 120 Tahun 2020 tentang Badan Restorasi Gambut dan Mangrove.", "u": "https://jdih.kemenkeu.go.id/api/download/a57dbc88-719c-48fc-bf35-7cc0e459fdc2/PERPRES120TAHUN2020.pdf"}, {"a": "World Bank (2016). The Cost of Fire: An Economic Analysis of Indonesia's 2015 Fire Crisis.", "u": "https://documents1.worldbank.org/curated/en/776101467990969768/pdf/103668-BRI-Cost-of-Fires-Knowledge-Note-PUBLIC-ADD-NEW-SERIES-Indonesia-Sustainable-Landscapes-Knowledge-Note.pdf"}, {"a": "Kompas (2025). BRGM Selesaikan Tugas dengan Restorasi 1,6 Juta Hektar Gambut dan 84.396 Hektar Mangrove.", "u": "https://money.kompas.com/read/2025/03/21/103000226/brgm-selesaikan-tugas-dengan-restorasi-1-6-juta-hektar-gambut-dan-84.000"}, {"a": "Kementerian LHK / Databoks (2021). Mangrove Indonesia sekitar 3,36 juta ha, 20,37% dari total dunia.", "u": "https://databoks.katadata.co.id/en/economics-macro/statistics/5e0a875c5ef64a5/indonesias-mangroves-account-for-2037-of-the-global-total-with-a-significant-portion-in-dense-condition"}]}, {"slug": "agroforestri-karbon-di-kebun", "topic": "Offset", "mood": "#4F7A3A", "title": "Agroforestri: menabung karbon tanpa berhenti bertani.", "dek": "Menyelipkan pohon di antara tanaman pangan menambah simpanan karbon sekaligus menjaga pendapatan petani — sebuah solusi 'dan', bukan 'atau'.", "hook": "Bagaimana kalau menanam pohon tak berarti berhenti bertani — malah menabung karbon di petak yang sama?", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan IPCC, FAO & KLHK", "read": 4, "blocks": [{"t": "lead", "x": "Cerita iklim sering dibingkai sebagai pilihan yang menyakitkan: tebang lahan demi hidup, atau tahan diri demi bumi. Agroforestri menolak dilema itu. Dengan menyelipkan pohon di antara tanaman pangan, satu petak lahan bisa memberi panen hari ini sekaligus menabung karbon untuk nanti — bukan 'atau', melainkan 'dan'."}, {"t": "p", "x": "Agroforestri — di Indonesia dikenal sebagai <b>wanatani</b> — adalah praktik memadukan pohon dengan tanaman semusim atau ternak dalam satu bidang lahan. Menurut <a href=\"https://www.fao.org/agroforestry/en/\">FAO</a>, ini sama sekali bukan hal baru: kebun campur, kopi yang tumbuh di bawah naungan, hingga pekarangan tradisional sudah lama melakukannya. Yang baru adalah cara kita menghargainya — sebagai penyimpan karbon yang bisa <b>dilacak</b>."}, {"t": "h2", "x": "Dua 'panen' dari satu petak"}, {"t": "p", "x": "Pohon menabung karbon di batang, akar, dan tanah, sementara tanaman di bawahnya tetap menghidupi keluarga petani. Analisis global Zomer dkk. (2016) menemukan bahwa <b>43% lahan pertanian dunia</b> sudah memiliki tutupan pohon minimal 10% <a href=\"https://www.nature.com/articles/srep29987\">↗</a> — bukti bahwa bertani dan berpohon memang bisa berdampingan, bukan bersaing. Naungan itu juga menahan kelembapan tanah dan meredam cuaca ekstrem, membuat panen lebih tahan guncangan."}, {"t": "stat", "n": "43%", "l": "lahan pertanian dunia sudah bertutupan pohon ≥10% — bertani & berpohon bukan lawan", "s": "Zomer dkk., Scientific Reports, 2016"}, {"t": "pull", "x": "Agroforestri mengubah pohon dari saingan lahan menjadi rekan tabungan — karbon di atas, pangan di bawah."}, {"t": "p", "x": "Panel iklim PBB menempatkan agroforestri sebagai salah satu opsi lahan yang jarang merugikan: ia menyerap karbon sekaligus memperkuat ketahanan pangan dan adaptasi <a href=\"https://www.ipcc.ch/srccl/\">IPCC (2019)</a>. Namun berapa persis karbon yang tersimpan sangat bergantung pada jenis pohon, tanah, dan usia tegakan — angkanya berkisar lebar dan sebaiknya diperlakukan sebagai perkiraan ⚠︎, bukan janji pasti."}, {"t": "p", "x": "Di Indonesia, agroforestri menjadi tulang punggung banyak izin <b>Perhutanan Sosial</b> dan bagian dari target <b>FOLU Net Sink 2030</b> — rencana menjadikan sektor lahan sebagai penyerap bersih karbon pada 2030. Luas dan capaiannya masih terus diperbarui ⚠︎, tetapi arahnya jelas: pohon di kebun petani mulai dihitung sebagai kontribusi iklim, bukan sekadar cadangan kayu."}, {"t": "h2", "x": "Jujur soal batasnya"}, {"t": "p", "x": "Agroforestri bukan tombol ajaib. Karbon yang ditabung pohon bisa lepas lagi bila tegakan ditebang atau terbakar, jadi klaimnya hanya sekuat pemantauannya. Karena itu Glyiv menekankan karbon yang <b>terlacak</b> — dipantau dari tahun ke tahun — dan menyebut hasilnya sebagai <b>kontribusi</b> iklim, bukan 'netral karbon'. Bagi petani, nilai terbesarnya sering bukan kredit karbon itu sendiri, melainkan <b>imbalan</b> tambahan di atas panen yang sudah ada: buah, kayu, dan tanah yang lebih subur."}], "story": [{"kind": "cover", "title": "Agroforestri: menabung karbon tanpa berhenti bertani", "text": "Menyelipkan pohon di antara tanaman pangan menambah simpanan karbon sekaligus menjaga pendapatan petani — solusi 'dan', bukan 'atau'."}, {"kind": "hook", "title": "Tak perlu memilih", "text": "Bagaimana kalau menanam pohon tak berarti berhenti bertani — malah menabung karbon di petak yang sama?"}, {"kind": "point", "title": "Bukan 'atau', tapi 'dan'", "text": "Pohon menyimpan karbon di batang, akar, dan tanah. Tanaman di bawahnya tetap memberi panen. Satu lahan, dua hasil."}, {"kind": "point", "title": "Sudah biasa berdampingan", "text": "Kopi di bawah naungan, kebun campur, pekarangan — wanatani sudah lama ada. Yang baru: cara melacaknya sebagai simpanan karbon."}, {"kind": "stat", "title": "Angka yang menenangkan", "big": "43%", "label": "lahan pertanian dunia sudah bertutupan pohon ≥10%", "source": "Zomer dkk., Scientific Reports, 2016"}, {"kind": "point", "title": "Sudah jalan di Indonesia", "text": "Jadi tulang punggung Perhutanan Sosial & bagian dari target FOLU Net Sink 2030. ⚠︎ angka capaian masih terus diperbarui."}, {"kind": "end", "title": "Karbon di atas, pangan di bawah", "text": "Kami menyebutnya kontribusi, bukan 'netral karbon' — dan menghargainya lewat karbon yang terlacak. Baca versi lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Zomer, R.J., Neufeldt, H., Xu, J. dkk. (2016). Global Tree Cover and Biomass Carbon on Agricultural Land: The contribution of agroforestry to global and national carbon budgets. Scientific Reports 6, 29987.", "u": "https://www.nature.com/articles/srep29987"}, {"a": "IPCC (2019). Climate Change and Land — Special Report (SRCCL): agroforestri sebagai opsi mitigasi & adaptasi.", "u": "https://www.ipcc.ch/srccl/"}, {"a": "FAO. Agroforestry — definisi dan manfaat sistem wanatani.", "u": "https://www.fao.org/agroforestry/en/"}, {"a": "Kementerian LHK (2022). Rencana Operasional Indonesia's FOLU Net Sink 2030.", "u": "https://www.menlhk.go.id/"}]}, {"slug": "terumbu-karang-jasa-tersembunyi", "topic": "Offset", "mood": "#1E5F8C", "title": "Terumbu karang: pelindung pantai yang tak muncul di neraca.", "dek": "Di neraca karbon terumbu karang nyaris tak bernilai, tapi jasa perlindungan pesisirnya menyelamatkan jutaan orang — pengingat bahwa iklim tak pernah hanya soal ton CO₂.", "hook": "Terumbu karang menyimpan sedikit karbon — tapi meredam 97% gelombang yang menghantam pantaimu. Ada nilai yang tak muat di neraca.", "cover": "https://images.unsplash.com/photo-1505142468610-359e7d316be0?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Nature Communications & sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Dalam akuntansi iklim, hampir semua hal diringkas ke satu satuan: ton CO₂. Hutan dihargai karena menyerapnya, pabrik ditagih karena melepasnya. Dengan logika itu, terumbu karang nyaris tak punya nilai — ia menyimpan sedikit karbon, dan proses pembentukan rangkanya justru melepaskan CO₂. Namun ada kolom yang tak pernah muncul di neraca, dan justru di sanalah karang menyimpan sebagian besar nilainya."}, {"t": "p", "x": "Istilah 'karbon biru' merujuk pada karbon yang dikunci ekosistem pesisir, dan daftarnya spesifik: <b>mangrove, padang lamun, dan rawa asin</b>. Ketiganya menabung karbon dalam jumlah besar di sedimen. Terumbu karang tidak masuk daftar itu. Kalsifikasi — proses karang membangun rangka kapur (CaCO₃) — malah melepaskan CO₂ ke air laut. Maka di atas kertas neraca karbon, karang tampak hampir tak berguna."}, {"t": "p", "x": "Bandingkan dengan tetangganya di garis pantai yang sama: Indonesia punya hamparan mangrove terluas di dunia — sekitar 3,3 juta hektare ⚠︎ — yang menyimpan karbon secara masif. Mangrove menabung karbon; karang menahan gelombang. Keduanya vital, tapi hanya satu yang mudah dihargai dalam satuan ton."}, {"t": "h2", "x": "Jasa yang tak masuk kolom"}, {"t": "p", "x": "Padahal karang adalah pemecah gelombang alami. Riset di <i>Nature Communications</i> menemukan terumbu karang sehat meredam rata-rata <b>97% energi gelombang</b> yang menerpanya — puncak karang (<i>reef crest</i>) sendiri sudah menyerap 86% <a href=\"https://www.nature.com/articles/ncomms4794\">(Ferrario dkk., 2014)</a>. Struktur berpori yang dibangun ribuan tahun itu bekerja seperti tembok laut yang memperbaiki diri sendiri selama karangnya hidup."}, {"t": "stat", "n": "97%", "l": "energi gelombang yang diredam terumbu karang sehat, rata-rata", "s": "Ferrario dkk., Nature Communications, 2014"}, {"t": "p", "x": "Perlindungan itu bisa dihitung nilainya. Studi lanjutan memperkirakan terumbu karang mencegah sekitar <b>US$4,3 miliar</b> kerugian banjir pesisir per tahun secara global — dan negara yang paling diuntungkan adalah <b>Indonesia</b>, dengan manfaat sekitar US$639 juta setiap tahun. Tanpa karang, kerugian banjir tahunan diperkirakan berlipat dua <a href=\"https://www.nature.com/articles/s41467-018-04568-z\">(Beck dkk., 2018)</a>. Lebih dari 100 juta orang hidup cukup dekat dengan karang untuk merasakan perlindungannya."}, {"t": "pull", "x": "Iklim bukan hanya soal ton CO₂. Sebagian ekosistem melindungi kita dengan cara yang tak pernah muncul di kolom karbon."}, {"t": "p", "x": "Ini pengingat penting bagi siapa pun yang membangun sistem karbon, termasuk kami. Ketika sebuah aset hanya dinilai dari berapa ton yang diserapnya, ekosistem seperti terumbu karang gampang dianggap remeh — lalu tergeser dari daftar prioritas pendanaan. Padahal perlindungan pesisir, penyokong perikanan, dan penahan abrasi adalah nilai yang nyata; satuannya saja yang berbeda."}, {"t": "p", "x": "Karena itu Glyiv memilih kata <b>kontribusi</b>, bukan 'netral karbon' — dampak iklim yang sesungguhnya selalu lebih luas daripada satu angka. Neraca yang jujur butuh ruang untuk mencatat jasa yang tak berbentuk ton. Terumbu karang adalah contoh paling terang bahwa menjaga alam kadang bernilai jauh lebih besar daripada sekadar menghitungnya."}], "story": [{"kind": "cover", "title": "Pelindung pantai yang tak muncul di neraca", "text": "Di neraca karbon terumbu karang nyaris tak bernilai, tapi jasa perlindungan pesisirnya menyelamatkan jutaan orang — pengingat bahwa iklim tak pernah hanya soal ton CO₂."}, {"kind": "hook", "title": "Sedikit karbon, banyak nyawa", "text": "Terumbu karang menyimpan sedikit karbon. Tapi ia meredam gelombang yang menghantam pantai — dan menjaga jutaan orang."}, {"kind": "point", "title": "Karbon biru itu daftar tertutup", "text": "Mangrove, lamun, rawa asin — mereka menabung karbon. Karang tak masuk; kalsifikasinya malah melepas CO₂."}, {"kind": "point", "title": "Tapi karang = tembok laut hidup", "text": "Terumbu sehat meredam rata-rata 97% energi gelombang. Puncak karang saja menyerap 86%."}, {"kind": "stat", "title": "Indonesia paling diuntungkan", "big": "US$639 jt/th", "label": "manfaat perlindungan banjir dari karang untuk Indonesia — tertinggi di dunia", "source": "Beck dkk., Nature Communications, 2018"}, {"kind": "quote", "title": "Bukan cuma ton CO₂", "text": "Iklim bukan hanya soal ton CO₂. Sebagian ekosistem melindungi kita di kolom yang tak pernah dihitung."}, {"kind": "end", "title": "Nilai yang tak muat di neraca", "text": "Baca kabar lengkapnya — dan telusuri cara Glyiv menilai alam lebih dari sekadar ton karbon."}], "sources": [{"a": "Ferrario, F., Beck, M.W., Storlazzi, C.D., Micheli, F., Shepard, C.C., Airoldi, L. (2014). The effectiveness of coral reefs for coastal hazard risk reduction and adaptation. Nature Communications 5:3794.", "u": "https://www.nature.com/articles/ncomms4794"}, {"a": "Beck, M.W., Losada, I.J., Menéndez, P., Reguero, B.G., Díaz-Simal, P., Fernández, F. (2018). The global flood protection savings provided by coral reefs. Nature Communications 9:2186.", "u": "https://www.nature.com/articles/s41467-018-04568-z"}, {"a": "Nellemann, C. dkk. (2009). Blue Carbon: The Role of Healthy Oceans in Binding Carbon. UNEP/GRID-Arendal — kerangka karbon biru mencakup mangrove, lamun, dan rawa asin (bukan terumbu karang).", "u": "https://www.grida.no/publications/145"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan (KLHK), Peta Mangrove Nasional — estimasi luas mangrove Indonesia ±3,3 juta hektare (angka bervariasi antar-sumber ⚠︎)."}]}, {"slug": "karhutla-emisi-tak-terlihat", "topic": "Offset", "mood": "#B5623A", "title": "Kebakaran hutan: sumber emisi yang datang tiba-tiba.", "dek": "Karhutla di lahan gambut melepas karbon yang tertimbun ribuan tahun hanya dalam hitungan minggu — cukup untuk sesaat membalik Indonesia dari penyerap menjadi pelepas karbon, seperti terjadi pada 2015.", "hook": "Sumber emisi terbesar Indonesia bisa jadi bukan pabrik atau kendaraan — tapi tanah yang terbakar diam-diam di puncak kemarau.", "cover": "https://images.unsplash.com/photo-1511497584788-876760111969?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (World Bank, WRI, KLHK)", "read": 4, "blocks": [{"t": "lead", "x": "Kebanyakan sumber emisi datang perlahan dan bisa dijadwalkan — cerobong pabrik, knalpot kendaraan, pembangkit yang menyala tiap hari. Kebakaran hutan dan lahan berbeda wataknya: ia datang tiba-tiba, memuncak dalam hitungan minggu di puncak kemarau, dan sanggup melepas karbon yang tersimpan selama ribuan tahun hanya dalam satu musim."}, {"t": "p", "x": "Kuncinya ada di gambut. Lahan gambut tropis Indonesia adalah gudang karbon raksasa — sisa tumbuhan yang menumpuk dalam kondisi basah selama ribuan tahun tanpa sempat lapuk. Selama tetap basah, karbon itu terkunci aman. Namun begitu dikeringkan lewat kanal untuk perkebunan, gambut berubah menjadi bahan bakar: mudah tersulut, dan apinya menjalar di bawah permukaan — membara berminggu-minggu, sulit dipadamkan, dan melepas CO2 jauh lebih banyak per hektare daripada kebakaran vegetasi biasa."}, {"t": "p", "x": "Skala persoalannya tidak kecil. Indonesia memiliki sekitar <b>13 juta hektare</b> lahan gambut ⚠︎ — termasuk yang terluas di dunia — dan sebagian besarnya telah dikeringkan atau terdegradasi, membuatnya rawan terbakar setiap kali kemarau panjang datang. Badan Restorasi Gambut dan Mangrove dibentuk justru untuk membasahi kembali dan memulihkan lahan-lahan ini."}, {"t": "pull", "x": "Yang paling berbahaya saat gambut terbakar bukan pepohonan di atasnya — melainkan karbon ribuan tahun yang tersimpan di bawahnya."}, {"t": "p", "x": "Tahun 2015 memperlihatkan skalanya. Pada puncak musim kebakaran, di banyak hari emisi harian dari karhutla Indonesia melampaui rata-rata emisi harian seluruh perekonomian Amerika Serikat <a href=\"https://www.wri.org/insights/indonesias-fire-outbreaks-producing-more-daily-emissions-entire-us-economy\">(WRI, 2015)</a>. Untuk sesaat, negara yang hutan dan gambutnya semestinya menyerap karbon justru menjelma menjadi salah satu pelepas terbesar di dunia — sekaligus menutup langit sebagian Asia Tenggara dengan kabut asap."}, {"t": "stat", "n": "USD 16,1 miliar", "l": "Perkiraan kerugian ekonomi krisis karhutla 2015 — setara ~1,9% PDB Indonesia", "s": "World Bank, 2016"}, {"t": "h2", "x": "Kenapa satu musim bisa membalik neraca"}, {"t": "p", "x": "Indonesia menargetkan sektor kehutanan dan lahannya menjadi penyerap bersih karbon pada 2030 — dikenal sebagai <b>FOLU Net Sink</b>, dengan sasaran serapan bersih sekitar −140 juta ton CO2e ⚠︎. Masalahnya, capaian itu dibangun perlahan lewat restorasi dan penjagaan, tapi bisa terhapus cepat: satu musim karhutla hebat mampu melepas emisi setara bertahun-tahun kerja penyerapan hanya dalam beberapa minggu. Itulah kenapa karhutla bukan sekadar bencana kabut asap, melainkan risiko yang bisa membalik seluruh neraca karbon nasional."}, {"t": "h2", "x": "Yang bisa dilacak, bisa dicegah lebih awal"}, {"t": "p", "x": "Emisi karhutla sulit terlihat justru karena sifatnya musiman dan tersembunyi — membara di bawah tanah, jauh dari cerobong yang gampang dipantau. Tapi ia bisa dilacak: titik panas satelit, tinggi muka air gambut, dan status restorasi lahan semuanya memberi sinyal dini. Bagi Glyiv, di sinilah letak kontribusi yang nyata — menjadikan risiko yang episodik dan tak kasat mata itu terlacak lebih awal, sehingga pencegahan dan pembasahan kembali gambut bisa datang sebelum, bukan sesudah, api menyala."}], "story": [{"kind": "cover", "title": "Kebakaran hutan: sumber emisi yang datang tiba-tiba.", "text": "Karhutla di lahan gambut melepas karbon yang tertimbun ribuan tahun hanya dalam hitungan minggu — cukup untuk sesaat membalik Indonesia dari penyerap menjadi pelepas karbon, seperti terjadi pada 2015."}, {"kind": "hook", "title": "Bukan pabrik. Bukan kendaraan.", "text": "Sumber emisi terbesar bisa jadi tanah yang terbakar diam-diam di puncak kemarau."}, {"kind": "point", "title": "Kenapa gambut?", "text": "Karbon ribuan tahun tersimpan di bawah lahan gambut. Dikeringkan, ia jadi bahan bakar yang membara berminggu-minggu."}, {"kind": "point", "title": "Pelajaran 2015", "text": "Di puncak kebakaran, emisi harian Indonesia melampaui seluruh ekonomi AS. Penyerap berubah jadi pelepas."}, {"kind": "stat", "title": "Harganya nyata", "big": "USD 16,1 M", "label": "Kerugian ekonomi karhutla 2015 (~1,9% PDB)", "source": "World Bank, 2016"}, {"kind": "quote", "title": "Yang tersembunyi di bawah", "text": "Yang paling berbahaya bukan pohon di atasnya — tapi karbon ribuan tahun di bawahnya."}, {"kind": "end", "title": "Terlacak lebih awal", "text": "Karhutla bisa dipantau: titik panas, muka air gambut, status restorasi. Baca selengkapnya bersama Glyiv Kabar."}], "sources": [{"a": "World Bank (2016). The Cost of Fire: An Economic Analysis of Indonesia's 2015 Fire Crisis.", "u": "https://www.worldbank.org/en/country/indonesia/publication/the-cost-of-fire-an-economic-analysis-of-indonesia-s-2015-fire-crisis"}, {"a": "World Resources Institute — Harris, N. et al. (2015). Indonesia's Fire Outbreaks Producing More Daily Emissions than Entire US Economy.", "u": "https://www.wri.org/insights/indonesias-fire-outbreaks-producing-more-daily-emissions-entire-us-economy"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan (2022). Rencana Operasional Indonesia's FOLU Net Sink 2030."}, {"a": "IPCC (2014). 2013 Supplement to the 2006 IPCC Guidelines for National Greenhouse Gas Inventories: Wetlands (emisi lahan gambut kering & terbakar)."}]}, {"slug": "kredit-karbon-double-counting", "topic": "Offset", "mood": "#1cae6b", "title": "Menghitung dua kali: dosa asal pasar karbon.", "dek": "Tanpa retirement satu-arah dan rekonsiliasi registri, satu ton bisa diklaim dua pihak sekaligus — dan mencegah penghitungan ganda adalah syarat mutlak sebelum sebuah kredit karbon layak disebut kredibel.", "hook": "Satu ton karbon, dua pemilik. Inilah \"dosa asal\" yang diam-diam bisa membatalkan seluruh janji iklim sebuah kredit.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Perjanjian Paris Pasal 6 & ICVCM", "read": 5, "blocks": [{"t": "lead", "x": "Bayangkan satu ton karbon yang tidak jadi terlepas ke atmosfer. Di dunia ideal, ia dihitung sekali, oleh satu pihak. Di pasar karbon yang nyata, ton yang sama kerap muncul di dua neraca sekaligus — diklaim penjual proyek, sekaligus tetap dihitung oleh negara tempat proyek itu berdiri. Itulah dosa asal yang menggerogoti kepercayaan pada kredit karbon: double-counting."}, {"t": "p", "x": "Double-counting terjadi ketika satu reduksi emisi dihitung lebih dari sekali. Di bawah Perjanjian Paris, penangkalnya bernama <b>corresponding adjustment</b>: negara yang mengekspor kredit wajib menambahkan kembali ton itu ke inventarisnya, supaya tidak ikut mengklaimnya dalam target nasional (NDC). Prinsipnya sederhana, penerapannya rumit — aturan lengkap Pasal 6 baru dituntaskan pada COP29 di Baku, 2024 ⚠︎, dan operasionalisasinya masih berjalan. <a href=\"https://unfccc.int/process-and-meetings/the-paris-agreement/article-64-mechanism\">(UNFCCC)</a>"}, {"t": "h2", "x": "Tiga cara satu ton dihitung dua kali"}, {"t": "p", "x": "Literatur integritas karbon memetakan tiga bentuknya <a href=\"https://doi.org/10.1007/s10584-015-1398-y\">(Schneider dkk., 2015)</a>. <b>Double issuance</b>: dua kredit diterbitkan untuk satu reduksi yang sama. <b>Double use</b> (atau double selling): satu kredit yang sama dipakai atau dijual lebih dari sekali. <b>Double claiming</b>: reduksi yang sama diakui dua pihak — pembeli yang memakainya sebagai kontribusi, dan negara tuan rumah yang tetap menghitungnya di NDC. Yang terakhir ini paling halus, dan paling butuh corresponding adjustment."}, {"t": "pull", "x": "Kredit yang dihitung dua kali bukan sekadar lemah — secara matematis ia membatalkan manfaat iklim yang dijanjikannya."}, {"t": "stat", "n": "1 ton = 1 klaim", "l": "Prinsip inti integritas: satu reduksi hanya boleh diklaim satu pihak", "s": "ICVCM, Core Carbon Principles, 2023"}, {"t": "h2", "x": "Retirement satu-arah dan rekonsiliasi registri"}, {"t": "p", "x": "Di pasar sukarela, benteng terakhirnya adalah <b>retirement</b>: begitu sebuah kredit dipakai untuk sebuah klaim, ia harus dipensiunkan permanen di registri — satu-arah, tak bisa dijual ulang. Tanpa retirement yang mengikat dan rekonsiliasi antar-registri, kredit yang sama bisa berpindah tangan berkali-kali, masing-masing pemegang mengira dirinya pemilik sah. Registri yang tidak saling berbicara adalah celah paling umum untuk double use."}, {"t": "p", "x": "Bagi Glyiv, ini bukan detail teknis yang bisa ditunda. Setiap kredit harus bisa ditelusuri ke satu petak lahan, satu tanggal pemantauan, dan satu retirement yang final — tercatat di rantai, terekonsiliasi ke registri resmi. Mencegah double-counting bukan fitur tambahan; ia syarat mutlak sebelum sebuah kredit pantas disebut kontribusi iklim yang jujur."}], "story": [{"kind": "cover", "title": "Menghitung dua kali: dosa asal pasar karbon.", "text": "Tanpa retirement satu-arah dan rekonsiliasi registri, satu ton bisa diklaim dua pihak sekaligus — dan mencegah penghitungan ganda adalah syarat mutlak kredibilitas kredit karbon."}, {"kind": "hook", "title": "Satu ton, dua pemilik", "text": "Ton karbon yang sama bisa muncul di dua neraca: diklaim penjual proyek, sekaligus dihitung negara tuan rumah. Itulah double-counting."}, {"kind": "point", "title": "Apa penangkalnya?", "text": "Di Perjanjian Paris: corresponding adjustment. Negara pengekspor kredit wajib menambah ton itu kembali ke inventarisnya agar tak dihitung dua kali. ⚠︎ Aturan Pasal 6 baru rampung di COP29, 2024."}, {"kind": "point", "title": "Tiga bentuknya", "text": "Double issuance: dua kredit untuk satu reduksi. Double use: satu kredit dijual dua kali. Double claiming: pembeli dan negara sama-sama mengklaim."}, {"kind": "stat", "title": "Prinsip intinya", "big": "1 ton = 1 klaim", "label": "Satu reduksi hanya boleh diklaim satu pihak", "source": "ICVCM, Core Carbon Principles, 2023"}, {"kind": "point", "title": "Retirement satu-arah", "text": "Sekali dipakai, kredit dipensiunkan permanen di registri — tak bisa dijual ulang. Tanpa rekonsiliasi antar-registri, satu kredit bisa berpindah tangan berkali-kali."}, {"kind": "end", "title": "Integritas dulu, baru klaim", "text": "Setiap kredit Glyiv tertelusur ke satu petak, satu pemantauan, satu retirement final. Baca versi lengkapnya di Glyiv Kabar."}], "sources": [{"a": "UNFCCC (2024). Article 6.4 Mechanism — Paris Agreement Crediting Mechanism (rincian aturan disepakati COP29, Baku).", "u": "https://unfccc.int/process-and-meetings/the-paris-agreement/article-64-mechanism"}, {"a": "Schneider, L., Kollmuss, A., & Lazarus, M. (2015). Addressing the risk of double counting emission reductions under the UNFCCC. Climatic Change, 131, 473–486.", "u": "https://doi.org/10.1007/s10584-015-1398-y"}, {"a": "Integrity Council for the Voluntary Carbon Market (2023). The Core Carbon Principles.", "u": "https://icvcm.org/the-core-carbon-principles/"}, {"a": "La Hoz Theuer, S., Schneider, L., & Broekhoff, D. (2019). When less is more: limits to international transfers under Article 6 of the Paris Agreement. Climate Policy, 19(4), 401–413.", "u": "https://doi.org/10.1080/14693062.2019.1678358"}]}, {"slug": "harga-kredit-alam-vs-teknis", "topic": "Offset", "mood": "#C6A15B", "title": "Kenapa kredit 'berbasis alam' dihargai berbeda.", "dek": "Di pasar karbon sukarela, tidak semua ton diciptakan setara: harga kini memisahkan kredit yang sekadar mencegah emisi dari yang benar-benar menyerap dan menyimpannya secara tahan lama.", "hook": "Kenapa satu kredit karbon dihargai US$3 dan yang lain di atas US$300? Jawabannya soal permanensi.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, S&P Global, Ecosystem Marketplace, IEA)", "read": 4, "blocks": [{"t": "lead", "x": "Di atas kertas, satu ton karbon terdengar seperti satu ton karbon. Di pasar sukarela, tidak lagi. Sebuah kredit yang mencegah emisi masa depan dan sebuah kredit yang benar-benar menarik CO₂ dari udara kini dihargai jauh berbeda — dan selisihnya terus melebar seiring pembeli belajar membaca kualitas."}, {"t": "p", "x": "Ada dua garis pemisah yang menentukan harga. Yang pertama: <b>avoidance</b> — menghindari emisi yang mungkin terjadi, misalnya mencegah sepetak hutan ditebang — versus <b>removal</b>, yang menyerap dan menyimpan karbon yang sudah terlanjur ada di atmosfer. Yang kedua: berbasis alam (hutan, mangrove, tanah) versus rekayasa teknis (biochar, penangkapan langsung dari udara). Pembeli serius kini menimbang kedua sumbu itu sekaligus, bukan sekadar mencari angka termurah."}, {"t": "p", "x": "Pembeda intinya adalah <b>permanensi</b>. IPCC mendefinisikan penyerapan karbon sebagai kegiatan yang menarik CO₂ dari atmosfer dan <b>menyimpannya secara tahan lama</b> — sekaligus menegaskan penyerapan tak bisa menggantikan pemangkasan emisi yang dalam <a href=\"https://www.ipcc.ch/report/ar6/wg3/downloads/outreach/IPCC_AR6_WGIII_Factsheet_CDR.pdf\">(IPCC AR6 WGIII)</a>. Karbon yang bisa lepas lagi — hutan yang terbakar, tanah yang terusik — secara logis bernilai lebih rendah daripada karbon yang tersimpan puluhan hingga ribuan tahun."}, {"t": "pull", "x": "Pasar tak lagi membayar untuk janji 'satu ton'. Ia membayar untuk seberapa yakin ton itu benar-benar terserap — dan seberapa lama ia bertahan."}, {"t": "stat", "n": "≈381%", "l": "Kredit removal rata-rata lebih mahal dibanding kredit avoidance di pasar sukarela 2024 ⚠︎", "s": "Ecosystem Marketplace, 2024 (dilaporkan Carbon Credits)"}, {"t": "h2", "x": "Alam bukan berarti otomatis unggul"}, {"t": "p", "x": "Yang sering disalahpahami: label 'berbasis alam' tidak dengan sendirinya berarti kualitas tinggi. Banyak kredit alam sesungguhnya bertipe avoidance — misalnya proyek REDD+ yang mengklaim mencegah deforestasi. Ketika integritas klaim itu diragukan, harganya jatuh: kredit avoidance berbasis alam sempat anjlok sekitar 81% menjadi hanya ±US$3 per ton pada awal 2024 <a href=\"https://www.spglobal.com/en/research-insights/special-reports/look-forward/a-tale-of-two-carbon-markets\">(S&P Global)</a>. Sebaliknya, penanaman kembali yang benar-benar menyerap karbon — dan bisa dibuktikan — bertahan jauh lebih baik."}, {"t": "p", "x": "Di ujung lain spektrum, penyerapan rekayasa seperti penangkapan langsung dari udara (DAC) menawarkan permanensi tertinggi, tapi masih sangat mahal — kisaran ratusan hingga di atas seribu dolar per ton untuk proyek saat ini ⚠︎ <a href=\"https://www.iea.org/reports/direct-air-capture-2022/executive-summary\">(IEA)</a>. Harga tinggi itu bukan tanda kegagalan; ia mencerminkan biaya nyata menyimpan karbon secara permanen dengan teknologi hari ini."}, {"t": "p", "x": "Untuk pembeli di Indonesia, pelajarannya jernih: harga adalah cerminan kualitas dan permanensi, bukan sekadar diskon. Kredit yang jejaknya <b>terlacak</b> — asal-usul lahan, pemantauan berkala, retirement satu-arah — akan makin dihargai. Dan istilah yang jujur tetap penting: membeli kredit adalah bentuk <b>kontribusi</b> pada iklim, bukan lisensi untuk menyebut diri 'netral karbon'."}], "story": [{"kind": "cover", "title": "Kenapa kredit 'berbasis alam' dihargai berbeda", "text": "Di pasar karbon sukarela, tidak semua ton diciptakan setara: harga kini memisahkan yang mencegah emisi dari yang benar-benar menyerap karbon."}, {"kind": "hook", "title": "Satu ton ≠ satu ton", "text": "Mencegah emisi dan menyerap karbon kini dinilai jauh berbeda oleh pasar."}, {"kind": "point", "title": "Dua garis pemisah", "text": "Avoidance vs removal. Berbasis alam vs rekayasa teknis. Pembeli serius membaca keduanya sekaligus."}, {"kind": "point", "title": "Kuncinya: permanensi", "text": "Karbon yang bisa lepas lagi bernilai lebih rendah daripada yang tersimpan tahan lama. — IPCC AR6"}, {"kind": "stat", "title": "Selisih yang melebar", "big": "≈381%", "label": "Premi harga kredit removal atas kredit avoidance, 2024 ⚠︎", "source": "Ecosystem Marketplace, 2024"}, {"kind": "quote", "title": "Bukan janji, tapi keyakinan", "text": "Pasar tak lagi membayar untuk janji 'satu ton' — ia membayar untuk seberapa yakin dan seberapa lama karbon itu tersimpan."}, {"kind": "end", "title": "Harga mengikuti kualitas", "text": "Kredit yang terlacak makin dihargai. Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "IPCC (2022). AR6 WGIII — Carbon Dioxide Removal (CDR) Factsheet.", "u": "https://www.ipcc.ch/report/ar6/wg3/downloads/outreach/IPCC_AR6_WGIII_Factsheet_CDR.pdf"}, {"a": "S&P Global (2024). A tale of two carbon markets.", "u": "https://www.spglobal.com/en/research-insights/special-reports/look-forward/a-tale-of-two-carbon-markets"}, {"a": "Ecosystem Marketplace (2024). State of the Voluntary Carbon Markets — premi kredit removal ~381% (dilaporkan Carbon Credits).", "u": "https://carboncredits.com/a-recap-of-the-voluntary-carbon-market-quality-over-quantity/"}, {"a": "IEA (2022). Direct Air Capture — Executive Summary (estimasi biaya per ton CO₂).", "u": "https://www.iea.org/reports/direct-air-capture-2022/executive-summary"}]}, {"slug": "permanen-vs-sementara-karbon", "topic": "Offset", "mood": "#0F2E22", "title": "Karbon yang 'permanen': berapa lama itu cukup?", "dek": "Menyimpan karbon di pohon dan tanah bisa dibalik oleh kebakaran, kekeringan, atau gergaji — maka pertanyaan sebenarnya bukan sekadar \"berapa ton\", tapi \"untuk berapa lama\", dan siapa yang menanggung bila karbon itu lepas kembali.", "hook": "Sebatang pohon bisa menyerap karbon selama puluhan tahun — lalu terbakar dalam satu sore. Jadi seberapa 'permanen' offset yang Anda beli?", "cover": "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 5, "blocks": [{"t": "lead", "x": "Bayangkan Anda membayar untuk satu ton karbon yang 'diserap' sebuah hutan tahun ini. Sepuluh tahun kemudian, hutan itu terbakar. Ke mana perginya karbon yang sudah Anda bayar? Inilah inti persoalan permanensi — dan alasan mengapa tidak semua ton karbon benar-benar setara."}, {"t": "p", "x": "Karbon dioksida yang kita lepas hari ini tidak menghilang begitu saja. Menurut <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">IPCC</a>, sebagian besar CO2 bertahan di atmosfer selama ratusan hingga ribuan tahun. Artinya, agar sebuah serapan benar-benar mengimbangi satu emisi, karbon itu idealnya harus tetap tersimpan sama lamanya. Pohon, tanah, dan lahan gambut memang menyimpannya — tapi penyimpanan itu bisa dibalik oleh kebakaran, hama, kekeringan, atau sekadar keputusan menebang."}, {"t": "h2", "x": "Risiko yang disebut 'keterbalikan'"}, {"t": "p", "x": "Dalam bahasa standar karbon, ancaman ini disebut <b>risiko keterbalikan</b> (reversal). Proyek berbasis lahan — reforestasi, restorasi mangrove, konservasi hutan — paling rentan, karena karbonnya tersimpan di makhluk hidup yang bisa mati atau habitat yang bisa rusak. Masalahnya, standar pun belum sepakat soal 'berapa lama': sebagian mensyaratkan komitmen 100 tahun, sebagian lain cukup beberapa dekade — padahal CO2 di atmosfer bertahan jauh lebih lama. Tidak ada proyek yang jujur bisa menjanjikan penyimpanan 'selamanya'; yang bisa dilakukan adalah menyediakan jaring pengaman."}, {"t": "pull", "x": "Pertanyaannya bukan hanya berapa ton yang diserap, tapi untuk berapa lama — dan siapa yang menanggung bila karbon itu lepas kembali."}, {"t": "stat", "n": "100 tahun", "l": "Periode permanensi yang disyaratkan program offset hutan kepatuhan California untuk proyek kehutanan", "s": "CARB, Compliance Offset Protocol U.S. Forest Projects"}, {"t": "p", "x": "Jaring pengaman itu bernama <b>cadangan penyangga</b> (buffer pool). Standar seperti <a href=\"https://verra.org/programs/verified-carbon-standard/\">Verra</a> mewajibkan setiap proyek lahan menyisihkan sebagian kreditnya — persentasenya ditentukan lewat penilaian risiko — ke dalam sebuah rekening penyangga bersama. Bila suatu saat karbon di satu proyek lepas, misalnya karena terbakar, kredit dari kolam bersama itu dibatalkan untuk menutup kerugian, sehingga pembeli tetap terlindungi. Buffer bekerja seperti asuransi kolektif untuk permanensi."}, {"t": "h2", "x": "Apakah penyangganya cukup?"}, {"t": "p", "x": "Di sinilah keraguan muncul. Sebuah analisis <a href=\"https://carbonplan.org/research/forest-offsets-buffer-pool\">CarbonPlan</a> (Badgley dkk., 2022) memperkirakan gelombang kebakaran hutan 2020–2021 di Amerika Serikat saja telah menggerus sebagian besar cadangan penyangga yang seharusnya menanggung risiko kebakaran selama 100 tahun ⚠︎. Bila benar, penyangga bisa terkuras jauh lebih cepat dari rancangannya — apalagi saat iklim yang memanas membuat kebakaran makin sering dan makin luas."}, {"t": "p", "x": "Karena itu posisi Glyiv sederhana dan jujur: sebut serapan sebagai <b>kontribusi</b> pada iklim, bukan netralisasi yang sempurna; pantau kelangsungan setiap tegakan secara terus-menerus lewat dMRV, bukan sekali klaim lalu ditinggalkan; dan akui terang-terangan bahwa permanensi adalah spektrum, bukan janji. Ton yang paling bernilai bukan yang paling murah, melainkan yang paling bisa dipertanggungjawabkan sepuluh, dua puluh, seratus tahun dari sekarang."}], "story": [{"kind": "cover", "title": "Karbon yang 'permanen': berapa lama itu cukup?", "text": "Menyimpan karbon di pohon dan tanah bisa dibalik oleh kebakaran, kekeringan, atau gergaji — maka pertanyaan sebenarnya bukan 'berapa ton', tapi 'untuk berapa lama'."}, {"kind": "hook", "title": "Menyerap puluhan tahun, lepas dalam satu sore", "text": "Sebatang pohon bisa menyimpan karbon selama puluhan tahun — lalu terbakar. Jadi seberapa 'permanen' offset yang Anda beli?"}, {"kind": "point", "title": "Karbon bisa lepas lagi", "text": "Pohon, tanah, dan gambut menyimpan karbon — tapi kebakaran, hama, atau gergaji bisa melepasnya kembali. Ini disebut risiko keterbalikan."}, {"kind": "point", "title": "CO2 bertahan berabad-abad", "text": "IPCC: sebagian besar CO2 tinggal di atmosfer ratusan hingga ribuan tahun. Serapan yang cuma bertahan sebentar tak sepenuhnya mengimbanginya."}, {"kind": "point", "title": "Jaring pengaman: buffer", "text": "Standar seperti Verra mewajibkan proyek menyisihkan sebagian kredit ke 'cadangan penyangga' bersama — dipakai menutup bila karbon suatu saat lepas."}, {"kind": "stat", "title": "Standar 100 tahun", "big": "100 tahun", "label": "Komitmen permanensi yang disyaratkan program offset hutan kepatuhan California", "source": "CARB, Compliance Offset Protocol U.S. Forest Projects"}, {"kind": "end", "title": "Kontribusi, bukan klaim netral", "text": "Glyiv memantau kelangsungan tiap tegakan dan jujur soal risiko keterbalikan. Baca artikel lengkapnya di Glyiv Kabar."}], "sources": [{"a": "IPCC (2021). Climate Change 2021: The Physical Science Basis, Sixth Assessment Report, Working Group I — persistensi CO2 atmosferik.", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "Verra (2023). Verified Carbon Standard — AFOLU Non-Permanence Risk Tool & mekanisme buffer pool.", "u": "https://verra.org/programs/verified-carbon-standard/"}, {"a": "Badgley, G. dkk. (2022). California's forest carbon offsets buffer pool is severely undercapitalized. Frontiers in Forests and Global Change / CarbonPlan.", "u": "https://carbonplan.org/research/forest-offsets-buffer-pool"}, {"a": "California Air Resources Board (CARB). Compliance Offset Protocol U.S. Forest Projects — persyaratan permanensi 100 tahun.", "u": "https://ww2.arb.ca.gov/our-work/programs/compliance-offset-program"}]}, {"slug": "ndvi-kesehatan-hutan-dari-langit", "topic": "Teknologi", "mood": "#6B4E8C", "title": "NDVI: cara satelit 'membaca' kehijauan dari orbit.", "dek": "Dari ketinggian ratusan kilometer, satelit tak benar-benar melihat pohon — ia membaca pantulan cahaya. Dari pola itulah lahir NDVI, indeks sederhana yang memungkinkan tegakan pohon dipantau tanpa harus hadir di lapangan.", "hook": "Satelit tak menghitung pohon satu per satu. Ia membaca cahaya — lalu menaksir apakah hutan sedang tumbuh atau meranggas.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (NASA, ESA, USGS)", "read": 4, "blocks": [{"t": "lead", "x": "Dari orbit, satelit tidak benar-benar 'melihat' pohon seperti mata kita. Yang ia baca adalah cahaya — tepatnya, bagaimana daun memantulkan sebagian panjang gelombang dan menyerap sebagian lainnya. Dari pola pantulan itulah lahir NDVI, indeks sederhana yang kini menjadi tulang punggung pemantauan vegetasi global."}, {"t": "p", "x": "Rahasianya ada pada klorofil. Daun yang sehat menyerap hampir seluruh cahaya merah untuk fotosintesis, tetapi memantulkan kuat cahaya inframerah-dekat (<i>near-infrared</i>). NDVI — <b>Normalized Difference Vegetation Index</b> — cukup membandingkan keduanya: (NIR − Merah) / (NIR + Merah). Semakin lebar selisihnya, semakin rapat dan sehat vegetasinya. Indeks ini dirumuskan tim Rouse pada awal 1970-an memakai data satelit ERTS — cikal bakal program Landsat <a href=\"https://earthobservatory.nasa.gov/features/MeasuringVegetation\">(NASA)</a>."}, {"t": "p", "x": "Hasilnya berupa angka antara −1 hingga +1. Air dan awan cenderung negatif; tanah gundul berkisar 0,1–0,2; sedangkan <b>vegetasi rapat dan sehat</b> umumnya berada di rentang 0,6–0,9 menurut NASA Earth Observatory. Satu petak lahan bisa dibaca berulang kali dari waktu ke waktu, sehingga perubahan kehijauan — musim tanam, kekeringan, hingga penebangan — muncul sebagai pergeseran angka yang bisa dilacak."}, {"t": "pull", "x": "Cahaya memberi petunjuk; bukti yang bisa diaudit dibangun dari petunjuk itu, bukan menggantikannya."}, {"t": "stat", "n": "0,6–0,9", "l": "rentang NDVI khas vegetasi rapat & sehat", "s": "NASA Earth Observatory, Measuring Vegetation"}, {"t": "h2", "x": "Memantau hutan tanpa menginjaknya"}, {"t": "p", "x": "Inilah yang membuat NDVI berguna untuk memantau tegakan pohon. Alih-alih menyurvei lahan luas dengan berjalan kaki, pengelola bisa menandai penurunan kehijauan di petak tertentu dari orbit — indikasi awal kebakaran, alih fungsi lahan, atau tegakan yang gagal tumbuh. Satelit <b>Sentinel-2</b> milik Copernicus, misalnya, memetakan permukaan bumi pada resolusi 10 meter dengan kunjungan ulang sekitar 5 hari memakai dua satelit <a href=\"https://sentinels.copernicus.eu/web/sentinel/missions/sentinel-2\">(ESA)</a>, sementara arsip <b>Landsat</b> menyimpan rekaman sejak 1972 — lebih dari lima dekade jejak perubahan lahan <a href=\"https://www.usgs.gov/landsat-missions\">(USGS)</a>."}, {"t": "p", "x": "Yang penting dijaga adalah kejujuran soal apa yang sebenarnya dibaca. NDVI menaksir <b>kehijauan</b>, bukan langsung mengukur karbon atau biomassa. Pada kanopi tropis yang sangat rapat, nilainya cenderung 'jenuh' (saturasi) sehingga sulit membedakan hutan lebat dari yang sedikit lebih lebat ⚠︎. Karena itu di Glyiv, NDVI dipakai sebagai satu lapisan dalam dMRV — untuk memantau kelangsungan tegakan dari waktu ke waktu, bukan untuk mengklaim angka serapan karbon secara instan. Kehijauan yang terlacak dari langit tetap perlu dipadankan dengan pengukuran lapangan sebelum menjadi bukti yang bisa diaudit."}], "story": [{"kind": "cover", "title": "NDVI: satelit membaca kehijauan dari orbit", "text": "Satelit tak melihat pohon — ia membaca pantulan cahaya. Dari pola itulah tegakan pohon bisa dipantau tanpa hadir di lapangan."}, {"kind": "hook", "title": "Bukan melihat, tapi membaca cahaya", "text": "Satelit tak menghitung pohon satu per satu. Ia membaca cahaya — lalu menaksir apakah hutan tumbuh atau meranggas."}, {"kind": "point", "title": "Klorofil membocorkan rahasianya", "text": "Daun sehat menyerap cahaya merah, memantulkan kuat inframerah-dekat. NDVI membandingkan keduanya."}, {"kind": "point", "title": "Satu angka: −1 sampai +1", "text": "Air negatif · tanah gundul ~0,1–0,2 · vegetasi rapat & sehat 0,6–0,9."}, {"kind": "point", "title": "Pantau hutan tanpa menginjaknya", "text": "Penurunan kehijauan dari orbit = sinyal awal kebakaran, alih fungsi lahan, atau tegakan gagal tumbuh."}, {"kind": "stat", "title": "Angka kunci", "big": "0,6–0,9", "label": "NDVI khas vegetasi rapat & sehat", "source": "NASA Earth Observatory"}, {"kind": "end", "title": "Kehijauan yang terlacak, bukan diklaim", "text": "NDVI menaksir kehijauan, bukan langsung karbon (⚠︎ bisa jenuh di kanopi rapat). Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Rouse, J.W., Haas, R.H., Schell, J.A., & Deering, D.W. (1974). Monitoring vegetation systems in the Great Plains with ERTS. NASA/Goddard, Third ERTS Symposium (NASA SP-351)."}, {"a": "NASA Earth Observatory. Measuring Vegetation (NDVI & EVI).", "u": "https://earthobservatory.nasa.gov/features/MeasuringVegetation"}, {"a": "ESA Copernicus. Sentinel-2 mission — resolusi 10 m, kunjungan ulang ~5 hari (dua satelit).", "u": "https://sentinels.copernicus.eu/web/sentinel/missions/sentinel-2"}, {"a": "USGS. Landsat Missions — arsip citra Bumi berkelanjutan sejak 1972.", "u": "https://www.usgs.gov/landsat-missions"}]}, {"slug": "erc-3643-token-berizin", "topic": "Teknologi", "mood": "#6B4E8C", "title": "ERC-3643: token karbon yang tahu siapa pemiliknya.", "dek": "Standar token berizin ERC-3643 menanam identitas dan aturan KYC/AML langsung di dalam kontrak — sehingga aset karbon dunia-nyata bisa berpindah tangan sesuai regulasi, bukan menghindarinya.", "hook": "Kebanyakan token kripto sengaja buta soal siapa pemiliknya. Untuk aset karbon, itu bukan fitur — itu masalah.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan EIP-3643 & sumber publik", "read": 5, "blocks": [{"t": "lead", "x": "Sebagian besar token kripto sengaja dibuat buta. Siapa pun bisa memegangnya, siapa pun bisa mengirimnya, dan kontraknya tak pernah tahu — apalagi peduli — siapa di balik dompet. Untuk aset spekulatif, itu fitur. Untuk aset karbon yang harus tunduk pada regulasi, itu cacat. ERC-3643 lahir untuk menutup celah itu."}, {"t": "p", "x": "ERC-3643 — dikenal juga sebagai standar <b>T-REX</b> (<i>Token for Regulated EXchanges</i>) — adalah standar token 'berizin' (<i>permissioned</i>) di jaringan Ethereum. Bedanya dengan token biasa: sebelum sebuah transfer dieksekusi, kontrak lebih dulu memeriksa apakah pengirim dan penerima adalah identitas yang sudah terverifikasi dan memenuhi syarat. Bila tidak, transaksi ditolak di level kode — bukan sekadar di halaman syarat dan ketentuan. Sejak Desember 2023 standar ini berstatus <a href=\"https://eips.ethereum.org/EIPS/eip-3643\">'Final' di daftar resmi Ethereum Improvement Proposals</a>, yang pertama untuk tokenisasi patuh-regulasi."}, {"t": "h2", "x": "Identitas yang menempel pada token"}, {"t": "p", "x": "Kuncinya ada pada dua lapisan. Pertama, <a href=\"https://tokeny.com/erc3643/\">ONCHAINID</a>: sebuah identitas di rantai tempat penerbit tepercaya menautkan klaim terverifikasi — lolos KYC, yurisdiksi, status kelayakan — tanpa membeberkan data pribadi ke publik. Kedua, <i>identity registry</i> dan modul kepatuhan yang tertanam di kontrak token: aturan main (siapa boleh memegang, batas jumlah, negara yang dikecualikan) dijalankan otomatis pada setiap transfer. Hasilnya, token karbon tak lagi bisa berpindah ke dompet anonim yang tak jelas asalnya."}, {"t": "pull", "x": "Token biasa tak peduli siapa pemiliknya. Untuk aset karbon yang diatur regulasi, justru itulah pertanyaan pertama yang harus dijawab."}, {"t": "stat", "n": "2023", "l": "tahun EIP-3643 mencapai status 'Final' — standar Ethereum yang matang, bukan draf percobaan", "s": "Ethereum Improvement Proposals, Des 2023"}, {"t": "p", "x": "Kenapa ini penting untuk karbon? Pasar kredit karbon lama dihantui masalah kepercayaan: klaim ganda (<i>double counting</i>), kredit yang berpindah tangan tanpa jejak, dan pembeli yang tak bisa memastikan siapa lawan transaksinya. Aset karbon dunia-nyata (RWA) yang hendak diperdagangkan lintas negara harus tunduk pada aturan KYC/AML dan hukum sekuritas yang berbeda di tiap yurisdiksi. Menanam kepatuhan itu di level kontrak membuat aset bisa berpindah <b>sesuai</b> regulasi — dan setiap perpindahan tetap tertelusur."}, {"t": "h2", "x": "Di mana Glyiv berdiri"}, {"t": "p", "x": "Glyiv memakai pendekatan ini untuk menokenisasi aset karbon nyata — misalnya serapan dari tegakan pohon yang dipantau — sebagai token berizin ERC-3643, dengan <i>retirement</i> satu-arah yang mencegah kredit dihitung dua kali dan terekonsiliasi ke registri resmi. Perlu jujur soal batasnya: standar ini menata <i>siapa</i> dan <i>bagaimana</i> aset berpindah, bukan menjamin mutu karbon di baliknya. Kualitas itu tetap bergantung pada pemantauan dan verifikasi yang kredibel <a href=\"https://icvcm.org/core-carbon-principles/\">sesuai prinsip integritas seperti ICVCM</a>. Yang ERC-3643 berikan adalah fondasinya: aset karbon yang, sejak baris pertama kodenya, tahu siapa pemiliknya."}], "story": [{"kind": "cover", "title": "Token karbon yang tahu siapa pemiliknya", "text": "Standar token berizin ERC-3643 menanam identitas dan aturan KYC/AML langsung di dalam kontrak — agar aset karbon berpindah sesuai regulasi, bukan menghindarinya."}, {"kind": "hook", "title": "Kripto biasa sengaja buta", "text": "Siapa pun bisa pegang, siapa pun bisa kirim. Untuk aset karbon yang diatur regulasi, itu bukan fitur — itu masalah."}, {"kind": "point", "title": "Apa itu ERC-3643", "text": "Standar token 'berizin' di Ethereum (T-REX). Setiap transfer diperiksa dulu: hanya identitas terverifikasi yang boleh memegang."}, {"kind": "point", "title": "Identitas di dalam kontrak", "text": "ONCHAINID menautkan klaim KYC & kelayakan tanpa membuka data pribadi. Aturan kepatuhan berjalan otomatis, bukan janji di ToS."}, {"kind": "point", "title": "Kenapa penting buat karbon", "text": "Melawan klaim ganda dan perpindahan tanpa jejak — aset karbon lintas negara jadi bisa diperdagangkan patuh regulasi."}, {"kind": "stat", "title": "Standar yang sudah matang", "big": "2023", "label": "EIP-3643 berstatus 'Final' — standar Ethereum matang, bukan draf", "source": "Ethereum Improvement Proposals, Des 2023"}, {"kind": "end", "title": "Fondasi, bukan jaminan mutu", "text": "Standar menata siapa & bagaimana; kualitas karbon tetap butuh verifikasi. Baca artikel lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Ethereum Improvement Proposals (2023). EIP-3643: T-REX – Token for Regulated EXchanges (status: Final).", "u": "https://eips.ethereum.org/EIPS/eip-3643"}, {"a": "ERC-3643 Association. The Permissioned Token Standard for RWA Tokenization.", "u": "https://www.erc3643.org/"}, {"a": "Tokeny. ERC-3643 & ONCHAINID: on-chain identity for compliant tokens.", "u": "https://tokeny.com/erc3643/"}, {"a": "Integrity Council for the Voluntary Carbon Market (ICVCM, 2023). Core Carbon Principles.", "u": "https://icvcm.org/core-carbon-principles/"}]}, {"slug": "oracle-depin-data-lapangan", "topic": "Teknologi", "mood": "#1F7A6B", "title": "Oracle & DePIN: menyambungkan sensor lapangan ke rantai.", "dek": "Kelembapan gambut dan tinggi pohon lahir di lapangan, jauh dari server mana pun; oracle dan jaringan perangkat terdesentralisasi (DePIN) berupaya membawanya ke rantai digital tanpa kehilangan jejak siapa yang mengukur, kapan, dan bagaimana.", "hook": "Sebuah smart contract tak bisa melihat rawa gambut — jadi bagaimana angka dari sensor di tengah hutan bisa dipercaya begitu sampai ke rantai?", "cover": "https://images.unsplash.com/photo-1558494949-ef010cbdcc31?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 5, "blocks": [{"t": "lead", "x": "Sebuah kontrak pintar (smart contract) di blockchain punya satu kelemahan mendasar: ia buta terhadap dunia luar. Ia bisa menghitung, menyimpan, dan mengeksekusi aturan dengan sempurna — tapi ia tak tahu apakah hujan turun di Riau, apakah pohon di petak tertentu masih hidup, atau seberapa basah lahan gambut pagi ini. Semua data itu lahir di lapangan, dan seseorang harus membawanya masuk."}, {"t": "p", "x": "Jembatan itu bernama <b>oracle</b>. Dalam dunia blockchain, oracle adalah lapisan yang memasok data dunia nyata ke dalam kontrak pintar — harga, cuaca, pembacaan sensor. Persoalannya klasik dan punya nama sendiri: <a href=\"https://chain.link/education-hub/oracle-problem\">the oracle problem</a>. Sebuah rantai bisa dibuat sangat tepercaya, tapi data yang masuk hanya sebaik sumbernya. Jaringan oracle mencoba menjawabnya dengan menghimpun banyak sumber independen, bukan satu, agar tak ada titik tunggal yang bisa berbohong."}, {"t": "h2", "x": "DePIN: banyak mata, bukan satu"}, {"t": "p", "x": "Di sinilah DePIN masuk. <b>Decentralized Physical Infrastructure Networks</b> adalah jaringan perangkat fisik — sensor, stasiun cuaca, antena — yang dimiliki dan dioperasikan banyak pihak, bukan satu perusahaan. Proyek seperti <a href=\"https://weatherxm.com/\">WeatherXM</a> menautkan ribuan stasiun cuaca warga; masing-masing menyumbang pembacaan dan menerima <b>imbalan</b> token. Prinsipnya sama untuk karbon: alih-alih satu lembaga mengukur kelembapan gambut sekali setahun, banyak sensor lapangan melaporkan terus-menerus, dan kesepakatan antar-sumber menjadi dasar kepercayaan."}, {"t": "pull", "x": "Oracle tidak membuat data menjadi benar. Ia hanya memindahkannya dengan setia — kepercayaan harus dibangun di titik sensor, bukan di rantai."}, {"t": "p", "x": "Poin itu mudah terlewat. Rantai yang tak bisa diubah tetap tak berarti apa-apa jika angka yang masuk keliru — sensor yang tak dikalibrasi, dipasang di tempat salah, atau sengaja dicurangi. Karena itu data lapangan lebih tepat disebut <b>terlacak</b>, bukan sekadar terukur: nilainya datang bersama jejak perangkat mana yang membaca, kapan, dan tanda tangan kriptografis yang membuktikan angka itu tak diutak-atik di tengah jalan. Redundansi, kalibrasi berkala, dan penandatanganan di perangkat adalah syaratnya."}, {"t": "stat", "n": "~40 cm", "l": "Ambang muka air tanah gambut — di bawah level ini lahan dianggap rusak dan emisi melonjak ⚠︎", "s": "KLHK · PP No. 57/2016 (rujukan regulasi)"}, {"t": "p", "x": "Untuk lahan gambut Indonesia, ini bukan soal teknis semata. Menurut <a href=\"https://www.ipcc-nggip.iges.or.jp/public/wetlands/\">IPCC (2013 Wetlands Supplement)</a>, gambut tropis yang dikeringkan melepaskan karbon dalam jumlah besar; menjaganya tetap basah adalah salah satu pengungkit iklim terkuat yang dimiliki negeri ini. Sensor muka air yang jujur dan terlacak memungkinkan klaim <b>kontribusi</b> — bukan 'netral karbon' — dibangun di atas bukti kelembapan harian, bukan asumsi tahunan."}, {"t": "p", "x": "Data tinggi pohon bekerja serupa: dipantau lewat sensor dan citra, ia memberi tahu apakah tegakan benar tumbuh atau hanya ada di atas kertas. Ketika DePIN menyediakan mata yang banyak dan oracle memindahkannya dengan jejak yang utuh, sebuah rawa yang jauh dari server mana pun akhirnya bisa berbicara ke sistem digital — dan didengar tanpa harus dipercaya buta."}], "story": [{"kind": "cover", "title": "Oracle & DePIN", "text": "Kelembapan gambut dan tinggi pohon lahir di lapangan, jauh dari server mana pun; oracle dan DePIN berupaya membawanya ke rantai tanpa kehilangan jejak siapa yang mengukur, kapan, dan bagaimana."}, {"kind": "hook", "title": "Rawa yang jauh dari server", "text": "Sebuah smart contract tak bisa melihat gambut. Jadi bagaimana angka dari sensor di tengah hutan bisa dipercaya saat sampai ke rantai?"}, {"kind": "point", "title": "Rantai itu buta", "text": "Blockchain menghitung sempurna, tapi tak tahu apakah hujan turun di Riau atau pohon di petak itu masih hidup. Oracle-lah yang membawanya masuk."}, {"kind": "point", "title": "DePIN: banyak mata", "text": "Bukan satu lembaga yang mengukur setahun sekali — banyak sensor milik banyak orang melaporkan terus-menerus, saling mengoreksi."}, {"kind": "stat", "title": "Kenapa muka air penting", "big": "~40 cm", "label": "Ambang muka air gambut; di bawah ini lahan dianggap rusak & emisi melonjak ⚠︎", "source": "KLHK · PP 57/2016"}, {"kind": "quote", "title": "Inti soalnya", "text": "Oracle tidak membuat data jadi benar. Ia memindahkannya dengan setia — kepercayaan dibangun di titik sensor."}, {"kind": "end", "title": "Baca selengkapnya", "text": "Bagaimana data lapangan jadi bukti yang terlacak — bukan asumsi. Selengkapnya di Glyiv Kabar."}], "sources": [{"a": "IPCC (2014). 2013 Supplement to the 2006 IPCC Guidelines for National Greenhouse Gas Inventories: Wetlands.", "u": "https://www.ipcc-nggip.iges.or.jp/public/wetlands/"}, {"a": "Chainlink. What Is the Blockchain Oracle Problem? (education hub).", "u": "https://chain.link/education-hub/oracle-problem"}, {"a": "WeatherXM. Jaringan stasiun cuaca terdesentralisasi (DePIN).", "u": "https://weatherxm.com/"}, {"a": "Pemerintah RI (2016). PP No. 57 Tahun 2016 tentang Perlindungan dan Pengelolaan Ekosistem Gambut."}]}, {"slug": "satelit-metana-kebocoran", "topic": "Teknologi", "mood": "#1E5F8C", "title": "Metana dari luar angkasa: kebocoran yang kini terlihat.", "dek": "Satelit seperti Sentinel-5P/TROPOMI kini memetakan sembulan metana dari fasilitas migas dan tempat pembuangan sampah — membuat kebocoran gas rumah kaca yang dulu tak terlihat menjadi terlacak, dan bisa dimintai tanggung jawab.", "hook": "Dari ratusan kilometer di atas Bumi, satelit kini bisa menunjuk persis di mana metana bocor — gas yang memerangkap panas puluhan kali lebih kuat dari CO2.", "cover": "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, IPCC, UNEP, ESA)", "read": 4, "blocks": [{"t": "lead", "x": "Metana tak berwarna dan nyaris tak berbau. Di permukaan tanah, kebocorannya gampang luput dari perhatian. Tetapi dari ketinggian ratusan kilometer, gas ini kini tampak jelas — sembulan terang di atas kilang minyak, sumur gas, dan tumpukan sampah, terekam oleh satelit yang mengelilingi Bumi setiap hari."}, {"t": "p", "x": "Instrumen bernama TROPOMI, yang dibawa satelit <b>Sentinel-5P</b> milik program Copernicus (ESA) sejak 2017, memindai seluruh planet setiap hari dan memetakan konsentrasi metana di atmosfer <a href=\"https://www.esa.int/Applications/Observing_the_Earth/Copernicus/Sentinel-5P\">(ESA)</a>. Ia tak menghitung molekul satu per satu, melainkan menangkap gumpalan emisi besar — cukup untuk menunjukkan di mana kebocoran terjadi, bukan sekadar bahwa ia terjadi."}, {"t": "p", "x": "Kenapa ini penting? Karena metana memerangkap panas jauh lebih kuat daripada CO2. Menurut laporan IPCC (AR6), dalam rentang 20 tahun metana kira-kira <b>80 kali</b> lebih ampuh menahan panas dibanding CO2, dan sekitar 28–30 kali lipat dalam 100 tahun <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">(IPCC AR6)</a>. Satu kebocoran yang luput hari ini setara dengan beban iklim yang besar dalam waktu dekat."}, {"t": "pull", "x": "Gas yang dulu tak terlihat kini punya alamat — dan itu mengubah siapa yang bisa dimintai tanggung jawab."}, {"t": "stat", "n": "~30%", "l": "kontribusi metana pada kenaikan suhu global sejak era industri", "s": "IEA, Global Methane Tracker 2024"}, {"t": "p", "x": "Sumbernya bukan misteri. Produksi dan penggunaan bahan bakar fosil saja melepas sekitar <b>120 juta ton</b> metana pada 2023 — lebih dari sepertiga total emisi metana akibat aktivitas manusia <a href=\"https://www.iea.org/reports/global-methane-tracker-2024\">(IEA, 2024)</a>. Sebagian besar berasal dari kebocoran yang, secara hitung-hitungan ekonomi, justru lebih murah ditutup daripada dibiarkan menguap."}, {"t": "h2", "x": "Dari deteksi ke tindakan"}, {"t": "p", "x": "Data satelit kini mulai memicu respons nyata. Lewat sistem <b>MARS</b> (Methane Alert and Response System) di bawah UNEP, sembulan besar yang tertangkap TROPOMI dianalisis bersama mitra seperti SRON dan Kayrros, lalu pemerintah serta perusahaan terkait diberi tahu agar bisa menambalnya <a href=\"https://www.unep.org/explore-topics/energy/what-we-do/methane/imeo-action/methane-alert-and-response-system-mars/about\">(UNEP)</a>. Satelit beresolusi lebih tinggi kemudian dipakai untuk melacak kebocoran hingga ke fasilitas tertentu."}, {"t": "p", "x": "Teknologi ini masih jauh dari sempurna. TROPOMI hanya menangkap sembulan terbesar; kebocoran kecil butuh sensor yang lebih tajam. Misi khusus pun rapuh: <b>MethaneSAT</b>, satelit pemburu metana yang diluncurkan 2024, kehilangan kontak dan dinyatakan tak terpulihkan pada pertengahan 2025 ⚠︎ <a href=\"https://www.edf.org/media/methanesat-loses-contact-satellite\">(EDF)</a>. Angka dari luar angkasa sebaiknya dibaca sebagai data yang <em>terlacak</em>, bukan terukur presisi di lapangan."}, {"t": "p", "x": "Bagi Indonesia — dengan ladang migas yang menua dan ratusan TPA yang melepas metana — mata dari orbit ini berarti transparansi yang tak lagi mudah disembunyikan. Lebih dari 150 negara telah berjanji memangkas metana 30% pada 2030 lewat Global Methane Pledge; Indonesia sejauh ini termasuk yang belum bergabung ⚠︎. Di sinilah kerja intelijen karbon dimulai: mengubah sembulan di peta menjadi tindakan yang bisa dipertanggungjawabkan — terlacak dari sumber hingga penutupannya."}], "story": [{"kind": "cover", "title": "Kebocoran yang kini terlihat", "text": "Satelit seperti Sentinel-5P/TROPOMI kini memetakan sembulan metana dari fasilitas migas dan TPA — membuat kebocoran yang dulu tak terlihat menjadi terlacak, dan bisa dimintai tanggung jawab."}, {"kind": "hook", "title": "Tak berbau, tapi terlihat", "text": "Dari ratusan kilometer di atas Bumi, satelit kini bisa menunjuk persis di mana metana bocor."}, {"kind": "point", "title": "Mata di orbit", "text": "TROPOMI di Sentinel-5P (ESA) memindai Bumi tiap hari, memetakan sembulan metana dari kilang, sumur gas, dan tumpukan sampah."}, {"kind": "point", "title": "Kecil molekulnya, besar dampaknya", "text": "IPCC (AR6): metana kira-kira 80x lebih kuat memerangkap panas dibanding CO2 dalam 20 tahun."}, {"kind": "stat", "title": "Sepertiga pemanasan kita", "big": "~30%", "label": "kontribusi metana pada kenaikan suhu global sejak era industri", "source": "IEA, Global Methane Tracker 2024"}, {"kind": "point", "title": "Dari deteksi ke tindakan", "text": "Sistem MARS (UNEP) memberi tahu pemerintah & perusahaan begitu sembulan besar tertangkap — agar bocoran bisa ditambal."}, {"kind": "end", "title": "Terlacak, bukan sekadar diklaim", "text": "Glyiv mengubah sembulan di peta jadi tindakan yang bisa dipertanggungjawabkan. Baca artikel lengkapnya di Glyiv Kabar."}], "sources": [{"a": "IEA (2024). Global Methane Tracker 2024 — Key findings & Understanding methane emissions.", "u": "https://www.iea.org/reports/global-methane-tracker-2024"}, {"a": "IPCC (2021). AR6 WGI, Chapter 7 — Global Warming Potential metana (GWP-20 ≈ 80–83; GWP-100 ≈ 27–30).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "UNEP / IMEO. Methane Alert and Response System (MARS) — deteksi & notifikasi sembulan metana via Sentinel-5P/TROPOMI.", "u": "https://www.unep.org/explore-topics/energy/what-we-do/methane/imeo-action/methane-alert-and-response-system-mars/about"}, {"a": "Environmental Defense Fund (2025). MethaneSAT Loses Contact with Satellite.", "u": "https://www.edf.org/media/methanesat-loses-contact-satellite"}]}, {"slug": "lidar-biomassa-hutan", "topic": "Teknologi", "mood": "#6B4E8C", "title": "LiDAR: menimbang karbon sebuah hutan tanpa menebangnya.", "dek": "Pemindaian laser membaca bentuk tiga dimensi tajuk hutan untuk menaksir biomassa dan simpanan karbonnya — menggeser taksiran kasar ke arah angka yang lebih tertelusur, tanpa satu pohon pun ditebang.", "hook": "Dulu, mengukur karbon hutan berarti menebang pohonnya lebih dulu. Laser mengubah itu.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (NASA GEDI, IPCC)", "read": 4, "blocks": [{"t": "lead", "x": "Untuk mengetahui berapa banyak karbon yang tersimpan di sebuah hutan, cara paling akurat dulu nyaris paradoks: tebang beberapa pohon, keringkan, lalu timbang. Dari sampel itulah para peneliti menyusun persamaan alometrik — rumus yang menghubungkan diameter batang dengan berat biomassa. Masalahnya, satu petak contoh tak pernah benar-benar mewakili seluruh hutan."}, {"t": "p", "x": "LiDAR membalik cara kerja itu. Alat ini — kependekan dari <b>Light Detection and Ranging</b> — menembakkan ratusan ribu hingga jutaan pulsa laser ke tajuk hutan, lalu mengukur waktu tiap pantulan kembali. Hasilnya bukan foto, melainkan rekonstruksi tiga dimensi: tinggi pohon, kerapatan dedaunan, sampai lapisan-lapisan di bawah kanopi."}, {"t": "p", "x": "Citra satelit biasa memang sudah lama dipakai memantau hutan, tapi kamera optik hanya melihat warna dan tutupan dari atas — ia sulit membedakan hutan tua yang padat karbon dari hutan muda yang tampak sama hijaunya. LiDAR menambahkan dimensi yang hilang itu: ketinggian dan volume."}, {"t": "p", "x": "Struktur itulah kuncinya. Hutan yang lebih tinggi dan berlapis padat umumnya menyimpan biomassa lebih banyak, dan biomassa berbanding lurus dengan karbon. Dengan mengalikan volume biomassa kering pada <b>fraksi karbon</b>, taksiran simpanan karbon bisa dihitung — kini di atas jutaan titik, bukan segelintir petak."}, {"t": "stat", "n": "0,47", "l": "fraksi karbon default per ton biomassa kering, dasar menghitung simpanan karbon", "s": "IPCC 2006 Guidelines (Refinement 2019)"}, {"t": "h2", "x": "Dari petak contoh ke peta menyeluruh"}, {"t": "p", "x": "Sejak 2018, instrumen <b>GEDI</b> milik NASA memindai hutan dunia dari Stasiun Luar Angkasa Internasional dengan laser penuh-gelombang, dirancang khusus untuk memetakan tinggi tajuk dan menaksir biomassa di atas permukaan <a href=\"https://gedi.umd.edu/\">secara global</a>. Yang dulu butuh tim survei berbulan-bulan di lapangan kini bisa disapu dari orbit — meski hasil orbit tetap perlu ditera ulang dengan data lapangan."}, {"t": "pull", "x": "Menimbang sebuah hutan tanpa menebang satu pohon pun — bukan dengan menghitung batangnya, melainkan dengan membaca bentuknya."}, {"t": "p", "x": "Tetap perlu kejujuran soal batasnya. LiDAR mengukur <b>struktur</b>, bukan karbon secara langsung; angkanya masih bergantung pada model alometrik, kalibrasi lokal, dan asumsi kepadatan kayu. Karena itu kami menyebutnya <b>tertelusur</b>, bukan mutlak akurat. Untuk hutan tropis Indonesia — apalagi lahan gambut yang menyimpan sebagian besar karbonnya di bawah tanah — margin ketidakpastiannya masih lebar ⚠︎."}, {"t": "p", "x": "Namun arah pergeserannya jelas dan penting: dari taksiran kasar berbasis rata-rata regional, menuju ukuran yang bisa ditelusuri hingga ke petak lahannya. Bagi pasar karbon yang lama diragukan karena klaim tak terbukti, bentuk tiga dimensi sebuah tajuk adalah salah satu bukti yang paling sulit dipalsukan — dan itulah fondasi agar setiap ton yang diklaim benar-benar ada."}], "story": [{"kind": "cover", "title": "LiDAR: menimbang karbon hutan tanpa menebangnya", "text": "Pemindaian laser membaca bentuk tiga dimensi tajuk hutan untuk menaksir biomassa dan simpanan karbonnya — menggeser taksiran kasar ke arah angka yang lebih tertelusur, tanpa satu pohon pun ditebang."}, {"kind": "hook", "title": "Tanpa satu tebangan", "text": "Cara lama mengukur karbon hutan: tebang pohon, keringkan, timbang. Laser membuat itu tak lagi perlu."}, {"kind": "point", "title": "Laser, bukan kamera", "text": "LiDAR menembakkan jutaan pulsa laser ke tajuk dan merekonstruksi bentuk 3D hutan: tinggi, kerapatan, lapisan kanopi."}, {"kind": "point", "title": "Bentuk mengungkap karbon", "text": "Hutan yang lebih tinggi dan padat menyimpan lebih banyak biomassa. Biomassa × fraksi karbon = taksiran simpanan karbon."}, {"kind": "stat", "title": "Angka kuncinya", "big": "0,47", "label": "fraksi karbon per ton biomassa kering", "source": "IPCC 2006 GL (Refinement 2019)"}, {"kind": "point", "title": "Kini dari orbit", "text": "Sejak 2018, GEDI milik NASA memetakan tinggi tajuk hutan dunia dari Stasiun Luar Angkasa — pekerjaan berbulan-bulan disapu dari orbit."}, {"kind": "end", "title": "Karbon yang bisa dibuktikan", "text": "Glyiv membangun intelijen karbon Indonesia yang tertelusur hingga petak lahannya. Baca selengkapnya, atau ikut membangun ekonomi hijau yang jujur."}], "sources": [{"a": "Dubayah, R. dkk. (2020). The Global Ecosystem Dynamics Investigation: High-resolution laser ranging of the Earth's forests and topography. Science of Remote Sensing.", "u": "https://gedi.umd.edu/"}, {"a": "IPCC (2006, Refinement 2019). 2006 IPCC Guidelines for National Greenhouse Gas Inventories, Vol. 4 AFOLU — fraksi karbon default 0,47 t C per t bahan kering.", "u": "https://www.ipcc-nggip.iges.or.jp/public/2006gl/vol4.html"}, {"a": "Zolkos, S.G., Goetz, S.J. & Dubayah, R. (2013). A meta-analysis of terrestrial aboveground biomass estimation using lidar remote sensing. Remote Sensing of Environment, 128:289–298."}]}, {"slug": "agen-ai-menutup-pemborosan", "topic": "Teknologi", "mood": "#1F7A6B", "title": "Agen AI: dari dashboard pasif ke tindakan yang menghemat.", "dek": "Alih-alih menampilkan angka lalu dilupakan, agen AI membaca data karbon berdampingan dengan biaya, menandai anomali, dan menyarankan langkah pemangkasan yang bisa dieksekusi minggu ini.", "hook": "Dashboard cantik tak menghemat sepeser pun. Agen yang bertindak — itu yang menutup pemborosan.", "cover": "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, McKinsey, US EPA)", "read": 4, "blocks": [{"t": "lead", "x": "Sebuah dashboard karbon yang cantik bisa memikat rapat direksi selama lima menit — lalu dilupakan. Ia menampilkan angka, tetapi angka yang hanya dipandang tidak memangkas satu rupiah pun biaya, atau satu ton pun emisi. Yang mengubah keadaan adalah ketika sistem berhenti sekadar melapor, dan mulai menunjuk: di sini uang bocor, dan begini cara menutupnya."}, {"t": "p", "x": "Itulah pergeseran yang dibawa agen AI. Alih-alih menunggu Anda membaca grafik, agen menyerap data aktivitas — konsumsi energi, invoice, jejak rantai pasok — lalu membaca <b>karbon berdampingan dengan biaya</b>. Ketika keduanya dipetakan bersama, pemborosan yang selama ini tenggelam dalam tagihan gabungan tiba-tiba punya wajah: sebuah pola, sebuah anomali, sebuah baris yang seharusnya tidak setinggi itu."}, {"t": "h2", "x": "Dari melihat ke bertindak"}, {"t": "p", "x": "Ambil contoh yang membosankan justru karena begitu umum: sebuah unit pendingin yang menyala penuh di jam gudang kosong. Dalam laporan bulanan, biayanya melebur ke satu angka listrik besar dan tak pernah ketahuan. Namun ketika karbon dan energi dipecah per fasilitas, per shift, agen menandainya sebagai anomali — dan menyarankan langkah konkret: ubah jadwal, setel ulang titik suhu, matikan saat idle. Bukan wacana dekarbonisasi abstrak, melainkan tindakan yang bisa dieksekusi minggu ini."}, {"t": "stat", "n": "±30%", "l": "energi di gedung komersial terbuang sia-sia ⚠︎ — pemborosan yang jarang tampil sebagai satu baris tagihan", "s": "US EPA ENERGY STAR"}, {"t": "pull", "x": "Angka yang hanya dilihat tidak menghemat apa pun. Angka yang ditindaklanjuti — itu yang menutup pemborosan."}, {"t": "p", "x": "Yang membuat pendekatan ini masuk akal secara bisnis: banyak langkah pemangkasan karbon justru <b>berbiaya negatif</b> — ia membayar dirinya sendiri lewat energi yang tak jadi terbakar. Kurva biaya abatement <a href=\"https://www.mckinsey.com/capabilities/sustainability/our-insights/pathways-to-a-low-carbon-economy\">McKinsey</a> lama menunjukkan hal ini: efisiensi energi kerap berada di sisi kiri kurva, tempat setiap ton yang dipangkas sekaligus memangkas ongkos. Di tangan agen, karbon menjadi lensa untuk menemukan efisiensi — bukan sekadar beban pelaporan."}, {"t": "h2", "x": "Jujur soal batasnya"}, {"t": "p", "x": "Agen bukan sihir. Ia menyarankan; manusia yang memutuskan. Rekomendasinya hanya sebaik data yang masuk, dan angka aktivitas untuk emisi tak-langsung umumnya <b>terlacak</b>, bukan terukur presisi — perlu diverifikasi sebelum ditindaklanjuti. Ada ironi yang layak diakui pula: AI sendiri haus energi. IEA memperkirakan konsumsi listrik pusat data, AI, dan kripto bisa menembus ~1.000 TWh pada 2026 ⚠︎, setara konsumsi listrik seluruh Jepang <a href=\"https://www.iea.org/reports/electricity-2024\">IEA, 2024</a>. Agen yang jujur harus menghemat jauh lebih banyak daripada yang ia pakai."}, {"t": "p", "x": "Inilah garis yang dikejar Glyiv: bukan dashboard yang lebih ramai, tapi agen yang membaca data karbon dan biaya berdampingan, menandai yang janggal, dan menyarankan langkah yang bisa dieksekusi — lalu jujur soal mana yang sudah pasti dan mana yang masih perkiraan. Menghitung karbon itu titik awal. Menutup pemborosan itu tujuannya."}], "story": [{"kind": "cover", "title": "Agen AI: dari dashboard pasif ke tindakan", "text": "Alih-alih menampilkan angka lalu dilupakan, agen AI membaca data karbon berdampingan dengan biaya, menandai anomali, dan menyarankan langkah pemangkasan yang bisa dieksekusi minggu ini."}, {"kind": "hook", "title": "Angka yang cuma dilihat tak menghemat apa pun", "text": "Gelombang berikutnya bukan dashboard yang lebih ramai — tapi agen yang benar-benar bertindak."}, {"kind": "point", "title": "Baca karbon di samping biaya", "text": "Agen menyerap energi, invoice, dan rantai pasok — lalu menunjuk di mana uang dan emisi bocor bersamaan."}, {"kind": "point", "title": "Tandai yang janggal, sarankan langkahnya", "text": "Pendingin menyala di gudang kosong tak pernah jadi satu baris tagihan. Agen menandainya, lalu menyarankan: ubah jadwal, setel ulang suhu, matikan saat idle."}, {"kind": "stat", "title": "Pemborosan tersembunyi", "big": "±30%", "label": "energi gedung komersial terbuang sia-sia ⚠︎", "source": "US EPA ENERGY STAR"}, {"kind": "quote", "title": "Dilihat vs. ditindaklanjuti", "text": "Angka yang hanya dilihat tidak menghemat apa pun. Angka yang ditindaklanjuti, iya."}, {"kind": "end", "title": "Karbon sebagai lensa efisiensi", "text": "Menghitung itu titik awal; menutup pemborosan tujuannya. Baca selengkapnya dan ikuti Glyiv Kabar."}], "sources": [{"a": "IEA (2024). Electricity 2024: Analysis and Forecast to 2026 — proyeksi konsumsi listrik pusat data, AI, dan kripto.", "u": "https://www.iea.org/reports/electricity-2024"}, {"a": "McKinsey & Company. Pathways to a Low-Carbon Economy — Global GHG Abatement Cost Curve (v2.1).", "u": "https://www.mckinsey.com/capabilities/sustainability/our-insights/pathways-to-a-low-carbon-economy"}, {"a": "US EPA ENERGY STAR. Manajemen energi fasilitas — estimasi energi terbuang di gedung komersial.", "u": "https://www.energystar.gov/buildings"}, {"a": "Analisis industri 2026: agen AI dalam akuntansi karbon (Persefoni, Watershed, CO2 AI)."}]}, {"slug": "blockchain-registri-transparan", "topic": "Teknologi", "mood": "#6B4E8C", "title": "Rantai blok untuk karbon: transparansi, bukan spekulasi.", "dek": "Setiap kali \"blockchain\" bertemu \"karbon\", orang menduga soal token. Manfaat sesungguhnya justru lebih sunyi: jejak audit yang tak bisa diubah diam-diam — dari petak lahan hingga kredit dipensiunkan.", "hook": "Sebut \"blockchain karbon\", orang membayangkan token naik-turun. Manfaat sejatinya adalah yang paling membosankan sekaligus paling langka: catatan yang tak bisa diam-diam diubah.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau terhadap pengumuman Verra & kerangka ICVCM · sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Setiap kali kata 'blockchain' bertemu 'karbon', bayangan pertama biasanya token yang naik-turun. Padahal manfaat yang benar-benar penting jauh lebih sunyi: sebuah catatan yang tak bisa diam-diam diubah — dan justru itulah yang paling dibutuhkan pasar karbon."}, {"t": "p", "x": "Nilai sebuah kredit karbon bertumpu pada satu pertanyaan sederhana: bisakah ia ditelusuri kembali? Dari petak lahan tempat pohon tumbuh, tanggal pemantauan, sampai saat kredit itu di-retire (dipensiunkan) — apakah tiap langkah punya jejak yang utuh? Di sinilah rantai blok berguna: bukan untuk menetapkan harga, melainkan mengunci <b>jejak audit</b> (data lineage) agar tak ada yang bisa dihapus atau ditulis ulang tanpa terlihat."}, {"t": "h2", "x": "Bukan harga token, tapi jejak yang tak bisa dihapus"}, {"t": "p", "x": "Pasar karbon menanggung luka lama: penghitungan ganda dan kredit yang asal-usulnya kabur. Sejumlah studi akademik menemukan banyak proyek konservasi hutan melebih-lebihkan pengurangan emisi yang mereka klaim — sebagian kredit bahkan tak mewakili karbon yang benar-benar tersimpan. Bila catatannya masih bisa diubah diam-diam, sisa kepercayaan ikut runtuh. Buku besar yang hanya bisa ditambah (append-only) menutup celah itu: sekali retirement tercatat, ia bersifat satu-arah dan permanen."}, {"t": "pull", "x": "Blockchain tidak membuat data buruk jadi benar. Ia hanya menjamin data — baik atau buruk — tak bisa diam-diam diubah setelah dicatat."}, {"t": "p", "x": "Justru karena itu, gelombang pertama 'karbon kripto' salah arah. Pada 2022, sejumlah protokol memindahkan (bridging) kredit lama berkualitas rendah ke rantai untuk diperdagangkan sebagai token. Verra — registri sukarela terbesar dunia — menanggapinya dengan <a href=\"https://verra.org/verra-addresses-crypto-instruments-and-tokens/\">melarang tokenisasi kredit yang sudah di-retire</a>. Pelajarannya jernih: yang bernilai bukan tokennya, melainkan integritas catatannya."}, {"t": "stat", "n": "Mei 2022", "l": "Verra melarang tokenisasi kredit yang sudah di-retire, menutup gelombang spekulasi 'karbon kripto'", "s": "Verra, 2022"}, {"t": "h2", "x": "Data dulu, rantai kemudian"}, {"t": "p", "x": "Maka urutan yang benar dimulai dari data, bukan dari rantai. Mutu kredit ditentukan di hulu — oleh MRV/dMRV yang jujur dan kerangka integritas seperti <a href=\"https://icvcm.org/the-core-carbon-principles/\">Core Carbon Principles</a> dari ICVCM; standar untuk kredit ter-tokenisasi pun masih terus dimatangkan ⚠︎. Rantai blok bekerja di hilir: merekam siapa mencatat apa dan kapan, lalu menautkannya ke registri resmi. Retirement satu-arah mencegah satu ton diklaim dua kali, dan 'corresponding adjustment' ala Pasal 6 Paris Agreement menjaga agar negara dan perusahaan tak menghitung kontribusi yang sama."}, {"t": "p", "x": "Bagi pembeli, dampaknya sederhana: mereka bisa menelusuri sebuah kredit sampai ke petak lahannya, bukan sekadar memercayai sertifikat PDF. Bagi Indonesia — dengan hutan dan mangrove bernilai iklim tinggi — transparansi seperti ini adalah syarat masuk pasar premium, bukan pemanis. Rantai blok, dipakai dengan jujur, tak pernah soal harga yang melonjak. Ia soal satu hal yang paling langka di pasar karbon: bukti yang bisa dipertanggungjawabkan."}], "story": [{"kind": "cover", "title": "Rantai blok untuk karbon", "text": "Setiap kali 'blockchain' bertemu 'karbon', orang menduga soal token. Manfaat sesungguhnya justru lebih sunyi: jejak audit yang tak bisa diubah diam-diam — dari petak lahan hingga kredit dipensiunkan."}, {"kind": "hook", "title": "Bukan soal harga token", "text": "Sebut 'blockchain karbon', orang membayangkan token naik-turun. Manfaat sejatinya jauh lebih penting — dan lebih sunyi."}, {"kind": "point", "title": "Nilai = bisa ditelusuri", "text": "Kredit karbon bernilai bila bisa dilacak: dari petak lahan, tanggal pemantauan, sampai saat di-retire."}, {"kind": "point", "title": "Yang dikunci rantai blok", "text": "Bukan harganya, tapi catatannya. Sekali tercatat, tak bisa diubah atau dihapus diam-diam."}, {"kind": "stat", "title": "Pelajaran 2022", "big": "Mei 2022", "label": "Verra melarang tokenisasi kredit yang sudah di-retire", "source": "Verra, 2022"}, {"kind": "quote", "title": "Yang dijamin rantai blok", "text": "Blockchain tak membuat data buruk jadi benar. Ia hanya menjamin data tak bisa diam-diam diubah setelah dicatat."}, {"kind": "end", "title": "Transparansi, bukan spekulasi", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan telusuri karbon yang benar-benar bisa dipertanggungjawabkan."}], "sources": [{"a": "Verra (2022). \"Verra Addresses Crypto Instruments and Tokens.\"", "u": "https://verra.org/verra-addresses-crypto-instruments-and-tokens/"}, {"a": "Integrity Council for the Voluntary Carbon Market (ICVCM) (2023). \"The Core Carbon Principles.\"", "u": "https://icvcm.org/the-core-carbon-principles/"}, {"a": "West, T.A.P., dkk. (2023). \"Action needed to make carbon offsets from forest conservation work for climate change mitigation.\" Science, 381(6660)."}, {"a": "UNFCCC. \"The Paris Agreement — Article 6.\"", "u": "https://unfccc.int/process-and-meetings/the-paris-agreement/article-6"}]}, {"slug": "iot-pabrik-emisi-real-time", "topic": "Teknologi", "mood": "#1F7A6B", "title": "Sensor IoT: melihat emisi pabrik saat itu juga.", "dek": "Tagihan energi bulanan menyembunyikan lini dan shift yang boros; meteran dan sensor proses membuat pemborosan itu terlacak saat kejadian — bukan sebulan kemudian.", "hook": "Tagihan listrik pabrik datang sebulan sekali — dan menyembunyikan persis di mana uang serta karbon Anda bocor.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, IEA, US DOE)", "read": 4, "blocks": [{"t": "lead", "x": "Tagihan listrik sebuah pabrik biasanya datang sebulan sekali: satu angka besar untuk seluruh gedung. Angka itu jujur, tapi buta. Ia tak bisa memberi tahu lini produksi mana yang boros, shift mana yang bocor, atau mesin mana yang menyala saat seharusnya diam. Sensor IoT dan meteran energi mengubah satu angka bulanan itu menjadi ribuan titik data yang bisa dibaca saat kejadian."}, {"t": "p", "x": "Prinsipnya sederhana. Meteran sub-level (submetering) dipasang bukan hanya di gardu utama, tapi di tiap lini, kompresor, dan sistem pendingin; sensor proses membaca suhu, tekanan, dan aliran. Hasilnya adalah konsumsi <b>per mesin, per shift</b>, mendekati waktu nyata. Yang tadinya tenggelam dalam satu tagihan gabungan kini <b>terlacak</b> — bukan terukur sempurna, tapi cukup untuk menunjuk sumber pemborosan lengkap dengan tanggal dan jamnya."}, {"t": "p", "x": "Kenapa ini soal emisi, bukan sekadar biaya? Karena di industri, sebagian besar emisi lahir dari energi yang dibakar dan dipakai. Sektor industri menyumbang sekitar <b>24% emisi gas rumah kaca global langsung</b> pada 2019 menurut <a href=\"https://www.ipcc.ch/report/ar6/wg3/\">IPCC AR6</a>. Setiap kilowatt-jam yang terbuang adalah rupiah sekaligus karbon — dan keduanya baru bisa dipangkas kalau lebih dulu terlihat."}, {"t": "h2", "x": "Yang tenggelam dalam tagihan gabungan"}, {"t": "p", "x": "Ambil contoh yang paling umum. Sistem motor listrik adalah pengguna listrik tunggal terbesar di pabrik — menurut <a href=\"https://www.iea.org/topics/energy-efficiency\">IEA</a>, motor menyerap lebih dari 40% listrik dunia ⚠︎, dan porsinya jauh lebih besar di lantai industri. Kompresor udara, pompa, dan kipas yang berjalan di jam sepi jarang muncul sebagai baris anggaran tersendiri. Mereka hanya menambah angka bulanan — sampai ada meteran yang menunjuk mereka."}, {"t": "stat", "n": "20–30%", "l": "keluaran kompresor udara yang lenyap jadi kebocoran di pabrik yang tak terpelihara — hanya terlihat bila dipantau per titik", "s": "U.S. Department of Energy"}, {"t": "pull", "x": "Anda tak bisa memangkas apa yang tak Anda lihat. Meteran per lini mengubah dugaan menjadi bukti — dengan tanggal, jam, dan lini yang jelas."}, {"t": "p", "x": "Tapi sensor bukan sihir. Data mentah tanpa konteks hanya menambah satu dashboard lagi. Nilainya muncul saat konsumsi dibaca berdampingan dengan jadwal produksi dan biaya — sebagai intensitas per unit keluaran, bukan sekadar total. Dari sana, submetering kerap memunculkan pemborosan beberapa persen hingga dua digit ⚠︎; besarnya sangat bergantung pada pabrik dan disiplin pemeliharaannya."}, {"t": "h2", "x": "Dari terpasang ke terpakai"}, {"t": "p", "x": "Langkah awal bukan memasang seribu sensor, tapi memetakan beban terbesar dan mengukurnya lebih dulu — selaras standar manajemen energi seperti <a href=\"https://www.iso.org/standard/69426.html\">ISO 50001</a> dan GHG Protocol untuk sisi karbon. Ketika data lini itu tertelusur dan bisa diaudit, karbon dan biaya menjadi satu lensa yang sama. Imbalannya ganda: tagihan turun, dan kontribusi pabrik pada iklim ikut membaik. Terlacak dulu — baru bisa dipangkas."}], "story": [{"kind": "cover", "title": "Sensor IoT: melihat emisi pabrik saat itu juga.", "text": "Tagihan energi bulanan menyembunyikan lini dan shift yang boros; meteran dan sensor proses membuat pemborosan itu terlacak saat kejadian — bukan sebulan kemudian."}, {"kind": "hook", "title": "Satu angka, sebulan sekali.", "text": "Tagihan listrik pabrik datang sekali sebulan — dan menyembunyikan persis di mana uang serta karbon Anda bocor."}, {"kind": "point", "title": "Tagihan gabungan itu buta", "text": "Ia tak bisa menunjuk lini yang boros, shift yang bocor, atau mesin yang menyala saat harusnya diam."}, {"kind": "point", "title": "Sensor mengubahnya", "text": "Meteran per lini + sensor proses = konsumsi per mesin, per shift, mendekati real-time. Terlacak, bukan sebulan kemudian."}, {"kind": "stat", "title": "Yang tersembunyi di tagihan", "big": "20–30%", "label": "keluaran kompresor udara lenyap jadi kebocoran di pabrik yang tak terpelihara", "source": "U.S. Department of Energy"}, {"kind": "quote", "title": "Lihat dulu, baru pangkas", "text": "Anda tak bisa memangkas apa yang tak Anda lihat."}, {"kind": "end", "title": "Terlacak dulu, baru dipangkas.", "text": "Baca Kabar lengkapnya — atau gabung Glyiv untuk menjadikan karbon dan biaya satu lensa yang sama."}], "sources": [{"a": "IPCC (2022). Climate Change 2022: Mitigation of Climate Change. Working Group III, Summary for Policymakers.", "u": "https://www.ipcc.ch/report/ar6/wg3/"}, {"a": "IEA (2023). Energy Efficiency 2023 — termasuk analisis sistem motor listrik industri.", "u": "https://www.iea.org/topics/energy-efficiency"}, {"a": "U.S. Department of Energy. Improving Compressed Air System Performance: A Sourcebook for Industry."}, {"a": "ISO 50001:2018. Energy management systems — Requirements with guidance for use.", "u": "https://www.iso.org/standard/69426.html"}]}, {"slug": "global-forest-watch-alarm-dini", "topic": "Teknologi", "mood": "#4F7A3A", "title": "Peringatan dini deforestasi: ketika hutan mengabari sendiri.", "dek": "Sistem seperti GLAD dan RADD di Global Forest Watch mengubah pemantauan hutan dari otopsi tahunan menjadi denyut mingguan — memberi penjaga hutan satu keunggulan yang paling langka: waktu.", "hook": "Bayangkan hutan yang bisa mengirim pesan tiap kali sepetaknya hilang. Kini itu nyata — dan alarmnya datang setiap minggu.", "cover": "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (GFW, Science, Nature Climate Change)", "read": 5, "blocks": [{"t": "lead", "x": "Dulu, kita baru tahu sepetak hutan lenyap berbulan-bulan setelah pohon terakhirnya tumbang — saat citra satelit tahunan akhirnya selesai diproses dan dibandingkan. Kini hutan bisa mengabari sendiri: dalam hitungan hari, sebuah alarm muncul di peta digital, menandai petak yang baru saja kehilangan tutupannya."}, {"t": "p", "x": "Fondasinya dibangun pada 2013, ketika Matthew Hansen dan timnya di University of Maryland merilis <a href=\"https://www.science.org/doi/10.1126/science.1244693\">peta perubahan tutupan pohon global</a> pertama beresolusi 30 meter, dari arsip Landsat. Peta itu mengubah cara dunia melihat hutan — tapi ritmenya <b>tahunan</b>: berguna untuk membaca tren, terlambat untuk mencegah kerusakan."}, {"t": "p", "x": "Yang mengubah ritme adalah sistem alarm. GLAD — Global Land Analysis & Discovery — di platform <a href=\"https://www.globalforestwatch.org/\">Global Forest Watch</a> milik World Resources Institute memindai citra Landsat tiap minggu dan menandai kehilangan tutupan pohon nyaris real-time. Kelemahannya satu: awan tropis kerap menutup lensa optik. Maka hadir RADD, alarm berbasis radar Sentinel-1 yang <a href=\"https://doi.org/10.1088/1748-9326/abd0a8\">menembus awan dan asap</a>, dikembangkan Wageningen University. Digabung, keduanya membuat hutan hujan sulit hilang tanpa jejak."}, {"t": "pull", "x": "Pemantauan berpindah dari otopsi tahunan menjadi denyut mingguan — dari mencatat kerusakan menjadi berpeluang mencegahnya."}, {"t": "stat", "n": "≈18%", "l": "penurunan deforestasi di wilayah Afrika yang menerima alarm GLAD (2016–2018)", "s": "Moffette dkk., Nature Climate Change, 2021"}, {"t": "h2", "x": "Alarm bukan penjaga"}, {"t": "p", "x": "Jujur saja: alarm hanya <b>mendeteksi</b>, bukan menghentikan. Satelit tak bisa menahan gergaji. Nilainya muncul saat data sampai ke tangan yang tepat — patroli, penegak hukum, masyarakat adat — cukup cepat untuk bertindak. Sebuah <a href=\"https://doi.org/10.1038/s41558-020-00956-w\">studi menemukan</a> bahwa ketika petugas di sejumlah wilayah Afrika berlangganan alarm mingguan lewat aplikasi Forest Watcher, laju deforestasi setempat menurun. Teknologinya nyata; dampaknya bergantung pada tindak lanjut manusia."}, {"t": "h2", "x": "Apa artinya bagi Indonesia"}, {"t": "p", "x": "Indonesia termasuk wilayah yang paling intens dipantau sistem ini. Data Global Forest Watch menunjukkan kehilangan hutan primer Indonesia sempat memuncak pada pertengahan 2010-an lalu menurun beberapa tahun terakhir ⚠︎ — meski angka tahunannya berfluktuasi dan definisi 'hutan' antar-lembaga tak selalu sama. Bagi Glyiv, alarm dini semacam ini adalah bahan baku: sinyal independen yang bisa disandingkan dengan pemantauan dMRV kami, sehingga status sebuah petak restorasi bukan sekadar diklaim, melainkan <b>terlacak</b> dari luar angkasa."}, {"t": "p", "x": "Hutan yang bisa mengabari sendiri tidak otomatis menyelamatkan dirinya. Tapi ia memindahkan keunggulan waktu — dari perusak ke penjaga. Dan dalam urusan hutan, waktu adalah hampir segalanya."}], "story": [{"kind": "cover", "title": "Hutan yang mengabari sendiri", "text": "Sistem seperti GLAD dan RADD di Global Forest Watch mengubah pemantauan hutan dari otopsi tahunan menjadi denyut mingguan — memberi penjaga hutan satu keunggulan yang paling langka: waktu."}, {"kind": "hook", "title": "Alarm tiap minggu", "text": "Bayangkan hutan yang mengirim pesan tiap kali sepetaknya hilang. Kini itu nyata."}, {"kind": "point", "title": "Dulu: peta tahunan", "text": "Peta Hansen (2013) memetakan kehilangan hutan global beresolusi 30 m — akurat, tapi baru terbaca setahun kemudian."}, {"kind": "point", "title": "Kini: denyut mingguan", "text": "GLAD memindai Landsat tiap minggu. RADD memakai radar Sentinel-1 yang menembus awan tropis."}, {"kind": "stat", "title": "Bukan sekadar sensor", "big": "≈18%", "label": "penurunan deforestasi di area Afrika yang menerima alarm GLAD", "source": "Moffette dkk., Nature Climate Change, 2021"}, {"kind": "quote", "title": "Alarm bukan penjaga", "text": "Satelit tak bisa menahan gergaji. Alarm hanya bernilai bila sampai ke tangan yang bertindak cukup cepat."}, {"kind": "end", "title": "Waktu untuk penjaga", "text": "Glyiv menyandingkan alarm publik dengan dMRV agar status hutan terlacak, bukan sekadar diklaim. Baca selengkapnya di Glyiv Kabar."}], "sources": [{"a": "Hansen, M. C., dkk. (2013). High-Resolution Global Maps of 21st-Century Forest Cover Change. Science, 342(6160), 850–853.", "u": "https://www.science.org/doi/10.1126/science.1244693"}, {"a": "Global Forest Watch / World Resources Institute. GLAD & Integrated Deforestation Alerts.", "u": "https://www.globalforestwatch.org/"}, {"a": "Reiche, J., dkk. (2021). Forest disturbance alerts for the Congo Basin using Sentinel-1 (RADD). Environmental Research Letters, 16(2).", "u": "https://doi.org/10.1088/1748-9326/abd0a8"}, {"a": "Moffette, F., Alix-Garcia, J., Shea, K., & Pickens, A. H. (2021). The impact of near-real-time deforestation alerts across the tropics. Nature Climate Change, 11, 172–178.", "u": "https://doi.org/10.1038/s41558-020-00956-w"}]}, {"slug": "digital-twin-pabrik-karbon", "topic": "Teknologi", "mood": "#1F7A6B", "title": "Kembaran digital: menguji pemangkasan sebelum dieksekusi.", "dek": "Sebelum menaruh modal pada retrofit hijau, kembaran digital membiarkan pabrik menguji skenario efisiensi secara virtual — melihat dampaknya pada emisi dan biaya lebih dulu, saat sebuah kesalahan masih murah untuk diperbaiki.", "hook": "Bagaimana kalau Anda bisa menguji pemangkasan emisi pabrik dulu — tanpa membongkar satu mesin pun?", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, DESNZ)", "read": 4, "blocks": [{"t": "lead", "x": "Sebelum sebuah pabrik mengganti sistem pendinginnya senilai miliaran rupiah, hampir selalu muncul pertanyaan yang sama: apakah investasi ini benar-benar akan memangkas emisi dan biaya seperti yang dijanjikan? Kembaran digital menawarkan cara menjawabnya lebih dulu — tanpa membongkar apa pun di lantai produksi."}, {"t": "p", "x": "Kembaran digital (<em>digital twin</em>) adalah replika virtual sebuah fasilitas yang terus disuapi data nyata dari sensor, meter listrik, dan sistem operasional. Ia bukan gambar 3D yang diam, melainkan model hidup yang meniru perilaku pabrik: aliran energi, suhu, beban mesin, jam sibuk dan jam sepi. Konsep ini lahir di dunia kedirgantaraan dan manufaktur, lalu menyebar ke sektor energi seiring makin murahnya sensor dan komputasi <a href=\"https://www.iea.org/reports/digitalisation-and-energy\">(IEA, Digitalisation and Energy)</a>."}, {"t": "h2", "x": "Menguji tanpa membongkar"}, {"t": "p", "x": "Nilainya untuk karbon bertumpu pada satu kata: <b>menguji</b>. Dengan kembaran digital, tim bisa menjalankan skenario di layar — menggeser jadwal pendingin ke jam listrik lebih murah, menambah pemulihan panas buang, atau mengganti motor tua — lalu melihat dampaknya yang dimodelkan terhadap konsumsi kWh, emisi yang <b>terlacak</b>, dan biaya. Semua itu sebelum satu rupiah modal dikeluarkan, saat sebuah kesalahan masih murah untuk diperbaiki."}, {"t": "p", "x": "Contohnya sederhana. Sebuah kompresor udara yang menyala penuh sepanjang malam mungkin tak pernah terlihat boros dalam tagihan listrik gabungan. Di kembaran digital, jadwalnya bisa 'dimatikan' secara virtual di jam kosong, dan sistem langsung menghitung berapa kWh, rupiah, dan kilogram CO2e yang ikut turun — sekaligus memastikan tekanan udara tetap cukup bagi lini yang benar-benar berjalan. Yang tadinya intuisi menjadi angka yang bisa dibandingkan antar-skenario."}, {"t": "pull", "x": "Kembaran digital memindahkan keputusan modal dari 'kira-kira begini' menjadi skenario yang sudah diuji."}, {"t": "stat", "n": ">40%", "l": "konsumsi listrik global berasal dari sistem penggerak motor listrik — target efisiensi terbesar di banyak pabrik", "s": "IEA, Electric Motors"}, {"t": "h2", "x": "Model hanya sebagus datanya"}, {"t": "p", "x": "Ada kejujuran yang harus dipegang: kembaran digital memodelkan, bukan menjamin. Penghematan yang muncul di simulasi adalah proyeksi, bukan hasil yang sudah terjadi. Emisi di sini <b>terlacak</b> lewat faktor emisi standar <a href=\"https://www.gov.uk/government/collections/government-conversion-factors-for-company-reporting\">(mis. IPCC dan DESNZ)</a>, bukan diukur langsung dari cerobong. Karena itu tiap skenario perlu divalidasi ulang terhadap meter nyata setelah diterapkan — agar angka janji dan angka kenyataan terus didamaikan."}, {"t": "p", "x": "Justru di situlah gunanya. Alih-alih bertaruh besar pada satu retrofit lalu berharap, fasilitas bisa menyaring puluhan opsi secara virtual, membuang yang tak berdampak, dan memusatkan modal pada yang — dalam model — paling besar kontribusinya menekan emisi per unit produksi. Bagi Glyiv, itulah inti dari menguji pemangkasan sebelum dieksekusi: keputusan hijau yang berangkat dari bukti, bukan sekadar harapan."}], "story": [{"kind": "cover", "title": "Kembaran digital: uji dulu, eksekusi kemudian", "text": "Sebelum menaruh modal pada retrofit hijau, kembaran digital membiarkan pabrik menguji skenario efisiensi secara virtual — melihat dampaknya pada emisi dan biaya lebih dulu, saat sebuah kesalahan masih murah untuk diperbaiki."}, {"kind": "hook", "title": "Coba dulu, tanpa bongkar", "text": "Bagaimana kalau Anda bisa menguji pemangkasan emisi pabrik dulu — tanpa membongkar satu mesin pun?"}, {"kind": "point", "title": "Apa itu kembaran digital?", "text": "Replika virtual pabrik yang terus disuapi data nyata dari sensor dan meter. Bukan gambar 3D yang diam — model hidup yang meniru aliran energi dan beban mesin."}, {"kind": "point", "title": "Uji sebelum keluar modal", "text": "Geser jadwal pendingin, tambah pemulihan panas, ganti motor tua — lihat dampaknya pada emisi terlacak dan biaya di simulasi dulu, sebelum berinvestasi."}, {"kind": "stat", "title": "Kenapa efisiensi motor penting", "big": ">40%", "label": "listrik global dari sistem motor listrik — peluang efisiensi terbesar di pabrik", "source": "IEA, Electric Motors"}, {"kind": "point", "title": "Jujur soal batasnya", "text": "Model memproyeksikan, bukan menjamin. Emisi terlacak lewat faktor emisi standar, lalu divalidasi ke meter nyata setelah diterapkan."}, {"kind": "end", "title": "Uji pemangkasan, lalu eksekusi", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan ikut menakar jalur rendah-karbon yang berangkat dari bukti, bukan harapan."}], "sources": [{"a": "IEA (2017). Digitalisation and Energy.", "u": "https://www.iea.org/reports/digitalisation-and-energy"}, {"a": "IEA (2023). Electric Motors — Energy System / Industry.", "u": "https://www.iea.org/energy-system/industry/electric-motors"}, {"a": "DESNZ & DEFRA (2024). UK Government Greenhouse Gas Conversion Factors for Company Reporting.", "u": "https://www.gov.uk/government/collections/government-conversion-factors-for-company-reporting"}]}, {"slug": "rwa-tokenisasi-aset-nyata", "topic": "Teknologi", "mood": "#6B4E8C", "title": "Tokenisasi aset nyata: menjembatani pohon dan pasar modal.", "dek": "Aset dunia-nyata seperti tegakan pohon bisa menjadi instrumen yang likuid dan dapat diaudit — tapi hanya jika ditopang dMRV yang nyata, bukan sekadar klaim di atas rantai.", "hook": "Sebuah token hijau hanya sebaik pohon di baliknya — dan pertanyaannya selalu: siapa yang benar-benar memantaunya?", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik & standar ERC-3643", "read": 5, "blocks": [{"t": "lead", "x": "Sebatang pohon adalah aset yang janggal di mata pasar modal. Ia menyimpan nilai nyata — menyerap karbon, menahan tanah, menopang mata pencaharian — tapi nilainya terkunci: sulit dibagi, sulit diperdagangkan, sulit diverifikasi dari jauh. Tokenisasi aset dunia-nyata (RWA) menjanjikan jembatan: mengubah tegakan pohon menjadi instrumen yang likuid dan dapat diaudit. Syaratnya satu, dan sering dilupakan — jembatan itu harus berpijak pada bukti, bukan klaim."}, {"t": "p", "x": "Tokenisasi RWA berarti merepresentasikan kepemilikan atau hak atas aset fisik — properti, komoditas, atau serapan karbon sebuah hutan — sebagai token di atas <em>blockchain</em>. Efeknya: aset yang tadinya berat dan tak terbagi bisa dipecah menjadi unit kecil, berpindah tangan hampir seketika, dan tercatat dalam satu buku yang sama untuk semua pihak. Konsultan <a href=\"https://www.bcg.com/publications/2022/relevance-of-on-chain-asset-tokenization\">BCG bersama ADDX memproyeksikan</a> nilai aset ter-tokenisasi global bisa mencapai <b>US$16 triliun pada 2030 ⚠︎</b> — angka besar yang tetap sebuah proyeksi, bukan kepastian."}, {"t": "h2", "x": "Token tanpa bukti hanyalah klaim lama berbaju baru"}, {"t": "p", "x": "Di sinilah pasar karbon punya luka lama. Terlalu banyak kredit dijual berdasarkan janji di atas kertas — pohon yang mungkin tak pernah tumbuh, atau serapan yang dihitung dua kali. <b>Blockchain tidak menyembuhkan itu dengan sendirinya.</b> Bila data yang masuk buruk, token justru membuat klaim buruk itu berpindah tangan lebih cepat. Prinsip <em>garbage in, garbage out</em> berlaku persis seperti di sistem lain."}, {"t": "pull", "x": "Blockchain hanya sebaik data yang masuk ke dalamnya. Tanpa dMRV, tokenisasi cuma memindahkan klaim lama lebih cepat."}, {"t": "p", "x": "Yang membuat sebuah token bermakna adalah lapisan di bawahnya: <b>dMRV</b> — <em>digital Monitoring, Reporting, Verification</em>. Setiap tegakan dipantau lewat citra satelit dan indeks vegetasi, tingkat kelangsungan hidupnya dilacak dari waktu ke waktu, dan setiap pembaruan meninggalkan jejak yang bisa ditelusuri. Serapan karbon lalu ter-tokenisasi sebagai RWA — bukan sebagai janji, melainkan sebagai posisi dengan asal-usul data yang jelas."}, {"t": "stat", "n": "US$16 triliun ⚠︎", "l": "proyeksi nilai aset ter-tokenisasi global pada 2030 — sebuah perkiraan, bukan kepastian", "s": "BCG & ADDX, 2022 (proyeksi)"}, {"t": "p", "x": "Agar dipercaya pasar modal, token semacam ini perlu lebih dari sekadar dapat diperdagangkan; ia harus dapat diaudit. Standar token ter-izin seperti <a href=\"https://www.erc3643.org/\">ERC-3643</a> menempelkan identitas dan pemeriksaan KYC/AML di level kontrak, sementara <b>retirement</b> — penghapusan kredit setelah dipakai — bersifat satu arah agar tak ada penghitungan ganda. Kepemilikan, perpindahan, dan pensiun sebuah unit bisa direkonsiliasi hingga ke petak lahan dan tanggal pemantauannya."}, {"t": "h2", "x": "Jujur soal yang belum pasti"}, {"t": "p", "x": "Glyiv memilih posisi yang terus terang. Sebuah token pohon adalah bukti <b>kontribusi</b> pada penyerapan karbon, bukan sertifikat 'netral karbon'. Imbalan bagi pemegangnya berpijak pada aset dan data yang nyata, bukan janji penghasilan. Sebagian jalur sertifikasi resmi pun masih dalam roadmap ⚠︎. Menjembatani pohon dan pasar modal bukan soal rantai yang canggih, melainkan soal apakah setiap token bisa dilacak kembali ke sesuatu yang hidup dan terpantau — itulah garis yang memisahkan aset nyata dari spekulasi berkostum hijau."}], "story": [{"kind": "cover", "title": "Menjembatani pohon dan pasar modal", "text": "Aset dunia-nyata seperti tegakan pohon bisa menjadi instrumen yang likuid dan dapat diaudit — tapi hanya jika ditopang dMRV yang nyata, bukan sekadar klaim di atas rantai."}, {"kind": "hook", "title": "Token sebaik pohonnya", "text": "Kalau tak ada yang benar-benar memantau pohonnya, kamu cuma membeli janji yang berpindah lebih cepat."}, {"kind": "point", "title": "Apa itu tokenisasi RWA", "text": "Hak atas aset nyata — termasuk serapan karbon hutan — direpresentasikan sebagai token: bisa dibagi kecil, berpindah tangan cepat, tercatat untuk semua pihak."}, {"kind": "point", "title": "Blockchain bukan obat mujarab", "text": "Data buruk yang di-tokenisasi tetap data buruk — hanya berpindah lebih cepat. Garbage in, garbage out."}, {"kind": "point", "title": "dMRV adalah isinya", "text": "Satelit memantau tegakan, kelangsungan hidup dilacak, tiap pembaruan punya jejak yang bisa ditelusuri. Itu yang membuat token bermakna."}, {"kind": "stat", "title": "Angka yang beredar", "big": "US$16 triliun ⚠︎", "label": "proyeksi nilai aset ter-tokenisasi global pada 2030", "source": "BCG & ADDX, 2022 (proyeksi)"}, {"kind": "end", "title": "Aset nyata, bukan spekulasi hijau", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan ikuti bagaimana kami membangun bukti, bukan klaim."}], "sources": [{"a": "Boston Consulting Group & ADDX (2022). Relevance of On-Chain Asset Tokenization in 'Crypto Winter'.", "u": "https://www.bcg.com/publications/2022/relevance-of-on-chain-asset-tokenization"}, {"a": "ERC-3643 Association. The T-REX permissioned token standard.", "u": "https://www.erc3643.org/"}, {"a": "IPCC (2022). AR6 WGIII, Bab 7: Agriculture, Forestry and Other Land Uses (AFOLU).", "u": "https://www.ipcc.ch/report/ar6/wg3/"}, {"a": "World Bank (2024). State and Trends of Carbon Pricing 2024.", "u": "https://openknowledge.worldbank.org/entities/publication/state-and-trends-of-carbon-pricing-2024"}]}, {"slug": "ai-hitung-jejak-produk", "topic": "Teknologi", "mood": "#1F7A6B", "title": "Menghitung jejak karbon satu produk, otomatis.", "dek": "Dengan basis data faktor emisi seperti ecoinvent dan DEFRA/DESNZ ditambah AI, jejak karbon per produk kini bisa disusun dalam hitungan menit alih-alih minggu — asalkan hasilnya tetap terlacak dan bisa diaudit, bukan sekadar cepat.", "hook": "Menghitung jejak karbon satu produk dulu makan berminggu-minggu. Basis data faktor emisi + AI memampatkannya jadi menit — selama hasilnya tetap bisa diaudit.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (ecoinvent, DEFRA/DESNZ, GHG Protocol)", "read": 4, "blocks": [{"t": "lead", "x": "Menyusun jejak karbon satu produk saja — katakanlah sebatang cokelat atau sekaleng cat tembok — dulu adalah pekerjaan berminggu-minggu: menelusuri tiap bahan, tiap kilometer pengangkutan, tiap kilowatt-jam listrik, lalu mencocokkan semuanya satu per satu dengan angka emisi yang tepat. Kombinasi basis data faktor emisi dan AI kini memampatkan pekerjaan itu menjadi hitungan menit — tanpa menghapus keharusan membuktikannya."}, {"t": "p", "x": "Pada dasarnya, perhitungan jejak karbon produk (<i>product carbon footprint</i>) adalah satu rumus yang diulang ribuan kali: <b>data aktivitas × faktor emisi</b>. Faktor emisi itulah yang selama ini tersimpan dalam basis data besar seperti <a href=\"https://ecoinvent.org\">ecoinvent</a> — lebih dari 20.000 dataset daur hidup ⚠︎ — dan tabel <a href=\"https://www.gov.uk/government/collections/government-conversion-factors-for-company-reporting\">faktor konversi DEFRA/DESNZ</a> yang diperbarui pemerintah Inggris setiap tahun. Yang berat bukan rumusnya, melainkan mencocokkan tiap komponen dengan faktor yang benar."}, {"t": "p", "x": "Contohnya sederhana. Sebaris faktur berbunyi <i>'2 ton polietilen tergranul'</i> tak berarti apa-apa bagi kalkulator karbon sampai ia dikaitkan dengan faktor produksi polietilen yang tepat — mempertimbangkan wilayah, teknologi, dan sumber energinya. Mencocokkan ratusan baris seperti itu, dari ribuan pemasok, adalah bagian yang paling menyita waktu sekaligus paling mudah keliru bila dikerjakan dengan tangan."}, {"t": "p", "x": "Di titik pencocokan inilah AI mempercepat kerja. Model bahasa dapat membaca daftar bahan (<i>bill of materials</i>), faktur, dan data belanja, lalu memetakannya ke faktor emisi yang paling sesuai; mengisi celah data dengan proksi yang masuk akal; dan menjaga metode tetap konsisten dari satu produk ke produk lain. Penilaian yang dulu manual bisa disiapkan dalam hitungan menit."}, {"t": "pull", "x": "AI mempercepat penyusunan, bukan menggantikan pembuktian. Angka yang tak bisa diaudit tetap angka yang tak bisa dijual."}, {"t": "h2", "x": "Cepat itu satu hal; bisa diaudit itu hal lain."}, {"t": "stat", "n": "11,4×", "l": "Emisi rantai pasok (Scope 3) rata-rata dibanding emisi operasional langsung", "s": "CDP Global Supply Chain Report, 2022"}, {"t": "p", "x": "Karena mayoritas jejak sebuah produk justru bersembunyi di rantai pasok, hasil AI harus dibaca dengan jujur. Faktor dalam basis data adalah <b>rata-rata industri</b>, bukan pengukuran pabrik Anda sendiri — maka lebih tepat disebut <b>terlacak</b> ketimbang terukur. Selisihnya bisa besar: studi lintas 38.700 pertanian oleh <a href=\"https://www.science.org/doi/10.1126/science.aaq0216\">Poore & Nemecek (2018)</a> menunjukkan jejak daging sapi bisa puluhan kali lipat jejak kacang-kacangan per kilogram — memilih faktor yang keliru bisa menggeser hasil jauh."}, {"t": "p", "x": "Untuk klaim yang dipertaruhkan ke pembeli atau regulator, hasil AI tetap perlu diverifikasi terhadap standar seperti <a href=\"https://ghgprotocol.org/product-standard\">GHG Protocol Product Standard</a> dan ISO 14067. Namun nilai terbesarnya bukan pada satu angka, melainkan pada <b>konsistensi</b>: ketika ribuan produk dihitung dengan metode dan basis data yang sama, jejaknya bisa dibandingkan, ditukar antar-perusahaan lewat kerangka seperti <a href=\"https://www.carbon-transparency.org\">PACT Pathfinder (WBCSD)</a>, dan disodorkan saat CBAM Uni Eropa menagih intensitas karbon per produk di perbatasan. Data yang cepat dan konsisten hari ini bisa menjadi izin dagang esok hari."}, {"t": "bars", "h": [0.85, 0.42, 0.2, 0.3, 0.12], "cap": "Ilustrasi komposisi jejak karbon per tahap daur hidup — kerap didominasi bahan baku & rantai pasok, bukan pabrik akhir. Pola umum: GHG Protocol / CDP, 2022."}], "story": [{"kind": "cover", "title": "Menghitung jejak karbon satu produk, otomatis.", "text": "Basis data faktor emisi + AI memampatkan pekerjaan berminggu-minggu jadi menit — asalkan hasilnya tetap terlacak dan bisa diaudit."}, {"kind": "hook", "title": "Dulu berminggu-minggu. Kini hitungan menit.", "text": "Menyusun jejak karbon satu produk tak lagi harus manual, baris demi baris."}, {"kind": "point", "title": "Satu rumus, ribuan kali", "text": "Jejak produk = data aktivitas × faktor emisi. Basis data seperti ecoinvent dan DEFRA/DESNZ menyimpan faktornya."}, {"kind": "point", "title": "Di sinilah AI masuk", "text": "AI mencocokkan bahan, faktur, dan belanja ke faktor yang tepat — lalu menjaga metode konsisten antar-produk."}, {"kind": "stat", "title": "Sebagian besar ada di rantai pasok", "big": "11,4×", "label": "Emisi rantai pasok vs. operasional langsung", "source": "CDP, 2022"}, {"kind": "quote", "title": "Prinsip Glyiv", "text": "AI mempercepat penyusunan, bukan menggantikan pembuktian."}, {"kind": "end", "title": "Terlacak, bukan sekadar cepat", "text": "Faktor basis data adalah rata-rata industri — untuk klaim serius, verifikasi ke GHG Protocol & ISO 14067. Baca selengkapnya di Glyiv Kabar."}], "sources": [{"a": "ecoinvent Association (2024). ecoinvent database v3.10 — life cycle inventory datasets.", "u": "https://ecoinvent.org"}, {"a": "DESNZ & DEFRA (2024). UK Government Greenhouse Gas Conversion Factors for Company Reporting.", "u": "https://www.gov.uk/government/collections/government-conversion-factors-for-company-reporting"}, {"a": "Poore, J. & Nemecek, T. (2018). Reducing food's environmental impacts through producers and consumers. Science 360(6392), 987–992.", "u": "https://www.science.org/doi/10.1126/science.aaq0216"}, {"a": "CDP (2022). Engaging the Chain: Driving Speed and Scale — CDP Global Supply Chain Report.", "u": "https://www.cdp.net/en/research/global-reports"}]}, {"slug": "data-lineage-anti-greenwashing", "topic": "Teknologi", "mood": "#6B4E8C", "title": "Data lineage: penawar paling ampuh untuk greenwashing.", "dek": "Klaim iklim bertahan bukan karena terdengar meyakinkan, tapi karena setiap angkanya bisa ditelusuri sampai ke sumber. Jejak data yang terbuka membuat greenwashing jauh lebih mudah terbongkar.", "hook": "Klaim hijau paling kokoh bukan yang paling nyaring — tapi yang setiap angkanya bisa kamu telusuri sampai ke sumbernya.", "cover": "https://images.unsplash.com/photo-1558494949-ef010cbdcc31?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 5, "blocks": [{"t": "lead", "x": "Greenwashing jarang hidup dari kebohongan telanjang. Ia tumbuh di celah antara klaim dan bukti — di angka yang terdengar meyakinkan tapi tak bisa ditelusuri asalnya. Menutup celah itu tak butuh slogan baru; ia butuh jejak data (data lineage): kemampuan melacak setiap angka karbon kembali ke sumbernya."}, {"t": "p", "x": "Dalam akuntansi karbon, satu angka emisi hampir tak pernah berdiri sendiri. Ia lahir dari tiga hal: <b>data aktivitas</b> (berapa liter solar, berapa kilowatt-jam), <b>faktor emisi</b> (berapa CO₂ per satuan), dan <b>metodologi</b> yang mengikatnya. Jejak data berarti ketiganya terbuka dan tertaut — sehingga siapa pun bisa bertanya 'angka ini datang dari mana?' dan mendapat jawaban yang bisa diperiksa, bukan sekadar diyakini."}, {"t": "p", "x": "Betapa lebarnya celah itu terlihat dari data regulator. Saat Komisi Eropa menyisir klaim lingkungan pada 2020, <b>40% di antaranya tak didukung bukti memadai</b> dan lebih dari separuh dinilai kabur atau menyesatkan <a href=\"https://ec.europa.eu/commission/presscorner/detail/en/ip_21_269\">(European Commission)</a>. Klaim seperti 'ramah lingkungan' atau 'netral karbon' kerap berhenti sebagai kata sifat, tanpa jejak yang mengarah ke perhitungan di baliknya."}, {"t": "pull", "x": "Klaim iklim yang paling kokoh bukan yang paling nyaring, tapi yang setiap angkanya bisa ditelusuri sampai ke sumber."}, {"t": "stat", "n": "40%", "l": "klaim lingkungan di UE yang tak didukung bukti memadai (2020)", "s": "European Commission, sweep klaim hijau 2020"}, {"t": "h2", "x": "Faktor emisi pun punya alamat"}, {"t": "p", "x": "Ambil contoh yang tampak sepele: emisi dari satu kilogram bahan pangan. Angka itu bukan tebakan — ia bisa dilacak ke basis data terbuka seperti studi <a href=\"https://www.science.org/doi/10.1126/science.aaq0216\">Poore & Nemecek (2018)</a> di jurnal Science, atau ke faktor konversi resmi yang diperbarui tiap tahun oleh pemerintah Inggris (DEFRA/DESNZ). Ketika sebuah klaim menyebut faktor emisi tanpa menyebut sumbernya, itu bukan detail teknis yang boleh dilewati — justru itu bagian yang paling perlu diperiksa."}, {"t": "p", "x": "Regulator pun mulai menutup pintu bagi klaim tanpa jejak. Pada 2024, Uni Eropa mengesahkan aturan yang melarang klaim generik seperti 'netral karbon' yang hanya bersandar pada offset, lewat <a href=\"https://eur-lex.europa.eu/eli/dir/2024/825/oj\">Directive (EU) 2024/825</a>, dengan penerapan penuh dijadwalkan mulai 2026 ⚠︎. Aturan pendampingnya, Green Claims Directive, masih dalam pembahasan akhir ⚠︎ — tapi arahnya jelas: klaim harus bisa dibuktikan, bukan sekadar dipasarkan. Di perbatasan, CBAM bahkan menghukum ketiadaan data dengan nilai default yang mahal."}, {"t": "h2", "x": "Jejak, bukan janji"}, {"t": "p", "x": "Bagi Glyiv, jejak data adalah postur, bukan fitur. Kami memilih menulis 'terlacak', bukan 'terukur', untuk data yang belum diverifikasi penuh; 'kontribusi', bukan 'netral karbon'; dan menandai angka yang belum pasti dengan ⚠︎. Bukan karena rendah hati, tapi karena hanya angka yang bisa ditelusuri yang benar-benar bertahan saat diaudit. Sisanya, cepat atau lambat, akan terbongkar."}], "story": [{"kind": "cover", "title": "Data lineage: penawar greenwashing", "text": "Klaim iklim bertahan bukan karena terdengar meyakinkan, tapi karena setiap angkanya bisa ditelusuri sampai ke sumber."}, {"kind": "hook", "title": "Bukan yang paling nyaring", "text": "Klaim hijau paling kokoh adalah yang setiap angkanya bisa kamu telusuri sampai ke sumbernya."}, {"kind": "point", "title": "Apa itu jejak data", "text": "Tiap angka emisi lahir dari data aktivitas + faktor emisi + metodologi. Jejak data membuat ketiganya terbuka dan bisa diperiksa."}, {"kind": "point", "title": "Celah greenwashing", "text": "Klaim 'ramah lingkungan' sering berhenti sebagai kata sifat — tanpa jejak menuju perhitungan di baliknya."}, {"kind": "stat", "title": "Seberapa lebar celahnya", "big": "40%", "label": "klaim lingkungan di UE tak didukung bukti memadai (2020)", "source": "European Commission"}, {"kind": "quote", "title": "Yang bertahan saat diaudit", "text": "Klaim iklim yang paling kokoh bukan yang paling nyaring, tapi yang setiap angkanya bisa ditelusuri sampai ke sumber."}, {"kind": "end", "title": "Jejak, bukan janji", "text": "Baca artikel lengkapnya di Glyiv Kabar — dan lihat kenapa kami menulis 'terlacak', bukan 'terukur'."}], "sources": [{"a": "European Commission (2021). Screening of websites for 'greenwashing': half of green claims lack evidence (sweep 2020).", "u": "https://ec.europa.eu/commission/presscorner/detail/en/ip_21_269"}, {"a": "Poore, J. & Nemecek, T. (2018). Reducing food's environmental impacts through producers and consumers. Science, 360(6392).", "u": "https://www.science.org/doi/10.1126/science.aaq0216"}, {"a": "Directive (EU) 2024/825 — Empowering consumers for the green transition.", "u": "https://eur-lex.europa.eu/eli/dir/2024/825/oj"}, {"a": "GHG Protocol (WRI & WBCSD). Corporate Value Chain (Scope 3) Accounting and Reporting Standard.", "u": "https://ghgprotocol.org/standards/scope-3-standard"}]}, {"slug": "citra-satelit-terbuka-gratis", "topic": "Teknologi", "mood": "#1E5F8C", "title": "Citra satelit gratis: demokratisasi pemantauan iklim.", "dek": "Data terbuka Landsat dan Sentinel membuat siapa pun bisa memantau perubahan tutupan lahan — menurunkan biaya MRV yang dulu hanya terjangkau korporasi.", "hook": "Data satelit yang dulu eksklusif kini gratis untuk siapa saja — dan itu mengubah siapa yang boleh memantau iklim.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (USGS, ESA Copernicus, Science)", "read": 4, "blocks": [{"t": "lead", "x": "Dulu, memantau perubahan hutan dari luar angkasa adalah kemewahan. Satu citra satelit beresolusi tinggi bisa berharga ratusan dolar ⚠︎, dan praktis hanya lembaga besar serta korporasi yang mampu membelinya secara rutin. Hari ini, data yang secara mendasar sama bisa diunduh siapa pun — peneliti, LSM, petani, jurnalis — tanpa biaya sepeser pun."}, {"t": "p", "x": "Titik baliknya terjadi pada <b>2008</b>. Saat itu Survei Geologi Amerika (USGS) membuka seluruh arsip Landsat untuk diunduh gratis <a href=\"https://doi.org/10.1126/science.320.5879.1011a\">[1]</a>. Landsat — program bersama NASA dan USGS yang telah mengorbit sejak 1972 — memotret permukaan Bumi pada resolusi sekitar 30 meter dan mengunjungi kembali tiap lokasi kira-kira 16 hari sekali. Begitu gratis, pemakaiannya meledak."}, {"t": "p", "x": "Eropa menyusul lewat program <b>Copernicus</b>. Satelit kembar Sentinel-2 milik Badan Antariksa Eropa (ESA) memotret daratan pada resolusi hingga 10 meter dengan siklus kunjungan sekitar lima hari, dan datanya bebas serta terbuka bagi siapa saja <a href=\"https://sentinels.copernicus.eu/web/sentinel/missions/sentinel-2\">[2]</a>. Dua konstelasi ini — Landsat dan Sentinel — kini menjadi tulang punggung pemantauan tutupan lahan global."}, {"t": "pull", "x": "Ketika data pemantauan menjadi milik publik, biaya membuktikan perubahan tutupan lahan runtuh — dan MRV berhenti menjadi hak istimewa korporasi."}, {"t": "stat", "n": "2008", "l": "Tahun USGS membuka seluruh arsip Landsat tanpa biaya — memicu lonjakan pemakaian data satelit", "s": "Woodcock et al., Science 2008; USGS"}, {"t": "h2", "x": "Menurunkan biaya MRV"}, {"t": "p", "x": "MRV — pengukuran, pelaporan, dan verifikasi (<i>measurement, reporting, verification</i>) — adalah fondasi setiap klaim karbon yang serius. Biaya terbesarnya sering ada di langkah pertama: mengetahui apa yang benar-benar terjadi di lapangan. Citra terbuka memangkasnya. Global Forest Watch, misalnya, membangun peta kehilangan tutupan pohon dari citra Landsat lewat metode Hansen dkk. (2013) <a href=\"https://doi.org/10.1126/science.1244693\">[3]</a> — sehingga siapa pun bisa melihat di mana hutan menyusut, nyaris seketika."}, {"t": "p", "x": "Efeknya nyata. Organisasi kecil yang tak punya anggaran citra komersial kini bisa memetakan deforestasi, memantau kesehatan vegetasi lewat indeks seperti NDVI, atau menghitung perubahan tutupan lahan untuk proyek restorasi — pekerjaan yang satu dekade lalu menuntut kontrak mahal dengan penyedia data."}, {"t": "p", "x": "Tapi kejujuran menuntut batas. Satelit membaca tutupan lahan, bukan segala hal: awan menghalangi, resolusi punya limit, dan citra tak bisa membedakan hutan alam dari perkebunan tanpa data pendukung. Karena itu kami menyebut tutupan lahan <b>terlacak</b> — bukan otomatis setiap ton karbon <i>terukur</i>. Data terbuka menurunkan biaya pembuktian; ia tidak menghapus kebutuhan verifikasi lapangan."}, {"t": "p", "x": "Bagi Indonesia — dengan hutan dan lahan gambut yang menjadi pusat neraca karbon nasional — pergeseran ini penting. Pemantauan yang dulu terjangkau segelintir pihak kini bisa dilakukan komunitas, pemerintah daerah, hingga pelaku usaha kecil. Di Glyiv, citra terbuka inilah lapisan dasar dMRV kami: bukti yang bisa ditelusuri, bukan klaim yang harus dipercaya begitu saja."}], "story": [{"kind": "cover", "title": "Citra satelit gratis", "text": "Data terbuka Landsat dan Sentinel membuat siapa pun bisa memantau perubahan tutupan lahan — menurunkan biaya MRV yang dulu hanya terjangkau korporasi."}, {"kind": "hook", "title": "Dulu mewah, kini gratis", "text": "Citra yang dulu berharga ratusan dolar ⚠︎ kini bisa diunduh siapa saja, tanpa biaya."}, {"kind": "point", "title": "Titik balik 2008", "text": "USGS membuka seluruh arsip Landsat gratis. Pemakaian data satelit langsung meledak."}, {"kind": "point", "title": "Eropa menyusul", "text": "Sentinel-2 (Copernicus/ESA): resolusi hingga 10 meter, kunjungan ~5 hari, bebas dan terbuka."}, {"kind": "stat", "title": "Angka kunci", "big": "2008", "label": "Landsat dibuka gratis oleh USGS", "source": "Woodcock et al., Science 2008"}, {"kind": "point", "title": "Yang berubah", "text": "MRV yang dulu mahal kini terjangkau komunitas, LSM, pemda, dan usaha kecil. Tutupan lahan terlacak — bukan sekadar diklaim."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv Kabar", "text": "Citra terbuka jadi lapisan dasar dMRV Glyiv. Pelajari bagaimana bukti menggantikan klaim."}], "sources": [{"a": "Woodcock, C.E., et al. (2008). \"Free Access to Landsat Imagery.\" Science, 320(5879), 1011.", "u": "https://doi.org/10.1126/science.320.5879.1011a"}, {"a": "U.S. Geological Survey. \"Landsat Missions\" — data disediakan tanpa biaya.", "u": "https://www.usgs.gov/landsat-missions"}, {"a": "ESA Copernicus. \"Sentinel-2 Mission\" — data bebas dan terbuka.", "u": "https://sentinels.copernicus.eu/web/sentinel/missions/sentinel-2"}, {"a": "Hansen, M.C., et al. (2013). \"High-Resolution Global Maps of 21st-Century Forest Cover Change.\" Science, 342(6160), 850–853.", "u": "https://doi.org/10.1126/science.1244693"}]}, {"slug": "sawit-metana-pome", "topic": "Sektor", "mood": "#4F7A3A", "title": "Limbah sawit yang menguap jadi metana — dan bisa jadi energi.", "dek": "Di kolam-kolam terbuka pabrik sawit, limbah cair POME membusuk dan melepas metana — gas yang jauh lebih kuat dari CO2 — padahal gas yang sama bisa ditangkap jadi biogas untuk memangkas emisi sekaligus menyalakan listrik.", "hook": "Limbah sawit yang dibiarkan membusuk di kolam terbuka diam-diam melepas metana ke langit. Tangkap gasnya, dan kolam bau itu bisa menyalakan lampu.", "cover": "https://images.unsplash.com/photo-1625246333195-78d9c38ad449?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan IPCC, IEA & data publik", "read": 4, "blocks": [{"t": "lead", "x": "Di balik setiap ton minyak sawit yang diproduksi Indonesia, ada aliran yang jarang terlihat: limbah cair kental bernama POME. Di kebanyakan pabrik, ia dibiarkan mengalir ke kolam terbuka, membusuk pelan-pelan, lalu melepas metana ke udara. Yang menguap itu bukan sekadar bau — itu energi yang terbuang, dan iklim yang ikut terbebani."}, {"t": "p", "x": "POME (<b>palm oil mill effluent</b>) adalah sisa dari proses memeras minyak dari tandan buah sawit. Volumenya besar: setiap ton minyak sawit mentah bisa meninggalkan sekitar 2,5–3 meter kubik limbah cair ini ⚠︎. Karena kaya bahan organik, POME membusuk tanpa oksigen di kolam terbuka — dan justru proses pembusukan itulah yang memproduksi metana."}, {"t": "p", "x": "Metana bukan gas rumah kaca biasa. Dalam rentang 20 tahun, ia memerangkap panas sekitar <b>80 kali</b> lebih kuat dari CO2 <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">(IPCC AR6, 2021)</a>. Itu sebabnya Badan Energi Internasional menaksir metana bertanggung jawab atas hampir sepertiga kenaikan suhu global sejak era industri <a href=\"https://www.iea.org/reports/global-methane-tracker-2024\">(IEA)</a>. Membiarkannya menguap dari kolam limbah, dengan kata lain, adalah salah satu emisi paling mahal yang paling mudah dicegah."}, {"t": "stat", "n": "±80×", "l": "daya panas metana dibanding CO2 dalam rentang 20 tahun", "s": "IPCC AR6, 2021"}, {"t": "h2", "x": "Dari kolam yang membusuk ke listrik"}, {"t": "p", "x": "Solusinya tidak eksotis. Kolam POME ditutup dengan membran, atau dipasangi <b>digester anaerobik</b>, sehingga gas yang selama ini lepas justru tertampung. Biogas hasilnya — kira-kira separuhnya metana — lalu dibakar di mesin gas untuk memutar generator listrik. Satu aliran limbah yang tadinya masalah berubah jadi bahan bakar: menekan tagihan solar genset pabrik, atau bahkan dijual ke jaringan setempat."}, {"t": "p", "x": "Manfaatnya ganda. Menutup kolam juga menahan pencemaran air — POME yang membusuk terbuka membawa beban organik tinggi yang bisa mencemari sungai di sekitarnya. Jadi menangkap metana sekaligus membereskan dua masalah lingkungan dari satu titik yang sama."}, {"t": "pull", "x": "Yang menguap dari kolam limbah bukan sekadar bau. Itu energi yang belum ditangkap — dan iklim yang bisa dihitung."}, {"t": "p", "x": "Yang membuat ini belum jadi standar bukan teknologinya, tapi hitung-hitungannya. Menutup kolam dan memasang mesin gas butuh modal awal, dan tidak semua pabrik punya akses pembiayaan atau jaringan untuk menjual listriknya. Indonesia punya lebih dari seribu pabrik sawit ⚠︎, tapi hanya sebagian kecil yang sudah menangkap metananya — celah yang justru masuk dalam rencana iklim nasional di sektor limbah dan energi <a href=\"https://unfccc.int/NDCREG\">(NDC Indonesia)</a>."}, {"t": "p", "x": "Bagi pabrik, ini bukan sekadar urusan kepatuhan. Biogas memangkas biaya bahan bakar, dan pengurangan emisi yang <b>terlacak</b> bisa menjadi kontribusi karbon yang bisa diaudit — bukan klaim 'netral karbon', melainkan angka yang bisa dipertanggungjawabkan. Langkah pertamanya sederhana: mengukur berapa banyak metana yang benar-benar lepas dari kolam, sebelum memutuskan cara menangkapnya."}], "story": [{"kind": "cover", "title": "Limbah sawit yang menguap jadi metana", "text": "Di kolam-kolam terbuka pabrik sawit, limbah cair POME membusuk dan melepas metana — gas yang jauh lebih kuat dari CO2 — padahal gas yang sama bisa ditangkap jadi biogas untuk memangkas emisi sekaligus menyalakan listrik."}, {"kind": "hook", "title": "Kolam bau yang diam-diam memanaskan bumi", "text": "Limbah sawit yang dibiarkan membusuk di kolam terbuka melepas metana ke langit. Tangkap gasnya, dan kolam itu bisa menyalakan lampu."}, {"kind": "point", "title": "Apa itu POME?", "text": "Limbah cair pabrik sawit yang dibiarkan membusuk di kolam terbuka. Setiap ton minyak sawit meninggalkan sekitar 2,5–3 m³ ⚠︎."}, {"kind": "point", "title": "Metananya bukan main-main", "text": "Pembusukan tanpa oksigen melepas metana — sekitar 80× lebih kuat dari CO2 dalam rentang 20 tahun."}, {"kind": "stat", "title": "Seberapa kuat metana", "big": "±80×", "label": "daya panas metana vs CO2 (20 tahun)", "source": "IPCC AR6, 2021"}, {"kind": "point", "title": "Ubah jadi listrik", "text": "Tutup kolam, tangkap biogasnya, bakar di mesin gas. Limbah jadi bahan bakar — dan emisi yang terlacak."}, {"kind": "end", "title": "Selami lebih dalam", "text": "Cara mengukur & memangkas emisi sawit, jujur dan bisa diaudit. Baca selengkapnya di Glyiv Kabar."}], "sources": [{"a": "IPCC (2021). AR6 Working Group I, Bab 7 — Global Warming Potentials (GWP-20 & GWP-100 metana).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "IEA (2024). Global Methane Tracker 2024.", "u": "https://www.iea.org/reports/global-methane-tracker-2024"}, {"a": "Kementerian LHK / UNFCCC. Enhanced Nationally Determined Contribution (NDC) Republik Indonesia, 2022.", "u": "https://unfccc.int/NDCREG"}]}, {"slug": "nikel-batu-bara-tersembunyi", "topic": "Sektor", "mood": "#B5623A", "title": "Nikel untuk baterai, tapi dilelehkan dengan batu bara.", "dek": "Indonesia menambang sekitar separuh nikel dunia — logam inti baterai kendaraan listrik. Tapi banyak smelternya ditenagai PLTU captive, sehingga 'logam hijau' itu lahir dengan jejak karbon proses yang sering tak terlihat.", "hook": "Baterai mobil listrikmu mungkin lahir dari tungku berbahan bakar batu bara. Selamat datang di sisi tersembunyi 'logam hijau'.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (USGS, IEA, Global Energy Monitor)", "read": 4, "blocks": [{"t": "lead", "x": "Nikel adalah salah satu logam paling dibutuhkan transisi energi — inti dari baterai kendaraan listrik. Indonesia kini menambang sekitar separuh pasokan dunia. Tapi ada ironi yang jarang muncul di brosur 'logam hijau': banyak nikel Indonesia dilelehkan dengan listrik dari batu bara."}, {"t": "p", "x": "Nikel laterit Indonesia tidak bisa langsung dipakai. Ia harus dilebur dalam tanur bersuhu tinggi — proses yang haus energi. Sebagian besar smelter berdiri di kawasan industri seperti Morowali (IMIP) dan Weda Bay (IWIP), yang ditenagai <b>PLTU captive</b>: pembangkit batu bara milik sendiri, di luar jaringan PLN dan di luar banyak target pensiun dini."}, {"t": "p", "x": "Dua jalur pemrosesan mendominasi. <b>RKEF</b> (rotary kiln–electric furnace) menghasilkan feronikel dan nickel pig iron; <b>HPAL</b> menghasilkan bahan kelas baterai. Keduanya intensif energi — dan ketika energinya batu bara, jejak karbon prosesnya melonjak. <a href=\"https://www.iea.org/reports/the-role-of-critical-minerals-in-clean-energy-transitions\">IEA</a> mencatat nikel yang diproses dengan listrik batu bara bisa punya intensitas emisi jauh lebih tinggi ⚠︎ ketimbang jalur berbasis energi bersih."}, {"t": "p", "x": "<a href=\"https://globalenergymonitor.org/projects/global-coal-plant-tracker/\">Global Energy Monitor</a> menempatkan Indonesia sebagai salah satu penyumbang pertumbuhan PLTU captive terbesar dunia, sebagian besar untuk industri logam ⚠︎ — kapasitas batu bara yang justru bertambah saat sebagian besar dunia menua-kannya."}, {"t": "pull", "x": "Logam yang menyalakan mobil listrik bisa lahir dari tungku yang menyalakan batu bara. 'Hijau' di hilir tak menjamin bersih di hulu."}, {"t": "stat", "n": "±50%", "l": "pangsa Indonesia dalam produksi nikel tambang dunia (2023)", "s": "USGS, Mineral Commodity Summaries 2024"}, {"t": "h2", "x": "Ironi 'logam hijau'"}, {"t": "p", "x": "Persoalannya bukan bahwa nikel itu jahat, tapi bahwa jejak karbon prosesnya sering tak terlihat oleh pembeli. Sebuah baterai bisa dipasarkan 'bersih' di Eropa, sementara emisi terbesarnya justru tertanam jauh di hulu — di tanur peleburan. Ketika <a href=\"https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en\">CBAM</a> dan aturan uji tuntas baterai UE mulai menagih emisi tertanam ⚠︎, angka yang tak terlacak berubah menjadi risiko pasar."}, {"t": "p", "x": "Yang bisa dilakukan bukan menyangkal, tapi <b>melacak</b>: memetakan emisi per ton nikel — dari tambang, peleburan, hingga pemurnian — dengan metodologi yang bisa diaudit. Data itu bukan sekadar kepatuhan; ia yang memisahkan produsen yang siap pasar rendah-karbon dari yang tertinggal. Kontribusi pada dekarbonisasi dimulai dari kejujuran angka."}], "story": [{"kind": "cover", "title": "Nikel untuk baterai — dilelehkan dengan batu bara.", "text": "Indonesia menambang sekitar separuh nikel dunia. Tapi banyak smelternya ditenagai PLTU captive, sehingga 'logam hijau' itu lahir dengan jejak karbon proses yang sering tak terlihat."}, {"kind": "hook", "title": "Sisi tersembunyi bateraimu", "text": "Logam inti mobil listrik bisa lahir dari tungku berbahan bakar batu bara."}, {"kind": "point", "title": "Laterit harus dilebur", "text": "Nikel Indonesia tak bisa langsung dipakai — harus dilebur di tanur suhu tinggi yang haus energi."}, {"kind": "point", "title": "PLTU captive", "text": "Smelter di Morowali & Weda Bay banyak ditenagai batu bara milik sendiri, di luar jaringan PLN."}, {"kind": "stat", "title": "Separuh nikel dunia", "big": "±50%", "label": "pangsa Indonesia dalam produksi nikel tambang dunia (2023)", "source": "USGS Mineral Commodity Summaries, 2024"}, {"kind": "quote", "title": "Hijau di hilir, bukan di hulu", "text": "'Hijau' di hilir tak menjamin bersih di hulu."}, {"kind": "end", "title": "Jejak yang bisa dilacak", "text": "Dekarbonisasi dimulai dari kejujuran angka. Baca artikel lengkapnya di Glyiv Kabar."}], "sources": [{"a": "U.S. Geological Survey (2024). Mineral Commodity Summaries: Nickel.", "u": "https://pubs.usgs.gov/periodicals/mcs2024/mcs2024-nickel.pdf"}, {"a": "International Energy Agency (2021). The Role of Critical Minerals in Clean Energy Transitions.", "u": "https://www.iea.org/reports/the-role-of-critical-minerals-in-clean-energy-transitions"}, {"a": "Global Energy Monitor (2023). Global Coal Plant Tracker — captive coal & Indonesia.", "u": "https://globalenergymonitor.org/projects/global-coal-plant-tracker/"}, {"a": "European Commission, DG TAXUD. Carbon Border Adjustment Mechanism (CBAM).", "u": "https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en"}]}, {"slug": "semen-klinker-masalahnya", "topic": "Sektor", "mood": "#B5623A", "title": "Semen: sebagian besar emisinya lahir dari kimia, bukan bahan bakar.", "dek": "Mayoritas CO₂ semen tidak keluar dari cerobong, melainkan dari batu kapur yang dipecah menjadi klinker — dan itu sebabnya menurunkan rasio klinker, bukan sekadar mengganti bahan bakar, yang jadi kunci sesungguhnya.", "hook": "Bukan cerobongnya yang jadi soal utama — tapi batunya. Sebagian besar emisi semen lahir dari reaksi kimia, bukan dari api.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, GCCA, Chatham House)", "read": 5, "blocks": [{"t": "lead", "x": "Bayangkan polusi dari sebuah pabrik semen, dan yang terbayang biasanya cerobong: batu bara dibakar, asap mengepul. Tapi sebagian besar CO₂ semen tidak keluar dari situ. Ia lahir dari batunya sendiri — dari reaksi kimia yang terjadi jauh sebelum soal bahan bakar ikut bicara."}, {"t": "p", "x": "Inti semen adalah <b>klinker</b>, dibuat dengan memanaskan batu kapur hingga sekitar 1.450°C. Pada suhu itu kalsium karbonat (CaCO₃) pecah menjadi kapur (CaO) dan gas CO₂ — reaksi bernama <b>kalsinasi</b>. Gas itu terlepas karena kimianya, bukan karena apinya. Artinya: sebersih apa pun bahan bakar tungku, CO₂ dari batu kapur tetap keluar. Kajian <a href=\"https://www.chathamhouse.org/2018/06/making-concrete-change-innovation-low-carbon-cement-and-concrete\">Chatham House</a> menegaskan bahwa proses inilah, bukan pembakaran, sumber terbesarnya."}, {"t": "p", "x": "Skalanya besar. Produksi semen menyumbang sekitar <b>7% emisi CO₂ global</b> dan termasuk sektor tersulit didekarbonisasi, justru karena emisinya menempel pada reaksi kimia — bukan sekadar pilihan energi yang bisa diganti. <a href=\"https://www.iea.org/energy-system/industry/cement\">IEA</a> menggolongkannya sebagai industri <em>hard-to-abate</em>."}, {"t": "stat", "n": "±60%", "l": "emisi CO₂ semen berasal dari kalsinasi batu kapur — reaksi kimia, bukan bahan bakar", "s": "IEA, Cement (2024); sebagian sumber menyebut hingga dua-pertiga"}, {"t": "pull", "x": "Ganti batu bara dengan biomassa, dan Anda tetap menyisakan mayoritas emisinya — kimianya tak ikut berganti."}, {"t": "p", "x": "Itu sebabnya strategi yang hanya berfokus pada energi — efisiensi tungku, beralih ke biomassa atau bahan bakar limbah — penting, tapi berhenti di sekitar sepertiga hingga separuh masalah. Sisanya, bagian kimia, hanya bisa disentuh lewat tiga jalur: memakai lebih sedikit klinker, mengubah kimia semennya, atau menangkap CO₂ di ujung cerobong lewat CCUS yang masih mahal dan langka ⚠︎."}, {"t": "h2", "x": "Kuncinya bukan bahan bakar, tapi rasio klinker"}, {"t": "p", "x": "Karena klinker adalah jantung karbon semen, cara paling ampuh menurunkan emisi adalah mengurangi porsinya — inilah <b>rasio klinker</b> (clinker-to-cement ratio). Sebagian klinker bisa digantikan pengikat lain: terak tanur (slag), abu terbang, batu kapur giling, atau lempung terkalsinasi. Peta jalan <a href=\"https://gccassociation.org/concretefuture/\">GCCA menuju Net Zero</a> menempatkan penurunan rasio klinker sebagai salah satu tuas utamanya."}, {"t": "p", "x": "Angkanya konkret. Rata-rata global rasio klinker kini sekitar <b>0,72</b>; skenario nol-bersih menuntutnya turun ke sekitar 0,65 pada 2030 ⚠︎ dan lebih rendah lagi setelahnya. Setiap poin penurunan berarti lebih sedikit batu kapur yang dikalsinasi — dan lebih sedikit CO₂ yang tak bisa ditawar."}, {"t": "p", "x": "Bagi Indonesia — produsen semen besar sekaligus salah satu sektor yang kelak tersentuh CBAM ⚠︎ — implikasinya jelas: mengganti bahan bakar tungku itu perlu, tapi tak menyentuh mayoritas masalah. Yang lebih menentukan adalah melacak emisi proses dan rasio klinker yang sebenarnya per produk, lalu menjadikannya dasar keputusan. Karbon yang <b>terlacak</b> per ton semen bukan sekadar laporan — ia peta menuju kontribusi penurunan yang nyata."}], "story": [{"kind": "cover", "title": "Semen: emisinya lahir dari kimia, bukan bahan bakar", "text": "Mayoritas CO₂ semen tidak keluar dari cerobong, melainkan dari batu kapur yang dipecah menjadi klinker — dan itu sebabnya menurunkan rasio klinker jadi kunci sesungguhnya."}, {"kind": "hook", "title": "Bukan cerobongnya. Batunya.", "text": "Sebagian besar CO₂ semen keluar dari batu kapur yang dipanaskan — sebelum bahan bakar apa pun ikut bicara."}, {"kind": "point", "title": "Reaksi yang tak bisa dihindari", "text": "Batu kapur (CaCO₃) dipanaskan ~1.450°C → kapur + gas CO₂. Namanya kalsinasi. Gas ini lepas karena kimianya, apa pun bahan bakarnya."}, {"kind": "stat", "title": "Angka kuncinya", "big": "±60%", "label": "emisi CO₂ semen dari kalsinasi, bukan bahan bakar", "source": "IEA, Cement (2024)"}, {"kind": "point", "title": "Kuncinya: rasio klinker", "text": "Kurangi porsi klinker dengan slag, abu terbang, batu kapur giling, atau lempung terkalsinasi — sejalan peta jalan GCCA."}, {"kind": "quote", "title": "Intinya", "text": "Ganti batu baranya, kimianya tetap sama."}, {"kind": "end", "title": "Ukur dulu, baru pangkas", "text": "Glyiv membantu melacak emisi proses dan rasio klinker per produk. Baca Kabar selengkapnya, atau gabung ekosistem karbon Glyiv."}], "sources": [{"a": "IEA (2024). Cement — Energy System / Industry. International Energy Agency, Paris.", "u": "https://www.iea.org/energy-system/industry/cement"}, {"a": "GCCA (2021). Concrete Future — The GCCA 2050 Cement and Concrete Industry Roadmap for Net Zero Concrete.", "u": "https://gccassociation.org/concretefuture/"}, {"a": "Lehne, J. & Preston, F. (2018). Making Concrete Change: Innovation in Low-carbon Cement and Concrete. Chatham House.", "u": "https://www.chathamhouse.org/2018/06/making-concrete-change-innovation-low-carbon-cement-and-concrete"}, {"a": "Andrew, R.M. (2019). Global CO₂ emissions from cement production, 1928–2018. Earth System Science Data, 11, 1675–1710.", "u": "https://essd.copernicus.org/articles/11/1675/2019/"}]}, {"slug": "baja-hijau-hidrogen", "topic": "Sektor", "mood": "#B5623A", "title": "Baja tanpa batu bara: mimpi hidrogen yang mulai nyata.", "dek": "Hampir setiap ton baja lahir dari batu bara yang dipakai bukan sebagai bahan bakar, melainkan sebagai bahan kimia untuk merampas oksigen dari bijih besi — dan reduksi berbasis hidrogen hijau kini mulai menawarkan jalan keluar yang nyata, bukan sekadar wacana.", "hook": "Batu bara di dalam baja bukan bahan bakar — ia bahan kimia. Dan hidrogen mulai menggantikannya.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan worldsteel, IEA & proyek HYBRIT", "read": 4, "blocks": [{"t": "lead", "x": "Baja ada di mana-mana: rangka gedung, rel kereta, sasis mobil, bahkan menara turbin angin. Tapi hampir setiap ton baja yang kita pakai lahir dari batu bara — dan bukan sekadar sebagai bahan bakar. Karbon dari kokas dipakai untuk merampas oksigen dari bijih besi, dan yang terlepas ke udara adalah karbon dioksida. Mengganti karbon itu dengan hidrogen adalah salah satu ide dekarbonisasi paling ambisius dekade ini."}, {"t": "p", "x": "Rute dominan dunia — tanur tinggi dan tungku oksigen dasar (BF-BOF) — memasok sekitar <b>70%</b> baja global dan bertumpu pada kokas batu bara. Reaksinya sederhana, dan justru di situ letak persoalannya: bijih besi ditambah karbon menghasilkan besi ditambah CO2. Karena karbon berada di jantung reaksi, memperbaiki efisiensi energi saja tak akan pernah membawa emisi ke nol."}, {"t": "stat", "n": "~1,9 ton", "l": "CO2 per ton baja kasar (rata-rata global)", "s": "worldsteel, 2021"}, {"t": "p", "x": "Dikalikan produksi tahunan yang mendekati 1,9 miliar ton, industri baja menyumbang sekitar <b>7–9%⚠︎</b> emisi CO2 global — dan <a href=\"https://www.iea.org/energy-system/industry/steel\">IEA</a> menempatkannya di antara sektor yang paling sulit didekarbonisasi."}, {"t": "h2", "x": "Membalik kimianya"}, {"t": "p", "x": "Jalur hidrogen membalik reaksi itu. Alih-alih karbon, gas hidrogen yang dipakai untuk mereduksi bijih besi; produk sampingannya bukan CO2, melainkan air. Besi hasil reduksi langsung (DRI) lalu dilebur dalam tungku busur listrik. Bila hidrogennya <b>hijau</b> — dari elektrolisis bertenaga listrik terbarukan — dan listriknya bersih, emisi sepanjang rantai bisa ditekan drastis, mendekati nol."}, {"t": "p", "x": "Ini bukan lagi teori. Pada 2021, proyek <a href=\"https://www.hybritdevelopment.se/en/\">HYBRIT</a> di Swedia — kolaborasi SSAB, LKAB, dan Vattenfall — mengirim batch pertama baja yang mereka sebut 'bebas fosil', hasil reduksi hidrogen, ke Volvo. Di Boden, perusahaan Stegra (dahulu H2 Green Steel) tengah membangun pabrik skala komersial pertama yang dirancang di sekitar hidrogen hijau. Jerman menyusul lewat SALCOS dan tkH2Steel."}, {"t": "pull", "x": "Ganti karbon dengan hidrogen, dan yang keluar dari cerobong bukan lagi karbon dioksida — melainkan uap air."}, {"t": "p", "x": "Tetap ada jarak antara demonstrasi dan transformasi. Hidrogen hijau masih mahal dan haus listrik: satu pabrik baja skala penuh membutuhkan gigawatt kapasitas terbarukan baru. Selama harganya belum turun dan listrik bersih belum melimpah, baja hidrogen masih lebih mahal daripada baja batu bara⚠︎. Yang menggeser hitungannya adalah harga karbon — termasuk <a href=\"https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en\">CBAM</a> Uni Eropa, yang menagih emisi tertanam di perbatasan sejak 2026."}, {"t": "p", "x": "Bagi Indonesia — produsen baja yang tumbuh sekaligus tujuan investasi logam — arah ini penting dibaca lebih awal. Baja rendah karbon bukan soal 'netral karbon' hari ini, melainkan soal <b>kontribusi</b> yang bisa dipertanggungjawabkan: jejak karbon per ton yang terlacak, terverifikasi, dan siap diaudit saat pembeli global mulai bertanya. Mimpi baja tanpa batu bara belum sepenuhnya nyata — tapi untuk pertama kalinya, ia sudah punya alamat pabrik."}], "story": [{"kind": "cover", "title": "Baja tanpa batu bara", "text": "Reduksi berbasis hidrogen hijau menawarkan jalan keluar dari salah satu industri paling sulit didekarbonisasi — dan pabrik pertamanya sudah berdiri."}, {"kind": "hook", "title": "Rahasia kotor baja", "text": "Batu bara di dalam baja bukan bahan bakar — ia bahan kimia. Dan hidrogen mulai menggantikannya."}, {"kind": "point", "title": "Bahan kimia, bukan bahan bakar", "text": "Karbon dari kokas dipakai merampas oksigen dari bijih besi. Hasilnya: besi — dan CO2. Efisiensi energi saja tak cukup."}, {"kind": "stat", "title": "Jejak karbonnya", "big": "~1,9 ton", "label": "CO2 per ton baja kasar (rata-rata global)", "source": "worldsteel, 2021"}, {"kind": "point", "title": "Hidrogen membalik reaksinya", "text": "Pakai hidrogen, bukan karbon. Produk sampingannya air, bukan CO2. HYBRIT sudah mengirim baja 'bebas fosil' pertama ke Volvo pada 2021."}, {"kind": "quote", "title": "Yang keluar dari cerobong", "text": "Ganti karbon dengan hidrogen, dan yang keluar bukan lagi karbon dioksida — melainkan uap air."}, {"kind": "end", "title": "Baru mimpi? Tidak lagi.", "text": "Baja hijau belum murah, tapi pabriknya sudah berdiri. Baca kabar selengkapnya dan ikuti Glyiv."}], "sources": [{"a": "worldsteel (2021). Climate change and the production of iron and steel — rata-rata ~1,9 ton CO2 per ton baja.", "u": "https://worldsteel.org/"}, {"a": "IEA (2023). Steel — Energy System / Industry tracking (baja ~7% emisi CO2 sektor energi).", "u": "https://www.iea.org/energy-system/industry/steel"}, {"a": "HYBRIT (SSAB, LKAB, Vattenfall) (2021). The world's first fossil-free steel ready for delivery.", "u": "https://www.hybritdevelopment.se/en/"}, {"a": "European Commission, DG TAXUD. Carbon Border Adjustment Mechanism (CBAM).", "u": "https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en"}]}, {"slug": "data-center-haus-listrik", "topic": "Sektor", "mood": "#0B2471", "title": "Pusat data: nafsu listrik yang tumbuh diam-diam.", "dek": "IEA memperkirakan pusat data menyerap sekitar 1,5% listrik dunia pada 2024 — dan angkanya bisa berlipat menjelang 2030 seiring ledakan AI. Indonesia pun kini jadi tujuan investasi baru, di atas jaringan listrik yang masih banyak batu bara.", "hook": "Setiap kali AI menjawab, ada server yang menyala di suatu tempat — dan tagihan listriknya sedang meledak.", "cover": "https://images.unsplash.com/photo-1532601224476-15c79f2f7a51?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan laporan IEA Energy and AI 2025 dan sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Sebagian besar dari kita membayangkan internet sebagai sesuatu yang ringan — awan, sinyal, layar yang menyala. Di baliknya ada bangunan tanpa jendela berisi ribuan server yang haus listrik sepanjang waktu, tak pernah tidur. Dan nafsu makannya sedang tumbuh, diam-diam."}, {"t": "p", "x": "Menurut Badan Energi Internasional (<a href=\"https://www.iea.org/reports/energy-and-ai/energy-demand-from-ai\">IEA</a>), pusat data di seluruh dunia menyerap sekitar <b>415 terawatt-jam</b> listrik pada 2024 — kira-kira <b>1,5% dari konsumsi listrik global</b>. Setara kebutuhan listrik sebuah negara berukuran sedang, dan sebagian besarnya tak pernah terlihat oleh kita yang mengetik di layar."}, {"t": "stat", "n": "~1,5%", "l": "porsi pusat data dari konsumsi listrik dunia (≈415 TWh, 2024)", "s": "IEA, Energy and AI, 2025"}, {"t": "p", "x": "Yang membuat cerita ini mendesak adalah kecepatannya. IEA memperkirakan konsumsi listrik pusat data bisa <b>lebih dari dua kali lipat</b> menjelang 2030, menembus sekitar <b>945 TWh⚠︎</b> — kurang lebih setara total konsumsi listrik Jepang hari ini. Diproyeksikan tumbuh sekitar 15% per tahun, empat kali lebih cepat daripada sektor lain. Pendorong utamanya satu kata: <b>AI</b>."}, {"t": "p", "x": "Perbedaannya besar. Satu permintaan ke model AI generatif bisa memakan energi berkali lipat dibanding satu pencarian web biasa — dan miliaran permintaan itu menumpuk. IEA memperkirakan konsumsi listrik server khusus AI (<i>accelerated server</i>) tumbuh sekitar 30% per tahun, jauh melampaui server konvensional. Kecerdasan yang terasa gratis di ujung jari punya ongkos yang nyata di ujung yang lain."}, {"t": "pull", "x": "Setiap prompt AI punya bayangan listrik. Yang tak terlacak, tak akan pernah bisa dikurangi."}, {"t": "h2", "x": "Indonesia masuk peta"}, {"t": "p", "x": "Gelombang ini sudah mendarat di sini. Indonesia menjadi tujuan investasi pusat data baru. Microsoft, misalnya, mengumumkan rencana investasi <b>USD 1,7 miliar⚠︎</b> untuk infrastruktur cloud dan AI pada April 2024, berlabuh di kampus pusat data di Karawang, Jawa Barat <a href=\"https://news.microsoft.com/apac/2024/04/30/microsoft-announces-us1-7-billion-investment-to-advance-indonesias-cloud-and-ai-ambitions/\">1</a>. Daya tariknya jelas: pasar Asia Tenggara yang tumbuh, lahan tersedia, dan permintaan digital yang meledak."}, {"t": "p", "x": "Tapi ada catatan jujur. Sebagian besar listrik Indonesia masih bersumber dari batu bara — bauran pembangkit masih didominasi fosil. Artinya, setiap megawatt yang diminum pusat data baru datang dengan jejak karbon yang nyata, kecuali dipasok energi terbarukan dan efisiensi yang ketat. Pusat data bisa jadi mesin ekonomi, tapi juga sumber emisi yang tumbuh diam-diam — dan sejumlah pengamat menilai ambisi AI kita berlari lebih cepat dari kesiapan jaringan listriknya."}, {"t": "p", "x": "Di sinilah pengukuran menjadi penting. Sebelum bicara 'netral karbon', langkah pertama adalah membuat konsumsi energi dan emisinya <b>terlacak</b> — per fasilitas, per beban kerja, per jam. Pusat data yang tahu persis dari mana listriknya datang bisa memilih waktu, lokasi, dan sumber yang lebih bersih; yang tak mengukur hanya bisa menebak. Nafsu listrik yang tumbuh diam-diam ini tak akan berhenti — tapi ia bisa dibuat kasat mata, dan dari situ, diarahkan."}], "story": [{"kind": "cover", "title": "Pusat data: nafsu listrik yang tumbuh diam-diam.", "text": "IEA memperkirakan pusat data menyerap ~1,5% listrik dunia pada 2024 — dan bisa berlipat menjelang 2030 seiring ledakan AI. Indonesia pun jadi tujuan investasi baru."}, {"kind": "hook", "title": "Awan yang berat", "text": "Setiap kali AI menjawab, ada server yang menyala di suatu tempat — dan tagihan listriknya sedang meledak."}, {"kind": "point", "title": "Nafsu yang tumbuh cepat", "text": "IEA: pusat data ≈415 TWh (1,5% listrik dunia) pada 2024, bisa lipat dua jadi ~945 TWh⚠︎ menjelang 2030 — didorong AI."}, {"kind": "point", "title": "Indonesia kebagian", "text": "Tujuan investasi baru; Microsoft rencanakan USD 1,7 miliar⚠︎ (2024, Karawang). Tapi listrik kita masih banyak batu bara."}, {"kind": "stat", "title": "Skalanya hari ini", "big": "~1,5%", "label": "porsi pusat data dari konsumsi listrik dunia (2024)", "source": "IEA, Energy and AI, 2025"}, {"kind": "quote", "title": "Bayangan listrik", "text": "Yang tak terlacak, tak akan pernah bisa dikurangi."}, {"kind": "end", "title": "Buat karbonnya kasat mata", "text": "Baca ulasan lengkapnya, dan kenali cara Glyiv melacak jejak energi jadi angka yang bisa dipertanggungjawabkan."}], "sources": [{"a": "IEA (2025). Energy and AI — Energy demand from AI. International Energy Agency.", "u": "https://www.iea.org/reports/energy-and-ai/energy-demand-from-ai"}, {"a": "IEA (2025). Energy and AI — Executive summary. International Energy Agency.", "u": "https://www.iea.org/reports/energy-and-ai/executive-summary"}, {"a": "Microsoft (2024). Microsoft announces US$1.7 billion investment to advance Indonesia's cloud and AI ambitions.", "u": "https://news.microsoft.com/apac/2024/04/30/microsoft-announces-us1-7-billion-investment-to-advance-indonesias-cloud-and-ai-ambitions/"}]}, {"slug": "rumah-sakit-gas-anestesi", "topic": "Sektor", "mood": "#6B4E8C", "title": "Jejak karbon rumah sakit: dimulai dari gas anestesi.", "dek": "Layanan kesehatan menyumbang sekitar 4–5%⚠︎ emisi dunia — dan salah satu titik pemangkasan terbesar bersembunyi di ruang operasi, pada gas bius yang lolos ke atmosfer tanpa pernah terurai.", "hook": "Ada karbon yang menguap begitu saja di ruang operasi — dan hampir tak ada yang menghitungnya.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (HCWH, NHS England, literatur anestesi)", "read": 4, "blocks": [{"t": "lead", "x": "Rumah sakit adalah tempat menyembuhkan — sekaligus salah satu bangunan paling rakus energi yang kita miliki: menyala 24 jam, penuh alat steril, cold-chain vaksin, dan ventilasi tanpa henti. Yang jarang disadari, sebagian jejak karbonnya justru mengalir keluar begitu saja lewat masker anestesi di ruang operasi."}, {"t": "p", "x": "Secara global, layanan kesehatan menyumbang sekitar <b>4–5%⚠︎</b> emisi gas rumah kaca — bila ia sebuah negara, ia akan menjadi emitter terbesar kelima di dunia <a href=\"https://noharm-global.org/documents/health-care-climate-footprint-report\" target=\"_blank\" rel=\"noopener\">[1]</a>. Sebagian besar berasal dari energi dan rantai pasok: obat, alat sekali pakai, makanan. Tapi ada satu sumber yang unik — gas anestesi volatil yang, setelah membius pasien, sebagian besar dihembuskan kembali <b>tanpa terurai</b> dan lolos langsung ke atmosfer."}, {"t": "h2", "x": "Mengapa satu gas jadi sorotan"}, {"t": "p", "x": "Tidak semua gas bius setara. Diukur dengan potensi pemanasan global 100 tahun (GWP100), <b>desflurane</b> bernilai 2.540 — artinya 1 kg gas ini setara sekitar 2,5 ton CO₂ <a href=\"https://pubmed.ncbi.nlm.nih.gov/20519425/\" target=\"_blank\" rel=\"noopener\">[2]</a>. Untuk efek klinis yang setara, sevoflurane hanya sekitar 130 — desflurane kira-kira <b>20 kali lebih memanaskan</b>, dan bertahan ~14 tahun di atmosfer. Gas gelak (N₂O) lebih 'ringan' per kilogram (GWP100 273⚠︎), tapi tetap masalah karena kebocoran pipa dan umur atmosfernya lebih dari seabad."}, {"t": "bars", "h": [0.05, 0.11, 0.2, 1], "cap": "GWP100 relatif empat gas — sevoflurane · N₂O · isoflurane · desflurane (skala terhadap desflurane = 1). Sumber: literatur atmosfer & anestesi; IPCC AR6 untuk N₂O."}, {"t": "pull", "x": "Gas yang membius pasien selama satu jam bisa ikut menghangatkan planet bertahun-tahun setelahnya."}, {"t": "p", "x": "Kabar baiknya, ini termasuk emisi yang paling mudah dipangkas tanpa mengorbankan mutu klinis. Pada 2023 NHS Inggris memutuskan menghentikan desflurane hampir sepenuhnya mulai awal 2024 — langkah yang diperkirakan memangkas sekitar 40 ribu ton CO₂ per tahun, setara listrik ~11.000 rumah <a href=\"https://www.england.nhs.uk/greenernhs/2023/01/putting-anaesthetic-emissions-to-bed/\" target=\"_blank\" rel=\"noopener\">[3]</a>. Pemakaiannya turun dari lebih dari 20% seluruh gas bius (2018/19) menjadi sekitar 3% (2022/23). Substitusi ke sevoflurane, teknik aliran-rendah, hingga menangkap gas buang adalah quick win yang nyata."}, {"t": "p", "x": "Bagi rumah sakit Indonesia, titik awalnya bukan klaim 'netral karbon', melainkan membuat jejak ini <b>terlacak</b>: berapa liter desflurane dibanding sevoflurane yang terpakai, berapa N₂O yang bocor, berapa energi HVAC ruang operasi. Dari data itu, kontribusi penurunan bisa dihitung, diaudit, dan diurutkan berdasarkan rupiah maupun ton CO₂. Gas anestesi hanyalah pintu masuk — tapi salah satu pintu yang paling jarang dilihat."}], "story": [{"kind": "cover", "title": "Jejak karbon rumah sakit", "text": "Layanan kesehatan menyumbang sekitar 4–5%⚠︎ emisi dunia — dan salah satu titik pemangkasan terbesar bersembunyi di ruang operasi, pada gas bius yang lolos ke atmosfer tanpa pernah terurai."}, {"kind": "hook", "title": "Sebagian karbon RS mengalir keluar lewat masker bius", "text": "Bukan cuma listrik atau limbah medis. Ruang operasi menyimpan emisi yang jarang dilihat."}, {"kind": "point", "title": "Sumber yang jarang disadari", "text": "Gas anestesi volatil sebagian besar dihembuskan kembali tanpa terurai — langsung lolos ke atmosfer."}, {"kind": "point", "title": "Tak semua gas bius sama", "text": "Desflurane kira-kira 20x lebih memanaskan dibanding sevoflurane untuk efek klinis setara, dan bertahan ~14 tahun."}, {"kind": "stat", "title": "Nilai GWP100 desflurane", "big": "2.540", "label": "1 kg desflurane ≈ 2,5 ton CO₂", "source": "Literatur atmosfer & anestesi; IPCC AR6"}, {"kind": "point", "title": "Bisa dipangkas tanpa turunkan mutu", "text": "NHS Inggris menghentikan desflurane sejak awal 2024 — hemat ~40 ribu ton CO₂/tahun, setara listrik ~11.000 rumah."}, {"kind": "end", "title": "Mulai dari yang terlacak", "text": "Ukur dulu, klaim belakangan. Baca versi lengkapnya di Kabar Glyiv."}], "sources": [{"a": "Health Care Without Harm & Arup (2019). Health Care's Climate Footprint: How the Health Sector Contributes to the Global Climate Crisis.", "u": "https://noharm-global.org/documents/health-care-climate-footprint-report"}, {"a": "Sulbaek Andersen MP, Nielsen OJ, Wallington TJ, dkk. Global warming potential of inhaled anaesthetics: application to clinical use (desflurane 2.540; sevoflurane ~130; isoflurane ~510).", "u": "https://pubmed.ncbi.nlm.nih.gov/20519425/"}, {"a": "NHS England (2023). Putting anaesthetic emissions to bed: commitment on desflurane.", "u": "https://www.england.nhs.uk/greenernhs/2023/01/putting-anaesthetic-emissions-to-bed/"}, {"a": "IPCC AR6 WG1 (2021). GWP100 nitrous oxide (N₂O) = 273.", "u": "https://www.ipcc.ch/report/ar6/wg1/"}]}, {"slug": "logistik-muatan-kosong", "topic": "Sektor", "mood": "#1E5F8C", "title": "Truk yang pulang kosong: emisi yang paling mudah dipangkas.", "dek": "Truk yang kembali dengan bak kosong membakar solar yang nyaris sama tanpa mengangkut apa pun. Menekan perjalanan kosong menurunkan emisi sekaligus biaya bahan bakar — efisiensi langka yang membayar dirinya sendiri.", "hook": "Truk yang selesai mengantar barang lalu pulang dengan bak kosong tetap membakar solar yang sama — hanya saja tanpa membawa apa pun.", "cover": "https://images.unsplash.com/photo-1449965408869-eaa3f722e40d?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data Eurostat, IEA & DESNZ", "read": 4, "blocks": [{"t": "lead", "x": "Setiap hari, sebagian besar truk barang menempuh separuh perjalanannya tanpa membawa apa pun. Mereka mengantar muatan ke satu kota, lalu kembali dengan bak kosong — membakar solar dalam jumlah yang nyaris sama, tetapi mengangkut nol ton kargo. Inilah 'empty miles', dan ia mungkin sumber emisi logistik yang paling mudah, dan paling murah, untuk dipangkas."}, {"t": "p", "x": "Perjalanan kosong bukan kejadian sesekali, melainkan pola struktural. Data <a href=\"https://ec.europa.eu/eurostat/statistics-explained/index.php?title=Road_freight_transport_statistics\">Eurostat</a> menunjukkan sekitar seperlima dari seluruh kilometer yang ditempuh truk di Uni Eropa dijalani dalam kondisi kosong. Di Indonesia, angka pastinya belum terlacak secara nasional ⚠︎, tetapi geografi kepulauan dan arus barang yang timpang antarwilayah membuat pola serupa sangat mungkin terjadi."}, {"t": "stat", "n": "≈20%", "l": "kilometer truk di UE ditempuh dengan bak kosong", "s": "Eurostat, Road freight transport statistics"}, {"t": "p", "x": "Yang membuatnya penting: bak kosong tetap membakar bahan bakar. Sektor transportasi menyumbang sekitar <a href=\"https://www.iea.org/energy-system/transport\">23% emisi CO₂ terkait energi global</a>, dan angkutan barang jalan adalah salah satu bagian terbesarnya. Setiap liter solar yang terbakar melepaskan sekitar 2,68 kg CO₂e menurut faktor konversi <a href=\"https://www.gov.uk/government/collections/government-conversion-factors-for-company-reporting\">DESNZ/DEFRA</a> — sehingga setiap kilometer kosong adalah <b>emisi murni tanpa nilai ekonomi</b> yang menyertainya."}, {"t": "pull", "x": "Ton emisi termurah adalah yang tak pernah perlu Anda keluarkan — truk yang tak berjalan kosong."}, {"t": "h2", "x": "Efisiensi yang membayar dirinya sendiri"}, {"t": "p", "x": "Di sinilah logistik berbeda dari kebanyakan langkah dekarbonisasi. Menekan perjalanan kosong — lewat optimasi rute, konsolidasi muatan, dan pencocokan muatan balik (<em>backhaul</em>) — memangkas kilometer yang ditempuh. Lebih sedikit kilometer berarti lebih sedikit solar, dan lebih sedikit solar berarti dua hal sekaligus: <b>biaya turun dan emisi turun</b>. Bahan bakar adalah salah satu komponen biaya operasi truk terbesar ⚠︎, jadi penghematannya terasa langsung di neraca."}, {"t": "p", "x": "Tetapi efisiensi ini tidak muncul dari niat baik saja — ia butuh data. Untuk tahu truk mana yang pulang kosong dan rute mana yang bisa digabung, operator perlu jejak per perjalanan: jarak tempuh, konsumsi solar, dan faktor muat. Ketika karbon <b>terlacak per rit</b>, pemborosan yang selama ini tersembunyi dalam tagihan solar gabungan menjadi terlihat — dan bisa ditutup."}, {"t": "bars", "h": [0.9, 0.72, 0.58, 0.46, 0.37, 0.3], "cap": "Ilustrasi: emisi dan biaya bahan bakar menurun saat perjalanan kosong ditekan dan faktor muat naik."}, {"t": "p", "x": "Bagi Glyiv, logistik adalah contoh paling bersih dari tesis kami: karbon yang terlacak bukan beban pelaporan, melainkan lensa efisiensi. Menghitung emisi rute hanyalah langkah pertama; nilainya muncul ketika angka itu dibaca berdampingan dengan biaya bahan bakar, lalu diubah menjadi keputusan — rute mana digabung, muatan balik mana dikejar. Bukan klaim 'netral karbon', melainkan kontribusi nyata yang kebetulan juga menghemat uang."}], "story": [{"kind": "cover", "title": "Truk yang pulang kosong", "text": "Truk yang kembali dengan bak kosong membakar solar yang nyaris sama tanpa mengangkut apa pun. Menekan perjalanan kosong menurunkan emisi sekaligus biaya bahan bakar — efisiensi langka yang membayar dirinya sendiri."}, {"kind": "hook", "title": "Emisi paling mudah dipangkas", "text": "Truk selesai mengantar barang, lalu pulang dengan bak kosong — tetap membakar solar yang sama, tanpa membawa apa pun."}, {"kind": "point", "title": "Apa itu 'empty miles'?", "text": "Mengantar muatan ke satu arah, pulang kosong. Solar terbakar, kargo nol. Pola ini struktural, bukan sesekali."}, {"kind": "stat", "title": "Seperlima perjalanan sia-sia", "big": "≈20%", "label": "kilometer truk di UE ditempuh dengan bak kosong", "source": "Eurostat, Road freight transport statistics"}, {"kind": "point", "title": "Menang dua kali", "text": "Transportasi ±23% emisi CO₂ energi global (IEA). Optimasi rute & muatan balik menekan kilometer kosong — biaya solar turun, emisi turun, bersamaan."}, {"kind": "quote", "title": "Ton termurah", "text": "Ton emisi termurah adalah yang tak pernah perlu Anda keluarkan."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv Kabar", "text": "Karbon yang terlacak bukan beban laporan, tapi lensa efisiensi. Kenali lebih dekat platform intelijen karbon Glyiv."}], "sources": [{"a": "Eurostat (2024). Road freight transport statistics — empty running of road freight vehicles.", "u": "https://ec.europa.eu/eurostat/statistics-explained/index.php?title=Road_freight_transport_statistics"}, {"a": "International Energy Agency (IEA). Transport — sektor transportasi menyumbang sekitar 23% emisi CO₂ terkait energi global.", "u": "https://www.iea.org/energy-system/transport"}, {"a": "DESNZ/DEFRA (2023). Greenhouse gas reporting: conversion factors — faktor emisi bahan bakar solar (≈2,68 kg CO₂e per liter).", "u": "https://www.gov.uk/government/collections/government-conversion-factors-for-company-reporting"}]}, {"slug": "umkm-karbon-tanpa-pusing", "topic": "Sektor", "mood": "#C6A15B", "title": "UMKM dan karbon: mulai dari tagihan listrik, bukan laporan tebal.", "dek": "UMKM menopang hampir 60% ekonomi Indonesia — dan bagi mereka, langkah iklim paling masuk akal bukan laporan emisi yang rumit, melainkan efisiensi energi yang langsung menekan tagihan.", "hook": "Bagi warung dan bengkel, karbon paling mudah dipahami lewat satu hal: tagihan listrik yang turun.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Bagi kebanyakan usaha mikro dan kecil, kata 'karbon' terdengar seperti urusan korporasi raksasa — laporan tebal, konsultan mahal, standar yang sulit dieja. Padahal titik masuk yang paling masuk akal justru ada di laci kasir: pada lembar tagihan listrik yang datang tiap bulan."}, {"t": "p", "x": "UMKM bukan pemain pinggiran. Mereka menopang sekitar <b>60% Produk Domestik Bruto</b> Indonesia dan menyerap lebih dari 97% tenaga kerja, menurut <a href=\"https://www.kemenkopukm.go.id/\">Kementerian Koperasi dan UKM</a>. Tapi kerangka pelaporan emisi — GHG Protocol, ISO 14064 — dirancang untuk korporasi dengan tim khusus. Menuntut warung kopi menyusun inventarisasi Scope 1–3 sama saja menyuruhnya menyerah sebelum mulai."}, {"t": "h2", "x": "Kenapa listrik dulu, bukan laporan"}, {"t": "p", "x": "Sebagian besar jejak karbon usaha kecil bersembunyi di kolom energi. Jaringan listrik nasional masih didominasi batu bara — sekitar 60% pembangkitan berasal dari PLTU, menurut <a href=\"https://www.iea.org/countries/indonesia\">IEA</a> — sehingga setiap kilowatt-jam yang dihemat di toko atau bengkel ikut memangkas emisi yang terlacak di hulu. ⚠︎ Faktor emisi jaringan berbeda antar sistem kelistrikan dan tahun, namun umumnya diperkirakan di kisaran 0,8 kg CO₂ per kWh — artinya penghematan energi dan pengurangan emisi bergerak searah."}, {"t": "pull", "x": "Bagi usaha kecil, ton karbon paling murah adalah yang tak jadi terbakar — dan itu dimulai dari tagihan yang turun."}, {"t": "stat", "n": "~60%", "l": "kontribusi UMKM terhadap PDB Indonesia", "s": "Kementerian Koperasi dan UKM RI, 2023"}, {"t": "p", "x": "Logikanya sederhana: efisiensi energi membayar dirinya sendiri. Mengganti lampu ke LED, merawat pendingin agar segelnya tak bocor, memindah beban berat dari jam beban puncak — semuanya menekan biaya lebih dulu, dengan pengurangan emisi datang sebagai imbalannya. Bukan kebetulan IEA menyebut efisiensi energi sebagai <b>'bahan bakar pertama'</b>: ia sumber daya paling murah, paling bersih, dan paling cepat tersedia — tanpa perlu menunggu pembangkit baru dibangun."}, {"t": "p", "x": "Contohnya nyata di lapangan. Lemari pendingin minuman yang segelnya aus akan menyala nyaris tanpa henti, membakar listrik — dan uang — sepanjang malam, tanpa pernah tampil sebagai baris pengeluaran tersendiri. Begitu pemakaian energi dipetakan per alat dan per jam, pemborosan semacam itu terlihat, dan tindakan perbaikannya biasanya murah serta cepat balik modal."}, {"t": "h2", "x": "Laporan menyusul, bukan mendahului"}, {"t": "p", "x": "Ini bukan berarti pengukuran tak penting — hanya soal urutan. Usaha kecil sebaiknya mulai dari tindakan yang menghemat uang, lalu membiarkan datanya mengalir dari yang memang sudah dicatat tiap bulan: tagihan, meteran, jam operasi. Dari sana jejak karbon bisa dilacak tanpa konsultan mahal, dan ketika suatu hari rantai pasok ekspor atau pembeli besar memintanya, angkanya sudah tersedia. Kontribusi terhadap iklim paling kokoh ketika ia tumbuh dari efisiensi yang nyata — bukan dari formulir yang diisi karena terpaksa."}], "story": [{"kind": "cover", "title": "UMKM dan karbon: mulai dari tagihan listrik", "text": "Langkah iklim paling masuk akal bagi usaha kecil bukan laporan rumit, melainkan efisiensi energi yang menekan biaya."}, {"kind": "hook", "title": "Karbon bukan cuma urusan pabrik besar", "text": "Bagi warung dan bengkel, iklim paling terasa lewat satu hal: tagihan listrik."}, {"kind": "point", "title": "60% ekonomi lewat mereka", "text": "UMKM menopang ~60% PDB Indonesia. Dekarbonisasi nasional harus melewati jutaan warung dan toko."}, {"kind": "point", "title": "Mulai dari energi", "text": "Listrik kita masih didominasi batu bara — tiap kWh yang dihemat ikut memangkas emisi yang terlacak."}, {"kind": "stat", "title": "Skala yang tak bisa diabaikan", "big": "~60%", "label": "kontribusi UMKM terhadap PDB Indonesia", "source": "Kementerian Koperasi dan UKM RI, 2023"}, {"kind": "quote", "title": "Ton paling murah", "text": "Ton karbon paling murah adalah yang tak jadi terbakar — dimulai dari tagihan yang turun."}, {"kind": "end", "title": "Efisiensi dulu, laporan menyusul", "text": "Baca ulasan lengkapnya — atau mulai langkah hijau usaha Anda bersama Glyiv."}], "sources": [{"a": "Kementerian Koperasi dan UKM RI (2023). Kontribusi UMKM terhadap PDB dan penyerapan tenaga kerja nasional.", "u": "https://www.kemenkopukm.go.id/"}, {"a": "International Energy Agency (2024). Indonesia — Countries & Regions (bauran pembangkitan listrik).", "u": "https://www.iea.org/countries/indonesia"}, {"a": "International Energy Agency (2023). Energy Efficiency 2023 — energy efficiency as 'the first fuel'.", "u": "https://www.iea.org/reports/energy-efficiency-2023"}]}, {"slug": "perbankan-net-zero-portofolio", "topic": "Sektor", "mood": "#0B2471", "title": "Bank net zero: janji yang diuji di portofolio kredit.", "dek": "Emisi terbesar sebuah bank bukan dari kantornya, melainkan dari kredit yang ia salurkan. Komitmen net zero perbankan hanya bermakna bila 'financed emissions' — emisi yang dibiayai — ikut turun.", "hook": "Sebuah bank bisa memasang panel surya di setiap kantornya dan tetap membiayai krisis iklim. Jejak karbon terbesarnya ada di tempat lain: di pinjaman yang ia setujui.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (CDP, IEA, PCAF, OJK)", "read": 5, "blocks": [{"t": "lead", "x": "Ketika sebuah bank mengumumkan target net zero, godaan pertamanya adalah menghitung yang paling mudah dilihat: listrik kantor cabang, perjalanan dinas, armada mobil dinas. Semua itu nyata — tetapi bukan di situ jejak karbon terbesar sebuah bank berada. Emisi terbesarnya justru mengalir keluar lewat pintu yang paling menghasilkan uang, yaitu pinjaman dan investasi yang ia salurkan."}, {"t": "p", "x": "Emisi dari portofolio kredit itu punya nama teknis: <b>financed emissions</b> — emisi yang 'dibiayai'. Dalam kerangka GHG Protocol ia masuk Cakupan 3 Kategori 15, dan sejak 2020 punya metodologi baku lewat <a href=\"https://carbonaccountingfinancials.com/en/standard\">PCAF</a> (Partnership for Carbon Accounting Financials): setiap rupiah pembiayaan menanggung porsi emisi dari perusahaan atau proyek yang didanainya, sebanding dengan besar eksposurnya."}, {"t": "stat", "n": "±700×", "l": "Financed emissions rata-rata lembaga keuangan dibanding emisi operasionalnya sendiri", "s": "CDP, 2021"}, {"t": "p", "x": "Angka itulah yang memindahkan ujian net zero perbankan dari gedung kantor ke neraca kredit. Net-Zero Banking Alliance (NZBA) — yang pada puncaknya (2024) mewakili sekitar 40% aset perbankan global ⚠︎ — mensyaratkan anggotanya menyelaraskan emisi portofolio pinjaman dan investasi menuju nol bersih pada 2050, dengan target antara di 2030. Janji itu hanya bermakna bila financed emissions benar-benar ikut turun, bukan cuma emisi operasional."}, {"t": "pull", "x": "Jejak karbon terbesar sebuah bank tidak ada di lampu kantornya. Ia ada di pinjaman yang ia setujui."}, {"t": "h2", "x": "Ujiannya ada di energi fosil"}, {"t": "p", "x": "Titik paling tajam adalah pembiayaan bahan bakar fosil. Peta jalan <a href=\"https://www.iea.org/reports/net-zero-by-2050\">IEA Net Zero by 2050</a> (2021) menyimpulkan bahwa jalur nol bersih tidak menyisakan ruang bagi ladang minyak dan gas baru maupun tambang batu bara baru di luar yang sudah disetujui. Maka bank yang mendanai ekspansi pasokan fosil sambil memasang target net zero sedang menampung dua janji yang saling bertolak belakang."}, {"t": "p", "x": "Bagi Indonesia, taruhannya konkret. Portofolio bank nasional bersandar pada sektor padat karbon — batu bara, kelapa sawit, semen, baja — dan bauran listrik yang masih didominasi batu bara. OJK sudah menerbitkan <a href=\"https://keuanganberkelanjutan.ojk.go.id/\">Taksonomi untuk Keuangan Berkelanjutan Indonesia</a> (TKBI, mulai Februari 2024) sebagai rujukan menilai mana aktivitas yang layak disebut hijau. Namun tanpa pengukuran financed emissions per sektor, taksonomi berhenti sebagai label — bukan lintasan penurunan yang bisa ditagih."}, {"t": "h2", "x": "Dari janji ke lintasan"}, {"t": "p", "x": "Kejujuran juga menuntut catatan: sepanjang 2025 sejumlah bank besar justru mundur atau melonggarkan komitmen iklimnya ⚠︎, memperlihatkan betapa rapuhnya janji tanpa mekanisme yang mengikat. Yang memisahkan komitmen kredibel dari siaran pers adalah rantai data yang bisa ditelusuri: emisi terlacak per debitur, per sektor, per tahun, lalu diperbandingkan dengan target. Di situ <b>kontribusi</b> bank terhadap dekarbonisasi bisa dipertanggungjawabkan — bukan sekadar diklaim. Net zero perbankan, pada akhirnya, adalah soal ke mana modal mengalir, dan apakah alirannya bisa dibuktikan menurun."}], "story": [{"kind": "cover", "title": "Bank net zero: janji yang diuji di portofolio kredit", "text": "Emisi terbesar sebuah bank bukan dari kantornya, melainkan dari kredit yang ia salurkan. Komitmen net zero hanya bermakna bila 'financed emissions' ikut turun."}, {"kind": "hook", "title": "Bukan di kantornya", "text": "Sebuah bank bisa memasang panel surya di setiap cabang dan tetap membiayai krisis iklim. Jejak terbesarnya ada di pinjaman yang ia setujui."}, {"kind": "point", "title": "Financed emissions", "text": "Emisi yang 'dibiayai' — GHG Protocol Cakupan 3 Kategori 15, dihitung dengan metodologi PCAF. Setiap rupiah pembiayaan menanggung porsi emisi debiturnya."}, {"kind": "stat", "title": "Perbandingannya ekstrem", "big": "700×", "label": "Financed emissions vs emisi operasional lembaga keuangan", "source": "CDP, 2021"}, {"kind": "point", "title": "Kenapa ini menentukan", "text": "IEA (2021): jalur net zero tak menyisakan ruang bagi ladang migas atau tambang batu bara baru. Bank yang mendanai ekspansi fosil menampung dua janji yang bertabrakan."}, {"kind": "point", "title": "Taruhan Indonesia", "text": "Portofolio bank nasional padat batu bara & sawit. OJK terbitkan TKBI (2024) — tapi tanpa hitung financed emissions per sektor, itu label, bukan lintasan."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv Kabar", "text": "Karbon yang tak terlacak adalah risiko yang tak terkelola. Telusuri intelijen karbon Glyiv untuk memahami ke mana modal mengalir."}], "sources": [{"a": "CDP (2021). The Time to Green Finance: press release — 'Finance sector's funded emissions over 700 times greater than its own'.", "u": "https://www.cdp.net/en/press-releases/finance-sectors-funded-emissions-over-700-times-greater-than-its-own"}, {"a": "PCAF (2022). The Global GHG Accounting and Reporting Standard for the Financial Industry, 2nd ed.", "u": "https://carbonaccountingfinancials.com/en/standard"}, {"a": "IEA (2021). Net Zero by 2050: A Roadmap for the Global Energy Sector.", "u": "https://www.iea.org/reports/net-zero-by-2050"}, {"a": "OJK (2024). Taksonomi untuk Keuangan Berkelanjutan Indonesia (TKBI).", "u": "https://keuanganberkelanjutan.ojk.go.id/"}]}, {"slug": "ritel-scope-3-rantai-pasok", "topic": "Sektor", "mood": "#B0894F", "title": "Ritel dan Scope 3: mayoritas emisi ada di luar tokonya.", "dek": "Bagi peritel dan F&B, gerai hanyalah ujung dari rantai yang panjang — dan di sepanjang rantai itulah, bukan di kasir, mayoritas emisi sebenarnya bersembunyi.", "hook": "Ganti semua lampu jadi LED, dan Anda mungkin baru menyentuh sepotong kecil jejak karbon toko Anda. Sisanya ada di rantai pasok.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan GHG Protocol, CDP, dan Poore & Nemecek (2018)", "read": 4, "blocks": [{"t": "lead", "x": "Sebuah kedai kopi atau minimarket tampak seperti sumber emisi yang gamblang: lampu menyala, lemari pendingin berdengung, AC bekerja sepanjang hari. Tetapi bila seluruh jejak karbonnya dijumlahkan, bagian terbesar justru tak pernah menyentuh gerai itu. Ia lahir di kebun, peternakan, pabrik, dan bak truk pemasok — jauh sebelum produk tiba di rak."}, {"t": "p", "x": "Standar akuntansi karbon yang paling luas dipakai, <a href=\"https://ghgprotocol.org/corporate-value-chain-scope-3-standard\">GHG Protocol</a>, membagi emisi ke dalam tiga lingkup. <b>Scope 1</b> adalah emisi langsung (generator, gas dapur), <b>Scope 2</b> listrik yang dibeli, dan <b>Scope 3</b> mencakup semua emisi tak langsung sepanjang rantai nilai — dari bahan baku pemasok hingga sampah yang dibuang pelanggan. Bagi peritel dan F&B, Scope 3 hampir selalu yang paling besar."}, {"t": "p", "x": "Seberapa besar? Menurut <a href=\"https://www.cdp.net/en/research/global-supply-chain-report\">CDP</a>, emisi rantai pasok sebuah perusahaan rata-rata sekitar <b>11 kali</b>⚠︎ lebih tinggi daripada emisi operasinya sendiri. Bagi bisnis yang hampir seluruh produknya dibuat pihak lain, timpangnya bisa lebih ekstrem lagi."}, {"t": "h2", "x": "Beban terberat bukan di dapur"}, {"t": "p", "x": "Riset lintas rantai pasok oleh <a href=\"https://www.science.org/doi/10.1126/science.aaq0216\">Poore & Nemecek (2018)</a> menunjukkan bahwa untuk sebagian besar produk pangan, mayoritas emisi terjadi di tahap lahan dan pertanian — bukan di toko. Transportasi biasanya menyumbang kurang dari 10%, sementara pengemasan dan ritel lebih kecil lagi. Artinya, mengganti lampu menjadi LED itu baik, tetapi tak menyentuh bongkahan terbesarnya."}, {"t": "bars", "h": [0.92, 0.68, 0.46, 0.3, 0.16, 0.11, 0.07], "cap": "Ilustrasi jejak karbon rata-rata satu produk pangan menurut tahap — perubahan lahan, pertanian, pakan & pengolahan, transport, pengemasan, ritel, energi gerai. Pola berdasarkan Poore & Nemecek (2018)."}, {"t": "pull", "x": "Bagi peritel, dekarbonisasi bukan soal gerai yang lebih hijau — melainkan rantai pasok yang lebih bersih."}, {"t": "h2", "x": "Pekerjaan bersama pemasok"}, {"t": "p", "x": "Karena emisinya ada di hulu, memangkasnya berarti bekerja bersama pemasok: meminta data emisi per produk, memilih sumber dengan jejak yang lebih rendah, serta mendorong praktik pertanian dan energi yang lebih bersih. Ini pekerjaan relasi jangka panjang, bukan sekadar audit satu gedung. Sebagai konteks, sistem pangan global diperkirakan menyumbang sekitar <b>sepertiga</b> emisi gas rumah kaca dunia <a href=\"https://www.nature.com/articles/s43016-021-00225-9\">(Crippa dkk., 2021)</a> — jadi keputusan sourcing seorang peritel punya bobot yang nyata."}, {"t": "p", "x": "Di sinilah intelijen karbon berperan. Alih-alih menebak, peritel dapat memetakan Scope 3 per pemasok dan per produk dari data yang bisa <b>ditelusuri</b> — sehingga setiap langkah dekarbonisasi, dan setiap klaim <b>kontribusi</b> iklim, terarah ke tempat emisi sebenarnya berada. Glyiv membangun peta itu bersama Anda."}], "story": [{"kind": "cover", "title": "Ritel & Scope 3: emisi ada di luar toko", "text": "Bagi peritel dan F&B, gerai hanyalah ujung dari rantai yang panjang — dan di sepanjang rantai itulah mayoritas emisi sebenarnya bersembunyi."}, {"kind": "hook", "title": "LED saja tak cukup", "text": "Ganti semua lampu, dan Anda mungkin baru menyentuh sepotong kecil jejak karbon toko. Sisanya ada di rantai pasok."}, {"kind": "point", "title": "Tiga lingkup emisi", "text": "Scope 1 & 2 = gerai Anda (bahan bakar, listrik). Scope 3 = seluruh rantai nilai. Untuk ritel & F&B, Scope 3 hampir selalu terbesar."}, {"kind": "point", "title": "Bebannya bukan di dapur", "text": "Untuk kebanyakan pangan, mayoritas emisi lahir di lahan & pertanian. Transport biasanya < 10%; ritel lebih kecil lagi. (Poore & Nemecek, 2018)"}, {"kind": "stat", "title": "Rantai pasok jauh lebih berat", "big": "≈11×⚠︎", "label": "emisi rantai pasok vs operasi gerai sendiri", "source": "CDP, Global Supply Chain Report"}, {"kind": "quote", "title": "Intinya", "text": "Dekarbonisasi ritel bukan soal gerai yang lebih hijau — melainkan rantai pasok yang lebih bersih."}, {"kind": "end", "title": "Peta emisi Anda mulai dari pemasok", "text": "Glyiv membantu peritel memetakan Scope 3 per pemasok dari data yang bisa ditelusuri. Baca lengkap — atau mulai bersama kami."}], "sources": [{"a": "GHG Protocol / WRI & WBCSD (2011). Corporate Value Chain (Scope 3) Accounting and Reporting Standard.", "u": "https://ghgprotocol.org/corporate-value-chain-scope-3-standard"}, {"a": "CDP (2022). Engaging the Chain: Global Supply Chain Report — emisi rantai pasok rata-rata ~11,4× emisi operasi.", "u": "https://www.cdp.net/en/research/global-supply-chain-report"}, {"a": "Poore, J. & Nemecek, T. (2018). Reducing food's environmental impacts through producers and consumers. Science, 360(6392).", "u": "https://www.science.org/doi/10.1126/science.aaq0216"}, {"a": "Crippa, M. dkk. (2021). Food systems are responsible for a third of global anthropogenic GHG emissions. Nature Food (EDGAR-FOOD).", "u": "https://www.nature.com/articles/s43016-021-00225-9"}]}, {"slug": "tambang-batu-bara-transisi", "topic": "Sektor", "mood": "#0F2E22", "title": "Ekonomi batu bara: bagaimana wilayah tambang bersiap berubah.", "dek": "Permintaan batu bara global sudah berbelok arah. Daerah yang mulai mendiversifikasi ekonominya lebih dini menukar krisis mendadak dengan transisi yang bisa dijadwalkan.", "hook": "Komoditas yang menghidupi daerah tambang punya tanggal kedaluwarsa. Pertanyaannya bukan apakah, tapi kapan.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, JETP, Bank Dunia)", "read": 4, "blocks": [{"t": "lead", "x": "Setiap daerah tambang batu bara hidup dengan satu kenyataan yang jarang diucapkan keras-keras: komoditas yang menghidupinya punya tanggal kedaluwarsa. Bukan besok, mungkin juga bukan dekade ini — tapi arah permintaan global sudah berbelok, dan wilayah yang menunggu sampai tambang tutup untuk mulai berpikir akan menanggung guncangan paling keras."}, {"t": "p", "x": "Sinyalnya datang dari lembaga yang tak bisa disebut aktivis. Dalam <a href=\"https://www.iea.org/reports/world-energy-outlook-2023\">World Energy Outlook 2023</a>, IEA memproyeksikan permintaan batu bara, minyak, dan gas <b>mencapai puncak sebelum 2030</b> pada skenario kebijakan yang berlaku saat ini. Puncak bukan berarti nol — batu bara masih akan terpakai bertahun-tahun — tapi tren yang menurun mengubah kalkulasi investasi, harga, dan lapangan kerja jauh sebelum ton terakhir digali."}, {"t": "p", "x": "Indonesia berada di titik yang rentan sekaligus strategis. Negeri ini adalah <b>pengekspor batu bara termal terbesar di dunia</b>, dan beberapa provinsi — Kalimantan Timur, Kalimantan Selatan, Sumatera Selatan — menyandarkan sebagian besar pendapatan daerah dan lapangan kerjanya pada satu sektor. Di Kalimantan Timur, sektor pertambangan diperkirakan menyumbang sekitar ⚠︎45% produk domestik regional bruto. Ketergantungan setinggi itu membuat penurunan permintaan bukan sekadar isu iklim, melainkan risiko fiskal dan sosial yang nyata."}, {"t": "h2", "x": "Guncangan yang bisa dijadwalkan"}, {"t": "p", "x": "Perbedaan antara transisi yang tertata dan yang kacau terletak pada waktu. Wilayah yang mulai mendiversifikasi ekonominya lebih dini — sebelum tambang menutup — punya ruang untuk mengalihkan tenaga kerja, membangun sektor pengganti, dan menata ulang basis pajaknya secara bertahap. Yang menunggu krisis biasanya berakhir dengan pengangguran massal dan kota yang menyusut, seperti pengalaman kawasan tambang tua di Eropa dan Amerika. Bank Dunia menyebutnya <a href=\"https://www.worldbank.org/en/topic/extractiveindustries\">just transition</a>: menata perubahan agar bebannya tak jatuh seluruhnya ke pundak pekerja dan komunitas."}, {"t": "pull", "x": "Guncangannya bukan soal apakah, melainkan kapan — dan wilayah yang merencanakannya lebih awal menukar krisis mendadak dengan transisi bertahap."}, {"t": "stat", "n": "US$ 20 miliar", "l": "Komitmen pendanaan Just Energy Transition Partnership (JETP) untuk Indonesia ⚠︎ realisasi masih berjalan", "s": "JETP Indonesia / G20, 2022"}, {"t": "p", "x": "Modal untuk berubah mulai tersedia. Lewat JETP, Indonesia menerima komitmen pendanaan campuran senilai US$ 20 miliar untuk mempercepat pensiun dini pembangkit batu bara dan pengembangan energi bersih ⚠︎ — meski pencairannya masih tersendat dan sebagian besar berupa pinjaman, bukan hibah. Pertanyaannya bukan lagi ada-tidaknya uang, tapi apakah daerah punya rencana yang cukup matang untuk menyerapnya menjadi lapangan kerja baru."}, {"t": "p", "x": "Diversifikasi tidak berarti menutup tambang besok. Ia berarti menaruh imbalan hari ini ke dalam aset yang bertahan setelahnya: hilirisasi mineral, energi terbarukan, restorasi lahan pascatambang, hingga jasa dan pangan. Beberapa daerah mulai memetakan potensi karbon dari rehabilitasi lahan bekas galian — sebuah kontribusi iklim yang, bila <b>terlacak</b> dan terverifikasi, bisa menjadi aliran pendapatan pengganti, bukan sekadar kewajiban."}, {"t": "p", "x": "Batu bara tidak akan hilang dalam semalam, dan tak ada gunanya berpura-pura demikian. Tapi wilayah yang jujur pada dirinya sendiri — bahwa puncaknya sudah di cakrawala — bisa memilih bentuk perubahannya sendiri, alih-alih menunggu perubahan itu datang tanpa diundang."}], "story": [{"kind": "cover", "title": "Ekonomi batu bara: wilayah tambang bersiap berubah", "text": "Permintaan global sudah berbelok. Daerah yang mendiversifikasi lebih dini menukar krisis mendadak dengan transisi yang bisa dijadwalkan."}, {"kind": "hook", "title": "Ada tanggal kedaluwarsa", "text": "Komoditas yang menghidupi daerah tambang tak akan bertahan selamanya. Pertanyaannya bukan apakah, tapi kapan."}, {"kind": "point", "title": "Arah sudah berbelok", "text": "IEA (WEO 2023): permintaan batu bara, minyak, dan gas memuncak sebelum 2030 pada skenario kebijakan yang berlaku."}, {"kind": "point", "title": "Indonesia rentan", "text": "Pengekspor batu bara termal terbesar dunia; sejumlah provinsi bergantung pada satu sektor untuk pendapatan dan kerja."}, {"kind": "stat", "title": "Modal transisi mulai ada", "big": "US$ 20 miliar", "label": "Komitmen JETP untuk transisi energi Indonesia ⚠︎ realisasi berjalan", "source": "JETP Indonesia / G20, 2022"}, {"kind": "quote", "title": "Memilih bentuk perubahan", "text": "Wilayah yang jujur pada dirinya sendiri bisa memilih bentuk perubahannya — alih-alih menunggu perubahan datang tanpa diundang."}, {"kind": "end", "title": "Baca selengkapnya", "text": "Pahami transisi karbon Indonesia lebih dekat bersama Glyiv Kabar."}], "sources": [{"a": "IEA (2023). World Energy Outlook 2023.", "u": "https://www.iea.org/reports/world-energy-outlook-2023"}, {"a": "JETP Indonesia Secretariat (2023). Comprehensive Investment and Policy Plan (CIPP).", "u": "https://jetp-id.org/"}, {"a": "World Bank (2018). Managing Coal Mine Closure: Achieving a Just Transition for All.", "u": "https://www.worldbank.org/en/topic/extractiveindustries"}]}, {"slug": "konstruksi-material-rendah-karbon", "topic": "Sektor", "mood": "#B5623A", "title": "Bangunan rendah karbon: separuhnya soal pilihan material.", "dek": "Sebelum sebuah gedung ditinggali, sebagian besar jejak iklimnya sudah terkunci di dalam semen dan baja yang membentuknya — dan di situlah pilihan material rendah-karbon paling menentukan.", "hook": "Sebuah gedung sudah \"boros karbon\" sebelum ada yang tinggal di dalamnya. Separuh jejaknya terkunci di semen dan baja.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (UNEP, IEA, WorldGBC, worldsteel)", "read": 4, "blocks": [{"t": "lead", "x": "Sebuah gedung mulai memancarkan karbon jauh sebelum lampu pertamanya menyala. Ketika semen dituang dan rangka baja ditegakkan, sebagian besar jejak iklim bangunan itu sudah 'tertanam' — terkunci di dalam material yang membentuknya. Emisi inilah yang jarang dibicarakan, padahal untuk gedung baru porsinya bisa mendekati separuh."}, {"t": "p", "x": "Sektor bangunan dan konstruksi menyumbang sekitar <b>37% emisi CO₂</b> terkait energi dan proses secara global, serta sekitar 34% permintaan energi dunia <a href=\"https://www.unep.org/resources/report/global-status-report-buildings-and-construction-20242025\">(UNEP)</a>. Sorotan biasanya jatuh pada emisi <b>operasional</b> — AC, pemanas, dan lampu selama gedung dipakai. Tapi ada lapisan kedua yang kerap luput: emisi <b>tertanam</b> (<em>embodied carbon</em>) dari memproduksi dan merakit materialnya."}, {"t": "p", "x": "Emisi tertanam ini diperkirakan bertanggung jawab atas sekitar <b>11% emisi karbon global</b> <a href=\"https://worldgbc.org/article/bringing-embodied-carbon-upfront/\">(WorldGBC)</a>. Dan karena bangunan baru makin hemat energi saat dihuni, bobot material justru makin menentukan: emisi <em>upfront</em> — dari material dan proses pembangunan, sebelum gedung ditempati — diproyeksikan menjadi hampir separuh seluruh jejak karbon konstruksi baru antara kini hingga 2050 ⚠︎ (proyeksi, bukan angka final)."}, {"t": "stat", "n": "~50%", "l": "jejak karbon konstruksi baru 2020–2050 diperkirakan berasal dari emisi 'upfront' material & pembangunan", "s": "WorldGBC, 2019 · proyeksi"}, {"t": "h2", "x": "Dua raksasa: semen dan baja"}, {"t": "p", "x": "Dua material mendominasi cerita ini. Produksi <b>semen</b> menyumbang sekitar 7% emisi CO₂ global — kira-kira 2,4 gigaton setahun <a href=\"https://www.iea.org/energy-system/industry/cement\">(IEA)</a> — dan yang membuatnya sulit dipangkas: kira-kira separuh emisinya bukan berasal dari bahan bakar, melainkan dari reaksi kimia <em>kalsinasi</em> batu kapur itu sendiri. <b>Baja</b> menambah 7–9% emisi global, dengan rata-rata sekitar <b>1,9 ton CO₂ per ton</b> baja mentah <a href=\"https://worldsteel.org/data/world-steel-in-figures/world-steel-in-figures-2024/\">(worldsteel)</a>. Dua material yang paling menopang sebuah gedung juga yang paling berat jejaknya."}, {"t": "pull", "x": "Karbon sebuah gedung sebagian besar ditentukan di meja gambar — bukan setelah pita peresmian digunting."}, {"t": "bars", "h": [0.95, 0.72, 0.5, 0.34, 0.16], "cap": "Ilustrasi urutan intensitas karbon tertanam per material: baja dan beton jauh di atas kayu rekayasa. Pola berdasar basis data EPD/ecoinvent."}, {"t": "h2", "x": "Memilih sejak desain"}, {"t": "p", "x": "Kabar baiknya, pilihan itu ada. Mengganti sebagian klinker semen dengan abu terbang, terak, atau lempung terkalsinasi (LC3); memakai baja daur ulang dari tungku busur listrik; hingga struktur kayu rekayasa untuk bangunan rendah-menengah — semuanya memangkas emisi tertanam sejak desain, bukan menambalnya belakangan. Bagi Indonesia yang membangun pesat, ini bukan urusan jauh: setiap ton semen dan baja hari ini mengunci emisi yang tak bisa 'dihemat kembali' oleh panel surya di atap nanti. ⚠︎ Belum ada kewajiban pelaporan <em>embodied carbon</em> di Indonesia, sehingga banyak proyek belum menghitungnya sama sekali. Yang dibutuhkan untuk memilih dengan yakin adalah data — <em>Environmental Product Declaration</em> (EPD) yang bisa ditelusuri per material, bukan klaim pemasaran. Sebuah gedung tak menjadi 'netral karbon' hanya karena hemat listrik; kontribusinya pada iklim dimulai dari bata pertama."}], "story": [{"kind": "cover", "title": "Bangunan rendah karbon: separuhnya soal material", "text": "Sebelum sebuah gedung ditinggali, sebagian besar jejak iklimnya sudah terkunci di dalam semen dan baja yang membentuknya."}, {"kind": "hook", "title": "Karbon yang sudah terkunci", "text": "Sebuah gedung sudah 'boros karbon' sebelum ada yang tinggal di dalamnya. Ini alasannya."}, {"kind": "point", "title": "Dua lapis emisi", "text": "Bukan cuma listrik saat dihuni. Ada emisi 'tertanam' dari membuat semen, baja, dan batanya — keluar di muka, dan permanen."}, {"kind": "point", "title": "Semen & baja, dua raksasa", "text": "Semen ~7% emisi CO₂ dunia; separuhnya dari kimia kalsinasi. Baja 7–9%, sekitar 1,9 ton CO₂ per ton.", "source": "IEA · worldsteel"}, {"kind": "stat", "title": "Hampir separuh", "big": "~50%", "label": "jejak karbon konstruksi baru diperkirakan dari emisi material & pembangunan 'upfront' (2020–2050)", "source": "WorldGBC, 2019 · proyeksi"}, {"kind": "quote", "title": "Di meja gambar", "text": "Karbon sebuah gedung sebagian besar ditentukan di meja gambar — bukan setelah pita peresmian digunting."}, {"kind": "end", "title": "Dipilih sejak desain", "text": "Material rendah-karbon memangkas jejak sebelum gedung berdiri. Baca versi lengkap di Glyiv Kabar."}], "sources": [{"a": "UNEP & GlobalABC (2024). Global Status Report for Buildings and Construction 2024/2025.", "u": "https://www.unep.org/resources/report/global-status-report-buildings-and-construction-20242025"}, {"a": "World Green Building Council (2019). Bringing Embodied Carbon Upfront.", "u": "https://worldgbc.org/article/bringing-embodied-carbon-upfront/"}, {"a": "IEA (2023). Cement — Tracking Clean Energy Progress.", "u": "https://www.iea.org/energy-system/industry/cement"}, {"a": "worldsteel (2024). World Steel in Figures 2024.", "u": "https://worldsteel.org/data/world-steel-in-figures/world-steel-in-figures-2024/"}]}, {"slug": "manufaktur-efisiensi-energi-dulu", "topic": "Sektor", "mood": "#1F7A6B", "title": "Dekarbonisasi manufaktur: efisiensi dulu, offset belakangan.", "dek": "Godaan terbesar adalah membeli offset lebih dahulu. Padahal di manufaktur, mengukur lalu memangkas energi kerap membuka penghematan 10–20%⚠︎ pada lini tertentu — dan offset yang jujur hanya menutup sisa yang benar-benar keras.", "hook": "Membeli offset dulu itu seperti menambal atap sebelum mematikan keran bocor. Di manufaktur, urutannya: ukur, pangkas, baru sisanya.", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data IEA, worldsteel & ISO 50001", "read": 4, "blocks": [{"t": "lead", "x": "Godaan terbesar dalam dekarbonisasi manufaktur adalah membeli jalan pintas: memesan sekumpulan kredit offset, menempelkannya pada laporan, lalu menyebut pabrik 'lebih hijau'. Urutan itu terbalik. Yang benar dimulai dari dalam pagar pabrik — mengukur di mana energi terbuang, lalu memangkasnya — jauh sebelum satu kredit pun dibeli."}, {"t": "p", "x": "Industri bukan pemain kecil. Menurut <a href=\"https://www.iea.org/energy-system/industry\">IEA</a>, sektor industri menyerap lebih dari sepertiga energi final dunia dan menyumbang hampir seperempat emisi CO2 terkait energi. Artinya, sebelum menoleh ke offset, ada ruang besar untuk dibereskan lebih dahulu di lini produksi sendiri — dan biasanya itu <b>menghemat uang</b>, bukan menambah biaya."}, {"t": "p", "x": "Sumber pemborosan paling umum tidak eksotis: motor listrik, pompa, kompresor, dan sistem uap yang berjalan boros di jam sepi. Sistem motor listrik saja diperkirakan menyedot sekitar 70% listrik industri <a href=\"https://www.iea.org/energy-system/energy-efficiency-and-demand\">(IEA)</a>. Menyetel ulang jadwal, memasang penggerak kecepatan variabel, atau sekadar mematikan yang tak perlu kerap membuka penghematan yang selama ini tenggelam dalam tagihan gabungan."}, {"t": "pull", "x": "Offset itu untuk sisa yang benar-benar keras dipangkas — bukan pengganti pekerjaan memangkasnya."}, {"t": "stat", "n": "10–20%⚠︎", "l": "penghematan biaya operasi yang kerap terungkap dari efisiensi energi pada lini tertentu", "s": "Riset operasional industri (mis. McKinsey)"}, {"t": "h2", "x": "Urutan yang benar: ukur, pangkas, baru sisanya"}, {"t": "p", "x": "Langkah pertama bukan membeli offset, tapi <b>mengukur</b>. Memetakan konsumsi energi per lini dan per shift dengan disiplin standar — misalnya sistem manajemen energi <a href=\"https://www.iso.org/standard/69426.html\">ISO 50001</a> — mengubah tagihan gabungan menjadi peta pemborosan yang bisa ditindak. Data itulah, bukan janji, yang menunjukkan persis di mana rupiah dan karbon bocor."}, {"t": "p", "x": "Baru setelah efisiensi dan elektrifikasi mentok, offset masuk untuk menutup sisa yang benar-benar keras — misalnya emisi proses pada baja dan semen yang tak hilang hanya dengan hemat energi (rata-rata sekitar <a href=\"https://worldsteel.org/\">1,9 ton CO2 menyertai tiap ton baja</a>). Bahkan di sini bahasanya tetap jujur: offset adalah <b>kontribusi</b> terhadap penurunan emisi, bukan klaim 'netral karbon'. Urutan yang benar bukan soal ideologi — ia sekadar cara paling murah untuk mencapai hasil yang paling bisa dipertanggungjawabkan."}], "story": [{"kind": "cover", "title": "Efisiensi dulu, offset belakangan", "text": "Di manufaktur, mengukur lalu memangkas energi kerap membuka penghematan 10–20%⚠︎ pada lini tertentu — dan offset yang jujur hanya menutup sisa yang benar-benar keras."}, {"kind": "hook", "title": "Urutannya sering terbalik", "text": "Membeli offset dulu itu seperti menambal atap sebelum mematikan keran bocor. Ukur, pangkas, baru sisanya."}, {"kind": "point", "title": "Industri itu berat", "text": "Sektor industri menyumbang hampir seperempat emisi CO2 terkait energi (IEA). Banyak yang bisa dibereskan di dalam pagar pabrik dulu."}, {"kind": "point", "title": "Pemborosan tak eksotis", "text": "Motor, pompa, kompresor, uap. Sistem motor menyedot ~70% listrik industri — sering cuma perlu disetel ulang."}, {"kind": "stat", "title": "Angka yang berulang", "big": "10–20%⚠︎", "label": "penghematan yang kerap terungkap dari efisiensi energi pada lini tertentu", "source": "Riset operasional industri (mis. McKinsey)"}, {"kind": "point", "title": "Offset itu belakangan", "text": "Untuk sisa yang keras dipangkas — emisi proses baja & semen. Dan tetap disebut kontribusi, bukan 'netral karbon'."}, {"kind": "end", "title": "Ukur dulu, pangkas kemudian", "text": "Baca uraian lengkapnya di Glyiv Kabar — atau tempuh jalan dekarbonisasi yang bisa dipertanggungjawabkan bersama Glyiv."}], "sources": [{"a": "IEA (2024). Industry & Energy Efficiency — Energy System. Share energi final dan emisi CO2 industri; sistem motor listrik ~70% listrik industri.", "u": "https://www.iea.org/energy-system/industry"}, {"a": "worldsteel (2023). Sustainability Indicators — rata-rata ~1,9 ton CO2 per ton baja mentah.", "u": "https://worldsteel.org/"}, {"a": "ISO 50001:2018. Energy management systems — Requirements with guidance for use.", "u": "https://www.iso.org/standard/69426.html"}, {"a": "McKinsey & Company. Decarbonization and operational cost savings in manufacturing."}]}, {"slug": "sawit-ispo-rspo-beda", "topic": "Sektor", "mood": "#4F7A3A", "title": "ISPO dan RSPO: dua label sawit, dua tuntutan berbeda.", "dek": "ISPO wajib dan menagih legalitas; RSPO sukarela dan menagih rantai pasok. Kini aturan bebas-deforestasi Uni Eropa menuntut keduanya membuktikan hal yang sama: dari petak mana minyak itu benar-benar berasal.", "hook": "Sebotol minyak sawit bisa membawa dua stempel \"berkelanjutan\" — dan artinya sama sekali tak sama.", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Perpres 44/2020, RSPO P&C, dan Regulation (EU) 2023/1115", "read": 4, "blocks": [{"t": "lead", "x": "Di rak ritel Eropa, sebotol minyak sawit yang sama bisa membawa dua stempel 'berkelanjutan': ISPO dan RSPO. Keduanya terdengar mirip, tapi lahir dari niat berbeda, menagih hal berbeda, kepada pihak yang berbeda. Memahami jaraknya penting justru sekarang — saat aturan bebas-deforestasi Uni Eropa mulai menuntut bukti yang lebih dalam dari keduanya."}, {"t": "p", "x": "<b>ISPO</b> (Indonesian Sustainable Palm Oil) adalah sertifikasi yang <b>wajib</b> dan bersifat nasional. Dasar hukumnya <a href=\"https://peraturan.bpk.go.id/Details/135663/perpres-no-44-tahun-2020\">Peraturan Presiden No. 44 Tahun 2020</a>, yang mengharuskan seluruh pelaku usaha perkebunan sawit — dari perusahaan besar hingga, secara bertahap, pekebun swadaya — memenuhi standar keberlanjutan yang ditetapkan negara. Fokusnya bertumpu pada <b>legalitas</b>: keabsahan izin, hak atas lahan, dan kepatuhan pada hukum Indonesia. Pekebun swadaya diberi masa transisi hingga sekitar 2025⚠︎."}, {"t": "p", "x": "<b>RSPO</b> (Roundtable on Sustainable Palm Oil) berjalan di jalur lain: <b>sukarela</b> dan digerakkan pasar. Berdiri sejak 2004 sebagai forum multipihak lintas negara, <a href=\"https://rspo.org/\">RSPO</a> menjual janji kepada pembeli global lewat prinsip <em>No Deforestation, No Peat, No Exploitation</em> — tanpa deforestasi, tanpa pembukaan gambut, tanpa eksploitasi pekerja — yang diverifikasi terhadap tanggal batas dan penilaian kawasan bernilai konservasi tinggi."}, {"t": "h2", "x": "Dua definisi 'tertelusur'"}, {"t": "p", "x": "Di sinilah keduanya berpisah. ISPO memastikan sebuah kebun <b>sah menurut hukum</b>, tapi tak terlalu menuntut pelacakan fisik tandan buah hingga ke pembeli akhir. RSPO justru dibangun di atas rantai pasok: lewat model Identity Preserved, Segregated, hingga Mass Balance, pembeli memilih seberapa ketat minyak yang dibeli dipisahkan dari sumber tak bersertifikat — lengkap dengan geolokasi kebun. Bagi Indonesia, produsen sawit terbesar dunia yang memasok lebih dari separuh pasokan global⚠︎, perbedaan ini menentukan ke pasar mana produk bisa mengalir."}, {"t": "pull", "x": "Satu label membuktikan kebun itu sah. Label lain membuktikan minyaknya bisa dilacak sampai ke petak. EUDR kini menuntut keduanya sekaligus."}, {"t": "stat", "n": "~19%⚠︎", "l": "porsi minyak sawit dunia yang bersertifikat RSPO", "s": "RSPO, Impact Report"}, {"t": "h2", "x": "Di mana EUDR ikut campur"}, {"t": "p", "x": "Regulasi Anti-Deforestasi Uni Eropa (<a href=\"https://eur-lex.europa.eu/eli/reg/2023/1115/oj\">EUDR, Regulation (EU) 2023/1115</a>) menambah lapisan baru. Ia mensyaratkan setiap komoditas — termasuk sawit — yang masuk pasar Eropa <b>bebas-deforestasi</b>: tak berasal dari lahan yang dibuka setelah 31 Desember 2020, diproduksi secara legal, dan disertai <b>koordinat geolokasi</b> setiap petak asalnya. Penerapannya beberapa kali digeser dan mulai mengikat operator besar sejak akhir 2025⚠︎, menyusul pelaku kecil pada 2026⚠︎."}, {"t": "p", "x": "Yang kerap disalahpahami: mengantongi ISPO atau RSPO <b>tidak otomatis</b> berarti lolos EUDR. Komisi Eropa menegaskan sertifikasi hanya membantu penilaian risiko, bukan pengganti uji tuntas. Titik temunya ada pada <b>ketertelusuran per petak</b> — data lokasi, tanggal, dan riwayat tutupan lahan yang bisa diaudit. Di situlah ketiga aturan bertemu, dan di situ pula pekerjaan sesungguhnya dimulai."}], "story": [{"kind": "cover", "title": "ISPO & RSPO: dua label, dua tuntutan", "text": "ISPO wajib dan menagih legalitas; RSPO sukarela dan menagih rantai pasok. Kini aturan bebas-deforestasi Uni Eropa menuntut keduanya membuktikan hal yang sama: dari petak mana minyak itu benar-benar berasal."}, {"kind": "hook", "title": "Dua stempel, satu botol", "text": "Sebotol minyak sawit bisa membawa dua label 'berkelanjutan' — dan artinya sama sekali tak sama."}, {"kind": "point", "title": "ISPO — wajib & nasional", "text": "Aturan negara (Perpres 44/2020). Menagih legalitas: izin sah, lahan sah, patuh hukum. Berlaku untuk semua pelaku sawit."}, {"kind": "point", "title": "RSPO — sukarela & pasar", "text": "Standar pembeli global sejak 2004. Prinsip NDPE: tanpa deforestasi, tanpa gambut, tanpa eksploitasi — dilacak lewat rantai pasok."}, {"kind": "stat", "title": "Seberapa luas RSPO?", "big": "~19%", "label": "minyak sawit dunia bersertifikat RSPO ⚠︎", "source": "RSPO, Impact Report"}, {"kind": "point", "title": "Lalu datang EUDR", "text": "Eropa minta koordinat tiap petak + bukti bebas-deforestasi sejak 2020. ISPO buktikan kebun sah, RSPO buktikan rantainya — sertifikat saja tak otomatis lolos."}, {"kind": "end", "title": "Baca versi lengkapnya", "text": "Kupas beda ISPO, RSPO, dan EUDR di Glyiv Kabar — intelijen karbon untuk ekonomi hijau Indonesia."}], "sources": [{"a": "Peraturan Presiden Republik Indonesia No. 44 Tahun 2020 tentang Sistem Sertifikasi Perkebunan Kelapa Sawit Berkelanjutan Indonesia (ISPO).", "u": "https://peraturan.bpk.go.id/Details/135663/perpres-no-44-tahun-2020"}, {"a": "RSPO (2018). Principles and Criteria for the Production of Sustainable Palm Oil; RSPO Impact Report.", "u": "https://rspo.org/"}, {"a": "Regulation (EU) 2023/1115 of the European Parliament and of the Council on the making available of deforestation-free products (EUDR), 2023.", "u": "https://eur-lex.europa.eu/eli/reg/2023/1115/oj"}, {"a": "USDA Foreign Agricultural Service. Oilseeds: World Markets and Trade — pangsa produksi minyak sawit Indonesia."}]}, {"slug": "nikel-hpal-limbah-tailing", "topic": "Sektor", "mood": "#B5623A", "title": "HPAL dan tailing: sisi lain rantai pasok baterai.", "dek": "Nikel kelas baterai kini banyak lahir dari proses HPAL yang menyisakan lautan tailing dan emisi proses — dan ke mana limbah itu dibuang ikut menentukan apakah 'transisi energi' benar-benar bersih.", "hook": "Mobil listrik Anda bersih di jalan. Tapi bagaimana dengan lumpur asam yang tertinggal di pesisir Sulawesi?", "cover": "https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, World Bank, GISTM)", "read": 5, "blocks": [{"t": "lead", "x": "Sebuah mobil listrik melaju tanpa asap knalpot, dan itulah yang membuatnya terasa bersih. Tapi jauh sebelum baterainya terpasang, nikel di dalamnya telah melewati proses industri yang menyisakan jejak nyata — sebagian tertinggal sebagai lumpur di lembah dan pesisir Sulawesi serta Halmahera, jauh dari pandangan pembeli."}, {"t": "p", "x": "Baterai membutuhkan nikel kelas satu: cukup murni untuk diolah menjadi nikel sulfat. Persoalannya, sebagian besar cadangan nikel Indonesia berupa laterit kadar rendah (limonit) yang sulit dimurnikan lewat peleburan biasa. Di sinilah <b>HPAL</b> — High Pressure Acid Leaching — berperan: bijih dilarutkan dengan asam sulfat pada suhu sekitar 250°C dan tekanan tinggi hingga menghasilkan endapan hidroksida campuran (MHP), bahan antara untuk katoda. Seiring <a href=\"https://www.iea.org/reports/the-role-of-critical-minerals-in-clean-energy-transitions\">melonjaknya permintaan mobil listrik</a>, proses ini menjadi tulang punggung pasokan nikel baterai dunia."}, {"t": "p", "x": "Proses itu efektif, tapi rakus. Setiap ton nikel menyisakan berkali-kali lipat massa limbah <b>tailing</b> — lumpur asam bercampur logam sisa. Karena volumenya raksasa, cara membuangnya menjadi pertanyaan besar: ditumpuk lalu dikeringkan di darat (<i>dry stacking</i>), atau dialirkan ke dasar laut (<i>deep-sea tailings placement</i>, DSTP). Keputusan itu, bukan logamnya, yang menentukan seberapa 'bersih' rantai pasok ini sebenarnya."}, {"t": "pull", "x": "Baterai boleh bersih di jalan. Tapi kebersihannya ditentukan jauh di hulu — di kolam tailing yang jarang kita lihat."}, {"t": "stat", "n": "6×", "l": "kandungan mineral sebuah mobil listrik dibanding mobil konvensional", "s": "IEA, 2021"}, {"t": "h2", "x": "Ke mana lumpurnya pergi"}, {"t": "p", "x": "DSTP lebih murah dan dianggap menghindari risiko jebolnya bendungan tailing saat gempa — ancaman nyata di wilayah rawan seismik. Namun membuang tailing ke laut punya rekam jejak ekologis yang buruk, terlebih di perairan kaya hayati seperti Segitiga Terumbu Karang. Pemerintah Indonesia menolak sejumlah proposal DSTP ⚠︎ dan mendorong operator ke penyimpanan darat — keputusan yang menggeser beban risiko, bukan menghapusnya. Standar global untuk pengelolaan tailing pun kini menuntut penanganan yang bisa diaudit, bukan sekadar 'dibuang jauh dari mata'."}, {"t": "h2", "x": "Yang tak terlihat di sticker"}, {"t": "p", "x": "Ada sisi kedua yang lebih senyap: emisi proses. HPAL sangat haus energi, dan di kawasan industri nikel Indonesia sebagian besar listriknya dipasok pembangkit batu bara <i>captive</i>. Akibatnya, nikel yang lahir demi 'kendaraan bersih' bisa membawa intensitas karbon yang tinggi ⚠︎ — beban yang tak pernah muncul di sticker mobil listrik. Bagi pembeli global, ini bukan sekadar soal etika: regulasi seperti CBAM Uni Eropa mulai menuntut bukti jejak karbon per produk ⚠︎, sehingga nikel yang tak tertelusur berisiko didiskon harga."}, {"t": "p", "x": "Ini bukan alasan menolak transisi energi, melainkan alasan menjalankannya dengan jujur. Transisi yang benar menuntut kita <b>melacak</b> karbon dan limbah sepanjang rantai — dari tambang, HPAL, hingga sel baterai — bukan menghitungnya hanya di knalpot. Yang bisa dipertanggungjawabkan bukan klaim 'bersih', tetapi angka yang terlacak dan keputusan pembuangan yang bisa diaudit."}], "story": [{"kind": "cover", "title": "HPAL dan tailing: sisi lain rantai pasok baterai", "text": "Nikel kelas baterai lahir dari proses yang menyisakan lautan tailing dan emisi. Ke mana limbah itu dibuang menentukan apakah transisi energi benar-benar bersih."}, {"kind": "hook", "title": "Bersih di jalan, lalu?", "text": "Mobil listrik tak berasap. Tapi lumpur asam dari nikelnya harus disimpan di suatu tempat."}, {"kind": "point", "title": "Apa itu HPAL?", "text": "Bijih nikel kadar rendah dilarutkan asam sulfat pada suhu & tekanan tinggi jadi MHP — bahan baku katoda baterai."}, {"kind": "point", "title": "Sisa yang tak terlihat", "text": "Tiap ton nikel meninggalkan berlipat ton tailing: lumpur asam. Ditumpuk di darat, atau dibuang ke laut dalam?"}, {"kind": "stat", "title": "Beban material transisi", "big": "6×", "label": "mineral sebuah mobil listrik vs mobil konvensional", "source": "IEA, 2021"}, {"kind": "point", "title": "Emisi yang senyap", "text": "HPAL haus energi. Listrik batu bara captive membuat nikel 'bersih' bisa berkarbon tinggi ⚠︎ — tak muncul di sticker."}, {"kind": "end", "title": "Transisi yang jujur", "text": "Bukan klaim 'bersih', tapi jejak yang terlacak sepanjang rantai. Baca selengkapnya & telusuri bersama Glyiv."}], "sources": [{"a": "IEA (2021). The Role of Critical Minerals in Clean Energy Transitions. International Energy Agency, Paris.", "u": "https://www.iea.org/reports/the-role-of-critical-minerals-in-clean-energy-transitions"}, {"a": "World Bank (2020). Minerals for Climate Action: The Mineral Intensity of the Clean Energy Transition. Washington, DC.", "u": "https://www.worldbank.org/en/topic/extractiveindustries/brief/climate-smart-mining-minerals-for-climate-action"}, {"a": "IEA (2024). Global Critical Minerals Outlook 2024. International Energy Agency, Paris.", "u": "https://www.iea.org/reports/global-critical-minerals-outlook-2024"}, {"a": "Global Tailings Review (2020). Global Industry Standard on Tailings Management (GISTM).", "u": "https://globaltailingsreview.org/"}]}, {"slug": "pltu-captive-industri", "topic": "Sektor", "mood": "#0F2E22", "title": "PLTU 'captive': listrik batu bara yang luput dari sorotan.", "dek": "Pembangkit batu bara mandiri di kawasan industri tumbuh paling cepat justru saat Indonesia berjanji pensiun dini — dan sebagian besar berada di luar target yang disepakati.", "hook": "Ada listrik batu bara yang tak masuk hitungan transisi energi kita. Ia menyala di dalam pagar kawasan industri — dan tumbuh paling cepat.", "cover": "https://images.unsplash.com/photo-1509391366360-2e959784a276?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Perpres 112/2022 & JETP CIPP", "read": 4, "blocks": [{"t": "lead", "x": "Ketika orang membicarakan transisi energi Indonesia, yang terbayang biasanya PLTU raksasa milik PLN yang memasok jaringan nasional. Tapi ada satu kategori pembangkit batu bara yang tumbuh diam-diam di luar sorotan itu: PLTU captive — dibangun langsung di dalam kawasan industri untuk melistriki satu pembeli, sering kali sebuah smelter nikel yang haus daya sepanjang hari."}, {"t": "p", "x": "Berbeda dari pembangkit on-grid, PLTU captive tidak menjual listrik ke jaringan umum; ia melayani pabrik di sebelahnya. Pendorongnya adalah ledakan hilirisasi nikel — bahan baku baterai kendaraan listrik — di Sulawesi dan Maluku Utara. <a href=\"https://globalenergymonitor.org/\">Global Energy Monitor</a> mencatat kapasitas captive Indonesia melonjak beberapa kali lipat dalam lima tahun terakhir, menjadikannya salah satu pipeline batu bara captive terbesar di dunia ⚠︎."}, {"t": "p", "x": "Konsentrasinya terlihat jelas di kawasan seperti Indonesia Morowali dan Weda Bay Industrial Park, tempat puluhan pabrik pengolahan logam berdiri berdampingan dengan pembangkitnya sendiri. Karena listriknya dipakai sendiri, PLTU ini kerap luput dari statistik sektor kelistrikan nasional yang menjadi acuan banyak target iklim."}, {"t": "h2", "x": "Celah yang dilewati"}, {"t": "p", "x": "<b>Perpres No. 112 Tahun 2022</b> resminya melarang pembangunan PLTU baru — tapi menyisakan pengecualian bagi pembangkit yang terintegrasi dengan industri bernilai tambah tinggi dan proyek strategis nasional, asalkan berkomitmen memangkas emisi 35% dalam sepuluh tahun dan berhenti beroperasi paling lambat 2050 ⚠︎. Lewat pintu itulah gelombang PLTU captive baru terus dibangun, bahkan saat pembangkit on-grid mulai dibatasi."}, {"t": "pull", "x": "Target pensiun dini batu bara sering berhenti di pagar jaringan PLN — sementara pembangkit captive terus menyala di dalam kawasan industri."}, {"t": "stat", "n": "250 juta ton", "l": "batas emisi listrik on-grid 2030 dalam JETP — PLTU captive sebagian besar berada di luarnya", "s": "JETP CIPP, 2023"}, {"t": "p", "x": "Di sinilah titik butanya. Ketika Indonesia dan mitra internasional menyepakati <a href=\"https://jetp-id.org/\">JETP</a>, batas emisi yang dijanjikan hanya berlaku untuk sistem on-grid. Emisi dari PLTU captive sebagian besar berada di luar hitungan itu — padahal volumenya besar dan justru tumbuh paling cepat. Rencana pensiun dini bisa tampak rapi di atas kertas, sementara sumber emisi yang membengkak luput dari peta jalan."}, {"t": "h2", "x": "Menghitung yang tak terhitung"}, {"t": "p", "x": "Ini bukan berarti listrik untuk hilirisasi tak penting; nikel Indonesia adalah bagian dari rantai pasok energi bersih global. Tapi transisi yang jujur menuntut agar emisi captive ikut <b>terlacak</b>, dilaporkan, dan masuk peta jalan — bukan disembunyikan di balik status 'mandiri'. Langkah pertama selalu sama: menghitung apa yang selama ini tak dihitung, per kawasan dan per smelter, supaya keputusan berikutnya berpijak pada data, bukan asumsi."}], "story": [{"kind": "cover", "title": "PLTU 'captive': listrik batu bara yang luput dari sorotan", "text": "Pembangkit batu bara mandiri di kawasan industri tumbuh paling cepat justru saat Indonesia berjanji pensiun dini — dan sebagian besar berada di luar target yang disepakati."}, {"kind": "hook", "title": "Ada listrik yang tak dihitung", "text": "Batu bara yang menyala di dalam pagar kawasan industri — dan justru tumbuh paling cepat."}, {"kind": "point", "title": "Apa itu PLTU captive?", "text": "Pembangkit batu bara di dalam kawasan industri, melistriki satu pabrik — biasanya smelter nikel — bukan jaringan umum."}, {"kind": "point", "title": "Tumbuh paling cepat", "text": "Didorong hilirisasi nikel di Sulawesi & Maluku Utara. Salah satu pipeline captive terbesar di dunia ⚠︎."}, {"kind": "point", "title": "Celah aturan", "text": "Perpres 112/2022 melarang PLTU baru — tapi mengecualikan pembangkit untuk industri strategis. Lewat sini captive terus dibangun."}, {"kind": "stat", "title": "Di luar hitungan", "big": "250 Jt ton", "label": "batas emisi listrik on-grid 2030 (JETP) — captive di luarnya", "source": "JETP CIPP, 2023"}, {"kind": "end", "title": "Titik buta yang perlu diterangi", "text": "Baca versi lengkapnya di Glyiv Kabar — dan ikut lacak emisi yang selama ini luput."}], "sources": [{"a": "Peraturan Presiden No. 112 Tahun 2022 tentang Percepatan Pengembangan Energi Terbarukan untuk Penyediaan Tenaga Listrik.", "u": "https://jdih.setneg.go.id/"}, {"a": "JETP Secretariat (2023). Comprehensive Investment and Policy Plan (CIPP), Indonesia.", "u": "https://jetp-id.org/"}, {"a": "Global Energy Monitor (2024). Global Coal Plant Tracker — captive coal Indonesia.", "u": "https://globalenergymonitor.org/"}, {"a": "Centre for Research on Energy and Clean Air (CREA) & Global Energy Monitor. Analisis pertumbuhan PLTU captive kawasan industri Indonesia."}]}, {"slug": "daging-sapi-jejak-terbesar", "topic": "Konsumen", "mood": "#B5623A", "title": "Kenapa sepiring rendang berjejak karbon paling besar.", "dek": "Kilogram demi kilogram, daging sapi duduk di puncak intensitas karbon pangan — dan sepiring rendang membawa jejak yang jauh lebih berat ketimbang ayam, tahu, atau kacang di piring sebelahnya.", "hook": "Ternyata yang menentukan jejak karbon makananmu bukan seberapa jauh ia datang — tapi apa yang ada di atas piring.", "cover": "https://images.unsplash.com/photo-1625246333195-78d9c38ad449?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan Poore & Nemecek (2018)", "read": 4, "blocks": [{"t": "lead", "x": "Rendang hampir selalu menang di meja makan — daging sapi yang dimasak berjam-jam dalam santan dan rempah sampai empuk dan pekat. Tapi di balik kelezatannya, sepiring rendang membawa sesuatu yang jarang kita hitung: jejak karbon yang, kilogram demi kilogram, termasuk salah satu yang terbesar dari semua bahan di piring kita."}, {"t": "p", "x": "Anggapan umum bilang 'beli lokal' adalah cara utama menekan jejak karbon makanan. Datanya berkata lain. Dalam kajian besar <a href=\"https://www.science.org/doi/10.1126/science.aaq0216\">Poore & Nemecek (2018)</a> atas ~38.700 pertanian di 119 negara, transportasi hanya menyumbang sebagian kecil emisi pangan — yang jauh lebih menentukan adalah <b>apa</b> yang kita makan, bukan seberapa jauh ia menempuh perjalanan. Secara keseluruhan, rantai pasok pangan menyumbang sekitar <b>26% emisi gas rumah kaca global</b>."}, {"t": "p", "x": "Dan di antara semua bahan pangan, daging sapi berdiri di puncak. Estimasi rata-rata menempatkannya di kisaran <b>~60 kg CO2e per kg⚠︎</b> daging — dengan rentang yang sangat lebar antar-peternakan. Sebagai pembanding, ayam sekitar 6 kg, tahu sekitar 3 kg, dan kacang-kacangan hanya 1–2 kg per kg. Artinya satu kilogram sapi bisa setara sepuluh kali lipat ayam, dan puluhan kali lipat sumber protein nabati."}, {"t": "pull", "x": "Yang menentukan jejak karbon sepiring makanan bukan seberapa jauh ia datang, tapi apa yang ada di atasnya."}, {"t": "bars", "h": [1, 0.4, 0.35, 0.12, 0.1, 0.05, 0.02], "cap": "Intensitas emisi per kg pangan, dinormalkan ke daging sapi (dari kiri: sapi, domba, keju, babi, ayam, tahu, kacang). Sumber: Poore & Nemecek 2018 / Our World in Data."}, {"t": "h2", "x": "Kenapa sapi begitu berat"}, {"t": "p", "x": "Dua hal membuat sapi berbeda. Pertama, <b>fermentasi enterik</b> — pencernaan sapi melepaskan metana, gas rumah kaca yang jauh lebih kuat dari CO2 dalam jangka pendek. Kedua, <b>alih fungsi lahan</b>: padang gembala dan kebun pakan kerap dibuka dari hutan, dan karbon yang lepas dari situ ikut terhitung. IPCC menempatkan sektor pertanian, kehutanan, dan penggunaan lahan sebagai salah satu penyumbang emisi terbesar dunia⚠︎."}, {"t": "h2", "x": "Menukar, bukan menghakimi"}, {"t": "p", "x": "Poinnya bukan bahwa rendang harus hilang dari meja — sesekali menikmatinya adalah bagian dari budaya kita. Tapi datanya memberi pilihan yang jujur: menukar sebagian porsi sapi mingguan dengan ayam, tempe, tahu, atau kacang menurunkan jejak karbon piring secara nyata — dampaknya jauh lebih besar ketimbang sekadar memburu bahan yang 'lokal'."}, {"t": "p", "x": "Di Glyiv, keputusan yang baik dimulai dari angka yang bisa dipertanggungjawabkan. Jejak karbon pangan memang belum sepenuhnya terlacak sampai ke setiap piring — angka ~60 kg tadi adalah rata-rata, bukan vonis. Tapi memahami urutannya saja sudah cukup untuk membuat kontribusi kecil yang, dikalikan jutaan piring, jadi berarti."}], "story": [{"kind": "cover", "title": "Kenapa sepiring rendang berjejak karbon paling besar", "text": "Kilogram demi kilogram, daging sapi duduk di puncak intensitas karbon pangan — jauh di atas ayam, tahu, atau kacang."}, {"kind": "hook", "title": "Bukan soal jarak", "text": "Yang menentukan jejak karbon makananmu bukan seberapa jauh ia datang — tapi apa yang ada di atas piring."}, {"kind": "point", "title": "Apa, bukan dari mana", "text": "Transportasi cuma sebagian kecil emisi pangan. Yang paling menentukan: jenis makanannya. Rantai pasok pangan ≈ 26% emisi global."}, {"kind": "point", "title": "Sapi di puncak", "text": "Daging sapi ~60 kg CO2e/kg⚠︎ — sekitar 10x ayam dan puluhan kali lipat tahu serta kacang."}, {"kind": "stat", "title": "Angkanya", "big": "~60 kg⚠︎", "label": "CO2e per kg daging sapi (rata-rata; rentang antar-peternakan sangat lebar)", "source": "Poore & Nemecek, Science, 2018"}, {"kind": "quote", "title": "Intinya", "text": "Yang menentukan jejak karbon sepiring makanan bukan seberapa jauh ia datang, tapi apa yang ada di atasnya."}, {"kind": "end", "title": "Pilih dengan sadar", "text": "Rendang tak harus hilang dari meja. Menukar sebagian porsi sapi dengan ayam, tempe, atau kacang sudah berarti. Baca lengkapnya di Glyiv Kabar."}], "sources": [{"a": "Poore, J. & Nemecek, T. (2018). Reducing food's environmental impacts through producers and consumers. Science, 360(6392), 987–992.", "u": "https://www.science.org/doi/10.1126/science.aaq0216"}, {"a": "Ritchie, H. & Roser, M. (2020). Environmental impacts of food production. Our World in Data (berdasarkan Poore & Nemecek 2018).", "u": "https://ourworldindata.org/environmental-impacts-of-food"}, {"a": "IPCC (2019). Climate Change and Land — Special Report on climate change, desertification, land degradation, food security (AFOLU).", "u": "https://www.ipcc.ch/srccl/"}]}, {"slug": "nasi-metana-sawah", "topic": "Konsumen", "mood": "#4F7A3A", "title": "Nasi kita dan metana: emisi yang muncul dari sawah tergenang.", "dek": "Sawah yang tergenang melepas metana dari bakteri anaerob — gas rumah kaca yang jauh lebih kuat dari CO2. Kabar baiknya: cara kita mengairi sawah bisa diubah tanpa mengorbankan panen.", "hook": "Sepiring nasimu menyimpan jejak gas rumah kaca yang tak terlihat. Namanya metana.", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, IRRI, UNEP)", "read": 4, "blocks": [{"t": "lead", "x": "Sepiring nasi terasa begitu sederhana dan tak bersalah. Tapi di bawah permukaan sawah yang menghidupinya berlangsung sebuah proses tak kasat mata: air yang menggenang berhari-hari menciptakan ruang tanpa oksigen, dan di situlah mikroba mulai memproduksi salah satu gas rumah kaca paling kuat yang kita kenal — metana. Makanan pokok kita, ternyata, membawa jejak iklim yang jarang kita bicarakan."}, {"t": "p", "x": "Mekanismenya sebenarnya lugas. Ketika sawah tergenang penuh, oksigen di dalam tanah cepat terkuras habis. <b>Bakteri anaerob</b> — mikroba yang justru berkembang biak tanpa udara — lalu mengurai bahan organik dan melepaskan <b>metana (CH4)</b> ke atmosfer. Semakin lama air menggenang, semakin banyak gas yang terlepas. Inilah sebabnya padi sawah tercatat sebagai salah satu sumber metana pertanian terbesar di dunia."}, {"t": "p", "x": "Metana memang kalah populer dari CO2, tapi jauh lebih 'panas'. Menurut <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">IPCC AR6</a>, satu ton metana memerangkap panas sekitar 28 kali lipat lebih besar dari satu ton CO2 dalam kurun 100 tahun. Dan skala Indonesia membuat angka itu terasa nyata: sebagai salah satu produsen beras terbesar dunia, negeri ini mengelola jutaan hektare sawah yang sebagian besar masih diairi dengan cara tergenang penuh sepanjang musim tanam."}, {"t": "stat", "n": "~8%⚠︎", "l": "porsi metana antropogenik global yang diperkirakan berasal dari padi sawah", "s": "Global Methane Assessment (UNEP/CCAC, 2021)"}, {"t": "pull", "x": "Bukan padinya yang melepas metana, melainkan cara kita menggenangi sawahnya. Dan cara itu bisa diubah."}, {"t": "h2", "x": "Genangan yang bisa diselang"}, {"t": "p", "x": "Kabar baiknya: metana ini lahir dari genangan, bukan dari tanaman padinya. Teknik <b>pengairan berselang</b> (alternate wetting and drying / AWD) mengeringkan sawah secara berkala alih-alih menggenanginya sepanjang musim. Saat permukaan air turun dan tanah sempat 'menghirup' udara, bakteri anaerob kehilangan ruang hidup, dan produksi metana pun menurun tajam. Petani cukup membiarkan sawah mengering beberapa hari sebelum kembali mengairinya — sebuah perubahan kebiasaan, bukan teknologi mahal."}, {"t": "p", "x": "Riset <a href=\"https://www.irri.org/\">International Rice Research Institute (IRRI)</a> menunjukkan AWD dapat memangkas emisi metana 30–70%⚠︎ tanpa menurunkan hasil panen, sekaligus menghemat air irigasi hingga sekitar seperempat⚠︎. Tapi ini bukan tombol ajaib: teknik ini butuh kendali air yang baik, dan pengeringan yang keliru bisa menggeser sebagian beban ke gas lain seperti dinitrogen oksida (N2O) ⚠︎. Karena itu ia paling berhasil ketika dipandu data lapangan yang tertelusur, bukan asumsi."}, {"t": "h2", "x": "Apa hubungannya dengan nasi kita?"}, {"t": "p", "x": "Sebagai konsumen, kita nyaris tak pernah melihat jejak ini. Padahal setiap kilogram beras membawa 'sejarah air' dari sawah asalnya. Ketika rantai pasok pangan mulai melacak — bukan sekadar menaksir — bagaimana padi itu diairi, pembeli dan konsumen bisa memberi <b>imbalan</b> bagi beras yang rendah metana. Di titik itulah data karbon yang tertelusur mengubah sebuah kebiasaan bertani menjadi <b>kontribusi</b> iklim yang bisa dipertanggungjawabkan — bukan sekadar klaim di atas label kemasan."}], "story": [{"kind": "cover", "title": "Nasi kita & metana", "text": "Sawah yang tergenang melepas metana dari bakteri anaerob — gas rumah kaca yang jauh lebih kuat dari CO2. Kabar baiknya: cara kita mengairi sawah bisa diubah tanpa mengorbankan panen."}, {"kind": "hook", "title": "Jejak tak terlihat di piringmu", "text": "Sepiring nasi terasa tak bersalah. Tapi sawah yang menggenang punya cerita iklim tersendiri."}, {"kind": "point", "title": "Dari mana metananya?", "text": "Sawah tergenang = tanah kehabisan oksigen. Bakteri anaerob tumbuh subur dan melepas metana ke udara."}, {"kind": "stat", "title": "Bisa dipangkas", "big": "30–70%⚠︎", "label": "potensi pemangkasan metana lewat pengairan berselang (AWD), tanpa menurunkan panen", "source": "IRRI"}, {"kind": "point", "title": "Selang, bukan genang", "text": "AWD mengeringkan sawah secara berkala. Tanah 'bernapas', bakteri anaerob mundur, metana turun — air irigasi pun lebih hemat."}, {"kind": "quote", "title": "Intinya", "text": "Bukan padinya yang melepas metana, melainkan cara kita menggenangi sawahnya."}, {"kind": "end", "title": "Baca cerita lengkapnya", "text": "Pahami bagaimana data karbon yang tertelusur mengubah sepiring nasi menjadi kontribusi iklim yang jujur. Ikuti Glyiv Kabar."}], "sources": [{"a": "IPCC (2021). AR6 Working Group I, Ch. 7 — Global Warming Potentials of methane (GWP-100).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "UNEP & Climate and Clean Air Coalition (2021). Global Methane Assessment: Benefits and Costs of Mitigating Methane Emissions.", "u": "https://www.unep.org/resources/report/global-methane-assessment"}, {"a": "International Rice Research Institute (IRRI). Alternate Wetting and Drying (AWD) — water-saving technology.", "u": "https://www.irri.org/"}, {"a": "FAO (2020). FAOSTAT: Emissions from rice cultivation (methane).", "u": "https://www.fao.org/faostat/"}]}, {"slug": "fast-fashion-lemari-boros", "topic": "Konsumen", "mood": "#6B4E8C", "title": "Fast fashion: baju murah, ongkos iklim mahal.", "dek": "Fast fashion membuat pakaian terasa murah — sebagian karena ongkos air, energi, dan karbonnya dibayar oleh iklim, bukan oleh label harga.", "hook": "Kausmu seharga secangkir kopi. Ongkos iklimnya tidak tercetak di label harga.", "cover": "https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan UNEP, Ellen MacArthur Foundation & Textile Exchange", "read": 4, "blocks": [{"t": "lead", "x": "Sehelai kaus kini bisa berpindah tangan seharga secangkir kopi. Tapi angka di label jarang mencerminkan ongkos sebenarnya — air, energi, dan karbon yang tertinggal di sepanjang rantai, dari ladang kapas atau kilang minyak sampai ke lemari kita. Fast fashion membuat pakaian terasa murah justru karena sebagian ongkosnya dibayar oleh iklim, bukan oleh pembeli."}, {"t": "p", "x": "Seberapa besar? Jawaban jujurnya: belum pasti. Perkiraan yang beredar berkisar <b>2-8% emisi gas rumah kaca global</b> ⚠︎, dan rentang selebar itu bukan kemalasan — melainkan tanda bahwa metodologi, batas sistem, dan kualitas data rantai pasok masih berbeda antar studi. UNEP sengaja memakai rentang ini agar jujur soal ketidakpastiannya <a href=\"https://www.unep.org/news-and-stories/story/environmental-costs-fast-fashion\">[UNEP]</a>. Angka populer '10%' yang sering dikutip media justru termasuk yang paling lemah dasarnya."}, {"t": "p", "x": "Sebagian besar pakaian hari ini bukan lagi kapas, melainkan <b>poliester</b> — serat sintetis berbasis minyak bumi. Menurut <a href=\"https://textileexchange.org/knowledge-center/reports/materials-market-report/\">Textile Exchange</a>, poliester menyumbang sekitar <b>54% produksi serat global</b> (2022), dan serat sintetis secara keseluruhan mendominasi pasar. Karena berasal dari fosil, produksinya intensif energi; seratnya pun tidak terurai secara alami — ia menetap sebagai mikroplastik dan timbunan sampah."}, {"t": "pull", "x": "Fast fashion membuat baju murah dengan memindahkan sebagian ongkosnya ke iklim — lalu menundanya ke masa depan."}, {"t": "stat", "n": "<1%", "l": "bahan pakaian yang didaur ulang kembali menjadi pakaian baru", "s": "Ellen MacArthur Foundation, 2017"}, {"t": "h2", "x": "Siklus pakai-buang yang makin cepat"}, {"t": "p", "x": "Yang memperparah jejak bukan cuma bahannya, tapi kecepatannya. Produksi pakaian dunia <b>berlipat dua</b> antara 2000 dan 2015, sementara rata-rata sebuah baju kini dipakai <b>sekitar 36% lebih sedikit</b> sebelum dibuang <a href=\"https://ellenmacarthurfoundation.org/a-new-textiles-economy\">[EMF]</a>. Setara satu truk sampah tekstil ditimbun atau dibakar <b>setiap detik</b>. Lebih banyak diproduksi, lebih cepat dibuang — itulah aritmetika yang membuat jejaknya menumpuk."}, {"t": "h2", "x": "Yang bisa kita pilih"}, {"t": "p", "x": "Kabar baiknya, sebagian besar jejak ini ada di tangan yang bisa memilih. Memakai lebih lama, memperbaiki, membeli lebih sedikit tapi lebih awet — ini bukan pengorbanan besar, tapi <b>kontribusi</b> nyata untuk menurunkan permintaan. Di sisi industri, yang dibutuhkan bukan klaim 'ramah lingkungan' tanpa bukti, melainkan jejak karbon per produk yang <b>terlacak</b> dan bisa ditelusuri — dari serat sampai rak toko. Baju murah tidak harus berongkos iklim mahal, asalkan ongkos itu berhenti disembunyikan."}], "story": [{"kind": "cover", "title": "Baju murah, ongkos iklim mahal", "text": "Fast fashion membuat pakaian terasa murah — sebagian karena ongkos air, energi, dan karbonnya dibayar oleh iklim, bukan oleh label harga."}, {"kind": "hook", "title": "Kausmu seharga secangkir kopi. Ongkos iklimnya tidak tercetak di label harga."}, {"kind": "point", "title": "Angkanya belum pasti", "text": "Industri tekstil menyumbang ~2-8% emisi global ⚠︎ — rentangnya lebar karena metodologi tiap studi berbeda. (UNEP)"}, {"kind": "point", "title": "Baju dari minyak", "text": "Poliester ~54% produksi serat dunia (2022): berbasis fosil, intensif energi, dan tak terurai. (Textile Exchange)"}, {"kind": "stat", "title": "Nyaris tak ada yang berputar", "big": "<1%", "label": "bahan pakaian yang didaur ulang jadi pakaian baru", "source": "Ellen MacArthur Foundation, 2017"}, {"kind": "point", "title": "Pakai-buang makin cepat", "text": "Produksi pakaian berlipat dua (2000-2015), tapi tiap baju dipakai ~36% lebih sedikit. Setara 1 truk tekstil dibuang tiap detik."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv Kabar", "text": "Pakai lebih lama, beli lebih awet — kontribusi kecil yang nyata. Ikuti wawasan karbon Glyiv: jujur & bisa dipertanggungjawabkan."}], "sources": [{"a": "UN Environment Programme (2020). Sustainability and Circularity in the Textile Value Chain: Global Stocktaking.", "u": "https://www.unep.org/news-and-stories/story/environmental-costs-fast-fashion"}, {"a": "Ellen MacArthur Foundation (2017). A New Textiles Economy: Redesigning fashion's future.", "u": "https://ellenmacarthurfoundation.org/a-new-textiles-economy"}, {"a": "Textile Exchange (2023). Materials Market Report.", "u": "https://textileexchange.org/knowledge-center/reports/materials-market-report/"}, {"a": "European Environment Agency (2022). Textiles and the environment: the role of design in Europe's circular economy.", "u": "https://www.eea.europa.eu/publications/textiles-and-the-environment-the"}]}, {"slug": "sampah-makanan-tpa-metana", "topic": "Konsumen", "mood": "#B5623A", "title": "Sampah makanan: membusuk di TPA, melepas metana.", "dek": "Di TPA yang mampat dan nyaris tanpa udara, sisa makanan tidak lenyap melainkan membusuk secara anaerob dan melepaskan metana — sebabnya mengurangi dan memilah sampah organik jauh lebih berdampak ketimbang sekadar mendaur ulang kemasan.", "hook": "Botol plastik Anda rajin dipisah. Tapi sisa nasi tadi? Itu yang diam-diam melepas metana di TPA.", "cover": "https://images.unsplash.com/photo-1532996122724-e3c354a0b15b?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (UNEP, IPCC, Bappenas)", "read": 4, "blocks": [{"t": "lead", "x": "Setiap kali sepiring nasi atau semangkuk sayur berakhir di tempat sampah, ceritanya tidak selesai di situ. Di tumpukan TPA yang mampat dan nyaris tanpa udara, sisa makanan tidak begitu saja lenyap — ia membusuk perlahan dan melepaskan metana, gas rumah kaca yang jauh lebih ganas ketimbang karbon dioksida."}, {"t": "p", "x": "Kuncinya ada pada cara ia terurai. Di ruang terbuka beroksigen, mikroba menghasilkan sebagian besar CO₂ biogenik. Tapi terkubur di dalam TPA — tertimbun, padat, tanpa udara — prosesnya berubah menjadi anaerob, dan yang keluar adalah gas TPA yang <b>sekitar separuhnya metana</b> (CH₄) <a href=\"https://www.epa.gov/lmop/basic-information-about-landfill-gas\">EPA</a>. Menurut IPCC, metana memerangkap panas sekitar <b>28 kali</b> lebih kuat dari CO₂ dalam kurun seabad — dan hampir 80 kali lebih kuat dalam 20 tahun pertamanya."}, {"t": "stat", "n": "~28×", "l": "potensi pemanasan metana dibanding CO₂ (100 tahun); hampir 80× dalam 20 tahun pertama", "s": "IPCC AR6, 2021"}, {"t": "p", "x": "Skalanya tidak kecil. UNEP mencatat sekitar <b>1,05 miliar ton</b> makanan terbuang sepanjang 2022, dengan rumah tangga sebagai penyumbang terbesar <a href=\"https://www.unep.org/resources/publication/food-waste-index-report-2024\">UNEP, 2024</a>. Bila digabung dengan susut pangan di sepanjang rantai pasok, makanan yang terbuang diperkirakan menyumbang sekitar <b>8–10% emisi gas rumah kaca global</b> — lebih besar dari seluruh penerbangan komersial dunia."}, {"t": "h2", "x": "Kenapa memilah lebih berdampak dari mendaur ulang kemasan"}, {"t": "p", "x": "Di sinilah letak salah kaprah yang umum. Banyak orang merasa sudah cukup hijau karena rajin memisahkan botol plastik dan kardus. Mendaur ulang kemasan memang baik — tapi kemasan tidak melepas metana saat ditimbun. Sisa makanan-lah yang melakukannya. Memisahkan sampah organik dari aliran TPA, lalu mengomposnya atau memprosesnya lewat pencernaan anaerob dengan penangkapan gas, memutus sumber metana itu di hulu. Kompos yang teraerasi baik menghasilkan sebagian besar CO₂ biogenik, bukan metana pekat khas TPA."}, {"t": "pull", "x": "Kemasan yang ditimbun tidak melepas metana. Sisa makanan yang membusuk tanpa udara-lah yang melakukannya."}, {"t": "p", "x": "Ada biaya kedua yang lebih tersembunyi. Membuang makanan berarti ikut membuang seluruh emisi yang sudah tertanam untuk memproduksinya — lahan, air, pupuk, hingga transportasi. Poore & Nemecek (2018) memetakan betapa besar jejak itu bahkan sebelum makanan sampai ke piring. Maka sepiring nasi yang terbuang membawa kerugian ganda: emisi produksinya hangus percuma, lalu ia melepas metana saat membusuk di TPA."}, {"t": "p", "x": "Bagi Indonesia, ini bukan soal yang jauh. Sisa makanan adalah komponen terbesar sampah yang masuk TPA — sekitar <b>40%</b>⚠︎ dari total menurut data KLHK. Kajian Bappenas memperkirakan susut dan sisa pangan mencapai <b>23–48 juta ton per tahun</b>, dengan kerugian ekonomi Rp 213–551 triliun setahun, setara sekitar 4–5% PDB."}, {"t": "p", "x": "Kabar baiknya, tuas yang paling berdampak justru paling sederhana: kurangi di sumber, lalu pilah yang organik. Di Glyiv, dampak semacam ini kami catat sebagai <b>kontribusi yang terlacak</b> — bukan klaim 'netral karbon' — agar setiap kilogram sisa makanan yang tak jadi metana bisa dipertanggungjawabkan, bukan sekadar ditaksir."}], "story": [{"kind": "cover", "title": "Sampah makanan melepas metana", "text": "Di TPA yang mampat dan nyaris tanpa udara, sisa makanan tidak lenyap melainkan membusuk secara anaerob dan melepaskan metana — sebabnya mengurangi dan memilah sampah organik jauh lebih berdampak ketimbang sekadar mendaur ulang kemasan."}, {"kind": "hook", "title": "Bukan kemasan, tapi sisa nasi", "text": "Botol plastik Anda rajin dipisah. Tapi sisa makanan tadi diam-diam melepas metana di TPA."}, {"kind": "point", "title": "Bukan lenyap — membusuk", "text": "Terkubur tanpa udara, sisa makanan terurai anaerob. Hasilnya gas TPA yang sekitar separuhnya metana."}, {"kind": "point", "title": "Metana jauh lebih ganas", "text": "IPCC: metana ~28× lebih kuat dari CO₂ dalam seabad, dan hampir 80× dalam 20 tahun pertama."}, {"kind": "stat", "title": "Porsi iklim yang terbuang", "big": "8–10%", "label": "emisi gas rumah kaca global dari makanan terbuang", "source": "UNEP / FAO"}, {"kind": "quote", "title": "Yang benar-benar melepas metana", "text": "Kemasan yang ditimbun tidak melepas metana. Sisa makanan yang membusuk tanpa udara-lah yang melakukannya."}, {"kind": "end", "title": "Mulai dari piring", "text": "Kurangi di sumber, pilah yang organik. Baca versi lengkapnya dan ikut lacak dampakmu di Glyiv Kabar."}], "sources": [{"a": "UNEP (2024). Food Waste Index Report 2024. United Nations Environment Programme.", "u": "https://www.unep.org/resources/publication/food-waste-index-report-2024"}, {"a": "IPCC (2021). AR6 WG1, Bab 7 — Global Warming Potential metana (GWP-100 & GWP-20).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "Kementerian PPN/Bappenas (2021). Food Loss and Waste in Indonesia: Supporting the Implementation of Circular Economy and Low Carbon Development.", "u": "https://lcdi-indonesia.id/"}, {"a": "Poore, J. & Nemecek, T. (2018). Reducing food's environmental impacts through producers and consumers. Science, 360(6392).", "u": "https://www.science.org/doi/10.1126/science.aaq0216"}]}, {"slug": "bank-sampah-ekonomi-sirkular", "topic": "Konsumen", "mood": "#4F7A3A", "title": "Bank sampah: ekonomi sirkular yang tumbuh dari RT.", "dek": "Ribuan bank sampah mengubah limbah rumah tangga menjadi imbalan bagi warga. Dampak iklimnya paling nyata bukan saat memungut plastik, tapi saat memutus aliran sampah organik ke TPA yang melepas metana.", "hook": "Belasan ribu bank sampah diam-diam menjahit ekonomi sirkular Indonesia — dan memangkas metana dari TPA, satu timbangan RT sekaligus.", "cover": "https://images.unsplash.com/photo-1532996122724-e3c354a0b15b?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, UNEP, KLHK, Bappenas)", "read": 4, "blocks": [{"t": "lead", "x": "Di sebuah gang RT, seorang ibu menimbang sekantong botol plastik lalu mencatat hasilnya di buku tabungan. Bukan tabungan uang — tabungan sampah. Adegan kecil itu berulang di ribuan titik di seluruh Indonesia, membentuk jaringan akar rumput yang diam-diam menjahit ekonomi sirkular dari unit paling bawah: bank sampah."}, {"t": "p", "x": "Mekanismenya sederhana tapi rapi. Warga memilah sampah di rumah, menyetornya ke bank sampah terdekat, lalu petugas menimbang dan mencatat. Plastik, kertas, kardus, dan logam dihargai per kilogram; nilainya masuk sebagai saldo yang bisa ditarik tunai, dipakai bayar listrik, atau ditukar sembako. Yang tadinya limbah berubah menjadi <b>imbalan</b> bagi warga — sekaligus bahan baku bagi industri daur ulang."}, {"t": "p", "x": "Skalanya tak main-main. Melalui SIPSN, KLHK mencatat belasan ribu unit bank sampah tersebar di hampir semua provinsi ⚠︎, digerakkan sebagian besar oleh ibu-ibu dan pengurus RT/RW. Tapi nilai terbesarnya melampaui uang."}, {"t": "h2", "x": "Di mana iklimnya masuk"}, {"t": "p", "x": "Kuncinya ada pada apa yang <i>tidak</i> berakhir di TPA. Sekitar 40% timbulan sampah nasional adalah sisa makanan dan bahan organik ⚠︎ (<a href=\"https://sipsn.menlhk.go.id/\">SIPSN, KLHK</a>). Ketika organik itu membusuk tertimbun tanpa oksigen — dan sebagian besar TPA di Indonesia masih <i>open dumping</i> — ia melepas metana. Secara global, sektor sampah menyumbang sekitar seperlima emisi metana buatan manusia (<a href=\"https://www.unep.org/resources/report/global-methane-assessment-benefits-and-costs-mitigating-methane-emissions\">UNEP & CCAC, 2021</a>)."}, {"t": "stat", "n": "±28×", "l": "potensi pemanasan metana dibanding CO₂ dalam 100 tahun", "s": "IPCC AR6, 2021"}, {"t": "pull", "x": "Dampak iklim bank sampah paling nyata bukan saat memungut plastik, melainkan saat memutus aliran sampah organik ke TPA."}, {"t": "h2", "x": "Nilai nyata, klaim yang jujur"}, {"t": "p", "x": "Perlu jujur soal batasnya. Mayoritas bank sampah masih fokus pada anorganik bernilai jual — plastik, kertas, logam — sedangkan fraksi organik yang justru paling banyak melepas metana kerap belum tergarap; ia butuh komposting, budidaya maggot, atau biodigester. Karena itu dampak iklimnya lebih tepat disebut <b>terlacak</b> ketimbang terukur presisi: menghitung metana yang 'tak jadi terlepas' menuntut data timbulan dan metode olah yang jarang lengkap di level RT."}, {"t": "p", "x": "Meski begitu, arah ekonominya sudah mahal untuk diabaikan. Bappenas memperkirakan kehilangan dan sampah pangan Indonesia setara kerugian Rp 213–551 triliun per tahun sepanjang 2000–2019 ⚠︎ — sebagian berakhir membusuk di TPA. Bank sampah adalah jawaban dari bawah: infrastruktur sosial yang mengubah kebiasaan memilah menjadi nilai. Tugas berikutnya — dan di sinilah <b>Glyiv</b> ingin membantu — adalah membuat kontribusi iklim itu bisa ditelusuri, dari timbangan di RT hingga angka yang bisa dipertanggungjawabkan."}], "story": [{"kind": "cover", "title": "Bank sampah: ekonomi sirkular dari RT", "text": "Ribuan bank sampah mengubah limbah rumah tangga menjadi imbalan bagi warga. Dampak iklimnya paling nyata saat memutus aliran sampah organik ke TPA yang melepas metana."}, {"kind": "hook", "title": "Menabung sampah", "text": "Belasan ribu bank sampah diam-diam menjahit ekonomi sirkular Indonesia — dan memangkas metana dari TPA, satu timbangan RT sekaligus."}, {"kind": "point", "title": "Limbah jadi imbalan", "text": "Warga memilah di rumah, menyetor, lalu ditimbang. Plastik, kertas, logam dihargai per kilo — masuk sebagai saldo yang bisa ditarik atau ditukar sembako."}, {"kind": "point", "title": "Yang tak sampai ke TPA", "text": "±40% sampah kita adalah organik ⚠︎. Membusuk tertimbun di TPA open dumping, ia melepas metana."}, {"kind": "stat", "title": "Kenapa metana penting", "big": "±28×", "label": "potensi pemanasan metana vs CO₂ (100 tahun)", "source": "IPCC AR6, 2021"}, {"kind": "quote", "title": "Inti soalnya", "text": "Dampaknya paling nyata saat memutus aliran organik ke TPA — bukan saat memungut plastik."}, {"kind": "end", "title": "Baca versi lengkapnya", "text": "Ekonomi sirkular tumbuh dari RT. Glyiv bantu agar kontribusi iklimnya bisa ditelusuri — baca Glyiv Kabar selengkapnya."}], "sources": [{"a": "IPCC (2021). Climate Change 2021: The Physical Science Basis (AR6 WG1) — Global Warming Potential metana (GWP100 ≈ 27–30).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "UNEP & CCAC (2021). Global Methane Assessment: Benefits and Costs of Mitigating Methane Emissions — sektor sampah ~20% metana antropogenik.", "u": "https://www.unep.org/resources/report/global-methane-assessment-benefits-and-costs-mitigating-methane-emissions"}, {"a": "KLHK. Sistem Informasi Pengelolaan Sampah Nasional (SIPSN) — komposisi sampah & data bank sampah.", "u": "https://sipsn.menlhk.go.id/"}, {"a": "Bappenas / LCDI (2021). Food Loss and Waste in Indonesia — kerugian ekonomi Rp 213–551 triliun/tahun (2000–2019)."}]}, {"slug": "motor-listrik-harian", "topic": "Konsumen", "mood": "#1E5F8C", "title": "Motor listrik: hitung ulang saat setrumnya masih batu bara.", "dek": "Beralih ke motor listrik menghapus asap dari knalpot — tapi jejak karbonnya berpindah ke pembangkit, dan di Indonesia pembangkit itu masih ⚠︎ sekitar 60% batu bara.", "hook": "Motor listrikmu tak berasap. Tapi coba tanya dulu: setrumnya datang dari mana?", "cover": "https://images.unsplash.com/photo-1449965408869-eaa3f722e40d?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data publik IEA, Ember & ICCT", "read": 4, "blocks": [{"t": "lead", "x": "Beralih ke motor listrik terasa seperti kemenangan seketika: tak ada lagi asap yang menyembur dari knalpot, tak ada bau bensin di lampu merah. Dan di titik itu, memang benar — emisinya nol. Tapi emisi tak benar-benar lenyap; ia hanya pindah tempat, dari knalpot di jalanan ke cerobong di pembangkit listrik. Maka pertanyaan yang jujur bukan 'apakah motor listrik bersih', melainkan 'setrumnya datang dari mana'."}, {"t": "p", "x": "Kabar baiknya, motor listrik sudah menang bahkan sebelum jaringan dibersihkan. Motornya mengubah sebagian besar energi menjadi gerak, sedangkan mesin bensin membuang kebanyakan energinya sebagai panas. Selisih efisiensi itu begitu lebar sehingga — dihitung dari sumber sampai roda (<em>well-to-wheel</em>) — sepeda motor listrik umumnya tetap beremisi lebih rendah daripada motor bensin, <b>meski listriknya dari batu bara</b> (<a href=\"https://theicct.org/publication/a-global-comparison-of-the-life-cycle-greenhouse-gas-emissions-of-combustion-engine-and-electric-passenger-vehicles/\">ICCT, 2021</a>)."}, {"t": "stat", "n": "⚠︎ ~60%", "l": "porsi batu bara dalam bauran pembangkit listrik Indonesia", "s": "Ember, Global Electricity Review 2024"}, {"t": "p", "x": "Tapi 'lebih rendah' tak sama dengan 'sebersih mungkin'. Di jaringan yang masih ⚠︎ sekitar 60% batu bara, setiap kilowatt-jam yang mengisi baterai ikut membawa jejak pembangkitnya — faktor emisi jaringan Indonesia ditaksir ⚠︎ di kisaran 0,8 kg CO₂ per kWh. Manfaat motor listrik nyata, tetapi belum maksimal: sebagiannya ditentukan oleh hal yang berada jauh di luar kendali pengendara."}, {"t": "p", "x": "Justru skalanya yang membuat ini penting. Indonesia menampung lebih dari ⚠︎ 120 juta sepeda motor — salah satu penyumbang terbesar polusi udara kota. Penghematan per unit yang 'belum maksimal' pun, bila dikalikan puluhan juta kendaraan, menjadi perbedaan nyata bagi udara Jakarta dan kota-kota lain, terutama karena knalpotnya lenyap tepat di tempat orang bernapas."}, {"t": "pull", "x": "Motor listrik tidak menghapus emisi. Ia memindahkannya ke pembangkit — dan di sanalah pertarungan sebenarnya."}, {"t": "h2", "x": "Jejaknya ikut bersih bersama jaringan"}, {"t": "p", "x": "Inilah bagian yang menjanjikan: jejak motor listrik menyusut dengan sendirinya setiap kali jaringan menua lebih hijau. Lewat kemitraan <a href=\"https://www.jetp-id.org/\">JETP</a>, Indonesia menargetkan porsi energi terbarukan naik dan emisi sektor listrik memuncak lebih awal ⚠︎ — artinya kendaraan yang sama makin bersih dari tahun ke tahun tanpa mengganti apa pun. Mesin bensin tak punya jalur seperti itu; ia terkunci pada emisi yang nyaris sama sepanjang usianya."}, {"t": "p", "x": "Pengendara pun bukan tanpa peran. Mengisi daya di siang hari saat surya atap bekerja, atau di jam beban rendah, menggeser sedikit angka itu. Yang terpenting, keputusannya berpijak jujur: motor listrik adalah <b>kontribusi</b> nyata pada udara yang lebih bersih dan jejak karbon yang lebih rendah — bukan klaim 'nol emisi'. Glyiv memilih menampilkan jejak itu apa adanya, <b>terlacak</b> sampai ke sumber setrumnya, agar keputusan hijau berpijak pada angka, bukan perasaan."}], "story": [{"kind": "cover", "title": "Motor listrik, saat setrumnya masih batu bara", "text": "Beralih ke motor listrik menghapus asap dari knalpot — tapi jejak karbonnya berpindah ke pembangkit, dan di Indonesia pembangkit itu masih ⚠︎ sekitar 60% batu bara."}, {"kind": "hook", "title": "Setrumnya dari mana?", "text": "Motor listrikmu tak berasap. Tapi coba tanya dulu: setrumnya datang dari mana?"}, {"kind": "point", "title": "Emisi tak lenyap — ia pindah", "text": "Knalpot bersih. Tapi jejaknya berpindah ke cerobong pembangkit listrik."}, {"kind": "point", "title": "Toh, tetap menang", "text": "Motor listrik jauh lebih efisien — emisinya lebih rendah dari bensin, bahkan di jaringan batu bara."}, {"kind": "stat", "title": "Sumber setrum kita", "big": "~60%", "label": "listrik Indonesia dari batu bara ⚠︎", "source": "Ember, 2024"}, {"kind": "point", "title": "Dan makin bersih tiap tahun", "text": "Saat jaringan membersih lewat JETP, motor yang sama otomatis makin rendah emisi. Bensin tak bisa begitu."}, {"kind": "end", "title": "Hitung ulang, dengan jujur", "text": "Glyiv menampilkan jejak karbon apa adanya — terlacak sampai sumbernya. Baca lengkap & gabung ekosistem Glyiv."}], "sources": [{"a": "Ember (2024). Global Electricity Review 2024 — Indonesia (bauran listrik & porsi batu bara).", "u": "https://ember-climate.org/insights/research/global-electricity-review-2024/"}, {"a": "Bieker, G. / ICCT (2021). A global comparison of the life-cycle greenhouse gas emissions of combustion engine and electric passenger vehicles.", "u": "https://theicct.org/publication/a-global-comparison-of-the-life-cycle-greenhouse-gas-emissions-of-combustion-engine-and-electric-passenger-vehicles/"}, {"a": "IEA (2024). Global EV Outlook 2024 (emisi daur hidup kendaraan listrik vs pembakaran dalam).", "u": "https://www.iea.org/reports/global-ev-outlook-2024"}, {"a": "JETP Secretariat Indonesia (2023). Comprehensive Investment and Policy Plan (CIPP) — target dekarbonisasi sektor listrik.", "u": "https://www.jetp-id.org/"}]}, {"slug": "ac-rumah-hemat-listrik", "topic": "Konsumen", "mood": "#C6A15B", "title": "AC: sumber tagihan (dan emisi) terbesar di rumah tropis.", "dek": "Di rumah tropis, pendingin ruangan diam-diam menjadi baris terbesar di tagihan listrik sekaligus penyumbang emisi terbesar dari rumah Anda — dan dua kebiasaan sederhana bisa memangkas keduanya sekaligus.", "hook": "Musuh tagihan listrik Anda bukan kulkas atau TV — tapi remote AC yang disetel 18°C.", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, US DOE)", "read": 4, "blocks": [{"t": "lead", "x": "Di rumah-rumah tropis, tidak ada satu alat pun yang menyedot listrik seperti pendingin ruangan. Ketika suhu siang menembus 33°C, AC menyala berjam-jam tanpa jeda — dan diam-diam menjadi baris terbesar di tagihan listrik sekaligus penyumbang emisi terbesar dari sebuah rumah. Kulkas memang menyala terus, tetapi dayanya kecil; AC justru menarik daya besar setiap kali kompresornya hidup."}, {"t": "p", "x": "Ini bukan sekadar kesan. Secara global, penyejuk udara dan kipas listrik sudah menyerap sekitar <b>10% dari seluruh konsumsi listrik dunia</b>, dan kebutuhan energi untuk pendinginan diperkirakan lebih dari tiga kali lipat pada 2050 — dengan sebagian besar pertumbuhannya justru di negara tropis seperti Indonesia <a href=\"https://www.iea.org/reports/the-future-of-cooling\">(IEA, 2018)</a>."}, {"t": "p", "x": "Yang membuat AC terasa lebih berat di sini bukan hanya lama nyalanya, tetapi <b>dari mana listriknya datang</b>. Mayoritas listrik Indonesia masih dibangkitkan dari batu bara, sehingga tiap kWh yang dipakai AC membawa jejak karbon yang relatif tinggi — faktor emisi jaringan nasional berkisar sekitar 0,8 kg CO₂ per kWh ⚠︎ (angka resmi diperbarui berkala). Artinya, memangkas pemakaian AC memangkas dua hal sekaligus: rupiah dan emisi."}, {"t": "pull", "x": "Menaikkan setelan AC beberapa derajat bukan soal menahan gerah — itu cara termurah memangkas tagihan sekaligus emisi, tanpa membeli apa pun."}, {"t": "h2", "x": "Dua tuas yang ada di tangan Anda"}, {"t": "p", "x": "Tuas pertama adalah <b>setelan suhu</b>. Semakin rendah suhu yang Anda minta, semakin keras dan lama kompresor harus bekerja. Menaikkan setelan dari 18–20°C ke sekitar 25°C bisa memangkas konsumsi energi pendinginan secara nyata — berbagai sumber memperkirakan penghematan sekitar 3–10% untuk setiap 1°C ⚠︎, sehingga selisih beberapa derajat saja sudah terasa di tagihan. Banyak orang mengira menyetel suhu serendah mungkin membuat ruangan dingin lebih cepat; padahal AC mendinginkan dengan laju yang sama, hanya berhenti lebih lama pada suhu yang lebih tinggi."}, {"t": "p", "x": "Tuas kedua adalah <b>perawatan rutin</b>. Filter yang tersumbat debu memaksa AC bekerja lebih keras untuk hasil pendinginan yang sama. Menurut Departemen Energi Amerika Serikat, mengganti filter kotor dengan yang bersih saja dapat menurunkan konsumsi listrik AC sebesar <b>5–15%</b> <a href=\"https://www.energy.gov/energysaver/maintaining-your-air-conditioner\">(US DOE)</a>; membersihkan koil dan memastikan refrigeran sesuai spesifikasi menambah efisiensi lagi."}, {"t": "stat", "n": "≈10%", "l": "bagian konsumsi listrik dunia yang sudah disedot AC dan kipas listrik", "s": "IEA, The Future of Cooling, 2018"}, {"t": "h2", "x": "Dari tagihan ke jejak yang terlacak"}, {"t": "p", "x": "Kabar baiknya, kedua langkah ini menurunkan biaya dan emisi sekaligus — tanpa perlu klaim muluk soal 'netral karbon'. Di Glyiv, penghematan seperti ini bisa <b>terlacak</b>: berapa kWh yang dipangkas, berapa kilogram CO₂ yang tak jadi terlepas. Bukan janji besar, melainkan kontribusi kecil yang bisa dipertanggungjawabkan — dan bagi rumah tangga yang konsisten hemat, bisa berujung pada imbalan di ekosistem kami."}], "story": [{"kind": "cover", "title": "AC: tagihan (dan emisi) terbesar di rumah tropis", "text": "Di rumah tropis, pendingin ruangan diam-diam menjadi baris terbesar di tagihan listrik sekaligus penyumbang emisi terbesar rumah Anda."}, {"kind": "hook", "title": "Musuh tagihanmu?", "text": "Bukan kulkas atau TV — tapi remote AC yang disetel 18°C."}, {"kind": "point", "title": "Penyedot listrik nomor satu", "text": "Di rumah tropis, AC kerap jadi baris terbesar di tagihan listrik sekaligus sumber emisi terbesar rumah tangga."}, {"kind": "point", "title": "Kenapa lebih berat di Indonesia", "text": "Listrik kita masih banyak dari batu bara, jadi tiap kWh AC membawa jejak karbon yang tak kecil. ⚠︎"}, {"kind": "point", "title": "Dua tuas gratis", "text": "Naikkan setelan ke sekitar 25°C dan servis rutin (ganti filter). Hemat biaya dan emisi tanpa beli apa pun."}, {"kind": "stat", "title": "Cuma dari ganti filter", "big": "5–15%", "label": "turun konsumsi listrik AC dengan mengganti filter tersumbat ke yang bersih", "source": "US DOE, energy.gov"}, {"kind": "end", "title": "Hemat yang terlacak", "text": "Baca artikel lengkapnya, dan lihat bagaimana Glyiv membuat penghematanmu terlacak — bukan sekadar klaim. Gabung ekosistem Glyiv."}], "sources": [{"a": "International Energy Agency (2018). The Future of Cooling: Opportunities for energy-efficient air conditioning.", "u": "https://www.iea.org/reports/the-future-of-cooling"}, {"a": "U.S. Department of Energy. Maintaining Your Air Conditioner (Energy Saver).", "u": "https://www.energy.gov/energysaver/maintaining-your-air-conditioner"}, {"a": "Kementerian ESDM / Ditjen Ketenagalistrikan. Faktor emisi jaringan (grid emission factor) sistem ketenagalistrikan Indonesia — diperbarui berkala."}]}, {"slug": "standby-power-vampir-listrik", "topic": "Konsumen", "mood": "#C6A15B", "title": "Listrik 'vampir': perangkat yang menyedot daya bahkan saat mati.", "dek": "Pengisi daya yang menempel dan elektronik yang menyala samar bisa menyumbang beberapa persen ⚠︎ dari tagihan listrik rumah — pemborosan senyap yang sering bisa dihentikan cuma dengan mencabut colokan.", "hook": "Perangkat yang \"mati\" di rumahmu mungkin masih menyesap listrik diam-diam sepanjang tahun — dan itu muncul di tagihan.", "cover": "https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data IEA & Berkeley Lab", "read": 4, "blocks": [{"t": "lead", "x": "Colokan yang tampak mati sering kali tidak benar-benar mati. Televisi yang padam tapi lampu indikatornya masih menyala, pengisi daya yang menempel di dinding tanpa ponsel, dekoder TV yang sekadar 'tidur' — semuanya masih menyesap listrik, diam-diam, sepanjang hari. Inilah yang kerap disebut listrik 'vampir': beban standby yang tak pernah benar-benar berhenti."}, {"t": "p", "x": "Fenomenanya nyata dan terlacak. Menurut <a href=\"https://standby.lbl.gov/\">Lawrence Berkeley National Laboratory</a>, satu perangkat bisa menarik 1–10 watt dalam mode standby — sepele untuk satu alat, tapi terkumpul di seluruh rumah. Rumah tangga modern rata-rata punya belasan hingga puluhan perangkat yang selalu tersambung, dan sebagian besar tak pernah dimatikan sepenuhnya."}, {"t": "stat", "n": "~400 TWh", "l": "listrik terbuang oleh perangkat terhubung dalam mode standby secara global (2013) — kira-kira setara konsumsi tahunan Inggris dan Norwegia digabung", "s": "IEA, More Data Less Energy, 2014"}, {"t": "p", "x": "Seberapa besar dampaknya ke tagihan? IEA memperkirakan beban standby menyumbang <b>beberapa persen</b> ⚠︎ dari konsumsi listrik rumah tangga di banyak negara — angka pastinya bergantung pada jumlah dan jenis perangkat. Sebuah studi <a href=\"https://www.nrdc.org/resources/home-idle-load-devices-wasting-huge-amounts-electricity-when-not-active-use\">NRDC</a> di rumah-rumah California bahkan menemukan perangkat 'selalu-menyala' (idle load, cakupannya lebih luas dari sekadar standby) menyerap sekitar 23% listrik rumah."}, {"t": "h2", "x": "Mana yang paling rakus"}, {"t": "p", "x": "Tidak semua vampir sama lapar. Dekoder TV berbayar dan konsol game lawas termasuk yang paling boros saat menganggur. Modem dan router memang perlu terus menyala, tapi printer, soundbar, microwave dengan jam digital, hingga pengisi daya yang dibiarkan menancap semuanya menambah beban yang mudah dilupakan — tak terlihat, tapi terus berjalan."}, {"t": "pull", "x": "Beban standby jarang muncul sebagai satu baris di tagihan — ia bersembunyi di dalam total, tetes demi tetes, sepanjang tahun."}, {"t": "p", "x": "Kabar baiknya, ini termasuk pemborosan yang paling mudah dihentikan. Cabut pengisi daya yang menganggur, satukan perangkat hiburan pada satu <b>power strip</b> yang bisa dimatikan sekaligus, dan aktifkan mode hemat daya pada TV serta konsol. Lewat inisiatif <a href=\"https://www.iea.org/reports/more-data-less-energy\">'1-Watt'</a>, IEA bahkan mendorong produsen menekan konsumsi standby ke bawah 1 watt per perangkat."}, {"t": "bars", "h": [0.15, 0.3, 0.45, 0.55, 0.72, 0.9], "cap": "Ilustrasi: konsumsi standby beragam perangkat rumah — dari pengisi daya menganggur hingga dekoder TV (watt relatif). Sumber: pola umum, Berkeley Lab."}, {"t": "p", "x": "Di Indonesia, data khusus soal beban standby rumah tangga belum banyak dipublikasikan ⚠︎, tapi logikanya sama: untuk tagihan yang dihitung per kWh, watt yang terbuang tetap watt yang dibayar. Bagi Glyiv, jejak sekecil ini menegaskan satu prinsip besar — yang terlacak bisa dikelola. Mematikan vampir listrik memang bukan solusi iklim tunggal, tapi ia menurunkan tagihan sekaligus emisi: sebuah kontribusi nyata yang dimulai dari satu colokan."}], "story": [{"kind": "cover", "title": "Listrik 'vampir'", "text": "Pengisi daya yang menempel dan elektronik yang menyala samar bisa menyumbang beberapa persen ⚠︎ dari tagihan listrik rumah — pemborosan senyap yang sering bisa dihentikan cuma dengan mencabut colokan."}, {"kind": "hook", "title": "Mati, tapi tetap menyedot", "text": "Charger nempel, TV padam, dekoder 'tidur' — semuanya masih menyesap daya sepanjang hari."}, {"kind": "point", "title": "Apa itu beban standby", "text": "Tiap perangkat menarik 1–10 watt saat menganggur. Kecil untuk satu alat, tapi terkumpul di seluruh rumah."}, {"kind": "stat", "title": "Bukan angka kecil", "big": "~400 TWh", "label": "listrik terbuang perangkat standby global (2013) — setara Inggris + Norwegia setahun", "source": "IEA, 2014"}, {"kind": "point", "title": "Hentikan dalam semenit", "text": "Cabut charger menganggur, satukan hiburan di satu power strip, nyalakan mode hemat daya TV & konsol."}, {"kind": "quote", "title": "Prinsipnya", "text": "Yang terlacak bisa dikelola — mematikan vampir listrik menurunkan tagihan sekaligus emisi."}, {"kind": "end", "title": "Baca selengkapnya", "text": "Pemborosan senyap, solusi sederhana. Ikuti Glyiv Kabar untuk cerita karbon lain yang bisa kamu tindaki hari ini."}], "sources": [{"a": "IEA (2014). More Data, Less Energy: Making Network Standby More Efficient in Billions of Connected Devices.", "u": "https://www.iea.org/reports/more-data-less-energy"}, {"a": "Lawrence Berkeley National Laboratory. Standby Power — measured wattage of common devices.", "u": "https://standby.lbl.gov/"}, {"a": "NRDC / Pierre Delforge (2015). Home Idle Load: Devices Wasting Huge Amounts of Electricity When Not in Active Use.", "u": "https://www.nrdc.org/resources/home-idle-load-devices-wasting-huge-amounts-electricity-when-not-active-use"}]}, {"slug": "transport-umum-mrt-jakarta", "topic": "Konsumen", "mood": "#1E5F8C", "title": "Beralih ke MRT: matematika sederhana penurunan emisi kota.", "dek": "Memindahkan perjalanan dari kendaraan pribadi ke angkutan massal memangkas emisi per penumpang-kilometer hingga sekitar seperlima — sekaligus mengurai macet dan menekan polusi udara kota.", "hook": "Satu mobil, satu orang. Satu MRT, ratusan orang. Emisi dibagi ke berapa kepala — di situ letak matematikanya.", "cover": "https://images.unsplash.com/photo-1449965408869-eaa3f722e40d?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, IEA, faktor emisi Pemerintah Inggris)", "read": 4, "blocks": [{"t": "lead", "x": "Bayangkan sebuah mobil membawa satu orang, dan sebuah rangkaian MRT membawa ratusan. Keduanya membakar energi untuk bergerak — tapi yang satu membagi jejaknya ke satu penumpang, yang lain ke ratusan. Di situlah letak matematika sederhana penurunan emisi kota: bukan soal mesin yang lebih ajaib, tapi soal berapa banyak orang yang ikut dalam satu perjalanan."}, {"t": "p", "x": "Transportasi menyumbang <b>sekitar seperempat</b> emisi CO2 terkait energi di dunia, dan sebagian besarnya datang dari kendaraan penumpang di jalan <a href=\"https://www.iea.org/energy-system/transport\">(IEA)</a>. Artinya, cara sebuah kota memindahkan warganya adalah salah satu tuas iklim paling langsung yang tersedia."}, {"t": "p", "x": "Perbandingannya jadi jernih ketika dihitung per <b>penumpang-kilometer</b> — emisi untuk memindahkan satu orang sejauh satu kilometer. Dengan faktor emisi Pemerintah Inggris 2022, mobil bensin berpenumpang satu melepas sekitar <b>170 gram CO2e</b> per penumpang-km, sementara kereta rel — termasuk metro dan tram — hanya di kisaran <b>30-an gram</b>, kira-kira seperlima-nya <a href=\"https://ourworldindata.org/travel-carbon-footprint\">(Our World in Data)</a>."}, {"t": "bars", "h": [1, 0.69, 0.39, 0.17, 0.14, 0.12], "cap": "Emisi gCO2e per penumpang-km (faktor Pemerintah Inggris 2022): pesawat domestik 246 · mobil bensin 1 orang 170 · bus 97 · mobil 4 orang 43 · kereta nasional 35 · metro/tram ~29. Sumber: Our World in Data."}, {"t": "p", "x": "Tapi angka ini bukan hukum alam. Yang menentukan adalah <b>tingkat keterisian</b>: kereta yang lengang atau mobil yang penuh empat orang bisa mempersempit jaraknya. Mobil bensin dengan empat penumpang, misalnya, turun ke sekitar 43 gram CO2e per penumpang-km. Justru karena itulah angkutan massal unggul — ia dirancang untuk terisi banyak, sepanjang hari."}, {"t": "pull", "x": "Rahasianya bukan mesin yang lebih bersih, melainkan pembagi yang lebih besar: satu kereta menyebar emisinya ke ratusan penumpang sekaligus."}, {"t": "h2", "x": "Angka untuk Jakarta"}, {"t": "p", "x": "Satu catatan jujur: faktor di atas memakai jaringan listrik Inggris yang sudah relatif bersih. MRT Jakarta berjalan dengan listrik dari jaringan Jawa-Bali yang masih didominasi batu bara ⚠︎, sehingga emisi per penumpang-km-nya lebih tinggi dari angka Inggris. Namun logika pembaginya tetap berlaku — karena satu rangkaian mengangkut ratusan orang, jejak per penumpang tetap jauh di bawah mobil pribadi. Dan seiring jaringan listrik makin hijau, selisihnya justru melebar."}, {"t": "p", "x": "Keuntungannya tak berhenti di karbon. Memindahkan perjalanan ke angkutan massal mengurai kemacetan dan menekan polusi udara lokal — Jakarta berulang kali masuk daftar kota dengan kualitas udara terburuk, dengan transportasi sebagai salah satu sumbernya ⚠︎ <a href=\"https://www.iqair.com/world-air-quality-report\">(IQAir)</a>. Emisi yang turun dan udara yang lebih bersih datang dari keputusan yang sama."}, {"t": "p", "x": "IPCC menempatkan perpindahan ke angkutan umum, jalan kaki, dan bersepeda sebagai salah satu langkah sisi-permintaan paling efektif untuk kota <a href=\"https://www.ipcc.ch/report/ar6/wg3/\">(AR6 WGIII)</a>. Bagi Glyiv, setiap perjalanan yang berpindah adalah kontribusi kecil yang bisa terlacak — bukan klaim heroik, melainkan penjumlahan yang jujur dari banyak pilihan sehari-hari."}], "story": [{"kind": "cover", "title": "Beralih ke MRT: matematika sederhana emisi kota", "text": "Memindahkan perjalanan dari kendaraan pribadi ke angkutan massal memangkas emisi per penumpang-kilometer hingga sekitar seperlima — sekaligus mengurai macet dan polusi."}, {"kind": "hook", "title": "Satu mobil, satu orang. Satu MRT, ratusan orang. Emisi dibagi ke berapa kepala?"}, {"kind": "point", "title": "Bagi ke berapa kepala?", "text": "Transportasi ~seperempat emisi energi dunia. Kuncinya bukan mesin ajaib, tapi satu kereta membagi emisinya ke ratusan penumpang."}, {"kind": "stat", "title": "Per penumpang-kilometer", "big": "170 → ~30", "label": "gram CO2e per penumpang-km: mobil pribadi (1 orang) vs kereta rel/metro", "source": "Faktor emisi Pemerintah Inggris 2022 · Our World in Data"}, {"kind": "point", "title": "Konteks Jakarta ⚠︎", "text": "Listrik Jawa-Bali masih banyak batu bara, jadi angka lokal lebih tinggi. Tapi karena kereta berbagi beban, jejak per penumpang tetap jauh di bawah mobil."}, {"kind": "quote", "title": "Pembagi yang lebih besar", "text": "Rahasianya bukan mesin yang lebih bersih, tapi pembagi yang lebih besar."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv", "text": "Setiap perjalanan yang berpindah adalah kontribusi kecil yang terlacak. Gabung Glyiv Kabar."}], "sources": [{"a": "IPCC (2022). AR6 Working Group III, Chapter 10: Transport. Mitigation of Climate Change.", "u": "https://www.ipcc.ch/report/ar6/wg3/"}, {"a": "Our World in Data — Hannah Ritchie (2023). Which form of transport has the smallest carbon footprint? (berdasarkan faktor emisi Pemerintah Inggris/BEIS 2022).", "u": "https://ourworldindata.org/travel-carbon-footprint"}, {"a": "IEA (2023). Transport — Energy System / CO2 emissions.", "u": "https://www.iea.org/energy-system/transport"}, {"a": "IQAir (2024). World Air Quality Report — data kualitas udara Jakarta.", "u": "https://www.iqair.com/world-air-quality-report"}]}, {"slug": "jejak-karbon-kopi", "topic": "Konsumen", "mood": "#B5623A", "title": "Secangkir kopi: di mana jejak karbonnya sebenarnya?", "dek": "Kita refleks menyalahkan biji yang diimpor dari jauh — padahal untuk kopi susu, sebagian besar jejaknya justru datang dari susu sapi, bukan dari kopinya.", "hook": "Menyalahkan biji impornya? Untuk kopi susu, jejak karbon terbesar biasanya ada di seloki susu sapinya.", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (Poore & Nemecek 2018, Our World in Data)", "read": 3, "blocks": [{"t": "lead", "x": "Kita cenderung menyalahkan bijinya. Kopi diimpor dari jauh, pikir kita, jadi pasti 'jejak mil'-nya besar. Tapi untuk secangkir kopi susu, tersangka utamanya sering bukan biji yang terbang lintas benua — melainkan seloki susu sapi yang dituang di atasnya."}, {"t": "p", "x": "Perhatikan takarannya. Satu cangkir hanya memakai sekitar <b>10–18 gram</b> biji kopi, sementara satu latte atau kopi susu kekinian bisa memuat <b>150–250 ml</b> susu. Dari berat saja, susu jauh mengungguli kopi — dan susu sapi kebetulan salah satu bahan minuman berjejak karbon tinggi, karena metana dari sapi, pakan ternak, dan lahan yang dibutuhkan <a href=\"https://ourworldindata.org/environmental-impact-milks\">(Our World in Data)</a>."}, {"t": "stat", "n": "≈ 3,2 kg CO₂e", "l": "per liter susu sapi — sekitar 3× kebanyakan susu nabati", "s": "Poore & Nemecek (2018) · Our World in Data"}, {"t": "p", "x": "Lalu bagaimana dengan 'jejak mil' tadi? Ternyata transportasi rata-rata hanya menyumbang sekitar <b>6% dari total emisi pangan global</b>; porsi terbesar terjadi di kebun dan peternakan, jauh sebelum produk naik kapal <a href=\"https://ourworldindata.org/food-choice-vs-eating-local\">(Our World in Data)</a>. Untuk kopi, emisi terpusat di budidaya dan pengolahan — bukan di perjalanannya ke cangkir Anda."}, {"t": "p", "x": "Jadi, ganti ke oat atau kedelai? Rata-rata, ya — susu nabati populer berjejak karbon sekitar sepertiga susu sapi. Tapi kejujuran menuntut catatan: tiap alternatif punya tukar-tambahnya sendiri, misalnya kebutuhan air yang besar pada almond. 'Lebih baik' bukan berarti 'tanpa dampak' — hanya berarti bebannya bisa jauh lebih ringan untuk keputusan kecil yang Anda ulang setiap hari."}, {"t": "pull", "x": "Intuisi soal 'apa yang hijau' sering meleset: jejak terbesar kopi susu kerap bersembunyi di susunya, bukan di bijinya."}, {"t": "h2", "x": "Bukan berarti bijinya bebas dosa"}, {"t": "p", "x": "Ini bukan izin menganggap kopi tanpa dampak. Perluasan kebun bisa mendorong alih fungsi hutan, pengolahan basah menghasilkan limbah, dan cara menyeduh pun berpengaruh — listrik mesin, air panas, sampai gelas sekali pakai. Tapi bila Anda mencari satu tuas terbesar untuk secangkir kopi susu, mengurangi atau mengganti susu sapinya lebih berdampak ketimbang mempersoalkan asal bijinya. Mike Berners-Lee memperkirakan sebuah latte besar bisa membawa <b>340–550 gram CO₂e</b> ⚠︎ — mayoritas dari susu — dibanding kopi hitam yang jauh lebih ringan."}, {"t": "p", "x": "Pelajaran yang lebih besar: intuisi adalah pemandu yang buruk untuk karbon. Yang <i>terasa</i> hijau belum tentu <b>terlacak</b> sebagai rendah emisi — dan sebaliknya. Di sinilah data bekerja: memisahkan tebakan dari yang benar-benar bisa dipertanggungjawabkan. Glyiv dibangun untuk itu — membuat jejak karbon sehari-hari, dari secangkir kopi hingga satu rantai pasok, menjadi sesuatu yang terlacak, bukan sekadar terasa."}], "story": [{"kind": "cover", "title": "Secangkir kopi: di mana jejaknya?", "text": "Kita refleks menyalahkan biji yang diimpor dari jauh — padahal untuk kopi susu, sebagian besar jejaknya justru datang dari susu sapi."}, {"kind": "hook", "title": "Bukan bijinya", "text": "Menyalahkan biji impornya? Untuk kopi susu, tersangka utamanya biasanya seloki susu sapi di atasnya."}, {"kind": "point", "title": "Soal takaran", "text": "10–18 gram biji kopi per cangkir vs 150–250 ml susu sapi dalam satu latte. Susu jauh lebih banyak — dan berjejak tinggi."}, {"kind": "point", "title": "'Jejak mil' itu mitos", "text": "Transportasi rata-rata hanya ~6% dari emisi pangan. Beban terbesar ada di kebun dan peternakan."}, {"kind": "stat", "title": "Susu sapi vs nabati", "big": "≈ 3×", "label": "jejak karbon susu sapi per liter dibanding kebanyakan susu nabati", "source": "Poore & Nemecek 2018 · Our World in Data"}, {"kind": "quote", "title": "Intuisi sering meleset", "text": "Jejak terbesar kopi susu kerap bersembunyi di susunya, bukan di bijinya."}, {"kind": "end", "title": "Terlacak, bukan sekadar terasa", "text": "Baca ulasan lengkapnya — dan lihat bagaimana Glyiv membuat jejak karbon sehari-hari jadi sesuatu yang bisa dipertanggungjawabkan."}], "sources": [{"a": "Poore, J. & Nemecek, T. (2018). Reducing food's environmental impacts through producers and consumers. Science, 360(6392), 987–992.", "u": "https://www.science.org/doi/10.1126/science.aaq0216"}, {"a": "Ritchie, H. (2022). Dairy vs. plant-based milk: what are the environmental impacts? Our World in Data.", "u": "https://ourworldindata.org/environmental-impact-milks"}, {"a": "Ritchie, H. (2020). You want to reduce the carbon footprint of your food? Focus on what you eat, not whether it is local. Our World in Data.", "u": "https://ourworldindata.org/food-choice-vs-eating-local"}, {"a": "Berners-Lee, M. (2020). How Bad Are Bananas? The Carbon Footprint of Everything (revised ed.). Profile Books."}]}, {"slug": "plastik-sekali-pakai-hitungan", "topic": "Konsumen", "mood": "#1E5F8C", "title": "Plastik sekali pakai: soal iklim atau soal laut?", "dek": "Jejak karbon plastik nyata dan lahir di pabrik; tapi luka terbesarnya kerap ada di laut. Memisahkan dua soal ini membuat solusi lebih tepat sasaran — bukan sekadar 'anti-plastik'.", "hook": "Sedotan plastik memang bikin masalah — tapi untuk laut, belum tentu untuk iklim. Bedanya penting.", "cover": "https://images.unsplash.com/photo-1532996122724-e3c354a0b15b?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 3, "blocks": [{"t": "lead", "x": "Setiap kali sedotan atau kantong plastik jadi sorotan, dua masalah yang sebenarnya berbeda kerap ditumpuk jadi satu: soal iklim dan soal laut. Keduanya nyata — tetapi bekerja di tempat yang berbeda, dan menyamakannya justru sering membuat solusi kita meleset dari sasaran."}, {"t": "p", "x": "Jejak karbon plastik memang nyata, tapi hampir seluruhnya lahir jauh sebelum benda itu sampai ke tangan kita. Menurut <a href=\"https://www.oecd.org/en/publications/global-plastics-outlook_de747aef-en.html\">OECD (2022)</a>, plastik menyumbang sekitar <b>3,4% emisi gas rumah kaca global</b> pada 2019, dan <b>90%</b> di antaranya berasal dari produksi serta pengolahannya dari bahan bakar fosil. Beban iklim plastik, dengan kata lain, terkunci di kilang dan pabrik petrokimia — bukan di tempat sampah dapur Anda."}, {"t": "stat", "n": "3,4%", "l": "kontribusi plastik ke emisi GRK global (2019) — 90% dari produksi & pengolahan fosil", "s": "OECD, Global Plastics Outlook, 2022"}, {"t": "p", "x": "Masalah terbesar plastik sekali pakai justru sering bukan karbonnya, melainkan ke mana ia pergi setelah dipakai beberapa menit. Plastik tak membusuk; ia hanya pecah menjadi serpihan yang bertahan puluhan hingga ratusan tahun. Laporan <a href=\"https://www.pewtrusts.org/en/research-and-analysis/articles/2020/07/23/breaking-the-plastic-wave-top-findings\">Pew & SYSTEMIQ (2020)</a> memperkirakan sekitar <b>11 juta ton</b> plastik mengalir ke laut setiap tahun — dan angka itu bisa hampir tiga kali lipat pada 2040 bila tak ada perubahan."}, {"t": "h2", "x": "Dua masalah, dua solusi"}, {"t": "p", "x": "Membedakan keduanya penting karena obatnya tak sama. Untuk <b>iklim</b>, yang paling menentukan adalah bagaimana plastik diproduksi dan seberapa sering sebuah benda dipakai ulang. Untuk <b>pencemaran</b>, yang menentukan adalah apakah plastik itu terkumpul, terpilah, dan terkelola — bukan bocor ke sungai lalu pantai. Kampanye 'anti-plastik' yang menyapu rata bisa keliru sasaran pada salah satu dari keduanya."}, {"t": "pull", "x": "Untuk iklim, yang penting sering bukan bahannya — tapi berapa kali ia dipakai."}, {"t": "p", "x": "Contohnya kerap menohok. Studi <a href=\"https://www.gov.uk/government/publications/life-cycle-assessment-of-supermarket-carrier-bags-a-review-of-the-bags-available-in-2006\">Environment Agency Inggris (2011)</a> menemukan sebuah kantong katun harus dipakai ulang sekitar <b>131 kali</b> untuk mengalahkan satu kantong plastik HDPE sekali pakai dari sisi dampak iklim — karena menanam kapas dan menenun kain jauh lebih boros energi. Mengganti plastik dengan bahan yang 'terlihat lebih hijau' belum tentu menurunkan emisi; tanpa dipakai ulang cukup sering, ia bisa malah menaikkannya."}, {"t": "p", "x": "Di sisi pencemaran, celahnya ada di pengelolaan, bukan di molekulnya. Secara global hanya sekitar <b>9%</b> sampah plastik yang benar-benar terdaur ulang (<a href=\"https://www.oecd.org/en/publications/global-plastics-outlook_de747aef-en.html\">OECD, 2022</a>). Indonesia sendiri, lewat Perpres 83/2018, menargetkan pengurangan sampah plastik di laut hingga <b>70% pada 2025</b> ⚠︎ — target yang jauh lebih soal infrastruktur pengumpulan dan kebiasaan warga ketimbang soal karbon."}, {"t": "p", "x": "Maka pertanyaan yang lebih berguna bukan 'plastik atau bukan', melainkan 'masalah mana yang sedang kita pecahkan'. Memilah isu — karbon di hulu, pencemaran di hilir — membuat setiap tindakan lebih tepat sasaran: kurangi dan pakai ulang untuk iklim, perbaiki pengumpulan dan daur ulang untuk laut. Di Glyiv, keduanya kami perlakukan sebagai dua angka terpisah yang sama-sama layak dilacak."}], "story": [{"kind": "cover", "title": "Plastik sekali pakai: soal iklim atau soal laut?", "text": "Jejak karbon plastik nyata dan lahir di pabrik; tapi luka terbesarnya kerap ada di laut. Memisahkan dua soal ini membuat solusi lebih tepat sasaran — bukan sekadar 'anti-plastik'."}, {"kind": "hook", "title": "Dua masalah, sering ditumpuk jadi satu", "text": "Sedotan plastik memang bikin masalah — tapi untuk laut, belum tentu untuk iklim. Bedanya penting."}, {"kind": "point", "title": "Karbonnya lahir di pabrik", "text": "Plastik = ~3,4% emisi GRK global (2019). Sekitar 90% dari produksi & pengolahan fosil — bukan dari tempat sampah dapurmu."}, {"kind": "point", "title": "Tapi masalah terbesarnya di laut", "text": "Plastik tak membusuk. ~11 juta ton mengalir ke laut tiap tahun, dan bisa hampir tiga kali lipat pada 2040 bila dibiarkan."}, {"kind": "stat", "title": "Yang benar-benar didaur ulang", "big": "9%", "label": "sampah plastik dunia yang benar-benar terdaur ulang", "source": "OECD, Global Plastics Outlook, 2022"}, {"kind": "point", "title": "Ganti bahan ≠ otomatis lebih hijau", "text": "Kantong katun perlu dipakai ulang ~131 kali untuk mengalahkan kantong plastik sekali pakai dari sisi iklim. Yang penting: berapa kali dipakai."}, {"kind": "end", "title": "Pilah dulu masalahnya", "text": "Karbon di hulu, pencemaran di hilir — beda soal, beda solusi. Baca versi lengkapnya di Kabar Glyiv."}], "sources": [{"a": "OECD (2022). Global Plastics Outlook: Economic Drivers, Environmental Impacts and Policy Options.", "u": "https://www.oecd.org/en/publications/global-plastics-outlook_de747aef-en.html"}, {"a": "Pew Charitable Trusts & SYSTEMIQ (2020). Breaking the Plastic Wave.", "u": "https://www.pewtrusts.org/en/research-and-analysis/articles/2020/07/23/breaking-the-plastic-wave-top-findings"}, {"a": "Environment Agency UK (2011). Life Cycle Assessment of Supermarket Carrier Bags (report SC030148).", "u": "https://www.gov.uk/government/publications/life-cycle-assessment-of-supermarket-carrier-bags-a-review-of-the-bags-available-in-2006"}, {"a": "Peraturan Presiden RI No. 83/2018 tentang Penanganan Sampah Laut (target pengurangan sampah plastik laut 70% pada 2025)."}]}, {"slug": "kompos-rumah-tangga", "topic": "Konsumen", "mood": "#4F7A3A", "title": "Mengompos di rumah: memutus rantai metana dari dapur.", "dek": "Sisa sayur dan nasi yang berakhir di TPA membusuk tanpa oksigen dan melepas metana — gas rumah kaca yang jauh lebih genting daripada CO2. Mengompos di rumah memutus rantai itu sejak dari dapur.", "hook": "Sisa dapurmu tidak \"hilang\" di TPA. Ia membusuk tanpa oksigen dan jadi metana. Kompos memutus rantainya.", "cover": "https://images.unsplash.com/photo-1532996122724-e3c354a0b15b?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, UNEP, KLHK, Bappenas)", "read": 4, "blocks": [{"t": "lead", "x": "Sepiring nasi sisa dan potongan sayur yang tak termakan tampak sepele. Tapi ke mana perginya menentukan dampaknya. Bila ia masuk kantong sampah dan berakhir di tempat pemrosesan akhir (TPA), sisa organik itu tidak sekadar 'hilang' — ia memulai reaksi kimia yang memanaskan bumi."}, {"t": "p", "x": "Di dalam tumpukan TPA, sampah tertimbun rapat dan kehabisan oksigen. Dalam kondisi anaerob inilah bakteri mengurai sisa makanan dan melepas <b>gas TPA</b> yang kira-kira separuhnya adalah metana (CH4) — sisanya karbon dioksida <a href=\"https://www.epa.gov/lmop/basic-information-about-landfill-gas\">(US EPA)</a>. Metana itulah inti masalahnya."}, {"t": "h2", "x": "Kenapa metana lebih genting dari CO2"}, {"t": "p", "x": "Metana memerangkap panas jauh lebih kuat daripada karbon dioksida. Menurut IPCC AR6, dalam rentang 100 tahun satu ton metana biogenik setara sekitar <b>27 ton</b> CO2 — dan dalam 20 tahun pertama, ketika efeknya paling tajam, sekitar <b>80 kali</b> lebih kuat <a href=\"https://www.epa.gov/ghgemissions/understanding-global-warming-potentials\">(IPCC AR6 / EPA)</a>. Ia berumur pendek di atmosfer, tapi memukul keras justru pada dekade yang paling menentukan bagi iklim."}, {"t": "stat", "n": "41,60%", "l": "sisa makanan — komponen terbesar sampah Indonesia (2023)", "s": "SIPSN, KLHK, 2023"}, {"t": "pull", "x": "Sisa dapur bukan 'hilang' begitu masuk TPA — ia membusuk tanpa oksigen dan berubah jadi metana. Kompos memutus rantai itu sejak dari sumbernya."}, {"t": "p", "x": "Mengompos membalik kondisinya. Kompos adalah proses <b>aerob</b> — dengan oksigen. Selama tumpukan cukup diaduk dan tak terlalu basah, mikroba mengurai bahan organik menjadi sebagian besar CO2 biogenik (bagian dari siklus karbon pendek) dan humus, dengan metana yang jauh lebih sedikit. Hasilnya bukan penghasilan, melainkan <b>kontribusi</b> nyata: sisa organik yang dialihkan dari TPA, plus kompos untuk menyuburkan tanah."}, {"t": "h2", "x": "Kecil di dapur, nyata di skala kota"}, {"t": "p", "x": "Skalanya yang membuat ini penting. Sisa makanan adalah komponen sampah terbesar Indonesia, dan rumah tangga adalah sumber terbesarnya. Kajian Bappenas memperkirakan Indonesia menghasilkan <b>23–48 juta ton</b> susut dan sisa pangan per tahun — kerugian ekonomi setara Rp 213–551 triliun, sekitar 4–5% PDB <a href=\"https://lcdi-indonesia.id/wp-content/uploads/2021/07/Report-Kajian-FLW-ENG.pdf\">(Bappenas, 2021)</a>. Tak semua sisa itu bisa dikompos di rumah, dan kompos rumahan sendiri belum tentu terlacak rapi ⚠︎. Tapi setiap ember sisa dapur yang tak jadi metana adalah satu rantai yang diputus."}, {"t": "p", "x": "Gambaran globalnya sejalan: dunia membuang sekitar 1,05 miliar ton pangan pada 2022, dan rumah tangga menyumbang <b>60%</b>-nya — kira-kira 79 kg per orang setahun <a href=\"https://www.unep.org/resources/publication/food-waste-index-report-2024\">(UNEP, 2024)</a>. Susut dan sisa pangan menyumbang 8–10% emisi gas rumah kaca dunia. Memulai kompos tak menuntut alat mahal: satu wadah berlubang udara, campuran bahan 'hijau' (sisa dapur) dan 'cokelat' (daun kering), lalu diaduk agar tetap beroksigen. Langkah kecil — tapi tepat di titik rantai metana bermula."}], "story": [{"kind": "cover", "title": "Mengompos di rumah: memutus rantai metana dari dapur.", "text": "Sisa sayur dan nasi yang berakhir di TPA membusuk tanpa oksigen dan melepas metana. Mengompos di rumah memutus rantai itu sejak dari dapur."}, {"kind": "hook", "title": "Sisa dapurmu tidak 'hilang' di TPA. Ia membusuk tanpa oksigen dan jadi metana."}, {"kind": "point", "title": "Di TPA, tak ada oksigen", "text": "Sisa organik tertimbun membusuk secara anaerob — dan melepas metana, kira-kira separuh dari gas TPA. (US EPA)"}, {"kind": "point", "title": "Metana memukul cepat", "text": "Sekitar 80x lebih kuat dari CO2 dalam 20 tahun pertama — dekade yang paling menentukan bagi iklim. (IPCC AR6)"}, {"kind": "stat", "title": "Sampah terbesar kita", "big": "41,60%", "label": "sisa makanan — komponen sampah terbesar Indonesia", "source": "SIPSN / KLHK, 2023"}, {"kind": "point", "title": "Kompos itu aerob", "text": "Dengan oksigen, hasilnya sebagian besar CO2 biogenik — metana jauh lebih sedikit. Sebuah kontribusi, bukan sekadar buang sampah."}, {"kind": "end", "title": "Mulai dari satu ember", "text": "Baca selengkapnya di Glyiv Kabar — dan lihat bagaimana aksi kecil bisa terlacak dan diberi imbalan."}], "sources": [{"a": "UNEP (2024). Food Waste Index Report 2024.", "u": "https://www.unep.org/resources/publication/food-waste-index-report-2024"}, {"a": "IPCC (2021). AR6 WG1, Bab 7 — nilai Global Warming Potential (metana GWP100 ≈ 27; GWP20 ≈ 80).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "Kementerian LHK — SIPSN (2023). Komposisi sampah nasional (sisa makanan 41,60%).", "u": "https://sipsn.menlhk.go.id/sipsn/public/data/komposisi"}, {"a": "Kementerian PPN/Bappenas (2021). Food Loss and Waste in Indonesia — Kajian Pembangunan Rendah Karbon.", "u": "https://lcdi-indonesia.id/wp-content/uploads/2021/07/Report-Kajian-FLW-ENG.pdf"}]}, {"slug": "belanja-online-emisi-pengiriman", "topic": "Konsumen", "mood": "#1E5F8C", "title": "Belanja online: lebih hijau atau lebih boros?", "dek": "Sekali klik memang bisa lebih hemat karbon daripada menyetir ke toko — tapi keunggulan itu rapuh, dan pengiriman kilat serta retur barang bisa membalikkannya dalam sekejap.", "hook": "Mengira belanja online pasti lebih hijau? Betul — sampai kamu pilih \"kirim sekarang\" lalu klik \"kembalikan\".", "cover": "https://images.unsplash.com/photo-1449965408869-eaa3f722e40d?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Ada keyakinan yang terasa masuk akal: memesan barang lewat aplikasi pasti lebih ramah lingkungan daripada menyetir sendiri ke toko. Sering kali memang begitu — satu kendaraan pengantar yang menyusuri satu rute bisa melayani puluhan alamat sekaligus, mengalahkan puluhan mobil pribadi yang masing-masing berangkat sendiri. Tapi keunggulan itu bertumpu pada syarat yang mudah patah."}, {"t": "p", "x": "Kuncinya ada pada satu kata: <b>konsolidasi</b>. Ketika satu van melayani banyak paket dalam perjalanan yang terencana, emisinya terbagi ke banyak titik sehingga jejak per paket menjadi kecil. Analisis <a href=\"https://ctl.mit.edu\">MIT Center for Transportation & Logistics</a> menemukan pembeli yang mengandalkan belanja online rata-rata dapat menghasilkan jejak karbon lebih rendah daripada mereka yang rutin berkendara ke toko — dengan catatan pengirimannya efisien."}, {"t": "h2", "x": "Dua hal yang membalik hitungannya"}, {"t": "p", "x": "Yang pertama adalah <b>pengiriman kilat</b>. Janji 'tiba hari ini' atau 'dalam dua jam' memaksa kurir berangkat sebelum muatan penuh, memutus rute yang paling hemat, dan tak jarang menurunkan satu-dua paket dengan kendaraan tersendiri. Semakin cepat pengiriman diminta, semakin sempit ruang untuk mengonsolidasikan muatan — dan di situlah keunggulan efisiensi tadi menguap."}, {"t": "pull", "x": "Belanja online lebih hijau bukan karena kliknya, melainkan karena satu perjalanan menanggung beban banyak orang. Pengiriman kilat dan retur menghapus kata 'berbagi' itu."}, {"t": "p", "x": "Yang kedua adalah <b>retur</b>. Karena mengembalikan barang terasa mudah dan gratis, tingkat pengembalian belanja online umumnya lebih tinggi daripada belanja di toko fisik <a href=\"https://nrf.com\">(NRF, 2023)</a>. Setiap retur menambah perjalanan — kembali ke gudang, disortir, dikemas ulang — dan sebagian barang tak lagi layak dijual hingga berakhir di pembuangan. Emisi tersembunyi inilah yang jarang terpikir saat tombol 'kembalikan' ditekan."}, {"t": "p", "x": "Konteksnya penting: sektor transportasi menyumbang hampir seperempat emisi CO₂ energi global, dan angkutan barang jalan raya termasuk bagian yang paling cepat tumbuh <a href=\"https://www.iea.org/topics/transport\">(IEA)</a>. Setiap kilometer ekstra yang lahir dari pengiriman kilat dan retur menumpuk pada beban yang memang sudah besar."}, {"t": "stat", "n": "~30%", "l": "proyeksi kenaikan emisi pengiriman last-mile di 100 kota besar dunia pada 2030, tanpa intervensi ⚠︎", "s": "World Economic Forum, 2020"}, {"t": "bars", "h": [0.92, 0.33, 0.85, 1], "cap": "Ilustrasi relatif emisi per barang: banyak mobil pribadi · van terkonsolidasi · pengiriman kilat · barang yang diretur. (Skema, bukan pengukuran)"}, {"t": "p", "x": "Kabar baiknya, tak satu pun dari ini menuntut kita berhenti belanja online. Memilih pengiriman reguler ketimbang kilat, menggabungkan beberapa pesanan jadi satu paket, dan berpikir sejenak sebelum memesan 'dua ukuran untuk dicoba' adalah keputusan kecil yang dampaknya bisa <b>terlacak</b>. Di Glyiv, kami percaya angka yang jujur — bukan klaim 'netral karbon' — yang membantu konsumen dan pedagang melihat kontribusi nyata dari setiap pilihan."}], "story": [{"kind": "cover", "title": "Belanja online: lebih hijau atau lebih boros?", "text": "Sekali klik bisa lebih hemat karbon daripada menyetir ke toko — tapi keunggulan itu rapuh."}, {"kind": "hook", "title": "Mengira belanja online pasti lebih hijau? Betul — sampai kamu pilih 'kirim sekarang' lalu klik 'kembalikan'."}, {"kind": "point", "title": "Kenapa online bisa lebih hijau", "text": "Satu van mengantar puluhan paket dalam satu rute. Emisi per paket dibagi banyak orang — mengalahkan puluhan mobil pribadi."}, {"kind": "point", "title": "Pembalik #1 — kirim kilat", "text": "'Tiba hari ini' memaksa kurir jalan sebelum muatan penuh. Konsolidasi hilang, emisi per paket melonjak."}, {"kind": "point", "title": "Pembalik #2 — retur", "text": "Retur online lebih sering daripada di toko. Perjalanan balik plus barang tak terjual = emisi tersembunyi."}, {"kind": "stat", "title": "Beban yang menumpuk", "big": "~30%", "label": "kenaikan emisi last-mile di 100 kota besar pada 2030 (proyeksi, tanpa intervensi ⚠︎)", "source": "World Economic Forum, 2020"}, {"kind": "end", "title": "Belanja tetap boleh — pilih dengan sadar", "text": "Reguler, bukan kilat. Gabungkan pesanan. Baca selengkapnya di Glyiv Kabar."}], "sources": [{"a": "Weideli, D. & Greene, S. (2013). Environmental Analysis of US Online Shopping. MIT Center for Transportation & Logistics.", "u": "https://ctl.mit.edu"}, {"a": "World Economic Forum (2020). The Future of the Last-Mile Ecosystem.", "u": "https://www.weforum.org/reports/the-future-of-the-last-mile-ecosystem"}, {"a": "National Retail Federation (2023). Consumer Returns in the Retail Industry.", "u": "https://nrf.com"}, {"a": "International Energy Agency (IEA). Transport — CO₂ emissions.", "u": "https://www.iea.org/topics/transport"}]}, {"slug": "jetp-indonesia-20-miliar", "topic": "Ekonomi", "mood": "#0B2471", "title": "JETP US$20 miliar: janji transisi yang kini diuji eksekusinya.", "dek": "Kemitraan JETP menjanjikan sekitar US$20 miliar⚠︎ untuk mempercepat transisi listrik Indonesia dari batu bara. Empat tahun kemudian, ujiannya bukan lagi besarnya komitmen — melainkan seberapa cepat ia mencair menjadi proyek nyata.", "hook": "Dunia bertepuk saat US$20 miliar dijanjikan untuk transisi energi Indonesia. Bagian yang sulit baru dimulai.", "cover": "https://images.unsplash.com/photo-1532601224476-15c79f2f7a51?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen publik JETP (CIPP)", "read": 5, "blocks": [{"t": "lead", "x": "Pada November 2022, di sela KTT G20 Bali, Indonesia mendapat tepuk tangan dunia: sekelompok negara kaya dan lembaga keuangan menjanjikan sekitar US$20 miliar untuk mempercepat transisi dari batu bara. Hampir empat tahun berselang, pertanyaannya sudah bergeser — bukan lagi berapa yang dijanjikan, melainkan berapa yang benar-benar mengalir menjadi proyek nyata."}, {"t": "p", "x": "JETP (Just Energy Transition Partnership) adalah kemitraan pendanaan iklim. Separuh komitmen berasal dari kelompok negara mitra (IPG) yang dipimpin Amerika Serikat dan Jepang, separuh lagi dari aliansi keuangan swasta GFANZ. Tujuannya menekan emisi sektor listrik sekaligus menambah porsi energi terbarukan, dituangkan dalam <a href=\"https://jetp-id.org/\">Comprehensive Investment and Policy Plan (CIPP)</a> yang terbit akhir 2023."}, {"t": "stat", "n": "US$20 miliar⚠︎", "l": "Komitmen awal JETP — US$10 M publik (IPG) + US$10 M swasta (GFANZ)", "s": "Joint Statement IPG–Indonesia, G20 Bali, 2022"}, {"t": "p", "x": "Di sinilah janji bertemu cetakan halusnya. Sebagian besar paket bukan hibah, melainkan <b>pinjaman</b> — banyak dengan bunga mendekati harga pasar. Analisis atas CIPP menaksir porsi hibah hanya sekitar 1–2%⚠︎ dari total; sisanya utang yang tetap harus dibayar. Bagi negara yang justru ingin menahan biaya listrik, struktur ini penting: ini bukan uang gratis."}, {"t": "h2", "x": "Dari komitmen ke pencairan"}, {"t": "pull", "x": "Komitmen menghasilkan siaran pers; pencairan menghasilkan pembangkit. Jarak di antara keduanya adalah ujian sesungguhnya."}, {"t": "p", "x": "Hambatan terbesar bukan niat, tapi kesiapan proyek. Uang iklim mengalir ke proyek yang <em>bankable</em> — punya arus kas jelas, izin lengkap, dan risiko terlacak. Membangun jalur proyek semacam itu butuh reformasi tarif PLN, perluasan jaringan untuk menyerap surya dan angin, serta skema pensiun dini PLTU seperti pilot Cirebon-1. Semua berjalan, tapi lambat."}, {"t": "p", "x": "Laporan-laporan menyebut pencairan bergerak jauh di bawah jadwal, sebagian karena kelebihan pasokan listrik PLN akibat kontrak <em>take-or-pay</em> era lama. Ruang untuk pembangkit baru jadi sempit sebelum permintaan tumbuh atau PLTU tua dipensiunkan. Artinya, US$20 miliar tak bisa sekadar 'dibelanjakan' — ia menunggu ekosistem yang siap menyerapnya."}, {"t": "p", "x": "CIPP menargetkan puncak emisi sektor listrik on-grid lebih awal dan menaikkan bauran terbarukan menjadi sekitar 44%⚠︎ pada 2030. Kritik menyoroti bahwa target awal mengecualikan PLTU <em>captive</em> milik industri — smelter nikel, misalnya — yang justru tumbuh pesat, sehingga gambaran emisi nasional bisa lebih berat dari yang tercatat di atas kertas."}, {"t": "p", "x": "Pelajarannya melampaui JETP: pendanaan iklim akan makin bersyarat pada bukti. Yang menentukan bukan besarnya angka komitmen, melainkan apakah dampaknya bisa <b>terlacak</b> — ton demi ton, proyek demi proyek. Di titik itulah transparansi data karbon berhenti menjadi formalitas dan menjadi syarat agar uang benar-benar mengalir."}], "story": [{"kind": "cover", "title": "JETP US$20 miliar: janji yang kini diuji", "text": "Kemitraan JETP menjanjikan sekitar US$20 miliar⚠︎ untuk transisi listrik Indonesia. Empat tahun kemudian, ujiannya adalah eksekusi — bukan komitmen."}, {"kind": "hook", "title": "Janji besar. Sekarang bagian yang sulit.", "text": "Dunia bertepuk saat komitmen diumumkan di G20 Bali. Yang menentukan datang sesudahnya."}, {"kind": "point", "title": "Bukan uang gratis", "text": "Dari US$20 miliar, porsi hibah sangat kecil (~1–2%⚠︎). Sisanya pinjaman — banyak mendekati bunga pasar."}, {"kind": "stat", "title": "Angka komitmen", "big": "US$20 miliar⚠︎", "label": "Komitmen awal JETP — publik + swasta", "source": "Joint Statement IPG–Indonesia, G20 Bali, 2022"}, {"kind": "point", "title": "Komitmen ≠ pembangkit", "text": "Uang iklim menunggu proyek bankable, reformasi tarif PLN, jaringan yang siap, dan pensiun dini PLTU. Semua berjalan lambat."}, {"kind": "quote", "title": "Ujian sesungguhnya", "text": "Komitmen menghasilkan siaran pers; pencairan menghasilkan pembangkit."}, {"kind": "end", "title": "Baca versi lengkap", "text": "Kenapa masa depan pendanaan iklim bergantung pada bukti yang terlacak — selengkapnya di Glyiv Kabar."}], "sources": [{"a": "International Partners Group & Pemerintah Indonesia (2023). JETP Comprehensive Investment and Policy Plan (CIPP).", "u": "https://jetp-id.org/"}, {"a": "Pemerintah Indonesia, IPG & GFANZ (2022). Joint Statement: Indonesia Just Energy Transition Partnership. G20 Bali, November 2022."}, {"a": "IEA (2022). An Energy Sector Roadmap to Net Zero Emissions in Indonesia.", "u": "https://www.iea.org/reports/an-energy-sector-roadmap-to-net-zero-emissions-in-indonesia"}, {"a": "Center for Research on Energy and Clean Air (CREA) (2023). Analisis komposisi pendanaan (porsi hibah vs pinjaman) dalam CIPP JETP Indonesia."}]}, {"slug": "panas-bumi-raksasa-tidur", "topic": "Ekonomi", "mood": "#B5623A", "title": "Panas bumi: raksasa energi bersih yang belum bangun penuh.", "dek": "Indonesia duduk di atas salah satu cadangan panas bumi terbesar dunia, tapi baru menyalakan sekitar sepersepuluhnya — energi baseload rendah-karbon yang tertahan bukan oleh geologi, melainkan oleh mahalnya risiko pengeboran eksplorasi.", "hook": "Kita duduk di atas \"baterai bumi\" terbesar kedua di dunia — dan baru menyalakan sepersepuluhnya.", "cover": "https://images.unsplash.com/photo-1509391366360-2e959784a276?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data publik ESDM, IPCC & World Bank", "read": 5, "blocks": [{"t": "lead", "x": "Bentangkan peta gunung api Indonesia, dan Anda sedang melihat peta energi yang belum dinyalakan. Di bawah Sabuk Api Pasifik itu tersimpan panas bumi — uap dan air panas yang mengalir stabil siang-malam, tak peduli cuaca. Tenaga itu sudah ada di sana sejak jutaan tahun lalu. Yang belum ada adalah keberanian modal untuk mengebornya."}, {"t": "p", "x": "Angkanya menggoda sekaligus menyayat. Kementerian ESDM menaksir potensi panas bumi Indonesia di kisaran <b>24 gigawatt</b> ⚠︎ — salah satu yang terbesar di dunia. Namun yang benar-benar menyala baru sekitar <b>2,6 GW</b> ⚠︎, atau kira-kira sepersepuluhnya. Ironisnya, dengan porsi sekecil itu Indonesia sudah menjadi <a href=\"https://www.esdm.go.id\">produsen panas bumi terbesar kedua di dunia</a> setelah Amerika Serikat."}, {"t": "p", "x": "Yang membuat panas bumi istimewa: ia <b>baseload</b>. Berbeda dari surya dan angin yang bergantung cuaca, pembangkit panas bumi menyala nyaris 24 jam dengan faktor kapasitas kerap di atas 80% ⚠︎. Emisinya pun rendah — median emisi daur hidup panas bumi sekitar <b>38 gram CO₂e per kWh</b> menurut <a href=\"https://www.ipcc.ch/report/ar5/wg3/\">IPCC</a>, berbanding batu bara di kisaran 820 gram. Di jaringan listrik Indonesia yang masih didominasi batu bara, setiap gigawatt panas bumi adalah baseload bersih yang menggeser pembangkit fosil — bukan 'netral karbon', tapi kontribusi yang bisa dilacak."}, {"t": "stat", "n": "±11%", "l": "potensi panas bumi Indonesia yang sudah dimanfaatkan (≈2,6 dari ≈24 GW) ⚠︎", "s": "Kementerian ESDM, 2024"}, {"t": "h2", "x": "Yang menahan bukan panasnya"}, {"t": "p", "x": "Kalau tenaganya melimpah, mengapa mangkrak? Jawabannya ada di fase paling awal. Panas bumi tak terlihat dari permukaan; keberadaannya harus dibuktikan dengan mengebor sumur eksplorasi — dan satu sumur dalam bisa menelan beberapa juta dolar AS ⚠︎, dengan kemungkinan nyata sumur itu 'kering'. World Bank menyebutnya risiko yang <b>menumpuk di depan</b>: pengembang membakar modal terbesar justru saat ketidakpastian paling tinggi dan belum ada pendapatan sepeser pun. <a href=\"https://www.esmap.org\">Bank pun enggan meminjamkan</a> untuk lubang yang belum tentu berisi."}, {"t": "pull", "x": "Panasnya sudah ada di bawah kaki kita sejak jutaan tahun lalu. Yang mahal bukan energinya — melainkan membuktikan ia benar ada di sana."}, {"t": "p", "x": "Karena itu kuncinya bukan teknologi, melainkan <b>siapa yang menanggung risiko sumur pertama</b>. Skema mitigasi risiko eksplorasi — dana pemerintah dan fasilitas seperti program pembiayaan panas bumi Bank Dunia — dirancang persis untuk itu: mengambil alih sebagian taruhan geologi agar proyek layak dibiayai. Tanpa itu, jarak antara ambisi dan realisasi menganga. Target RUEN sebesar 7,2 GW pada 2025 ⚠︎, misalnya, jauh dari tercapai."}, {"t": "p", "x": "Maka raksasa ini tak sedang tidur karena kehabisan tenaga. Ia menunggu modal yang berani menanggung lubang pertama — dan data yang membuat risiko itu bisa dihitung, bukan ditebak. Di situlah peluang terbesar transisi energi Indonesia: bukan menemukan energinya, tapi membuktikannya."}], "story": [{"kind": "cover", "title": "Panas bumi: raksasa yang belum bangun penuh", "text": "Indonesia duduk di atas salah satu cadangan panas bumi terbesar dunia, tapi baru menyalakan sekitar sepersepuluhnya."}, {"kind": "hook", "title": "Kita duduk di atas 'baterai bumi' terbesar kedua di dunia — dan baru menyalakan sepersepuluhnya."}, {"kind": "point", "title": "Raksasa yang terlelap", "text": "Potensi ≈24 GW ⚠︎. Yang menyala baru ≈2,6 GW — sekitar sepersepuluh. Toh Indonesia tetap produsen No.2 dunia."}, {"kind": "point", "title": "Baseload bersih", "text": "Nyala nyaris 24 jam, tak bergantung cuaca. Emisi daur hidup ≈38 gCO₂e/kWh vs batu bara ≈820 (IPCC)."}, {"kind": "stat", "title": "Baru sepersepuluh", "big": "±11%", "label": "potensi panas bumi yang sudah dimanfaatkan", "source": "Kementerian ESDM, 2024 ⚠︎"}, {"kind": "quote", "title": "Bukan energinya yang mahal", "text": "Yang mahal bukan energinya — melainkan membuktikan ia benar ada di bawah kaki kita."}, {"kind": "end", "title": "Raksasa yang menunggu dibangunkan", "text": "Baca ulasan lengkapnya di Glyiv Kabar — wawasan energi & karbon, jujur & bisa dipertanggungjawabkan."}], "sources": [{"a": "Kementerian ESDM RI (2024). Data potensi & pemanfaatan panas bumi Indonesia.", "u": "https://www.esdm.go.id"}, {"a": "IPCC (2014). AR5 WG III, Annex III: Technology-specific Cost and Performance Parameters (emisi daur hidup pembangkit).", "u": "https://www.ipcc.ch/report/ar5/wg3/"}, {"a": "World Bank / ESMAP (2012). Geothermal Handbook: Planning and Financing Power Generation.", "u": "https://www.esmap.org"}, {"a": "IRENA (2024). Renewable Capacity Statistics — kapasitas panas bumi global terpasang.", "u": "https://www.irena.org"}]}, {"slug": "surya-atap-potensi-besar", "topic": "Ekonomi", "mood": "#C6A15B", "title": "Surya atap: potensi melimpah yang terganjal aturan.", "dek": "Matahari Indonesia bersinar hampir sepanjang tahun, tapi laju pemasangan panel surya di atap justru melambat — bukan karena teknologinya, melainkan karena aturan kuota dan skema ekspor listrik yang terus berubah.", "hook": "Radiasi mataharinya gratis dan melimpah. Yang mahal justru aturannya.", "cover": "https://images.unsplash.com/photo-1532601224476-15c79f2f7a51?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (ESDM, IESR, World Bank)", "read": 5, "blocks": [{"t": "lead", "x": "Indonesia duduk tepat di garis khatulistiwa. Matahari datang hampir setiap hari, sepanjang tahun, dengan intensitas yang di banyak negara empat-musim hanya bisa diimpikan. Di atas kertas, tak ada sumber energi yang lebih murah — dan lebih adil untuk sebuah negara kepulauan — daripada cahaya yang jatuh gratis ke setiap atap. Tapi di lapangan, panel surya di atap rumah dan pabrik justru terpasang dengan tersendat, dan alasannya jarang soal teknologi."}, {"t": "p", "x": "Sumber dayanya nyata dan berlimpah. Rata-rata radiasi matahari harian di Indonesia sekitar <b>4,8 kWh per meter persegi</b>, relatif merata dari Aceh sampai Papua sepanjang tahun <a href=\"https://globalsolaratlas.info\">World Bank Global Solar Atlas</a>. Artinya hampir setiap atap di negeri ini bisa menjadi pembangkit kecil. Yang menahan laju pemasangan bukan langit, melainkan meja regulasi — tempat aturan mainnya sempat berubah beberapa kali dalam waktu singkat."}, {"t": "h2", "x": "Aturan yang berubah arah"}, {"t": "p", "x": "Selama beberapa tahun, PLTS atap berjalan dengan skema mirip <em>net metering</em>: kelebihan listrik yang diekspor ke jaringan PLN dihitung sebagai kredit yang memotong tagihan bulan berikutnya. <b>Permen ESDM No. 26/2021</b> bahkan sempat menaikkan nilai ekspor itu mendekati penuh, memperpendek waktu balik modal. Lalu arahnya berbalik. <b>Permen ESDM No. 2/2024</b> menghapus skema ekspor-impor tersebut dan menggantinya dengan <b>sistem kuota</b> yang jatahnya ditetapkan PLN per wilayah <a href=\"https://iesr.or.id\">IESR</a>."}, {"t": "pull", "x": "Radiasi mataharinya gratis. Yang membuat rumah tangga dan investor ragu justru aturannya — yang bisa berubah di tengah jalan."}, {"t": "stat", "n": "3.000+ GW", "l": "potensi teknis tenaga surya nasional ⚠︎ — berkali lipat total kapasitas listrik terpasang", "s": "Kementerian ESDM, Potensi EBT 2021"}, {"t": "p", "x": "Dampaknya terasa di hitung-hitungan. Tanpa kredit ekspor, listrik berlebih di siang hari praktis hangus alih-alih tersimpan sebagai imbalan, sehingga masa balik modal memanjang. Ditambah kuota yang membuat calon pemasang harus mengantre jatah, kepastian pun menyusut. Padahal, saat program diluncurkan pada 2021, pemerintah menargetkan <b>3,6 GW</b> PLTS atap terpasang pada 2025 — target yang realisasinya masih jauh tertinggal ⚠︎."}, {"t": "p", "x": "Ironisnya, permintaan justru sedang tumbuh. Industri yang mengekspor ke pasar yang mulai menagih karbon — seperti Eropa lewat CBAM — butuh listrik bersih yang murah untuk menekan jejak karbon produknya. Atap pabrik yang luas adalah tempat paling logis untuk memasangnya. Ketika aturan justru mengerem, sebagian peluang itu tertahan di ruang tunggu."}, {"t": "h2", "x": "Kenapa ini penting"}, {"t": "p", "x": "Bagi Indonesia yang menargetkan nol emisi bersih pada 2060, atap adalah lahan yang sudah tersedia — tak perlu membebaskan tanah baru atau membangun jaringan panjang. Setiap kilowatt-jam surya yang menggantikan listrik batu bara adalah kontribusi nyata pada penurunan emisi, bukan sekadar janji. Yang dibutuhkan bukan matahari yang lebih terang, melainkan aturan yang stabil dan bisa diperhitungkan bertahun-tahun ke depan — agar potensi yang melimpah itu benar-benar terlacak menjadi listrik, bukan berhenti sebagai angka di atas kertas."}], "story": [{"kind": "cover", "title": "Surya atap: potensi melimpah yang terganjal aturan", "text": "Matahari Indonesia bersinar hampir sepanjang tahun, tapi laju pemasangan panel surya di atap justru melambat — bukan karena teknologinya, melainkan karena aturan kuota dan skema ekspor listrik yang terus berubah."}, {"kind": "hook", "title": "Radiasi mataharinya gratis dan melimpah. Yang mahal justru aturannya."}, {"kind": "point", "title": "Sumber dayanya melimpah", "text": "Radiasi ~4,8 kWh/m² per hari, merata sepanjang tahun. Potensi teknis surya nasional lebih dari 3.000 GW. ⚠︎"}, {"kind": "point", "title": "Aturannya berubah arah", "text": "Permen ESDM 2/2024 menghapus skema ekspor-impor listrik, diganti sistem kuota yang ditetapkan PLN."}, {"kind": "stat", "title": "Target yang tertinggal", "big": "3,6 GW", "label": "target PLTS atap 2025 — realisasi masih jauh tertinggal ⚠︎", "source": "IESR; Kementerian ESDM"}, {"kind": "quote", "title": "Bukan soal matahari", "text": "Radiasi mataharinya gratis. Yang membuat ragu justru aturannya."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv", "text": "Kabar karbon Indonesia — jujur & bisa dipertanggungjawabkan. Gabung Glyiv."}], "sources": [{"a": "Kementerian ESDM RI (2024). Peraturan Menteri ESDM No. 2 Tahun 2024 tentang PLTS Atap yang Terhubung pada Jaringan Tenaga Listrik Pemegang IUPTLU.", "u": "https://jdih.esdm.go.id"}, {"a": "IESR — Institute for Essential Services Reform (2024). Analisis kebijakan PLTS atap dan sistem kuota.", "u": "https://iesr.or.id"}, {"a": "World Bank / ESMAP (2020). Global Solar Atlas — sumber daya surya Indonesia.", "u": "https://globalsolaratlas.info"}, {"a": "Kementerian ESDM RI (2021). Potensi Energi Baru Terbarukan Indonesia (tenaga surya ±3.294 GW)."}]}, {"slug": "pensiun-dini-pltu-etm", "topic": "Ekonomi", "mood": "#0F2E22", "title": "Memensiunkan PLTU lebih cepat: siapa yang menanggung biaya?", "dek": "Skema seperti ETM ADB menjanjikan pensiun dini PLTU batu bara — tapi kasus Cirebon-1, yang batal pada Desember 2025, memperlihatkan pertanyaan tersulitnya bukan soal iklim, melainkan siapa yang menanggung tagihannya dan bagaimana nasib pekerja.", "hook": "Memensiunkan PLTU lebih cepat terdengar mudah — sampai kamu bertanya siapa yang membayar.", "cover": "https://images.unsplash.com/photo-1509391366360-2e959784a276?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen ADB & laporan publik 2023–2026", "read": 5, "blocks": [{"t": "lead", "x": "PLTU Cirebon-1 seharusnya menjadi bukti bahwa Indonesia bisa memensiunkan batu bara lebih cepat. Ia dipilih sebagai percontohan pertama dan ditandatangani di panggung iklim internasional. Lalu, pada Desember 2025, pemerintah membatalkannya. Alasannya bukan soal iklim — melainkan soal siapa yang harus membayar tagihannya."}, {"t": "p", "x": "Skema di baliknya adalah <b>Energy Transition Mechanism (ETM)</b> dari Bank Pembangunan Asia (ADB): memakai pendanaan campuran — sebagian lunak, sebagian komersial — untuk membiayai ulang PLTU batu bara dan memensiunkannya lebih awal dari jadwal <a href=\"https://www.adb.org/what-we-do/energy-transition-mechanism-etm\">ADB</a>. Di COP28 2023, ADB bersama PLN, Cirebon Electric Power, dan Indonesia Investment Authority sepakat mengakhiri kewajiban pasok listrik Cirebon-1 (660 MW) pada Desember 2035 — bukan Juli 2042, hampir tujuh tahun lebih cepat <a href=\"https://www.adb.org/news/new-agreement-aims-retire-indonesia-660-mw-coal-plant-almost-7-years-early\">ADB</a>."}, {"t": "p", "x": "Lalu aritmetikanya menyusul. PLN memperkirakan menanggung sekitar <b>Rp 60 triliun</b> (±US$3,8 miliar) penalti selama lima tahun bila pensiun dini berjalan, sementara Kementerian Keuangan menyoroti biaya penggantian daya hingga US$1,3 miliar — sebagian besar berupa subsidi untuk menutup selisih biaya pembangkitan <a href=\"https://news.mongabay.com/2026/01/indonesia-backs-away-from-coal-exit-test-case-amid-financial-and-political-pushback/\">Mongabay</a>. Menko Airlangga Hartarto akhirnya menyebut target 2035 'tidak layak'."}, {"t": "stat", "n": "Rp 60 triliun", "l": "estimasi penalti PLN bila Cirebon-1 dipensiunkan dini (5 tahun)", "s": "Dir. PLN Suroso Isnandar, via Mongabay 2026"}, {"t": "h2", "x": "Siapa yang menanggung biaya?"}, {"t": "p", "x": "Akar soalnya struktural. Kontrak jual-beli listrik (PPA) berjangka hingga 30 tahun bersifat <b>take-or-pay</b> — PLN tetap membayar meski listriknya tak sepenuhnya terpakai. Ditambah aturan harga batu bara domestik (DMO) yang mematok harga di bawah pasar, batu bara jadi tampak murah secara artifisial dibanding energi terbarukan <a href=\"https://news.mongabay.com/2026/01/indonesia-backs-away-from-coal-exit-test-case-amid-financial-and-political-pushback/\">Mongabay</a>. Dalam skema ETM, pemilik pembangkit dikompensasi atas laba yang belum sempat diraih lewat pinjaman konsesi berbunga lebih rendah."}, {"t": "pull", "x": "Memangkas usia PLTU itu mudah dijanjikan; yang sulit adalah memastikan tagihannya tidak jatuh ke pihak yang paling tak mampu menanggung."}, {"t": "p", "x": "Di sinilah pertanyaan keadilan menggigit. Sebagian besar dana ETM dan JETP — paket <b>US$20 miliar</b> yang diumumkan di G20 Bali 2022 — bersumber publik atau bersifat lunak <a href=\"https://www.gov.uk/government/news/indonesia-just-energy-transition-partnership-launched-at-g20\">JETP</a>. Memakainya untuk menambal laba investor batu bara yang belum terwujud berisiko terlihat seperti membayar dua kali pihak yang paling diuntungkan era fosil: dulu untuk membangun pembangkit, kini untuk menutupnya."}, {"t": "p", "x": "Lalu ada pekerja dan daerah penghasil. Beban subsidi serta kompensasi ke PLN untuk menopang aset batu bara dilaporkan membengkak — naik sekitar 24% pada 2024 ⚠︎ — yang justru menyempitkan ruang fiskal untuk alih-keterampilan dan pemulihan komunitas. Prinsip <b>'just transition'</b> yang dijanjikan JETP baru bermakna bila anggarannya benar-benar sampai ke komunitas, bukan berhenti di neraca korporasi."}, {"t": "p", "x": "Bagi Glyiv, pelajarannya bukan apakah pensiun dini itu baik untuk iklim — jelas baik. Pelajarannya soal <b>bukti</b>: setiap rupiah yang mengklaim mempercepat penutupan harus bisa dilacak — berapa ton emisi yang benar-benar dihindari, siapa yang menerima kompensasi, dan apa yang diterima pekerja. Kontribusi terhadap transisi hanya kredibel bila angkanya terbuka."}], "story": [{"kind": "cover", "title": "Pensiun dini PLTU: siapa yang bayar?", "text": "Skema seperti ETM ADB menjanjikan menutup PLTU batu bara lebih cepat. Kasus Cirebon-1 memperlihatkan pertanyaan tersulitnya: siapa menanggung tagihannya, dan nasib pekerjanya."}, {"kind": "hook", "title": "Percontohan yang batal", "text": "Cirebon-1 dipilih jadi bukti Indonesia bisa keluar dari batu bara lebih cepat. Desember 2025: batal. Bukan soal iklim — soal biaya."}, {"kind": "point", "title": "Apa itu ETM", "text": "Skema ADB: dana campuran lunak + komersial untuk membiayai ulang PLTU dan memensiunkannya lebih awal. Target Cirebon-1: berhenti 2035, bukan 2042."}, {"kind": "point", "title": "Aritmetika yang menang", "text": "PLN taksir ~Rp 60 triliun penalti dalam 5 tahun; Kemenkeu soroti ~US$1,3 miliar biaya pengganti. Target 2035 pun disebut 'tidak layak'."}, {"kind": "stat", "title": "Ongkos yang membatalkan", "big": "Rp 60 triliun", "label": "estimasi penalti PLN atas pensiun dini Cirebon-1 (5 tahun)", "source": "Dir. PLN, via Mongabay 2026"}, {"kind": "point", "title": "Adil untuk siapa?", "text": "Dana ETM/JETP banyak yang publik & lunak. Menambal laba investor batu bara dengannya = bayar dua kali? Sementara ruang untuk alih-keterampilan pekerja menyempit."}, {"kind": "end", "title": "Baca versi lengkapnya", "text": "Transisi yang adil hanya kredibel bila angkanya terbuka — berapa ton dihindari, siapa dikompensasi, apa yang diterima pekerja. Selami di Glyiv Kabar."}], "sources": [{"a": "Asian Development Bank (2023). New Agreement Aims to Retire Indonesia's 660-MW Cirebon-1 Coal Plant Almost 7 Years Early.", "u": "https://www.adb.org/news/new-agreement-aims-retire-indonesia-660-mw-coal-plant-almost-7-years-early"}, {"a": "Asian Development Bank. Energy Transition Mechanism (ETM).", "u": "https://www.adb.org/what-we-do/energy-transition-mechanism-etm"}, {"a": "Mongabay (2026). Indonesia backs away from coal exit test case amid financial and political pushback.", "u": "https://news.mongabay.com/2026/01/indonesia-backs-away-from-coal-exit-test-case-amid-financial-and-political-pushback/"}, {"a": "Government of the UK (2022). Indonesia Just Energy Transition Partnership Launched at G20 (mobilisasi US$20 miliar).", "u": "https://www.gov.uk/government/news/indonesia-just-energy-transition-partnership-launched-at-g20"}]}, {"slug": "subsidi-energi-fosil-arah", "topic": "Ekonomi", "mood": "#B0894F", "title": "Subsidi energi fosil: uang besar yang menahan transisi.", "dek": "Subsidi BBM dan listrik menahan harga agar terjangkau — tapi menyerap anggaran raksasa dan menumpulkan sinyal yang seharusnya mendorong efisiensi. Realokasinya jadi perdebatan ekonomi-politik yang pelik.", "hook": "Menekan harga BBM terasa seperti bantuan. Tapi harga yang terlalu murah punya biaya sendiri — dan kita membayarnya dua kali.", "cover": "https://images.unsplash.com/photo-1532601224476-15c79f2f7a51?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data IEA, IMF & Kemenkeu", "read": 5, "blocks": [{"t": "lead", "x": "Subsidi energi terasa seperti bantuan: harga BBM di pompa dan tarif listrik di meteran ditahan agar tetap terjangkau. Tapi di balik kelegaan itu ada tagihan besar yang dibayar dua kali — sekali dari anggaran negara, sekali lagi dari sinyal harga yang sengaja dibuat tumpul."}, {"t": "p", "x": "Angkanya tidak kecil. IEA mencatat subsidi konsumsi bahan bakar fosil global menembus rekor lebih dari <b>USD 1 triliun</b> pada 2022, seiring lonjakan harga energi (<a href=\"https://www.iea.org/reports/fossil-fuels-consumption-subsidies-2022\">IEA, 2023</a>). Bila biaya yang tak pernah tertagih ikut dihitung — polusi udara, kerusakan iklim — IMF memperkirakan totalnya mencapai sekitar ⚠︎ USD 7 triliun, atau kira-kira 7% dari PDB dunia (<a href=\"https://www.imf.org/en/Publications/WP/Issues/2023/08/22/IMF-Fossil-Fuel-Subsidies-Data-2023-Update-537281\">IMF, 2023</a>)."}, {"t": "h2", "x": "Harga murah yang menahan efisiensi"}, {"t": "p", "x": "Masalahnya bukan sekadar besarnya anggaran, tapi apa yang dilakukan harga murah pada perilaku. Ketika BBM dan listrik dijual di bawah biaya sebenarnya, insentif untuk berhemat melemah: kendaraan boros tetap masuk akal secara ekonomi, pabrik menunda investasi efisiensi energi, dan pembangkit terbarukan harus bersaing melawan harga fosil yang secara artifisial ditekan. Dalam arti itu, subsidi bekerja seperti <b>pajak terbalik atas efisiensi</b>."}, {"t": "pull", "x": "Subsidi energi fosil menahan dua hal sekaligus: anggaran yang bisa dipakai untuk hal lain, dan harga yang seharusnya mendorong kita berhemat."}, {"t": "stat", "n": "USD 1 triliun", "l": "Subsidi konsumsi energi fosil global 2022 — rekor tertinggi", "s": "IEA, 2023"}, {"t": "p", "x": "Di Indonesia, bebannya terasa langsung di APBN. Sepanjang 2022, saat harga minyak dunia melonjak, pemerintah menaikkan pagu subsidi dan kompensasi energi hingga sekitar ⚠︎ <b>Rp 502 triliun</b> — lebih besar dari banyak pos belanja produktif (<a href=\"https://www.kemenkeu.go.id\">Kementerian Keuangan RI, 2022</a>). Ketika beban itu tak lagi tertanggung, harga Pertalite dan Solar tetap dinaikkan sekitar 30% pada September 2022. Subsidi menunda penyesuaian, bukan menghapusnya."}, {"t": "p", "x": "Ada ironi lain. Subsidi harga yang tampak pro-rakyat justru kerap paling dinikmati kelompok yang mampu, karena merekalah yang mengonsumsi paling banyak bahan bakar. IEA dan Bank Dunia berulang kali menunjukkan bahwa subsidi BBM adalah cara yang mahal dan tidak tepat sasaran untuk melindungi rumah tangga miskin — sebagian besar manfaatnya bocor ke atas (<a href=\"https://www.worldbank.org/en/topic/energy/publication/energy-subsidy-reform\">World Bank</a>)."}, {"t": "h2", "x": "Realokasi: pelik, tapi bukan mustahil"}, {"t": "p", "x": "Di sinilah perdebatan menjadi rumit. Mencabut subsidi tanpa jaring pengaman berisiko memukul yang rentan dan memicu gejolak politik — pelajaran yang berulang di banyak negara. Karena itu lembaga seperti Bank Dunia dan IMF menganjurkan realokasi, bukan pencabutan mendadak: mengganti subsidi harga yang tumpul dengan bantuan tunai bertarget yang langsung menyasar rumah tangga miskin, lalu mengalihkan sisanya ke transisi energi. Yang berubah bukan besarnya kepedulian, melainkan ke mana uang itu mengalir — dari menahan harga hari ini menuju membangun ketahanan untuk esok."}], "story": [{"kind": "cover", "title": "Subsidi energi fosil", "text": "Uang besar yang menahan transisi — dan sinyal harga yang seharusnya mendorong efisiensi."}, {"kind": "hook", "title": "Terasa seperti bantuan", "text": "Menekan harga BBM dan listrik memang melegakan. Tapi harga yang terlalu murah punya biaya sendiri — dan kita membayarnya dua kali."}, {"kind": "point", "title": "Dibayar dua kali", "text": "Sekali dari anggaran negara. Sekali lagi dari sinyal harga yang sengaja dibuat tumpul, sehingga insentif untuk berhemat ikut melemah."}, {"kind": "stat", "title": "Skalanya raksasa", "big": "USD 1 triliun", "label": "Subsidi energi fosil global 2022 — rekor tertinggi", "source": "IEA, 2023"}, {"kind": "point", "title": "Menahan efisiensi", "text": "Saat energi dijual di bawah biaya sebenarnya, kendaraan boros tetap masuk akal, efisiensi ditunda, dan energi terbarukan bersaing melawan harga yang ditekan."}, {"kind": "quote", "title": "Ironi subsidi", "text": "Subsidi harga yang tampak pro-rakyat justru paling dinikmati yang mampu — merekalah yang mengonsumsi paling banyak bahan bakar."}, {"kind": "end", "title": "Baca kabar selengkapnya", "text": "Realokasi bukan soal mengurangi kepedulian, tapi mengarahkan uang ke tempat yang lebih tepat. Telusuri isu ini bersama Glyiv."}], "sources": [{"a": "IEA (2023). Fossil Fuels Consumption Subsidies 2022.", "u": "https://www.iea.org/reports/fossil-fuels-consumption-subsidies-2022"}, {"a": "Black, S. et al. / IMF (2023). IMF Fossil Fuel Subsidies Data: 2023 Update.", "u": "https://www.imf.org/en/Publications/WP/Issues/2023/08/22/IMF-Fossil-Fuel-Subsidies-Data-2023-Update-537281"}, {"a": "Kementerian Keuangan RI (2022). Tambahan subsidi & kompensasi energi dalam APBN 2022 (⚠︎ pagu ~Rp 502 triliun).", "u": "https://www.kemenkeu.go.id"}, {"a": "World Bank. Energy Subsidy Reform.", "u": "https://www.worldbank.org/en/topic/energy/publication/energy-subsidy-reform"}]}, {"slug": "green-jobs-peluang-baru", "topic": "Ekonomi", "mood": "#1cae6b", "title": "Green jobs: pekerjaan yang lahir dari transisi energi.", "dek": "Transisi energi tak cuma soal megawatt — ia diam-diam menulis ulang daftar pekerjaan: menuntut teknisi surya, auditor karbon, dan ahli restorasi lahan, sekaligus menuntut kita menyiapkan ulang pekerja sektor lama.", "hook": "Setiap panel surya yang terpasang butuh tangan baru — dan transisi energi diam-diam sedang menulis ulang daftar pekerjaan.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IRENA/ILO, Bappenas)", "read": 4, "blocks": [{"t": "lead", "x": "Transisi energi biasanya dibicarakan lewat megawatt dan target emisi. Tapi ada sisi yang jauh lebih dekat dengan hidup sehari-hari: pekerjaan. Setiap panel surya yang dipasang, setiap hektare lahan yang dipulihkan, setiap ton karbon yang dilacak — semuanya butuh tangan dan keahlian yang, sepuluh tahun lalu, belum banyak dicari."}, {"t": "p", "x": "Angkanya sudah terlihat. Menurut IRENA dan ILO, sektor energi terbarukan mempekerjakan <b>16,2 juta orang pada 2023</b>, naik dari 13,7 juta pada 2022 — lonjakan tahunan terbesar yang pernah tercatat. Tenaga surya sendiri menyerap sekitar 7,2 juta pekerjaan, penyumbang terbesar di dalamnya <a href=\"https://www.irena.org/News/pressreleases/2024/Oct/Highest-Annual-Growth-of-Renewables-Jobs-in-2023-Reaching-16-point-2-Million\">1</a>."}, {"t": "p", "x": "Yang lahir bukan sekadar 'lebih banyak pekerjaan', melainkan jenis keahlian baru: teknisi pemasang dan perawat panel surya, <b>auditor karbon</b> yang membaca jejak emisi sebuah pabrik, ahli restorasi lahan yang memulihkan mangrove dan gambut. Pekerjaan-pekerjaan ini menautkan keterampilan lama — kelistrikan, agronomi, akuntansi — ke satu konteks baru: iklim."}, {"t": "h2", "x": "Peluang datang bersama tuntutan"}, {"t": "p", "x": "Transisi tidak otomatis adil. ILO memperkirakan langkah menuju ekonomi rendah karbon bisa menciptakan sekitar <b>24 juta pekerjaan baru</b> secara global pada 2030 — tetapi sekitar 6 juta pekerjaan di sektor lama, seperti pertambangan batu bara, akan menyusut <a href=\"https://www.ilo.org/publications/world-employment-and-social-outlook-2018-greening-jobs-summary\">2</a>. Selisihnya positif, namun angka bersih itu tidak berarti banyak bagi seorang penambang yang kehilangan pekerjaannya bila tak ada program keahlian ulang (reskilling) yang menjembatani."}, {"t": "pull", "x": "Angka bersih yang positif tidak berarti apa-apa bagi pekerja yang keahliannya telanjur usang — kecuali ada jembatan keahlian ulang."}, {"t": "stat", "n": "16,2 juta", "l": "pekerjaan energi terbarukan global pada 2023 (naik dari 13,7 juta setahun sebelumnya)", "s": "IRENA & ILO, Renewable Energy and Jobs – Annual Review 2024"}, {"t": "h2", "x": "Bagaimana dengan Indonesia?"}, {"t": "p", "x": "Bagi Indonesia, taruhannya besar. Lewat Just Energy Transition Partnership (JETP) yang disepakati pada 2022, sekitar <b>USD 20 miliar</b> dijanjikan untuk mempercepat transisi, dengan target energi terbarukan menyumbang 34% pembangkitan listrik pada 2030 <a href=\"https://jetp-id.org/\">3</a>. Bappenas memperkirakan ekonomi hijau dapat menciptakan sekitar 4,4 juta lapangan kerja pada 2030 ⚠︎ — tersebar di energi terbarukan, pertanian, manufaktur, konstruksi, hingga jasa <a href=\"https://perpustakaan.bappenas.go.id/e-library/\">4</a>."}, {"t": "p", "x": "Tetapi peluang itu bukan janji otomatis. Ia bergantung pada satu hal yang sering diremehkan: kesiapan orang. Tanpa pelatihan vokasi, sertifikasi keahlian, dan jalur alih-profesi bagi pekerja sektor lama, permintaan keahlian baru akan diisi dari luar — dan transisi yang seharusnya jadi peluang justru terasa seperti ancaman. Green jobs bukan hadiah dari transisi energi; ia adalah pekerjaan rumah yang harus disiapkan sejak sekarang."}], "story": [{"kind": "cover", "title": "Green jobs: pekerjaan yang lahir dari transisi energi", "text": "Transisi energi tak cuma soal megawatt — ia menulis ulang daftar pekerjaan, dari teknisi surya sampai auditor karbon."}, {"kind": "hook", "title": "Diam-diam, daftar pekerjaan berubah", "text": "Setiap panel surya yang terpasang butuh tangan baru. Setiap ton karbon yang dilacak butuh keahlian baru."}, {"kind": "point", "title": "Keahlian yang baru dicari", "text": "Teknisi surya. Auditor karbon. Ahli restorasi lahan. Pekerjaan yang sepuluh tahun lalu belum banyak ada."}, {"kind": "stat", "title": "Sudah terlihat di angka", "big": "16,2 juta", "label": "pekerjaan energi terbarukan global pada 2023 (naik dari 13,7 juta)", "source": "IRENA & ILO, 2024"}, {"kind": "point", "title": "Tapi ada sisi lain", "text": "~24 juta pekerjaan bisa lahir pada 2030. Sekaligus ~6 juta di sektor lama menyusut. Reskilling jadi kunci."}, {"kind": "quote", "title": "Kenapa keahlian ulang penting", "text": "Angka bersih yang positif tidak berarti apa-apa bagi pekerja yang keahliannya usang — kecuali ada jembatan keahlian ulang."}, {"kind": "end", "title": "Bukan hadiah, tapi pekerjaan rumah", "text": "Green jobs harus disiapkan sejak sekarang. Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "IRENA & ILO (2024). Renewable Energy and Jobs – Annual Review 2024.", "u": "https://www.irena.org/News/pressreleases/2024/Oct/Highest-Annual-Growth-of-Renewables-Jobs-in-2023-Reaching-16-point-2-Million"}, {"a": "ILO (2018). World Employment and Social Outlook 2018: Greening with Jobs.", "u": "https://www.ilo.org/publications/world-employment-and-social-outlook-2018-greening-jobs-summary"}, {"a": "JETP Indonesia (2022). Just Energy Transition Partnership — Joint Statement & targets.", "u": "https://jetp-id.org/"}, {"a": "Bappenas (2023). Peta Jalan Pengembangan Tenaga Kerja Hijau Indonesia (Green Jobs Roadmap).", "u": "https://perpustakaan.bappenas.go.id/e-library/"}]}, {"slug": "transisi-berkeadilan-siapa-tertinggal", "topic": "Ekonomi", "mood": "#6B4E8C", "title": "Transisi berkeadilan: memastikan tak ada yang tertinggal.", "dek": "Menutup PLTU dan menanam energi bersih adalah keharusan iklim — tapi jika pekerja tambang dan komunitas yang bergantung padanya ditinggalkan, transisi itu gagal sebelum benar-benar dimulai.", "hook": "Dekarbonisasi tanpa keadilan tidak menyelesaikan masalah — ia hanya memindahkannya ke bahu yang paling rentan. Jadi siapa yang menanggung ongkos transisi?", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (ILO, IPCC, JETP Indonesia)", "read": 5, "blocks": [{"t": "lead", "x": "Setiap peta jalan iklim berbicara tentang megawatt, ton CO₂, dan tenggat. Jarang yang berbicara tentang operator PLTU berusia 45 tahun di Cirebon, atau keluarga penambang di Kalimantan Timur yang seluruh penghidupannya melekat pada batu bara. Padahal di situlah dekarbonisasi benar-benar diuji: bukan pada seberapa cepat kita mematikan mesin lama, tapi pada apakah orang-orang yang bekerja di sana ikut punya masa depan."}, {"t": "p", "x": "Gagasan <b>'transisi berkeadilan'</b> (just transition) lahir dari gerakan buruh, lalu dibakukan Organisasi Buruh Internasional lewat <a href=\"https://www.ilo.org/publications/guidelines-just-transition-towards-environmentally-sustainable-economies-and\">Pedoman Transisi Berkeadilan (ILO, 2015)</a>. Intinya sederhana tapi menuntut: peralihan ke ekonomi rendah karbon harus <b>menciptakan kerja layak</b>, melindungi yang paling rentan, dan mengajak pekerja serta komunitas ikut merancang perubahan — bukan sekadar menerima akibatnya."}, {"t": "p", "x": "Bagi Indonesia, taruhannya konkret. Lebih dari separuh listrik nasional masih berasal dari batu bara, dan rantai nilainya — tambang, pengangkutan, pembangkit — menopang penghidupan banyak keluarga di Kalimantan dan Sumatra. Menutup pembangkit tanpa rencana bagi mereka bukanlah keadilan iklim; itu hanya memindahkan beban dari atmosfer ke bahu yang paling lemah, lalu menyebutnya kemajuan."}, {"t": "h2", "x": "Kenapa keadilan jadi syarat, bukan hiasan"}, {"t": "p", "x": "Ekonomi hijau memang membuka lapangan kerja — tapi tidak otomatis di tempat, waktu, dan untuk orang yang sama dengan yang kehilangan. ILO memperkirakan aksi iklim bisa menciptakan sekitar <b>24 juta pekerjaan baru</b> secara global pada 2030, sementara sekitar 6 juta lainnya lenyap <a href=\"https://www.ilo.org/publications/major-publications/world-employment-and-social-outlook-2018-greening-jobs\">(ILO, 2018)</a>. Angka bersihnya positif, tapi rata-rata menyamarkan hal penting: penambang batu bara di satu daerah tak serta-merta menjadi teknisi surya di daerah lain. Tanpa pelatihan ulang, jaring pengaman sosial, dan diversifikasi ekonomi daerah, 'transisi' hanya jadi kata halus untuk pemutusan kerja."}, {"t": "pull", "x": "Karbon yang turun sambil meninggalkan orang di belakang bukanlah kemajuan — itu utang sosial yang sekadar ditunda."}, {"t": "stat", "n": "24 juta", "l": "perkiraan lapangan kerja hijau baru secara global pada 2030 (sekitar 6 juta lainnya hilang)", "s": "ILO, Greening with Jobs, 2018"}, {"t": "p", "x": "Indonesia sudah menaruh ini di atas meja. Lewat <a href=\"https://jetp-id.org/\">Just Energy Transition Partnership (JETP)</a> yang diumumkan di G20 Bali pada 2022, sekitar US$20 miliar⚠︎ dijanjikan untuk mempercepat energi bersih — dan dokumen investasinya secara eksplisit memuat pilar transisi berkeadilan. Tetapi komitmen di atas kertas berbeda dari pencairan nyata: sebagian besar target dan skema pendanaannya masih dalam pembahasan⚠︎. Yang menentukan bukan angka miliaran itu, melainkan apakah pelatihan ulang dan perlindungan benar-benar sampai ke pekerja yang terdampak."}, {"t": "h2", "x": "Peran yang jujur"}, {"t": "p", "x": "Di sinilah data yang jujur menjadi penting. Transisi berkeadilan tak bisa dinilai dari klaim, melainkan dari yang bisa <b>terlacak</b>: berapa pekerja yang beralih ke kerja layak, berapa komunitas yang penghidupannya pulih, berapa daerah yang ekonominya benar-benar terdiversifikasi. Posisi Glyiv sebagai platform ekonomi hijau sederhana — dekarbonisasi hanya kredibel bila keadilan sosial ikut terhitung sejak awal, bukan ditempel sebagai hiasan di akhir. IPCC pun menegaskan transisi yang adil sebagai bagian dari kebijakan iklim yang efektif, bukan pelengkap opsional. Keadilan bukan biaya transisi; ia adalah syarat agar transisi itu bertahan."}], "story": [{"kind": "cover", "title": "Transisi berkeadilan: memastikan tak ada yang tertinggal.", "text": "Menutup PLTU dan menanam energi bersih adalah keharusan iklim — tapi jika pekerja tambang dan komunitas yang bergantung padanya ditinggalkan, transisi itu gagal sebelum benar-benar dimulai."}, {"kind": "hook", "title": "Dekarbonisasi tanpa keadilan tak menyelesaikan masalah — ia memindahkannya ke bahu yang paling rentan."}, {"kind": "point", "title": "Apa itu transisi berkeadilan?", "text": "Peralihan ke ekonomi rendah karbon yang menciptakan kerja layak dan melindungi yang rentan — bukan sekadar mematikan mesin lama. Dibakukan ILO sejak 2015."}, {"kind": "point", "title": "Taruhan Indonesia", "text": "Lebih dari separuh listrik kita masih dari batu bara. Menutup PLTU tanpa rencana bagi pekerjanya bukan keadilan — itu memindahkan beban."}, {"kind": "stat", "title": "Angka yang menipu bila dirata-rata", "big": "24 juta", "label": "lapangan kerja hijau baru global pada 2030 (≈6 juta hilang)", "source": "ILO, Greening with Jobs, 2018"}, {"kind": "quote", "title": "Inti persoalan", "text": "Karbon yang turun sambil meninggalkan orang di belakang bukanlah kemajuan — itu utang sosial yang ditunda."}, {"kind": "end", "title": "Karbon turun, orang tak ditinggal", "text": "Baca ulasan lengkapnya — dan ikut bangun ekonomi hijau yang adil bersama Glyiv."}], "sources": [{"a": "International Labour Organization (2015). Guidelines for a just transition towards environmentally sustainable economies and societies for all.", "u": "https://www.ilo.org/publications/guidelines-just-transition-towards-environmentally-sustainable-economies-and"}, {"a": "International Labour Organization (2018). World Employment and Social Outlook 2018: Greening with Jobs.", "u": "https://www.ilo.org/publications/major-publications/world-employment-and-social-outlook-2018-greening-jobs"}, {"a": "JETP Indonesia Secretariat (2023). Comprehensive Investment and Policy Plan (CIPP).", "u": "https://jetp-id.org/"}, {"a": "IPCC (2022). Climate Change 2022: Mitigation of Climate Change (AR6, Working Group III), Summary for Policymakers.", "u": "https://www.ipcc.ch/report/ar6/wg3/"}]}, {"slug": "desa-hijau-energi-mandiri", "topic": "Ekonomi", "mood": "#4F7A3A", "title": "Desa mandiri energi: listrik bersih dari sumber sendiri.", "dek": "Mikrohidro, biogas, dan surya komunal membawa listrik yang lebih andal ke desa terpencil sekaligus memangkas ketergantungan pada diesel — bukti bahwa pembangunan dan iklim bisa berjalan seiring.", "hook": "Saat genset diesel akhirnya dimatikan, yang terdengar bukan sunyi — melainkan sungai, ternak, dan matahari desa yang kini menyalakan listriknya sendiri.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IEA, IRENA, IPCC)", "read": 5, "blocks": [{"t": "lead", "x": "Di banyak desa terpencil Indonesia, malam masih ditentukan oleh suara genset diesel: berisik, mahal, dan padam begitu solar habis atau kapal pengangkut telat datang. Tapi di sejumlah desa lain, malam kini terang dari sumber yang tak perlu diantar siapa pun — sungai kecil yang mengalir, kotoran ternak yang menumpuk, dan matahari yang tiap hari datang cuma-cuma."}, {"t": "p", "x": "Secara nasional, angkanya terlihat hampir sempurna: pemerintah mencatat rasio elektrifikasi Indonesia menyentuh 99,8% pada akhir 2023 ⚠︎. Tapi 'punya listrik' dan 'punya listrik yang andal' adalah dua hal berbeda. Di ujung-ujung kepulauan, sebagian sambungan masih bergantung pada genset diesel yang hanya menyala beberapa jam semalam. Di tingkat global, <a href=\"https://www.iea.org/reports/tracking-sdg7-the-energy-progress-report-2024\">685 juta orang masih tanpa akses listrik sama sekali pada 2022</a> — mayoritas di pedesaan."}, {"t": "h2", "x": "Tiga sumber, satu tujuan"}, {"t": "p", "x": "<b>Mikrohidro</b> memanfaatkan aliran sungai kecil — tanpa bendungan raksasa — untuk memutar turbin dan menyalakan listrik hingga 24 jam bagi puluhan sampai ratusan rumah. Karena dikelola koperasi atau kelompok warga desa sendiri, biaya operasinya jauh di bawah diesel, dan tak ada solar yang harus dibeli tiap bulan."}, {"t": "p", "x": "<b>Biogas</b> mengubah masalah menjadi tenaga: kotoran ternak dan limbah organik difermentasi menjadi gas untuk memasak sekaligus pembangkit kecil. Bonusnya, proses ini <i>menangkap</i> metana yang tadinya lepas ke udara — gas rumah kaca yang, menurut <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">IPCC AR6</a>, puluhan kali lebih kuat memerangkap panas dibanding CO₂ dalam kurun 100 tahun (GWP-100 sekitar 27)."}, {"t": "pull", "x": "Listrik dari sungai, ternak, dan matahari desa sendiri — pembangunan dan iklim tak lagi harus dipilih salah satu."}, {"t": "p", "x": "<b>Surya komunal</b> melengkapi keduanya di siang hari. Harga panel sudah runtuh: biaya listrik surya skala besar turun sekitar 90% antara 2010 dan 2023 menurut <a href=\"https://www.irena.org/Publications/2024/Sep/Renewable-Power-Generation-Costs-in-2023\">IRENA</a>. Alhasil jaringan mikro (microgrid) surya-plus-baterai kini bisa benar-benar menggeser diesel di banyak lokasi, bukan sekadar melengkapinya."}, {"t": "stat", "n": "685 juta", "l": "orang masih tanpa akses listrik pada 2022 — mayoritas di pedesaan", "s": "IEA, IRENA, UNSD, World Bank, WHO — Tracking SDG 7, 2024"}, {"t": "p", "x": "Yang dipangkas bukan cuma tagihan. Satu kWh dari genset diesel melepas sekitar 0,8 kg CO₂ ⚠︎; setiap kilowatt-jam yang berpindah ke mikrohidro, biogas, atau surya adalah emisi yang tak jadi terbakar. Dampaknya nyata — tapi jujur harus disebut sebagai <b>kontribusi</b> penurunan emisi yang bisa dilacak, bukan klaim 'netral karbon'. Tantangan terbesarnya pun sering bukan teknologi, melainkan pemeliharaan jangka panjang, suku cadang, dan pembiayaan awal yang memberatkan desa."}, {"t": "bars", "h": [0.9, 0.72, 0.55, 0.4, 0.28, 0.18], "cap": "Ilustrasi: porsi diesel dalam listrik desa menyusut saat mikrohidro, biogas, dan surya ditambahkan ke jaringan."}], "story": [{"kind": "cover", "title": "Desa mandiri energi: listrik bersih dari sumber sendiri", "text": "Mikrohidro, biogas, dan surya komunal membawa listrik yang lebih andal ke desa terpencil sekaligus memangkas ketergantungan pada diesel."}, {"kind": "hook", "title": "Genset diesel dimatikan", "text": "Yang menyala kini: sungai, ternak, dan matahari desa sendiri — tanpa perlu diantar siapa pun."}, {"kind": "point", "title": "Mikrohidro", "text": "Aliran sungai kecil memutar turbin. Listrik hingga 24 jam, tanpa solar yang harus dibeli tiap bulan."}, {"kind": "point", "title": "Biogas", "text": "Kotoran ternak jadi gas masak & listrik — sekaligus menangkap metana sebelum lepas ke udara."}, {"kind": "point", "title": "Surya komunal", "text": "Biaya listrik surya turun ~90% (2010–2023, IRENA). Microgrid surya-baterai kini menggeser diesel."}, {"kind": "stat", "title": "Skalanya masih besar", "big": "685 juta", "label": "orang tanpa akses listrik pada 2022 — mayoritas di desa", "source": "Tracking SDG 7, 2024"}, {"kind": "end", "title": "Pembangunan & iklim, bersama", "text": "Baca kabar lengkapnya di Glyiv — tempat emisi yang terhindar bisa dilacak dengan jujur, bukan sekadar diklaim."}], "sources": [{"a": "IEA, IRENA, UNSD, World Bank, WHO (2024). Tracking SDG 7: The Energy Progress Report 2024.", "u": "https://www.iea.org/reports/tracking-sdg7-the-energy-progress-report-2024"}, {"a": "IRENA (2024). Renewable Power Generation Costs in 2023.", "u": "https://www.irena.org/Publications/2024/Sep/Renewable-Power-Generation-Costs-in-2023"}, {"a": "IPCC (2021). AR6 Working Group I, Bab 7 — nilai GWP-100 metana.", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "DESNZ/DEFRA (2024). UK Government GHG Conversion Factors — faktor emisi diesel (asumsi efisiensi genset ⚠︎).", "u": "https://www.gov.uk/government/publications/greenhouse-gas-reporting-conversion-factors-2024"}]}, {"slug": "harga-karbon-pendapatan-negara", "topic": "Ekonomi", "mood": "#B0894F", "title": "Harga karbon: sumber pendapatan, bukan sekadar beban.", "dek": "Pajak dan pasar karbon tak cuma menaikkan biaya — pada 2023 keduanya menghasilkan penerimaan rekor lebih dari US$100 miliar, dan desain kebijakanlah, bukan harganya, yang menentukan siapa diuntungkan.", "hook": "Harga karbon terdengar seperti beban. Tapi di 2023 ia menghasilkan lebih dari US$100 miliar — dan ke mana uang itu pergi adalah pilihan, bukan takdir.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (World Bank, UU HPP)", "read": 4, "blocks": [{"t": "lead", "x": "Pajak karbon dan pasar karbon kerap dibaca sebagai satu hal saja: beban baru bagi industri dan, pada akhirnya, bagi konsumen. Tapi ada sisi yang jarang dibicarakan — uang yang terkumpul tidak lenyap. Ia menjadi penerimaan negara, dan ke mana penerimaan itu mengalir adalah keputusan desain, bukan takdir."}, {"t": "p", "x": "Angkanya sudah cukup besar untuk diperhitungkan. Menurut <a href=\"https://carbonpricingdashboard.worldbank.org/\">World Bank</a>, penerimaan global dari pajak dan sistem perdagangan emisi (ETS) melampaui US$100 miliar untuk pertama kalinya pada 2023 — sebuah rekor. Ada 75 instrumen harga karbon yang beroperasi di dunia, mencakup sekitar 24% emisi gas rumah kaca global. Karbon, dengan kata lain, sudah punya harga di banyak yurisdiksi — dan harga itu menghasilkan aliran fiskal yang nyata."}, {"t": "stat", "n": "US$104 miliar", "l": "Penerimaan global dari pajak & pasar karbon pada 2023 — rekor tertinggi", "s": "World Bank, State and Trends of Carbon Pricing 2024"}, {"t": "h2", "x": "Penerimaan yang bisa dialihkan"}, {"t": "p", "x": "Yang menentukan bukan besarnya, tapi arahnya. Laporan World Bank mencatat <b>lebih dari separuh</b> penerimaan itu dipakai untuk mendanai program iklim dan alam. Sisanya bisa masuk anggaran umum, memangkas pajak lain, atau kembali ke rumah tangga sebagai transfer tunai. British Columbia di Kanada, misalnya, sejak 2008 menjalankan pajak karbon yang awalnya dirancang bersifat netral-penerimaan — hasilnya dikembalikan lewat pemotongan pajak dan rabat bagi warga berpendapatan rendah."}, {"t": "pull", "x": "Harga karbon tidak otomatis adil atau tidak adil. Desain kebijakannya — ke mana uang itu pergi — yang menentukan siapa diuntungkan."}, {"t": "p", "x": "Indonesia sudah meletakkan dasar hukumnya. <a href=\"https://peraturan.bpk.go.id/Details/191725/uu-no-7-tahun-2021\">UU No. 7/2021</a> tentang Harmonisasi Peraturan Perpajakan menetapkan tarif pajak karbon minimum Rp30 per kilogram CO2e — setara Rp30.000 per ton. Namun penerapannya berulang kali ditunda sejak rencana awal 2022 ⚠︎, sehingga penerimaan riilnya belum bisa dipastikan. Di sisi pasar, Bursa Karbon Indonesia (IDXCarbon) resmi beroperasi sejak September 2023 sebagai kanal perdagangan unit karbon."}, {"t": "h2", "x": "Desain menentukan siapa diuntungkan"}, {"t": "p", "x": "Ini bagian yang jujur harus diakui: tanpa desain yang hati-hati, harga karbon bisa bersifat regresif — menekan rumah tangga miskin lebih keras karena porsi belanja energi mereka lebih besar. Tapi persoalan itu bisa ditangani justru dengan penerimaan yang sama. Sebagian dana dapat dikembalikan sebagai bantuan sosial atau 'dividen karbon', sementara sebagian lain membiayai transisi energi — jaringan listrik bersih, transportasi umum, pelatihan ulang tenaga kerja. Beban di satu sisi bisa menjadi imbalan di sisi lain, bila arah aliran dananya memang dirancang untuk itu."}, {"t": "p", "x": "Glyiv membaca ini sebagai soal keterlacakan, bukan slogan. Selama emisi belum terlacak dengan kredibel, harga karbon sulit dihitung adil — dan penerimaannya sulit dipertanggungjawabkan. Titik awalnya selalu sama: data yang bisa diaudit, sebelum bicara siapa membayar dan siapa menerima."}], "story": [{"kind": "cover", "title": "Harga karbon: sumber pendapatan, bukan sekadar beban.", "text": "Pajak dan pasar karbon tak cuma menaikkan biaya — pada 2023 keduanya menghasilkan penerimaan rekor lebih dari US$100 miliar, dan desain kebijakanlah, bukan harganya, yang menentukan siapa diuntungkan."}, {"kind": "hook", "title": "Harga karbon terdengar seperti beban. Tapi di 2023 ia menghasilkan lebih dari US$100 miliar — dan ke mana uang itu pergi adalah pilihan."}, {"kind": "point", "title": "Uangnya tidak lenyap", "text": "Pajak & pasar karbon menjadi penerimaan negara. Ke mana ia mengalir adalah keputusan desain."}, {"kind": "stat", "title": "Rekor 2023", "big": "US$104 miliar", "label": "Penerimaan global harga karbon, 2023 (rekor)", "source": "World Bank, 2024"}, {"kind": "point", "title": "Bisa dialihkan", "text": "Lebih dari separuh penerimaan dunia mendanai program iklim & alam. Sebagian lagi bisa jadi bantuan sosial dan transisi energi."}, {"kind": "quote", "title": "Soal desain", "text": "Harga karbon tidak otomatis adil atau tidak adil. Desainnya — ke mana uang itu pergi — yang menentukan siapa diuntungkan."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv", "text": "Wawasan karbon Indonesia — jujur, terlacak, bisa dipertanggungjawabkan."}], "sources": [{"a": "World Bank (2024). State and Trends of Carbon Pricing 2024.", "u": "https://carbonpricingdashboard.worldbank.org/"}, {"a": "Republik Indonesia (2021). UU No. 7 Tahun 2021 tentang Harmonisasi Peraturan Perpajakan (tarif pajak karbon minimum Rp30/kg CO2e).", "u": "https://peraturan.bpk.go.id/Details/191725/uu-no-7-tahun-2021"}, {"a": "Bursa Efek Indonesia. IDXCarbon — Bursa Karbon Indonesia (diluncurkan September 2023).", "u": "https://www.idxcarbon.co.id/"}, {"a": "Province of British Columbia. British Columbia's Carbon Tax (diperkenalkan 2008)."}]}, {"slug": "kota-hijau-ruang-terbuka", "topic": "Ekonomi", "mood": "#4F7A3A", "title": "Kota yang lebih sejuk: ruang hijau sebagai infrastruktur iklim.", "dek": "Pohon dan taman kota tak akan membuat sebuah kota \"netral karbon\" — tapi ia mendinginkan pusat yang memanas, menyerap air hujan, dan diam-diam ikut menyimpan karbon. Bagi kota tropis, itu adaptasi dan mitigasi sekaligus.", "hook": "Pohon kota adalah pendingin yang tak butuh listrik. Di kota tropis, itu bukan estetika — itu infrastruktur.", "cover": "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, IEA, UU Penataan Ruang)", "read": 4, "blocks": [{"t": "lead", "x": "Di kota tropis, panas bukan sekadar rasa tak nyaman. Ia menaikkan tagihan listrik, menekan produktivitas, dan memperberat beban kesehatan. Aspal dan beton menyerap terik siang lalu melepaskannya perlahan hingga malam, membuat pusat kota beberapa derajat lebih panas ketimbang pinggirannya. Di titik itu, pohon dan taman berhenti menjadi hiasan — dan mulai bekerja sebagai infrastruktur."}, {"t": "p", "x": "Fenomenanya bernama pulau panas perkotaan (<i>urban heat island</i>): permukaan gelap dan padat memerangkap panas, sementara minimnya vegetasi menghapus pendinginan alami. Pohon melawannya dengan dua cara sederhana — menaungi permukaan dari radiasi matahari, dan menguapkan air lewat daun (evapotranspirasi) yang menyejukkan udara sekitar. <a href=\"https://www.ipcc.ch/report/ar6/wg2/\">IPCC</a> menempatkan <b>infrastruktur hijau dan biru</b> sebagai salah satu opsi adaptasi utama bagi kota yang memanas."}, {"t": "stat", "n": "≈0,94°C", "l": "rata-rata taman kota lebih sejuk dari area sekitarnya pada siang hari", "s": "Bowler dkk., Landscape and Urban Planning, 2010"}, {"t": "p", "x": "Angka itu terdengar kecil, tapi dampaknya berlipat. Udara yang lebih sejuk menurunkan kebutuhan pendingin ruangan — dan menurut <a href=\"https://www.iea.org/reports/the-future-of-cooling\">IEA</a>, pendinginan adalah salah satu penggunaan energi yang tumbuh paling cepat di gedung. Setiap derajat yang tak perlu diturunkan oleh mesin adalah listrik, dan emisi, yang tak jadi dikeluarkan."}, {"t": "p", "x": "Untuk kota tropis, taruhannya lebih tinggi. Di iklim yang memang sudah panas dan lembap, tambahan beberapa derajat dari pulau panas bisa mendorong suhu ke ambang yang berbahaya bagi lansia, pekerja luar ruang, dan mereka yang tanpa akses pendingin. Naungan pohon di trotoar, koridor hijau di sepanjang sungai, dan atap yang ditanami bukan kemewahan — semuanya menurunkan suhu yang benar-benar dirasakan tubuh, di tempat orang berjalan dan menunggu."}, {"t": "pull", "x": "Ruang hijau bukan taman yang bagus difoto. Ia sistem pendingin kota yang berjalan tanpa listrik."}, {"t": "p", "x": "Soal serapan karbon, sebaiknya jujur. Pohon kota memang menyimpan karbon, tapi jumlahnya adalah sebuah <b>kontribusi</b> — bukan penyeimbang emisi seluruh kota. Nilai terbesarnya justru pada adaptasi: meredam panas, menyerap air hujan sehingga mengurangi risiko banjir, dan menjaga kesehatan warga. Menyebutnya jalan menuju 'netral karbon' akan berlebihan; menyebutnya infrastruktur iklim yang bekerja ganda — itu tepat."}, {"t": "h2", "x": "Target 30% yang sering meleset"}, {"t": "p", "x": "Indonesia sebenarnya sudah punya aturannya. UU No. 26/2007 tentang Penataan Ruang mewajibkan setiap kota menyediakan <b>ruang terbuka hijau minimal 30%</b> dari luas wilayah — 20% publik dan 10% privat. Persoalannya ada pada pelaksanaan: banyak kota besar diperkirakan masih jauh di bawah ambang itu ⚠︎, tergerus alih fungsi lahan menjadi bangunan dan jalan."}, {"t": "p", "x": "Membalik keadaan bukan soal menanam sebanyak mungkin, melainkan menaruh pohon yang tepat di tempat yang tepat, lalu memantaunya agar benar-benar hidup. Ruang hijau yang <b>terlacak</b>, terawat, dan terhubung dengan data iklim kota adalah bentuk investasi yang jarang disebut sebagai infrastruktur — padahal ia mendinginkan hari ini sekaligus, sedikit demi sedikit, ikut menyimpan karbon untuk esok."}], "story": [{"kind": "cover", "title": "Kota yang lebih sejuk", "text": "Ruang hijau tak membuat kota 'netral karbon', tapi mendinginkan pusat yang memanas, menyerap air hujan, dan ikut menyimpan karbon. Adaptasi dan mitigasi sekaligus."}, {"kind": "hook", "title": "Pusat kota memanggang, pinggiran lebih adem", "text": "Aspal dan beton memerangkap terik siang. Pohon melawannya — dengan naungan dan uap air dari daun."}, {"kind": "point", "title": "Dua trik sederhana pohon", "text": "Menaungi permukaan dari matahari, lalu menyejukkan udara lewat penguapan daun (evapotranspirasi)."}, {"kind": "stat", "title": "Seberapa sejuk taman kota?", "big": "≈0,94°C", "label": "rata-rata taman kota lebih sejuk dari sekitarnya pada siang hari", "source": "Bowler dkk., 2010"}, {"kind": "point", "title": "Karbonnya? Kontribusi, bukan penyeimbang", "text": "Nilai terbesar ruang hijau adalah adaptasi: meredam panas, menyerap air hujan, menjaga kesehatan warga."}, {"kind": "quote", "title": "Pendingin tanpa listrik", "text": "Ruang hijau bukan taman yang bagus difoto. Ia sistem pendingin kota yang berjalan tanpa listrik."}, {"kind": "end", "title": "Kota yang mendinginkan dirinya", "text": "Baca telaah lengkapnya — dan ikuti Glyiv Kabar untuk cara kota tropis mengubah pohon menjadi infrastruktur iklim."}], "sources": [{"a": "IPCC (2022). AR6 Working Group II, Bab 6: Cities, Settlements and Key Infrastructure — infrastruktur hijau-biru sebagai opsi adaptasi.", "u": "https://www.ipcc.ch/report/ar6/wg2/"}, {"a": "Bowler, D.E., Buyung-Ali, L., Knight, T.M., Pullin, A.S. (2010). Urban greening to cool towns and cities: A systematic review of the empirical evidence. Landscape and Urban Planning, 97(3), 147-155."}, {"a": "IEA (2018). The Future of Cooling — pendinginan ruang sebagai salah satu penggunaan energi gedung yang tumbuh tercepat.", "u": "https://www.iea.org/reports/the-future-of-cooling"}, {"a": "Republik Indonesia (2007). UU No. 26 Tahun 2007 tentang Penataan Ruang — kewajiban RTH minimal 30% (20% publik, 10% privat)."}]}, {"slug": "banjir-rob-adaptasi-pesisir", "topic": "Ekonomi", "mood": "#1E5F8C", "title": "Rob dan pesisir yang tenggelam: biaya adaptasi yang membengkak.", "dek": "Muka air laut naik, tapi di Jakarta dan Semarang tanahnya turun lebih cepat. Adaptasi kini bukan proyek yang bisa dijadwal ulang — ia sudah menjadi pos anggaran, dan pertanyaannya tinggal siapa yang membayar.", "hook": "Di pesisir utara Jawa, banjir rob bukan lagi bencana yang datang sesekali — ia sudah jadi jadwal.", "cover": "https://images.unsplash.com/photo-1505142468610-359e7d316be0?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, UNEP, studi penurunan tanah)", "read": 4, "blocks": [{"t": "lead", "x": "Di sebagian Jakarta Utara dan pesisir Semarang, banjir rob bukan lagi bencana yang datang sesekali — ia sudah menjadi jadwal. Air laut naik lewat gorong-gorong saat pasang, menggenangi jalan dan lantai rumah, lalu surut, lalu kembali. Yang berubah bukan cuma cuaca, tapi tanah di bawah kaki: ia turun lebih cepat daripada laut naik."}, {"t": "p", "x": "Secara global, muka air laut telah naik sekitar <b>0,20 meter</b> antara 1901 dan 2018, dan lajunya makin cepat — dari sekitar 1,3 mm menjadi <b>3,7 mm per tahun</b> pada 2006–2018 <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">(IPCC AR6)</a>. Angka itu terdengar kecil. Tapi di kota yang tanahnya ambles, laju efektif yang dirasakan warga bisa berkali lipat lebih besar."}, {"t": "h2", "x": "Dua ancaman yang bertumpuk"}, {"t": "p", "x": "Penurunan muka tanah — akibat pengambilan air tanah berlebih dan beban bangunan — menjadi pengganda. Di sebagian Jakarta Utara, tanah tercatat turun <b>hingga sekitar 25 cm per tahun</b>, dengan penurunan kumulatif beberapa meter dalam dua dekade menurut studi geodesi <a href=\"https://link.springer.com/article/10.1007/s11069-011-9866-9\">(Abidin dkk.)</a>. Pesisir Semarang mengalami pola serupa, dengan laju hingga sekitar 10 cm per tahun di beberapa titik ⚠︎ — cukup untuk menenggelamkan kawasan yang dulu kering hanya dalam hitungan tahun."}, {"t": "stat", "n": "USD 215–387 miliar", "l": "perkiraan kebutuhan pendanaan adaptasi iklim negara berkembang, per tahun hingga 2030", "s": "UNEP, Adaptation Gap Report 2023"}, {"t": "p", "x": "Biayanya nyata dan berulang. Rob merendam kawasan industri dan pelabuhan, memaksa pabrik meninggikan lantai, merusak jalan, dan menurunkan produktivitas — kerugian yang jarang muncul sebagai satu baris anggaran, tapi terus menggerus ekonomi pesisir tahun demi tahun. Yang tak diadaptasi hari ini akan ditagih dengan bunga esok."}, {"t": "pull", "x": "Adaptasi bukan lagi pilihan yang bisa dijadwal ulang. Ia sudah menjadi pos anggaran — pertanyaannya tinggal siapa yang membayar, dan kapan."}, {"t": "p", "x": "Respons terbesar juga yang termahal. Tanggul laut raksasa (Giant Sea Wall / NCICD) yang digagas untuk melindungi pantai utara Jawa diperkirakan menelan puluhan miliar dolar dan berpuluh tahun pengerjaan ⚠︎ — angka yang masih bergerak karena desain dan skema pembiayaannya belum final. Di sisi lain, pemindahan sebagian fungsi ibu kota ke Nusantara turut dilatari kerentanan Jakarta yang sama."}, {"t": "p", "x": "Yang sering luput: adaptasi dan mitigasi bukan dua pilihan, tapi satu tagihan yang sama. Setiap ton emisi yang tak dipangkas hari ini menambah tinggi tanggul yang harus dibangun esok. Bagi kota dan industri pesisir, langkah pertama yang jujur adalah membuat biaya itu <b>terlacak</b> — memetakan eksposur banjir, emisi, dan anggaran adaptasi dalam angka yang bisa dipertanggungjawabkan, bukan sekadar diklaim. Karena laut tidak menunggu anggaran disahkan."}], "story": [{"kind": "cover", "title": "Rob dan pesisir yang tenggelam", "text": "Muka air laut naik, tapi di Jakarta dan Semarang tanahnya turun lebih cepat. Adaptasi kini jadi pos anggaran yang tak bisa ditunda."}, {"kind": "hook", "title": "Banjir rob bukan lagi bencana sesekali", "text": "Di pesisir utara Jawa, ia sudah menjadi jadwal: pasang datang, air masuk, lalu kembali."}, {"kind": "point", "title": "Dua ancaman bertumpuk", "text": "Laut naik ~3,7 mm/tahun. Tapi tanah Jakarta Utara ambles hingga ~25 cm/tahun — jauh lebih cepat."}, {"kind": "point", "title": "Biayanya berulang", "text": "Rob merendam pabrik, pelabuhan, dan jalan — kerugian yang terus menggerus ekonomi pesisir tiap tahun."}, {"kind": "stat", "title": "Tagihan adaptasi", "big": "USD 215–387 miliar", "label": "kebutuhan pendanaan adaptasi negara berkembang, per tahun hingga 2030", "source": "UNEP, Adaptation Gap Report 2023"}, {"kind": "quote", "title": "Bukan lagi pilihan", "text": "Adaptasi bukan lagi pilihan yang bisa dijadwal ulang. Ia sudah menjadi pos anggaran."}, {"kind": "end", "title": "Buat biayanya terlacak", "text": "Petakan eksposur banjir, emisi, dan anggaran dalam angka yang bisa dipertanggungjawabkan. Baca lengkap di Glyiv Kabar."}], "sources": [{"a": "IPCC (2021). Climate Change 2021: The Physical Science Basis (AR6 WGI), Summary for Policymakers.", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "Abidin, H.Z., Andreas, H., dkk. (2011). Land subsidence of Jakarta (Indonesia) and its relation with urban development. Natural Hazards.", "u": "https://link.springer.com/article/10.1007/s11069-011-9866-9"}, {"a": "UNEP (2023). Adaptation Gap Report 2023: Underfinanced. Underprepared.", "u": "https://www.unep.org/resources/adaptation-gap-report-2023"}, {"a": "National Capital Integrated Coastal Development (NCICD) / Giant Sea Wall — rencana pemerintah; angka biaya masih indikatif ⚠︎."}]}, {"slug": "asuransi-iklim-risiko-fisik", "topic": "Ekonomi", "mood": "#0B2471", "title": "Asuransi di era iklim: saat risiko fisik jadi sukar dihitung.", "dek": "Meningkatnya banjir, kekeringan, dan cuaca ekstrem menaikkan klaim dan premi — menjadikan asuransi salah satu industri pertama yang benar-benar 'membayar' ongkos perubahan iklim.", "hook": "Industri yang tugasnya menghitung risiko kini kesulitan menghitung risiko terbesar zamannya.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (IPCC, Swiss Re, BNPB)", "read": 4, "blocks": [{"t": "lead", "x": "Bisnis asuransi, pada intinya, adalah menghitung masa depan dari masa lalu: seberapa sering rumah terbakar, mobil bertabrakan, atau sungai meluap — lalu menetapkan premi yang sepadan. Perubahan iklim merusak asumsi paling dasar itu. Ketika banjir yang dulu disebut 'seratus tahunan' datang beberapa kali dalam satu dekade, sejarah berhenti menjadi panduan yang bisa dipercaya."}, {"t": "p", "x": "Arah perubahannya sudah cukup jelas secara ilmiah. Laporan <a href=\"https://www.ipcc.ch/report/ar6/syr/\">IPCC AR6</a> menyimpulkan bahwa pemanasan akibat aktivitas manusia telah memperkuat cuaca ekstrem — hujan lebat, kekeringan, dan gelombang panas — di hampir semua kawasan berpenghuni. Bagi penanggung risiko, artinya frekuensi dan besaran klaim ikut bergerak naik, sementara model harga mereka masih banyak bersandar pada data masa lampau."}, {"t": "stat", "n": "USD 108 miliar", "l": "kerugian tertanggung akibat bencana alam global sepanjang 2023 — jauh di atas rata-rata satu dekade sebelumnya", "s": "Swiss Re Institute, sigma 2024"}, {"t": "p", "x": "Dan itu baru sebagian cerita. Dari sekitar <b>USD 280 miliar</b> total kerugian ekonomi pada tahun yang sama, lebih dari separuh tidak tertanggung sama sekali — 'celah perlindungan' yang paling lebar justru menganga di negara berkembang, menurut <a href=\"https://www.swissre.com/institute/research/sigma-research/sigma-2024-01.html\">Swiss Re</a>. Respons industri sering kali sederhana: menaikkan premi, mempersempit pertanggungan, atau menarik diri sama sekali dari wilayah yang dianggap terlalu berisiko."}, {"t": "pull", "x": "Asuransi termasuk industri pertama yang benar-benar 'membayar' perubahan iklim — lewat klaim yang membengkak dan premi yang mengejar."}, {"t": "h2", "x": "Indonesia dan celah yang melebar"}, {"t": "p", "x": "Indonesia termasuk yang paling terpapar. Data <a href=\"https://dibi.bnpb.go.id/\">BNPB</a> menunjukkan mayoritas bencana di tanah air bersifat hidrometeorologis — banjir, tanah longsor, dan cuaca ekstrem — dengan kecenderungan meningkat dalam satu dekade terakhir⚠︎. Sementara itu, penetrasi asuransi masih rendah, sehingga sebagian besar kerugian akhirnya ditanggung langsung oleh rumah tangga, pelaku usaha kecil, dan anggaran negara."}, {"t": "p", "x": "Di sinilah data menjadi penentu. Penanggung risiko makin membutuhkan gambaran yang <b>terlacak</b>: seberapa terpapar sebuah aset terhadap banjir, seberapa tinggi intensitas karbon sebuah rantai pasok, dan ke mana keduanya bergerak. Bagi Glyiv, ini bagian dari pekerjaan yang sama — menjadikan risiko dan emisi sebagai angka yang bisa ditelusuri serta diaudit, bukan sekadar perkiraan yang menenangkan hati."}, {"t": "p", "x": "Perubahan iklim tidak menghapus asuransi; ia memaksanya menghitung ulang. Pihak yang mampu membuktikan eksposurnya dengan data kredibel berpeluang mendapat pertanggungan yang lebih adil — dan yang tidak, akan mendapati pintunya kian menyempit."}], "story": [{"kind": "cover", "title": "Asuransi di era iklim", "text": "Saat banjir, kekeringan, dan cuaca ekstrem membuat risiko fisik jadi sukar dihitung."}, {"kind": "hook", "title": "Menghitung masa depan dari masa lalu", "text": "Itu inti kerja asuransi. Iklim yang berubah merusak asumsi paling dasarnya."}, {"kind": "point", "title": "Sejarah bukan lagi panduan", "text": "Banjir 'seratus tahunan' kini datang beberapa kali dalam satu dekade. IPCC AR6 menegaskan cuaca ekstrem menguat di hampir semua kawasan."}, {"kind": "point", "title": "Klaim naik, premi mengejar", "text": "Respons industri: premi naik, pertanggungan menyempit, sebagian wilayah ditinggalkan."}, {"kind": "stat", "title": "Ongkos yang membengkak", "big": "USD 108 mrd", "label": "kerugian tertanggung akibat bencana alam global, 2023", "source": "Swiss Re Institute, sigma 2024"}, {"kind": "quote", "title": "Pihak pertama yang membayar", "text": "Asuransi termasuk industri pertama yang benar-benar 'membayar' perubahan iklim."}, {"kind": "end", "title": "Risiko yang bisa ditelusuri", "text": "Glyiv menjadikan risiko & emisi sebagai angka yang terlacak dan bisa diaudit. Baca ulasan lengkapnya."}], "sources": [{"a": "IPCC (2023). AR6 Synthesis Report: Climate Change 2023 — Summary for Policymakers.", "u": "https://www.ipcc.ch/report/ar6/syr/"}, {"a": "Swiss Re Institute (2024). sigma: Natural catastrophes in 2023 — kerugian tertanggung USD 108 miliar, total kerugian ekonomi USD 280 miliar.", "u": "https://www.swissre.com/institute/research/sigma-research/sigma-2024-01.html"}, {"a": "BNPB. Data Informasi Bencana Indonesia (DIBI) — dominasi bencana hidrometeorologis.", "u": "https://dibi.bnpb.go.id/"}]}, {"slug": "obligasi-hijau-pembiayaan", "topic": "Ekonomi", "mood": "#1cae6b", "title": "Obligasi hijau: meminjam untuk proyek yang menekan emisi.", "dek": "Obligasi hijau dan sukuk hijau mengarahkan pinjaman ke proyek energi bersih dan transportasi rendah-karbon. Indonesia jadi salah satu pelopornya — dan kredibilitasnya bertumpu pada satu hal yang mudah diabaikan: laporan dampak yang jujur.", "hook": "Meminjam uang untuk memangkas emisi, bukan untuk menambahnya. Tapi bagaimana kita tahu janjinya benar-benar ditepati?", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (ICMA, World Bank, OJK)", "read": 4, "blocks": [{"t": "lead", "x": "Biasanya kita meminjam untuk hal-hal yang mendesak hari ini. Obligasi hijau membalik logika itu: uang dipinjam sekarang untuk membangun sesuatu yang menekan emisi bertahun-tahun ke depan — pembangkit surya, jaringan kereta, pengelolaan sampah. Janjinya menarik. Tapi seperti semua janji keuangan, nilainya bergantung pada apakah ia benar-benar ditepati."}, {"t": "p", "x": "<b>Obligasi hijau</b> (green bond) adalah surat utang biasa dengan satu syarat tambahan: dananya hanya boleh dipakai untuk proyek ramah iklim. <b>Sukuk hijau</b> adalah versi syariahnya — berbasis aset nyata dan tanpa riba, dengan komitmen lingkungan yang sama. Investor menerima pokok dan imbalan seperti obligasi lain; yang berbeda hanya ke mana uangnya pergi. Pasarnya tumbuh pesat: penerbitan obligasi hijau global kini mencapai ratusan miliar dolar AS per tahun ⚠︎, menurut Climate Bonds Initiative."}, {"t": "p", "x": "Indonesia bukan pemain baru di sini. Pada Maret 2018, pemerintah menerbitkan <b>sukuk hijau negara pertama di dunia</b>, mengumpulkan USD 1,25 miliar untuk proyek energi terbarukan, transportasi rendah-karbon, dan ketahanan iklim. Sejak itu Indonesia menerbitkannya hampir tiap tahun dan — ini bagian pentingnya — merilis laporan alokasi dan dampak tahunan yang memerinci ke mana dana mengalir."}, {"t": "stat", "n": "USD 1,25 M", "l": "Sukuk hijau negara pertama di dunia, diterbitkan Indonesia (2018)", "s": "World Bank / Kementerian Keuangan RI, 2018"}, {"t": "h2", "x": "Kredibilitas ada di laporannya, bukan di namanya"}, {"t": "p", "x": "Label 'hijau' tidak diberikan begitu saja. Standar sukarela yang paling luas dipakai, <b>Green Bond Principles</b> dari ICMA, menuntut empat hal: kejelasan penggunaan dana, proses seleksi proyek, pengelolaan dana yang terpisah, dan — yang paling sering diabaikan — <b>pelaporan dampak</b> secara berkala <a href=\"https://www.icmagroup.org/sustainable-finance/the-principles-guidelines-and-handbooks/green-bond-principles-gbp/\">[ICMA]</a>. Di Indonesia, penerbitannya diatur lewat POJK No. 60/2017 tentang efek utang berwawasan lingkungan."}, {"t": "pull", "x": "Sebuah obligasi menjadi hijau bukan karena namanya, melainkan karena laporan yang membuktikan ke mana dananya pergi."}, {"t": "p", "x": "Di sinilah risikonya. Tanpa laporan yang jujur, 'obligasi hijau' bisa menyusut jadi sekadar pemasaran — dana masuk ke proyek yang toh akan dibangun, atau penghematan emisi yang dilebih-lebihkan. Karena itu angka penurunan emisi dalam laporan dampak sebaiknya dibaca sebagai <b>estimasi yang terlacak</b>, bukan hasil yang sudah pasti terukur ⚠︎ — dan paling kredibel bila diverifikasi pihak ketiga yang independen."}, {"t": "h2", "x": "Yang membedakan hijau sungguhan"}, {"t": "p", "x": "Bedanya bukan pada besar imbalan, tapi pada jejak yang bisa ditelusuri: dana dapat dilacak sampai ke proyeknya, dan dampaknya dilaporkan terbuka setiap tahun. Obligasi hijau bukan sihir iklim — ia hanya mengarahkan modal ke arah yang benar. Yang menjaganya tetap bermakna adalah kejujuran laporan, bukan warna pada sampulnya."}], "story": [{"kind": "cover", "title": "Obligasi hijau: meminjam untuk menekan emisi", "text": "Obligasi hijau dan sukuk hijau mengarahkan pinjaman ke proyek energi bersih dan transportasi rendah-karbon. Indonesia jadi salah satu pelopornya — dan kredibilitasnya bertumpu pada satu hal yang mudah diabaikan: laporan dampak yang jujur."}, {"kind": "hook", "title": "Utang yang membangun, bukan membebani", "text": "Meminjam hari ini untuk memangkas emisi bertahun ke depan. Menarik — asalkan janjinya ditepati."}, {"kind": "point", "title": "Apa itu obligasi & sukuk hijau", "text": "Surat utang biasa dengan satu syarat: dana hanya untuk proyek ramah iklim. Sukuk hijau = versi syariahnya, berbasis aset nyata."}, {"kind": "point", "title": "Indonesia sang pelopor", "text": "2018: sukuk hijau negara pertama di dunia. Dananya mengalir ke energi terbarukan & transportasi rendah-karbon."}, {"kind": "stat", "title": "Angka yang bisa dipegang", "big": "USD 1,25 M", "label": "Sukuk hijau negara pertama di dunia (Indonesia, 2018)", "source": "World Bank / Kemenkeu RI"}, {"kind": "quote", "title": "Kuncinya laporan, bukan label", "text": "Sebuah obligasi menjadi hijau bukan karena namanya, melainkan karena laporan yang membuktikan ke mana dananya pergi."}, {"kind": "end", "title": "Baca selengkapnya di Glyiv Kabar", "text": "Pahami cara modal hijau bekerja — dan cara membedakan yang sungguhan dari yang sekadar berlabel. Gabung Glyiv."}], "sources": [{"a": "ICMA (2021). Green Bond Principles: Voluntary Process Guidelines for Issuing Green Bonds.", "u": "https://www.icmagroup.org/sustainable-finance/the-principles-guidelines-and-handbooks/green-bond-principles-gbp/"}, {"a": "World Bank (2020). Pioneering the Green Sukuk: Three Years On."}, {"a": "Kementerian Keuangan RI, DJPPR (2018). Green Bond and Green Sukuk Framework."}, {"a": "Otoritas Jasa Keuangan (2017). POJK No. 60/POJK.04/2017 tentang Penerbitan dan Persyaratan Efek Bersifat Utang Berwawasan Lingkungan (Green Bond)."}]}, {"slug": "petani-kecil-imbalan-karbon", "topic": "Ekonomi", "mood": "#4F7A3A", "title": "Imbalan karbon untuk petani kecil: menjanjikan, tapi rumit.", "dek": "Proyek karbon lahan bisa menambah imbalan bagi petani kecil — tapi biaya verifikasi dan risiko permanensi kerap membuat bagian mereka menipis. Desain yang adil jadi penentu siapa yang benar-benar diuntungkan.", "hook": "Karbon di tanah petani itu nyata. Yang sering hilang justru bagian petaninya.", "cover": "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan IPCC & World Bank", "read": 4, "blocks": [{"t": "lead", "x": "Bagi petani kecil, gagasan dibayar karena menyimpan karbon di tanah dan pepohonan terdengar seperti keadilan yang lama tertunda: lahan yang selama ini menahan emisi akhirnya dihargai. Janjinya nyata — tetapi jalan dari janji itu ke amplop yang benar-benar sampai ke tangan petani jauh lebih berliku daripada yang terlihat."}, {"t": "p", "x": "Potensinya besar. <b>Praktik lahan</b> seperti agroforestri, olah tanah minimum, pemulihan mangrove, dan penambahan bahan organik tanah bisa menyerap karbon sekaligus memperbaiki kesuburan. IPCC menilai sektor lahan (AFOLU) sebagai salah satu sumber mitigasi paling murah yang tersedia hingga 2050 <a href=\"https://www.ipcc.ch/report/ar6/wg3/\">(IPCC AR6, 2022)</a>. Di atas kertas, sebagian nilai itu bisa mengalir kembali sebagai <b>imbalan</b> bagi yang merawat lahannya."}, {"t": "h2", "x": "Kenapa bagian petani sering menipis"}, {"t": "p", "x": "Masalahnya ada di ongkos membuktikan. Kredit karbon hanya laku bila serapannya <b>terlacak</b> dan diverifikasi pihak ketiga — pengukuran awal, pemantauan berkala, lalu audit. Untuk petak yang luasnya kerap kurang dari satu hektare, biaya tetap MRV (<i>monitoring, reporting, verification</i>) ini bisa menelan sebagian besar nilai kredit sebelum sampai ke petani. ⚠︎ Besarannya berbeda-beda tiap proyek dan belum ada angka baku yang berlaku umum."}, {"t": "pull", "x": "Karbonnya nyata, tapi ongkos membuktikannya kerap lebih besar dari bagian yang tersisa untuk petani."}, {"t": "stat", "n": "8–14 Gt", "l": "potensi mitigasi sektor lahan per tahun (opsi berbiaya hingga USD100/ton CO₂e, 2020–2050)", "s": "IPCC AR6 WGIII, 2022 (SPM)"}, {"t": "p", "x": "Lalu ada risiko <b>permanensi</b>. Karbon yang tersimpan di tanah atau pohon bisa lepas kembali — karena kebakaran, kekeringan, pohon mati, atau lahan kembali diolah <a href=\"https://www.ipcc.ch/srccl/\">(IPCC SRCCL, 2019)</a>. Karena itu pembeli menahan sebagian kredit di 'penyangga' (<i>buffer</i>) dan pembayaran kerap dicicil bertahun-tahun, bukan lunas di muka. Bagi petani yang butuh modal di musim tanam ini, imbalan yang baru cair lima tahun lagi bernilai jauh berbeda."}, {"t": "p", "x": "Desain yang adil bisa memperkecil jurang ini: <b>menggabungkan</b> banyak petani dalam satu proyek agar biaya verifikasi ditanggung bersama, MRV berbasis satelit yang menekan ongkos survei lapangan, pembayaran sebagian di muka, dan kontrak yang jujur soal siapa menanggung risiko bila karbon lepas. Sama pentingnya: menyebutnya apa adanya — ini <b>kontribusi</b> pada mitigasi, bukan janji 'netral karbon', dan imbalan <i>tambahan</i>, bukan pengganti penghasilan tani."}, {"t": "bars", "h": [0.95, 0.66, 0.5, 0.36, 0.26], "cap": "Ilustrasi: nilai kredit yang tersisa untuk petani menyusut setelah biaya MRV, penyangga permanensi, dan perantara. Angka nyata bervariasi per proyek."}], "story": [{"kind": "cover", "title": "Imbalan karbon untuk petani kecil", "text": "Proyek karbon lahan bisa menambah imbalan bagi petani kecil — tapi biaya verifikasi dan risiko permanensi kerap membuat bagian mereka menipis. Desain yang adil jadi penentu siapa yang benar-benar diuntungkan."}, {"kind": "hook", "title": "Yang sering hilang", "text": "Karbon di tanah petani itu nyata. Yang sering hilang justru bagian petaninya."}, {"kind": "point", "title": "Janjinya nyata", "text": "Agroforestri, mangrove, dan tanah yang lebih sehat menyerap karbon — dan sebagian nilainya bisa kembali sebagai imbalan bagi yang merawat lahan."}, {"kind": "point", "title": "Ongkos membuktikan", "text": "Kredit hanya laku bila serapannya terlacak & diverifikasi. Untuk petak kecil, biaya MRV bisa menelan sebagian besar nilai sebelum sampai ke petani. ⚠︎ bervariasi."}, {"kind": "stat", "title": "Sebesar apa potensinya", "big": "8–14 Gt", "label": "potensi mitigasi sektor lahan / tahun (opsi hingga USD100/ton)", "source": "IPCC AR6 WGIII, 2022"}, {"kind": "quote", "title": "Intinya", "text": "Karbonnya nyata, tapi ongkos membuktikannya kerap lebih besar dari bagian yang tersisa untuk petani."}, {"kind": "end", "title": "Desain adil jadi kunci", "text": "Menggabungkan petani, MRV satelit, dan pembayaran di muka bisa memperbaiki bagian mereka. Baca ulasan lengkapnya di Glyiv Kabar."}], "sources": [{"a": "IPCC (2022). Climate Change 2022: Mitigation of Climate Change. Contribution of WGIII to AR6 — Summary for Policymakers (C.9) & Bab 7 (AFOLU).", "u": "https://www.ipcc.ch/report/ar6/wg3/"}, {"a": "IPCC (2019). Climate Change and Land (SRCCL) — reversibilitas & permanensi karbon lahan.", "u": "https://www.ipcc.ch/srccl/"}, {"a": "World Bank (2024). State and Trends of Carbon Pricing 2024 — harga & kualitas pasar karbon sukarela.", "u": "https://www.worldbank.org/en/programs/pricing-carbon"}]}, {"slug": "cop28-berpaling-dari-fosil", "topic": "Global", "mood": "#1E5F8C", "title": "COP28: untuk pertama kalinya, dunia sepakat 'berpaling' dari fosil.", "dek": "Kesepakatan Dubai 2023 memuat kalimat bersejarah — dunia diminta 'berpaling dari bahan bakar fosil'. Untuk pertama kali fosil disebut dengan namanya, meski tanpa tenggat yang mengikat.", "hook": "Selama hampir 30 tahun perundingan iklim PBB, dua kata ini tak pernah masuk teks resmi: 'bahan bakar fosil'. Di Dubai, akhirnya masuk.", "cover": "https://images.unsplash.com/photo-1509391366360-2e959784a276?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen UNFCCC & sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "Pada 13 Desember 2023, palu diketuk di Expo City Dubai — dan untuk pertama kalinya dalam hampir tiga dekade perundingan iklim, kesepakatan resmi PBB menyebut penyebab utama krisis ini dengan namanya: bahan bakar fosil. Selama ini istilah itu nyaris absen, seolah krisis iklim bisa dibahas tanpa menyebut sumbernya."}, {"t": "p", "x": "Dokumen penutup COP28 — hasil <b>Global Stocktake</b> pertama, yakni evaluasi menyeluruh atas capaian Perjanjian Paris — menyerukan seluruh negara untuk 'berpaling dari bahan bakar fosil dalam sistem energi' secara adil, tertib, dan setara, demi mencapai nol-bersih pada 2050 sejalan dengan sains <a href=\"https://unfccc.int/documents/637073\">1</a>. Batu bara, minyak, dan gas akhirnya masuk ke dalam teks."}, {"t": "p", "x": "Betapa besar loncatannya baru terasa bila menengok ke belakang. Perjanjian Paris 2015 tak sekali pun menyebut kata 'bahan bakar fosil'; selama itu, penyebab utama pemanasan justru menjadi bahasan yang paling dihindari. Baru di Glasgow (COP26, 2021) muncul seruan mengurangi batu bara tanpa penangkap emisi — itu pun terbatas pada batu bara. Dubai menjadi COP pertama yang menamai <b>seluruh</b> bahan bakar fosil sebagai sesuatu yang harus ditinggalkan."}, {"t": "pull", "x": "Untuk pertama kalinya, dunia sepakat menuliskan arahnya — meski belum menuliskan tenggatnya."}, {"t": "h2", "x": "Bahasa bersejarah, tanpa jadwal mengikat"}, {"t": "p", "x": "Namun setiap kata dipilih dengan hati-hati. Teks memakai frasa 'berpaling' (<i>transitioning away</i>), bukan 'penghapusan' (<i>phase-out</i>) yang didorong lebih dari 100 negara. Tak ada tahun target yang mengikat, dan teks membuka ruang bagi 'bahan bakar transisi' — dibaca: gas — serta teknologi penangkap karbon yang belum terbukti pada skala besar. Aliansi Negara Kepulauan Kecil (AOSIS) menyebut hasilnya penuh celah, dan mencatat mereka bahkan belum berada di ruangan ketika palu diketuk <a href=\"https://www.carbonbrief.org/cop28-key-outcomes-agreed-at-the-un-climate-talks-in-dubai/\">2</a>."}, {"t": "stat", "n": "−43%", "l": "pemangkasan emisi gas rumah kaca global pada 2030 (dibanding 2019) yang dibutuhkan agar batas 1,5°C tetap terjangkau", "s": "IPCC AR6, 2022 — dirujuk dalam teks Global Stocktake COP28"}, {"t": "p", "x": "Angka itu menuntut kecepatan, sebab fosil bukan pemain kecil: bahan bakar fosil masih memasok sekitar <b>80%</b> energi dunia <a href=\"https://www.iea.org/reports/world-energy-outlook-2023\">3</a>. Sebagai penyeimbang, COP28 juga menyepakati target melipatgandakan kapasitas energi terbarukan hingga tiga kali lipat dan menggandakan laju perbaikan efisiensi energi pada 2030 ⚠︎ — arah yang tepat, tetapi jarak dari janji ke pelaksanaan masih lebar. Melipatgandakan energi bersih tidak otomatis menghapus fosil; keduanya harus berjalan bersamaan."}, {"t": "h2", "x": "Apa artinya bagi Indonesia"}, {"t": "p", "x": "Bagi Indonesia — yang sebagian besar listriknya masih bertumpu pada batu bara — 'berpaling dari fosil' bukan slogan abstrak. Lewat <b>JETP</b> (kemitraan transisi energi berkeadilan), sekelompok mitra internasional menjanjikan mobilisasi dana hingga US$20 miliar ⚠︎ sejak 2022, meski pencairan nyatanya berjalan lambat dan masih diperdebatkan <a href=\"https://jetp-id.org/\">4</a>. Di sinilah kejujuran data menjadi penting: transisi hanya bermakna bila setiap ton yang berpindah benar-benar <b>terlacak</b>, dan setiap klaim adalah kontribusi yang bisa diaudit — bukan sekadar bahasa indah di atas kertas."}], "story": [{"kind": "cover", "title": "Dunia akhirnya menyebut namanya: fosil.", "text": "Kesepakatan Dubai 2023 memuat kalimat bersejarah — dunia diminta 'berpaling dari bahan bakar fosil'. Untuk pertama kali fosil disebut dengan namanya, meski tanpa tenggat yang mengikat."}, {"kind": "hook", "title": "30 tahun tanpa dua kata itu", "text": "Sejak perundingan iklim PBB dimulai, 'bahan bakar fosil' tak pernah masuk teks resmi. Di COP28 Dubai, akhirnya masuk."}, {"kind": "point", "title": "Kata yang akhirnya masuk teks", "text": "Paris 2015: fosil tak disebut sama sekali. Glasgow 2021: hanya batu bara. Dubai 2023: seluruh bahan bakar fosil."}, {"kind": "point", "title": "Bahasa, bukan tenggat", "text": "Teks memakai 'berpaling', bukan 'penghapusan'. Tanpa tahun mengikat, dengan celah untuk gas dan teknologi penangkap karbon."}, {"kind": "stat", "title": "Kecepatan yang dibutuhkan", "big": "−43%", "label": "emisi GRK global harus turun pada 2030 (vs 2019) agar 1,5°C terjangkau", "source": "IPCC AR6, 2022"}, {"kind": "quote", "title": "Suara yang paling terancam", "text": "'Ada serangkaian celah dalam teks ini.' — Aliansi Negara Kepulauan Kecil (AOSIS), plenary penutup COP28", "source": "AOSIS, 2023"}, {"kind": "end", "title": "Arah sudah tertulis. Tenggatnya belum.", "text": "Baca versi lengkapnya di Glyiv Kabar — dan ikuti bagaimana janji iklim diubah menjadi data karbon yang terlacak."}], "sources": [{"a": "UNFCCC (2023). Outcome of the first global stocktake, Decision 1/CMA.5, COP28 Dubai.", "u": "https://unfccc.int/documents/637073"}, {"a": "IPCC (2022). AR6 WG3, Summary for Policymakers — penurunan emisi 43% pada 2030 vs 2019 untuk jalur 1,5°C.", "u": "https://www.ipcc.ch/report/ar6/wg3/"}, {"a": "IEA (2023). World Energy Outlook 2023 — pangsa bahan bakar fosil dalam pasokan energi global.", "u": "https://www.iea.org/reports/world-energy-outlook-2023"}, {"a": "JETP Indonesia (2023). Comprehensive Investment and Policy Plan (CIPP) — mobilisasi US$20 miliar.", "u": "https://jetp-id.org/"}]}, {"slug": "cop29-pendanaan-iklim", "topic": "Global", "mood": "#0B2471", "title": "COP29 Baku: janji pendanaan iklim yang dianggap kurang.", "dek": "Baku menutup \"COP pendanaan\" dengan janji paling sedikit US$300 miliar per tahun pada 2035 — kenaikan hampir tiga kali lipat di atas kertas, yang tetap dinilai jauh dari kebutuhan negara berkembang.", "hook": "Angka yang katanya bersejarah, disebut negara berkembang cuma \"ilusi optik\". Apa sebenarnya yang disepakati di COP29 Baku?", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen UNFCCC & sumber publik", "read": 4, "blocks": [{"t": "lead", "x": "COP29 di Baku dijuluki \"COP pendanaan\" — pertemuan yang seharusnya menjawab pertanyaan paling praktis dari krisis iklim: siapa yang membayar, dan berapa. Setelah dua minggu negosiasi alot yang molor hingga dini hari, jawabannya keluar sebagai satu angka. Dan angka itu justru membuat banyak negara yang paling membutuhkannya merasa ditinggalkan."}, {"t": "p", "x": "Kesepakatan itu bernama <b>New Collective Quantified Goal</b> (NCQG). Intinya: negara maju \"memimpin\" penggalangan pendanaan iklim paling sedikit <b>US$300 miliar per tahun pada 2035</b>, dari campuran sumber publik dan swasta. Angka ini menggantikan target lama US$100 miliar per tahun yang disepakati pada 2009 dan baru benar-benar tercapai pada 2022, <a href=\"https://www.carbonbrief.org/cop29-key-outcomes-agreed-at-the-un-climate-talks-in-baku/\">menurut Carbon Brief</a>."}, {"t": "p", "x": "Di atas kertas, itu kenaikan hampir tiga kali lipat. Persoalannya ada pada jaraknya dengan kebutuhan. Panitia teknis PBB menaksir kebutuhan yang sudah terhitung dari 98 negara berkembang saja setara US$455–584 miliar⚠︎ per tahun hingga 2030 — dan itu belum mencakup banyak negara lain. Sementara janji US$300 miliar baru jatuh tempo lima tahun setelahnya."}, {"t": "pull", "x": "Negara berkembang menyebutnya \"ilusi optik\" — angka yang terlihat besar di siaran pers, tetapi jauh dari kebutuhan nyata di lapangan."}, {"t": "stat", "n": "US$1,3 triliun⚠︎", "l": "perkiraan kebutuhan pendanaan eksternal negara berkembang (di luar Tiongkok) per tahun pada 2035", "s": "IHLEG untuk Presidensi COP29/COP30, 2024"}, {"t": "h2", "x": "Kenapa angkanya terasa kurang"}, {"t": "p", "x": "Bukan sekadar soal besaran. Teks kesepakatan hanya meminta negara maju \"memimpin\", bukan \"menjamin\" — sementara negara berkembang didorong ikut \"berkontribusi secara sukarela\". Bagi banyak delegasi, rumusan itu mengaburkan tanggung jawab historis yang diatur prinsip Tanggung Jawab Bersama namun Berbeda (CBDR). Ditambah kenyataan lama: sebagian besar pendanaan iklim selama ini mengalir sebagai <b>pinjaman</b>, bukan hibah — menambah beban utang negara yang justru sudah rentan, <a href=\"https://india.mongabay.com/2024/11/cop29-ends-with-a-300-billion-promise-overshadowed-by-distrust-and-discontent/\">seperti dicatat Mongabay</a>."}, {"t": "p", "x": "Baku juga menyisakan janji yang lebih besar tetapi lebih lunak: seruan menggalang US$1,3 triliun⚠︎ per tahun pada 2035 dari \"semua sumber\" — dikenal sebagai Peta Jalan Baku-Belém. Angka itu mendekati taksiran kebutuhan riil, namun statusnya sekadar ajakan. Tanpa pembagian beban yang mengikat, ia lebih mudah dijanjikan ketimbang ditagih."}, {"t": "h2", "x": "Yang bisa dikendalikan Indonesia"}, {"t": "p", "x": "Bagi Indonesia, pesannya jujur: pendanaan global yang seret berarti sebagian besar biaya transisi harus ditanggung dari dalam — sementara komitmen seperti JETP senilai US$20 miliar⚠︎ pun mensyaratkan proyek yang benar-benar layak-danai. Yang bisa kita kendalikan bukan besaran janji orang lain, melainkan kualitas bukti kita sendiri. Setiap ton emisi yang <b>terlacak</b> — bukan sekadar diklaim — memperkuat posisi tawar atas dana yang memang ada: lewat CBAM, pasar karbon, atau mitra transisi. Itulah pekerjaan yang tidak perlu menunggu hasil COP berikutnya."}], "story": [{"kind": "cover", "title": "COP29 Baku: janji US$300 miliar yang dianggap kurang", "text": "Baku menutup \"COP pendanaan\" dengan angka yang, di atas kertas, naik tiga kali lipat — tapi tetap dinilai jauh dari kebutuhan negara berkembang."}, {"kind": "hook", "title": "\"Terlalu sedikit, terlalu jauh\"", "text": "Pertemuan iklim terbesar 2024 berakhir dengan satu angka yang membuat Global South kecewa."}, {"kind": "point", "title": "Apa yang disepakati", "text": "Negara maju \"memimpin\" pendanaan iklim paling sedikit US$300 miliar/tahun pada 2035 — menggantikan target lama US$100 miliar."}, {"kind": "point", "title": "Kenapa dianggap kurang", "text": "Kebutuhan negara berkembang ditaksir jauh lebih besar. Sebagian besar dana pun berupa pinjaman, bukan hibah."}, {"kind": "stat", "title": "Selisih dengan kebutuhan", "big": "US$1,3 triliun⚠︎", "label": "kebutuhan pendanaan eksternal per tahun pada 2035 (di luar Tiongkok)", "source": "IHLEG, 2024"}, {"kind": "quote", "title": "Suara Global South", "text": "\"Ilusi optik\" — begitu delegasi India menyebut janji US$300 miliar itu."}, {"kind": "end", "title": "Selisih itu nyata", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan ikuti bagaimana data karbon yang terlacak memperkuat posisi tawar Indonesia."}], "sources": [{"a": "UNFCCC (2024). Decision 1/CMA.6: New Collective Quantified Goal on Climate Finance — COP29, Baku.", "u": "https://unfccc.int/cop29"}, {"a": "Carbon Brief (2024). COP29: Key outcomes agreed at the UN climate talks in Baku.", "u": "https://www.carbonbrief.org/cop29-key-outcomes-agreed-at-the-un-climate-talks-in-baku/"}, {"a": "Independent High-Level Expert Group on Climate Finance / Grantham Research Institute (2024). Baku to Belém Roadmap to 1.3T — external climate finance for developing countries.", "u": "https://www.lse.ac.uk/granthaminstitute/news/new-report-lays-out-feasible-path-to-mobilising-external-finance-of-us1-3-trillion-annually-by-2035-for-climate-investments-in-developing-countries/"}, {"a": "Mongabay India (2024). COP29 ends with a $300 billion promise overshadowed by distrust and discontent.", "u": "https://india.mongabay.com/2024/11/cop29-ends-with-a-300-billion-promise-overshadowed-by-distrust-and-discontent/"}]}, {"slug": "2024-tahun-terpanas", "topic": "Global", "mood": "#B5623A", "title": "2024: tahun pertama yang melewati ambang 1,5°C.", "dek": "Copernicus menegaskan 2024 sebagai tahun kalender terpanas dalam catatan — dan yang pertama melampaui 1,5°C di atas era praindustri, membuat ambang Paris terasa kian dekat untuk ditembus permanen.", "hook": "Satu tahun penuh di atas 1,5°C. Bukan proyeksi — sudah terjadi, tahun lalu.", "cover": "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan data publik Copernicus & WMO", "read": 4, "blocks": [{"t": "lead", "x": "Selama hampir satu dekade, angka 1,5°C menjadi garis merah paling terkenal dalam diplomasi iklim — batas yang disepakati dunia untuk tidak dilampaui. Pada 2024, untuk pertama kalinya, satu tahun kalender penuh berada di atas garis itu. Copernicus Climate Change Service (C3S) menegaskan 2024 sebagai tahun terpanas yang pernah tercatat, sekaligus yang pertama melampaui 1,5°C di atas rata-rata era praindustri."}, {"t": "p", "x": "Menurut C3S, suhu rata-rata permukaan global 2024 berada sekitar <b>1,60°C ⚠︎</b> di atas periode praindustri (1850–1900) — memecahkan rekor yang baru dibuat 2023 <a href=\"https://climate.copernicus.eu/global-climate-highlights-2024\">Copernicus, 2025</a>. Organisasi Meteorologi Dunia (WMO), yang menggabungkan enam kumpulan data, mencatat angka sedikit berbeda, sekitar <b>1,55°C ⚠︎</b> dengan rentang ketidakpastian. Selisih ini wajar: tiap lembaga memakai baseline dan metode berbeda, jadi angka pastinya masih terlacak, bukan tunggal."}, {"t": "h2", "x": "Apakah batas Paris sudah ditembus?"}, {"t": "p", "x": "Belum — setidaknya belum secara teknis. Target 1,5°C dalam Perjanjian Paris mengacu pada <b>rata-rata jangka panjang</b>, umumnya diukur selama 20–30 tahun, bukan satu tahun kalender <a href=\"https://www.ipcc.ch/report/ar6/syr/\">IPCC AR6</a>. Jadi 2024 yang melewati 1,5°C bukan berarti batas itu resmi dilanggar permanen. Namun ia adalah peringatan paling nyata sejauh ini: marjin yang tersisa menipis, dan tahun sepanas ini akan makin sering, bukan makin jarang."}, {"t": "pull", "x": "Satu tahun di atas 1,5°C belum berarti kalah — tapi ia memberi tahu kita persis seberapa tipis marjin yang tersisa."}, {"t": "stat", "n": "1,60°C ⚠︎", "l": "Suhu rata-rata global 2024 di atas era praindustri (1850–1900) — rekor terpanas", "s": "Copernicus Climate Change Service, 2025"}, {"t": "p", "x": "Apa yang mendorongnya? Kombinasi dua hal: konsentrasi gas rumah kaca yang terus menumpuk, dan fenomena El Niño yang memuncak di awal 2024 lalu mereda. Konsentrasi CO₂ atmosfer mencapai rekor sekitar <b>422 ppm ⚠︎</b> — level tertinggi dalam ratusan ribu tahun. El Niño memberi dorongan sementara, tetapi tren dasarnya jelas: sepuluh tahun terpanas yang pernah tercatat semuanya terjadi dalam sepuluh tahun terakhir."}, {"t": "p", "x": "Bagi Indonesia — negara kepulauan dengan salah satu garis pantai terpanjang di dunia — angka global ini bukan abstraksi. Pemanasan yang lebih tinggi terlacak lewat naiknya muka laut, gelombang panas laut yang memutihkan terumbu, dan pola hujan yang makin sulit ditebak bagi petani dan nelayan. Dampaknya tidak merata, dan yang paling rentan sering menanggung paling banyak."}, {"t": "h2", "x": "Dari angka ke tindakan"}, {"t": "p", "x": "Rekor ini bukan alasan untuk menyerah, melainkan untuk mempertajam fokus. Setiap sepersepuluh derajat yang bisa dicegah tetap berarti. Di situlah kontribusi ekonomi hijau bekerja: mengukur emisi dengan jujur, menekan yang bisa ditekan, lalu membiayai penyerapan yang bisa diaudit. Glyiv membangun untuk bagian itu — bukan menjanjikan angka nol, tetapi membuat setiap ton yang terlacak dan setiap kontribusi bisa dipertanggungjawabkan."}], "story": [{"kind": "cover", "title": "2024: tahun pertama di atas 1,5°C", "text": "Copernicus menegaskan 2024 sebagai tahun kalender terpanas dalam catatan — dan yang pertama melampaui ambang Paris."}, {"kind": "hook", "title": "Bukan proyeksi. Sudah terjadi.", "text": "Untuk pertama kalinya, satu tahun kalender penuh berada di atas 1,5°C."}, {"kind": "point", "title": "Rekor yang dikonfirmasi", "text": "Suhu global 2024 sekitar 1,60°C ⚠︎ di atas era praindustri (Copernicus). WMO mencatat ~1,55°C ⚠︎ — beda dataset, tren sama."}, {"kind": "point", "title": "Batas Paris belum resmi ditembus", "text": "Target 1,5°C dihitung sebagai rata-rata 20–30 tahun, bukan satu tahun. Tapi marjinnya kini sangat tipis."}, {"kind": "stat", "title": "Seberapa panas", "big": "1,60°C ⚠︎", "label": "Suhu global 2024 di atas era praindustri — tahun terpanas dalam catatan", "source": "Copernicus Climate Change Service, 2025"}, {"kind": "quote", "title": "Marjin yang menipis", "text": "Satu tahun di atas 1,5°C belum berarti kalah — tapi ia memberi tahu kita seberapa tipis marjin yang tersisa."}, {"kind": "end", "title": "Dari angka ke tindakan", "text": "Setiap sepersepuluh derajat berarti. Baca ulasan lengkapnya, dan kenali bagaimana Glyiv membuat setiap ton terlacak."}], "sources": [{"a": "Copernicus Climate Change Service (C3S) (2025). Global Climate Highlights 2024.", "u": "https://climate.copernicus.eu/global-climate-highlights-2024"}, {"a": "World Meteorological Organization (WMO) (2025). WMO confirms 2024 as warmest year on record at about 1.55°C above pre-industrial level.", "u": "https://wmo.int/news/media-centre/wmo-confirms-2024-warmest-year-record-about-155degc-above-pre-industrial-level"}, {"a": "IPCC (2023). AR6 Synthesis Report — framing target 1,5°C sebagai rata-rata jangka panjang.", "u": "https://www.ipcc.ch/report/ar6/syr/"}]}, {"slug": "anggaran-karbon-tersisa", "topic": "Global", "mood": "#0F2E22", "title": "Anggaran karbon: berapa banyak lagi yang boleh kita lepas?", "dek": "IPCC menghitung sisa \"jatah\" karbon untuk peluang 1,5°C tinggal beberapa ratus gigaton — kerangka yang mengubah target iklim abstrak menjadi neraca yang bisa dihitung, dan tenggat yang diukur dalam tahun, bukan generasi.", "hook": "Bayangkan atmosfer sebagai rekening bersama: saldonya tinggal beberapa ratus gigaton — dan dunia masih menarik sekitar 40 setiap tahun.", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan laporan IPCC & Global Carbon Project", "read": 4, "blocks": [{"t": "lead", "x": "Bumi punya semacam rekening bersama. Setiap ton karbon dioksida yang kita lepas ke atmosfer menetap di sana selama berabad-abad, dan jumlahnya terus menumpuk. 'Anggaran karbon' adalah cara ilmuwan menerjemahkan janji iklim yang abstrak menjadi satu angka konkret: berapa banyak CO₂ lagi yang boleh dilepas dunia sebelum peluang menahan pemanasan di 1,5°C benar-benar tertutup."}, {"t": "p", "x": "Angkanya mengejutkan justru karena kecil. Dalam laporan AR6, IPCC memperkirakan sisa anggaran karbon dari awal 2020 tinggal sekitar <b>500 gigaton CO₂</b> untuk peluang 50% menahan pemanasan di 1,5°C — dan hanya <b>400 gigaton</b> bila kita menginginkan peluang yang lebih aman, 67% <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">(IPCC AR6, WG1)</a>. Bukan ratusan ribu; hanya beberapa ratus."}, {"t": "stat", "n": "500 Gt CO₂", "l": "Sisa anggaran karbon 1,5°C (peluang 50%, dihitung dari awal 2020)", "s": "IPCC AR6 WG1, 2021"}, {"t": "p", "x": "Bandingkan dengan seberapa cepat kita membelanjakannya. Emisi CO₂ global — dari bahan bakar fosil ditambah perubahan tata guna lahan — kini sekitar <b>40 gigaton per tahun</b> <a href=\"https://globalcarbonproject.org/carbonbudget/\">(Global Carbon Budget 2024)</a>. Dengan laju itu, saldo 500 gigaton terkuras hanya dalam waktu belasan tahun. Setiap tahun kita menunda pemangkasan, sisa peluang ikut menyusut."}, {"t": "pull", "x": "Anggaran karbon menggeser pertanyaannya — dari 'seberapa hijau kita' menjadi 'berapa banyak yang tersisa'. Dan jawabannya diukur dalam tahun, bukan generasi."}, {"t": "h2", "x": "Dari target abstrak ke neraca"}, {"t": "p", "x": "Kabar yang lebih tajam datang dari pembaruan tahunan para ilmuwan iklim. Studi <i>Indicators of Global Climate Change</i> memperkirakan sisa anggaran 1,5°C tinggal sekitar <b>200 gigaton CO₂</b>⚠︎ pada awal 2024 — kira-kira lima tahun emisi dengan laju sekarang <a href=\"https://essd.copernicus.org/articles/16/2625/2024/\">(Forster dkk., 2024)</a>. Angka ini terus direvisi dan menyimpan ketidakpastian besar, terutama soal pemanasan dari gas non-CO₂; karena itu ia lebih tepat dibaca sebagai peringatan arah, bukan hitung mundur yang pasti."}, {"t": "p", "x": "Yang membuat kerangka ini berguna bukan angkanya semata, melainkan apa yang ia paksa kita lakukan: memperlakukan karbon seperti neraca keuangan. Setiap ton punya bobot, dan setiap klaim pengurangan baru berarti bila bisa <b>terlacak</b> sampai ke sumbernya. Di situlah pekerjaan yang tampak membosankan — mengukur, memverifikasi, mencatat — menjadi penting. Tanpa data yang bisa dipertanggungjawabkan, 'anggaran' hanya jadi kata, bukan disiplin."}, {"t": "p", "x": "Bagi Indonesia, salah satu pemilik hutan tropis dan lahan gambut terluas di dunia, neraca ini berjalan dua arah — sumber emisi sekaligus penyerapnya. Mengubahnya menjadi kontribusi nyata, bukan sekadar klaim di atas kertas, dimulai dari satu hal yang sama: menghitung dengan jujur."}], "story": [{"kind": "cover", "title": "Berapa banyak karbon lagi yang tersisa?", "text": "IPCC menghitung sisa 'jatah' karbon untuk peluang 1,5°C tinggal beberapa ratus gigaton — target iklim abstrak yang berubah jadi neraca konkret."}, {"kind": "hook", "title": "Rekening bersama", "text": "Bayangkan atmosfer sebagai satu rekening. Saldonya tinggal beberapa ratus gigaton — dan dunia masih menarik sekitar 40 setiap tahun."}, {"kind": "point", "title": "Apa itu anggaran karbon", "text": "Batas total CO₂ yang boleh dilepas dunia sebelum peluang menahan pemanasan di 1,5°C tertutup."}, {"kind": "point", "title": "Sisanya kecil", "text": "IPCC AR6: ~500 Gt untuk peluang 50%, ~400 Gt untuk 67% — dihitung dari awal 2020."}, {"kind": "stat", "title": "Saldo yang tersisa", "big": "500 Gt", "label": "Sisa anggaran 1,5°C (peluang 50%, dari 2020)", "source": "IPCC AR6 WG1, 2021"}, {"kind": "quote", "title": "Peringatan yang lebih tajam", "text": "Pembaruan 2024 menaksir sisa tinggal ~200 Gt⚠︎ — kira-kira lima tahun emisi dengan laju sekarang."}, {"kind": "end", "title": "Karbon butuh neraca, bukan slogan", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan ikut membangun ekonomi hijau yang terlacak sampai ke sumbernya."}], "sources": [{"a": "IPCC (2021). Climate Change 2021: The Physical Science Basis (AR6 WG1), Summary for Policymakers, Table SPM.2 (sisa anggaran karbon).", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "Friedlingstein, P. dkk. / Global Carbon Project (2024). Global Carbon Budget 2024 (emisi CO₂ global ~40 Gt/tahun).", "u": "https://globalcarbonproject.org/carbonbudget/"}, {"a": "Forster, P. M. dkk. (2024). Indicators of Global Climate Change 2023. Earth System Science Data (sisa anggaran 1,5°C ~200 Gt per awal 2024).", "u": "https://essd.copernicus.org/articles/16/2625/2024/"}]}, {"slug": "harga-karbon-eu-ets", "topic": "Global", "mood": "#B0894F", "title": "EU ETS: bagaimana Eropa menetapkan harga sebuah ton CO2.", "dek": "Harga karbon di pasar EU ETS berayun puluhan euro per ton — dan sejak 2026, ayunan itu menempel langsung pada tarif CBAM untuk besi, baja, dan semen yang kita ekspor ke Eropa.", "hook": "Berapa harga satu ton CO2? Di Eropa, jawabannya berubah tiap minggu — dan itu ikut menentukan tarif ekspor Indonesia.", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (Komisi Eropa)", "read": 4, "blocks": [{"t": "lead", "x": "Di Eropa, satu ton karbon dioksida punya harga — dan harga itu tidak pernah diam. Ia bisa berayun puluhan euro dalam hitungan bulan, digerakkan oleh aturan, cuaca, dan denyut permintaan industri. Angka yang terdengar abstrak itu kini menjadi acuan yang menyentuh eksportir Indonesia secara sangat langsung."}, {"t": "p", "x": "Mesin di balik harga itu adalah <b>EU ETS</b> (Emissions Trading System), pasar karbon pertama sekaligus terbesar di dunia, yang beroperasi sejak 2005. Prinsipnya cap-and-trade: Uni Eropa menetapkan plafon total emisi, membaginya menjadi izin (allowance) yang masing-masing setara satu ton CO2, lalu membiarkan pasar memperdagangkannya. Sistem ini mencakup sekitar <b>40% emisi gas rumah kaca UE</b> — dari pembangkit listrik, industri berat, sampai penerbangan di dalam kawasan. <a href=\"https://climate.ec.europa.eu/eu-action/eu-emissions-trading-system-eu-ets_en\">Komisi Eropa</a>"}, {"t": "h2", "x": "Kenapa harganya bergerak"}, {"t": "p", "x": "Plafon itu sengaja dibuat menyusut setiap tahun, sehingga izin kian langka seiring waktu — dan kelangkaan menaikkan harga. Ketika pasar sempat kebanjiran izin murah pada dekade lalu, UE membentuk <b>Market Stability Reserve</b> pada 2019 untuk menyerap kelebihan pasokan. Hasilnya terasa: dari kisaran satu digit euro selama bertahun-tahun, harga izin sempat menyentuh rekor sekitar €100 per ton pada Februari 2023. Faktor jangka pendek — harga gas, musim dingin, tingkat produksi pabrik — membuatnya terus berayun naik-turun."}, {"t": "stat", "n": "≈€100", "l": "Rekor harga izin EU ETS per ton CO2, Feb 2023", "s": "Data pasar EUA (ICE) via Reuters, 2023"}, {"t": "p", "x": "Volatilitas inilah intinya. Bagi UE, harga karbon adalah alat kebijakan, bukan sekadar pajak: harga yang naik memberi sinyal ke seluruh industri bahwa memangkas emisi kini lebih murah daripada terus membeli izin untuk mengeluarkannya. Makin mahal karbon, makin cepat pabrik beralih ke proses rendah-emisi."}, {"t": "pull", "x": "Harga karbon Eropa bukan sekadar angka di layar bursa — lewat CBAM, ia ikut menentukan tarif yang ditagihkan pada barang ekspor kita."}, {"t": "h2", "x": "Acuan diam-diam bagi eksportir kita"}, {"t": "p", "x": "Inilah kaitannya dengan Indonesia. <b>CBAM</b> — pungutan karbon di perbatasan UE yang masuk fase bayar sejak 1 Januari 2026 — tidak menetapkan harganya sendiri. Harga sertifikat CBAM justru <b>mengikuti rata-rata harga lelang mingguan izin EU ETS</b>. Dengan kata lain, setiap ayunan harga karbon di Eropa langsung menjadi besaran tarif yang menempel pada besi, baja, aluminium, semen, dan pupuk asal Indonesia. <a href=\"https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en\">Komisi Eropa</a>"}, {"t": "p", "x": "Konsekuensinya praktis: makin tinggi harga EU ETS, makin mahal tarif CBAM bagi produk berjejak karbon tinggi. Eksportir memang tak bisa mengendalikan harga karbon Eropa, tapi bisa mengendalikan satu hal — seberapa <b>terlacak</b> emisi produknya. Jejak karbon per produk yang bisa diaudit menurunkan nilai default yang biasanya dipatok mahal, sekaligus menjaga akses ke pasar premium. Berapa persis harga EU ETS sepanjang 2026 masih ⚠︎ bergerak, tapi arah kebijakannya jelas: mengetat, seiring plafon yang terus dipangkas."}], "story": [{"kind": "cover", "title": "EU ETS: harga sebuah ton CO2", "text": "Harga karbon di pasar EU ETS berayun puluhan euro per ton — dan sejak 2026, ayunan itu menempel langsung pada tarif CBAM untuk besi, baja, dan semen yang kita ekspor ke Eropa."}, {"kind": "hook", "title": "Berapa harga satu ton CO2? Di Eropa, jawabannya berubah tiap minggu — dan itu ikut menentukan tarif ekspor Indonesia."}, {"kind": "point", "title": "Pasar karbon pertama di dunia", "text": "EU ETS (sejak 2005) menetapkan plafon emisi, lalu memperdagangkan izin — satu izin = satu ton CO2. Mencakup ~40% emisi UE."}, {"kind": "point", "title": "Kenapa harganya berayun", "text": "Plafon menyusut tiap tahun; izin makin langka. Harga sempat melompat dari satu digit euro ke rekor ~€100/ton pada 2023."}, {"kind": "stat", "title": "Rekor ≈€100 per ton", "big": "≈€100", "label": "Rekor harga izin EU ETS per ton CO2 (Feb 2023)", "source": "Data pasar EUA (ICE) via Reuters, 2023"}, {"kind": "point", "title": "Acuan tarif CBAM kita", "text": "Harga sertifikat CBAM mengikuti harga lelang mingguan EU ETS. Ayunan karbon Eropa = tarif untuk besi, baja, semen ekspor kita."}, {"kind": "end", "title": "Karbon yang terlacak, bukan sekadar diklaim", "text": "Baca selengkapnya di Glyiv Kabar — dan siapkan jejak karbon produkmu sebelum tarif menagih."}], "sources": [{"a": "European Commission. EU Emissions Trading System (EU ETS).", "u": "https://climate.ec.europa.eu/eu-action/eu-emissions-trading-system-eu-ets_en"}, {"a": "European Commission. Carbon Border Adjustment Mechanism (CBAM).", "u": "https://taxation-customs.ec.europa.eu/carbon-border-adjustment-mechanism_en"}, {"a": "Reuters (2023). EU carbon price hits record 100 euros per tonne.", "u": "https://www.reuters.com/markets/carbon/eu-carbon-price-hits-record-100-euros-tonne-2023-02-21/"}]}, {"slug": "amazon-fund-model-brasil", "topic": "Global", "mood": "#4F7A3A", "title": "Dana Amazon: model Brasil membayar untuk hutan yang tegak.", "dek": "Selama lebih dari 15 tahun, Amazon Fund membayar Brasil hanya setelah satelit membuktikan hutannya tidak ditebang — sebuah model pembiayaan berbasis hasil yang kini relevan bagi ambisi FOLU Net Sink 2030 Indonesia.", "hook": "Bagaimana kalau uang untuk menjaga hutan baru cair setelah pohonnya terbukti masih berdiri? Brasil sudah melakukannya sejak 2008.", "cover": "https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (BNDES, INPE, KLHK)", "read": 5, "blocks": [{"t": "lead", "x": "Selama bertahun-tahun dunia berdebat soal siapa yang harus membayar agar hutan tropis tetap berdiri. Brasil sudah menjalankan satu jawaban selama lebih dari 15 tahun — dan aturannya membalik logika biasa: uang baru mengalir setelah hutan terbukti tidak ditebang. Namanya Amazon Fund."}, {"t": "p", "x": "Amazon Fund (Fundo Amazônia) dibentuk pada 2008 dan dikelola <b>BNDES</b>, bank pembangunan Brasil. Yang membuatnya berbeda: donasi diikat pada penurunan emisi dari deforestasi yang <b>sudah terjadi dan terverifikasi</b>. Dana tidak dibayar di muka untuk proyek yang menjanjikan hasil — ia dibayar belakangan, setelah satelit memastikan laju penebangan benar-benar turun. Uangnya lalu mengalir ke proyek pencegahan deforestasi, pemantauan hutan, dan penghidupan masyarakat di sekitar hutan. <a href=\"https://www.fundoamazonia.gov.br/en/home/\">Fundo Amazônia</a>"}, {"t": "p", "x": "Sebagian besar dananya datang dari luar. <b>Norwegia</b> menyumbang sekitar 93% dari total — memenuhi komitmennya senilai kurang lebih USD 1 miliar — disusul <b>Jerman</b> lewat bank pembangunan KfW dengan sekitar 6%, ditambah kontribusi domestik Petrobras. Total sumber daya Fund kini menembus <b>R$ 3,1 miliar</b>. Bagi negara donor, membayar Brasil menekan deforestasi adalah cara mendanai pengurangan emisi global dengan biaya per ton yang relatif murah."}, {"t": "pull", "x": "Dana ini tidak membeli janji menanam pohon. Ia membayar hutan yang terbukti masih berdiri."}, {"t": "h2", "x": "Membayar hasil, bukan janji"}, {"t": "p", "x": "Verifikasinya bertumpu pada <b>PRODES</b>, sistem pemantauan satelit lembaga antariksa Brasil (INPE) yang melacak deforestasi tiap tahun. Rekam jejaknya nyata: dari puncak sekitar 27.000 km² per tahun pada 2004, laju penebangan turun hampir 80% menjelang 2012. Tapi modelnya juga rapuh. Ketika deforestasi kembali melonjak dan tata kelola bermasalah pada 2019, Norwegia dan Jerman membekukan kontribusi — Fund baru diaktifkan lagi pada Januari 2023. Pembiayaan bisa memberi imbalan, tapi tak bisa menggantikan kemauan politik."}, {"t": "bars", "h": [1, 0.46, 0.17, 0.28, 0.39, 0.42, 0.23], "cap": "Laju deforestasi Amazon Brasil, skala relatif terhadap puncak 2004: turun tajam, sempat naik, lalu turun lagi. Sumber: PRODES/INPE (ilustrasi tren)."}, {"t": "h2", "x": "Cermin bagi FOLU Net Sink Indonesia"}, {"t": "p", "x": "Indonesia menaruh taruhan pada sektor yang sama. Lewat <b>FOLU Net Sink 2030</b>, kehutanan dan penggunaan lahan ditargetkan berubah dari sumber emisi menjadi penyerap neto — menuju tingkat <b>−140 juta ton CO₂e</b> pada 2030 (KLHK, berdasarkan Perpres 98/2021). Target sebesar itu butuh pembiayaan berskala besar, dan Indonesia sudah menyentuh jalur berbasis hasil ini lewat kemitraan dengan Norwegia dan Green Climate Fund ⚠︎ (nilai dan status pencairan bervariasi antar sumber). <a href=\"https://www.kehutanan.go.id/program/INDONESIA-FOLU-NET-SINK-2030\">KLHK</a>"}, {"t": "p", "x": "Pelajaran dari Brasil bukan bahwa uang menyelamatkan hutan, melainkan bahwa <b>bukti</b> yang membuat uang bisa mengalir. Hutan yang tetap berdiri adalah karbon termurah yang kita punya — tapi hanya bila serapannya <b>terlacak</b>, terverifikasi, dan bisa diaudit hingga ke petak lahannya. Di situlah pembiayaan berhenti menjadi sekadar kepercayaan dan mulai menjadi kontribusi yang bisa dipertanggungjawabkan."}], "story": [{"kind": "cover", "title": "Dana Amazon: model Brasil membayar untuk hutan yang tegak.", "text": "Selama lebih dari 15 tahun, Amazon Fund membayar Brasil hanya setelah satelit membuktikan hutannya tidak ditebang — model pembiayaan berbasis hasil yang relevan bagi FOLU Net Sink 2030 Indonesia.", "label": "Glyiv Kabar · Global"}, {"kind": "hook", "title": "Uang setelah bukti", "text": "Bagaimana kalau dana untuk menjaga hutan baru cair setelah pohonnya terbukti masih berdiri? Brasil sudah melakukannya sejak 2008."}, {"kind": "point", "title": "Bayar hasil, bukan janji", "text": "Amazon Fund (dikelola BNDES) mencairkan dana hanya setelah satelit PRODES/INPE membuktikan deforestasi turun. Pendananya: Norwegia ~93%, Jerman ~6%."}, {"kind": "quote", "title": "Inti idenya", "text": "Dana ini tidak membeli janji menanam pohon. Ia membayar hutan yang terbukti masih berdiri."}, {"kind": "stat", "title": "Angkanya", "big": "−30,6%", "label": "Deforestasi Amazon Brasil turun (Agu 2023–Jul 2024), terendah dalam 9 tahun", "source": "INPE/PRODES, 2024"}, {"kind": "point", "title": "Cermin bagi Indonesia", "text": "FOLU Net Sink 2030 menargetkan sektor hutan & lahan jadi penyerap neto −140 juta ton CO₂e. Model berbasis hasil seperti ini butuh data yang terlacak dan bisa diaudit."}, {"kind": "end", "title": "Baca selengkapnya", "text": "Hutan yang tegak adalah karbon termurah kita — bila terbukti. Selami kisah lengkapnya bersama Glyiv Kabar."}], "sources": [{"a": "BNDES / Fundo Amazônia (2024). Amazon Fund — sumber daya, donasi, dan hasil (Norwegia, Jerman/KfW, Petrobras).", "u": "https://www.fundoamazonia.gov.br/en/home/"}, {"a": "INPE (2024). PRODES — Monitoramento do Desmatamento da Amazônia Legal por Satélite (data 2023/2024: 6.288 km², turun 30,6%).", "u": "http://terrabrasilis.dpi.inpe.br/app/dashboard/deforestation/biomes/legal_amazon/rates"}, {"a": "Kementerian Lingkungan Hidup dan Kehutanan (2022). Rencana Operasional Indonesia's FOLU Net Sink 2030 (Kepmen LHK No. 168/2022; Perpres 98/2021).", "u": "https://www.kehutanan.go.id/program/INDONESIA-FOLU-NET-SINK-2030"}]}, {"slug": "costa-rica-bayar-jasa-lingkungan", "topic": "Global", "mood": "#1cae6b", "title": "Kosta Rika: negara yang membalikkan deforestasinya.", "dek": "Pada 1987 hutannya tinggal sekitar seperlima daratan; kini menutup lebih dari separuh wilayah. Lewat skema membayar warga untuk menjaga hutan, Kosta Rika menunjukkan arah deforestasi bisa dibalik — meski ceritanya lebih rumit dari satu kebijakan.", "hook": "Sebuah negara pernah nyaris menghabiskan hutannya — lalu menumbuhkannya kembali dengan cara membayar warganya untuk tidak menebang.", "cover": "https://images.unsplash.com/photo-1425913397330-cf8af2ff40a1?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (World Bank, FONAFIFO, FAO)", "read": 4, "blocks": [{"t": "lead", "x": "Pada akhir 1980-an, Kosta Rika hampir kehilangan hutannya. Negeri yang pada 1940 masih tiga-perempat berhutan menyaksikan tutupan hutannya anjlok ke sekitar seperlima daratan — salah satu laju deforestasi tercepat di dunia saat itu. Yang terjadi berikutnya jarang tercatat dalam sejarah lingkungan: negara itu membalik arahnya, dan hari ini hutannya kembali menutup lebih dari separuh wilayah."}, {"t": "p", "x": "Hutan tidak menghilang tanpa sebab. Sepanjang 1960-an hingga 1980-an, lahan dibuka besar-besaran untuk peternakan sapi yang dagingnya diekspor, didorong kredit murah dan permintaan global. Menebang hutan, saat itu, adalah keputusan ekonomi yang masuk akal bagi pemilik lahan. ⚠︎ Angka titik terendah bervariasi antar-sumber — banyak kutipan menyebut sekitar 21% pada 1987 — tetapi arah trennya tidak diperdebatkan: hutan Kosta Rika sedang menuju habis."}, {"t": "h2", "x": "Membayar orang untuk menjaga hutan"}, {"t": "p", "x": "Titik baliknya adalah kebijakan. Lewat Undang-Undang Kehutanan No. 7575 tahun 1996, Kosta Rika melarang alih fungsi hutan alam sekaligus meluncurkan skema <b>Pembayaran Jasa Lingkungan</b> (PSA). Gagasannya membalik logika lama: bila hutan yang berdiri memberi jasa — menyimpan karbon, menjaga air, memelihara keanekaragaman hayati, dan keindahan bentang alam — maka pemilik lahan layak menerima <b>imbalan</b> untuk merawatnya, bukan menebangnya. Lembaga bernama <a href=\"https://www.fonafifo.go.cr/\">FONAFIFO</a> menyalurkan pembayaran itu, didanai terutama dari sebagian penerimaan pajak bahan bakar (⚠︎ sekitar 3,5%) serta dukungan Bank Dunia dan GEF."}, {"t": "pull", "x": "Kosta Rika tidak sekadar melarang penebangan lalu berharap. Ia memberi nilai ekonomi pada hutan yang dibiarkan berdiri — dan benar-benar membayarnya."}, {"t": "bars", "h": [0.75, 0.5, 0.21, 0.42, 0.52, 0.6], "cap": "Perkiraan tutupan hutan Kosta Rika lintas dekade: ~75% (1940) → titik terendah ±21% (1987) → pulih di atas 50%. ⚠︎ Angka bervariasi antar-sumber. Sumber: FAO FRA 2020 / SINAC."}, {"t": "p", "x": "Namun kejujuran menuntut satu catatan penting: PSA bukan satu-satunya penyebab. Laju deforestasi sudah melambat sebelum skema ini berjalan penuh — runtuhnya harga daging sapi, larangan alih fungsi hutan, dan tumbuhnya ekowisata semuanya ikut berperan. Beberapa studi bahkan menemukan sebagian lahan yang didaftarkan ke PSA sesungguhnya tidak sedang terancam ditebang, sehingga kontribusi bersih skema ini terhadap hutan yang benar-benar terselamatkan lebih kecil dari yang terlihat <a href=\"https://www.iied.org/g03726\">(Porras dkk., IIED, 2013)</a>. Yang terlacak jelas adalah tren nasionalnya; seberapa besar tepatnya andil satu kebijakan tetap sulit dipisahkan."}, {"t": "p", "x": "Justru di situ letak pelajarannya bagi Indonesia. Membalik deforestasi bukan soal satu tombol ajaib, melainkan bauran: aturan yang tegas, pembiayaan lestari lewat sumber penerimaan khusus, pemantauan yang bisa diaudit, dan insentif yang berpihak pada pemilik lahan. Kosta Rika membuktikan arah bisa dibalik — dan itu, bagi negara mana pun yang hutannya masih menyusut, adalah kabar yang layak dipelajari."}], "story": [{"kind": "cover", "title": "Negara yang membalikkan deforestasinya", "text": "Pada 1987 hutannya tinggal sekitar seperlima daratan; kini menutup lebih dari separuh wilayah. Lewat skema membayar warga untuk menjaga hutan, Kosta Rika menunjukkan arah deforestasi bisa dibalik — meski ceritanya lebih rumit dari satu kebijakan."}, {"kind": "hook", "title": "Sebuah negara pernah nyaris menghabiskan hutannya — lalu menumbuhkannya kembali dengan cara membayar warganya untuk tidak menebang."}, {"kind": "point", "title": "Dari 75% ke ±21%", "text": "Peternakan sapi ekspor & kredit murah membuka lahan besar-besaran. Pada 1987 ⚠︎ tutupan hutan anjlok ke sekitar seperlima daratan."}, {"kind": "point", "title": "Membayar jasa lingkungan", "text": "UU Kehutanan 1996 melarang alih fungsi hutan & meluncurkan PSA: pemilik lahan menerima imbalan untuk menjaga hutan — karbon, air, hayati, bentang alam."}, {"kind": "stat", "title": "Kira-kira berlipat", "big": "±21% → >50%", "label": "Tutupan hutan Kosta Rika, 1987 ke 2020-an", "source": "FAO FRA 2020 / SINAC ⚠︎"}, {"kind": "quote", "title": "Bukan larangan, tapi nilai", "text": "Kosta Rika tidak sekadar melarang penebangan lalu berharap. Ia memberi nilai ekonomi pada hutan yang berdiri — dan membayarnya."}, {"kind": "end", "title": "Arah bisa dibalik", "text": "Bukan satu tombol ajaib, tapi bauran kebijakan, pembiayaan, dan pemantauan. Baca selengkapnya di Glyiv Kabar."}], "sources": [{"a": "World Bank. Costa Rica: Payment for Environmental Services (PES) program — case study.", "u": "https://www.worldbank.org/en/news/feature/2021/05/27/how-costa-rica-reversed-deforestation-and-raised-tourism"}, {"a": "Porras, I., Barton, D.N., Miranda, M. & Chacón-Cascante, A. (2013). Learning from 20 years of Payments for Ecosystem Services in Costa Rica. IIED, London.", "u": "https://www.iied.org/g03726"}, {"a": "Daniels, A.E. et al. (2010). Understanding the impacts of Costa Rica's PES: Are we asking the right questions? Ecological Economics 69(11), 2116–2126.", "u": "https://doi.org/10.1016/j.ecolecon.2010.06.011"}, {"a": "FAO (2020). Global Forest Resources Assessment 2020 — Country report: Costa Rica.", "u": "https://www.fao.org/forest-resources-assessment/2020"}]}, {"slug": "global-methane-pledge", "topic": "Global", "mood": "#1F7A6B", "title": "Janji Metana Global: gas yang paling cepat memberi hasil.", "dek": "Global Methane Pledge menargetkan pemangkasan metana 30% pada 2030⚠︎ — dan karena gas ini hanya bertahan sekitar 12 tahun di atmosfer, memangkasnya adalah cara tercepat memperlambat pemanasan dalam hidup kita.", "hook": "Ada satu gas rumah kaca yang, kalau dipangkas hari ini, hasilnya terasa dalam satu dekade — bukan satu abad.", "cover": "https://images.unsplash.com/photo-1532601224476-15c79f2f7a51?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan IPCC, UNEP & IEA", "read": 3, "blocks": [{"t": "lead", "x": "Kalau iklim punya rem darurat, metana adalah pedalnya. Karbon dioksida menentukan seberapa panas dunia dalam jangka panjang — tapi metana menentukan seberapa cepat kita bisa memperlambat pemanasan, karena ia menghilang dari atmosfer dalam hitungan belasan tahun, bukan berabad-abad."}, {"t": "p", "x": "Metana (CH₄) adalah gas rumah kaca kedua terpenting setelah CO₂, dan jauh lebih 'panas': dalam rentang 20 tahun, satu ton metana <a href=\"https://www.ipcc.ch/report/ar6/wg1/\">memerangkap lebih dari 80 kali panas</a> dibanding satu ton CO₂. Bedanya, umur metana di atmosfer hanya sekitar 12 tahun, sementara sebagian CO₂ bertahan ratusan hingga ribuan tahun. Maka begitu emisinya dipangkas, konsentrasinya ikut turun relatif cepat — dan efek pendinginannya terasa dalam hitungan dekade."}, {"t": "p", "x": "Di sinilah <b>Global Methane Pledge</b> masuk. Diluncurkan di KTT iklim COP26 Glasgow pada 2021 dan dipimpin Amerika Serikat serta Uni Eropa, pakta ini mengajak negara-negara memangkas emisi metana global setidaknya <b>30% dari level 2020 pada 2030⚠︎</b>. <a href=\"https://www.globalmethanepledge.org/\">Lebih dari 150 negara telah bergabung</a> — meski sejumlah emiter besar masih berada di luarnya⚠︎. Angka 30% itu bersifat kolektif, bukan target per negara, dan justru karena metana bekerja cepat, para perancangnya melihatnya sebagai 'kemenangan awal' yang paling masuk akal dikejar dalam dekade ini."}, {"t": "pull", "x": "Metana adalah satu-satunya tuas iklim yang hasilnya terasa dalam satu dekade, bukan satu abad."}, {"t": "stat", "n": "±0,3°C", "l": "pemanasan yang bisa dihindari pada dekade 2040-an⚠︎ bila metana dari aktivitas manusia dipangkas ~45%", "s": "UNEP/CCAC, Global Methane Assessment, 2021"}, {"t": "h2", "x": "Kenapa metana memberi hasil tercepat"}, {"t": "p", "x": "Menurut analisis IPCC dan UNEP, metana telah menyumbang <a href=\"https://www.unep.org/resources/report/global-methane-assessment-benefits-and-costs-mitigating-methane-emissions\">sekitar 0,5°C</a> dari pemanasan yang sudah terjadi sejak era praindustri — hampir separuh dari totalnya. Karena umurnya pendek, memangkas metana tidak seperti melawan CO₂ yang sudah 'terkunci' berabad-abad di atmosfer; ia lebih seperti menutup keran yang isinya cepat mengering. Itulah alasan banyak ilmuwan menyebutnya peluang pendinginan tercepat yang kita punya hari ini."}, {"t": "p", "x": "Kabar baiknya, sebagian besar solusinya sudah ada dan murah. IEA memperkirakan emisi metana dari sektor energi bisa dipangkas <a href=\"https://www.iea.org/reports/global-methane-tracker-2024\">sekitar 70%</a> dengan teknologi yang tersedia sekarang — menambal kebocoran pipa, sumur, dan fasilitas gas — dan sebagian besar bisa dilakukan tanpa biaya bersih, karena gas yang tadinya bocor justru bisa dijual. Dengan kata lain, banyak pemangkasan metana bukan beban biaya, melainkan efisiensi yang selama ini terbuang."}, {"t": "h2", "x": "Artinya bagi Indonesia"}, {"t": "p", "x": "Di Indonesia, tiga sumber metana paling nyata adalah sawah, sektor minyak dan gas, serta timbunan sampah — dan ketiganya sudah tersentuh komitmen iklim nasional⚠︎. Kabar baiknya, ketiganya bisa dilacak. Di titik itulah kerja Glyiv dimulai: bukan menjanjikan 'netral karbon', tapi membantu memetakan dan melacak jejak metana per fasilitas hingga bisa diaudit — supaya keran yang bocor benar-benar ditutup, bukan sekadar dihitung."}], "story": [{"kind": "cover", "title": "Janji Metana Global", "text": "Global Methane Pledge menargetkan pemangkasan metana 30% pada 2030⚠︎ — dan karena gas ini hanya bertahan sekitar 12 tahun di atmosfer, memangkasnya adalah cara tercepat memperlambat pemanasan dalam hidup kita."}, {"kind": "hook", "title": "Rem darurat iklim", "text": "Ada satu gas rumah kaca yang, kalau dipangkas hari ini, hasilnya terasa dalam satu dekade — bukan satu abad."}, {"kind": "point", "title": "Umurnya pendek", "text": "Metana hanya bertahan ~12 tahun di atmosfer; CO₂ berabad-abad. Pangkas metana, konsentrasinya turun cepat — dan pemanasan ikut melambat."}, {"kind": "point", "title": "Targetnya 30%", "text": "Global Methane Pledge: turunkan metana global 30% dari level 2020 pada 2030⚠︎. Lebih dari 150 negara sudah bergabung."}, {"kind": "stat", "title": "Hampir separuh pemanasan", "big": "0,5°C", "label": "pemanasan yang sudah disumbang metana sejak era praindustri", "source": "IPCC AR6 & UNEP, 2021"}, {"kind": "quote", "title": "Tuas tercepat", "text": "Metana adalah satu-satunya tuas iklim yang hasilnya terasa dalam satu dekade, bukan satu abad."}, {"kind": "end", "title": "Baca lengkap di Glyiv Kabar", "text": "Kami tak menjual 'netral karbon' — kami bantu melacak jejak karbonmu sampai bisa diaudit. Gabung Glyiv."}], "sources": [{"a": "UNEP & Climate and Clean Air Coalition (2021). Global Methane Assessment: Benefits and Costs of Mitigating Methane Emissions.", "u": "https://www.unep.org/resources/report/global-methane-assessment-benefits-and-costs-mitigating-methane-emissions"}, {"a": "IEA (2024). Global Methane Tracker 2024.", "u": "https://www.iea.org/reports/global-methane-tracker-2024"}, {"a": "IPCC (2021). AR6 Working Group I, Bab 7 (metrik GWP) & Ringkasan untuk Pembuat Kebijakan.", "u": "https://www.ipcc.ch/report/ar6/wg1/"}, {"a": "Global Methane Pledge (2021). Situs resmi pakta (COP26).", "u": "https://www.globalmethanepledge.org/"}]}, {"slug": "loss-and-damage-fund", "topic": "Global", "mood": "#6B4E8C", "title": "Dana Kerugian & Kerusakan: siapa membayar bencana iklim?", "dek": "Loss and Damage Fund yang disepakati di COP membantu negara paling rentan menanggung dampak iklim yang tak lagi bisa dicegah — keadilan yang lama tertunda, dan baru mulai dibayar.", "hook": "Pulau tenggelam, panen gagal, kota pesisir diterjang rob berulang — siapa yang menanggung tagihannya?", "cover": "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan dokumen UNFCCC & IPCC", "read": 4, "blocks": [{"t": "lead", "x": "Ada jenis kerugian iklim yang tak bisa lagi dicegah maupun diadaptasi: pulau yang perlahan tenggelam, panen yang gagal karena kekeringan berkepanjangan, kota pesisir yang berulang kali diterjang banjir rob. Pertanyaannya bukan lagi bagaimana menghindarinya, melainkan siapa yang menanggung biayanya — dan selama puluhan tahun, jawabannya nyaris selalu: negara yang paling sedikit menyebabkannya."}, {"t": "p", "x": "Inilah yang disebut <b>kerugian dan kerusakan</b> (loss and damage) — dampak yang sudah melewati batas mitigasi (menekan emisi) dan adaptasi (menyesuaikan diri). Setelah tiga dekade didesak negara-negara rentan, dunia akhirnya sepakat: pada COP27 di Mesir (2022) lahir keputusan untuk membentuk dana khusus yang menanggung kerugian semacam itu <a href=\"https://unfccc.int/loss-and-damage\">UNFCCC</a>."}, {"t": "p", "x": "Setahun kemudian, di hari pembukaan COP28 Dubai (2023), dana itu resmi dioperasikan — kini bernama <b>Fund for responding to Loss and Damage</b>, dengan Bank Dunia sebagai tuan rumah sementara untuk empat tahun pertama. Janji awal terkumpul lebih dari US$700 juta ⚠︎ — angka yang, betapapun bersejarah, terasa seperti setetes dibanding kebutuhan."}, {"t": "pull", "x": "Negara yang paling sedikit menyebabkan krisis iklim justru paling berat menanggungnya. Dana ini soal keadilan, bukan amal."}, {"t": "stat", "n": "3,3–3,6 miliar", "l": "orang hidup di wilayah yang sangat rentan terhadap perubahan iklim", "s": "IPCC AR6 WGII, 2022"}, {"t": "h2", "x": "Jurang antara janji dan kebutuhan"}, {"t": "p", "x": "Seberapa besar tetesan itu? Satu kajian yang kerap dirujuk memperkirakan kerugian dan kerusakan di negara berkembang bisa mencapai US$290–580 miliar per tahun pada 2030 ⚠︎ (Markandya & González-Eguino, 2019). Bandingkan dengan janji ratusan juta dolar, dan skalanya terasa timpang. Dana ini nyata dan penting — tetapi menutup jurangnya menuntut komitmen yang jauh lebih besar, dan yang benar-benar cair, bukan sekadar diumumkan di panggung."}, {"t": "p", "x": "Ketimpangan itulah inti perdebatannya. Negara kepulauan kecil dan komunitas termiskin menyumbang porsi emisi historis yang sangat kecil, namun menanggung gelombang panas, badai, dan naiknya muka laut lebih dulu dan lebih keras. IPCC mencatat 3,3–3,6 miliar orang tinggal di konteks yang sangat rentan terhadap iklim <a href=\"https://www.ipcc.ch/report/ar6/wg2/\">IPCC</a>. Bagi mereka, 'kerugian dan kerusakan' bukan istilah teknis — melainkan rumah, ladang, dan mata pencaharian."}, {"t": "h2", "x": "Apa artinya bagi Indonesia"}, {"t": "p", "x": "Sebagai negara kepulauan dengan garis pantai terpanjang kedua di dunia, Indonesia berdiri di kedua sisi meja: rentan terhadap dampak, sekaligus penyumbang emisi yang tidak kecil. Akses ke pendanaan seperti ini akan bergantung pada satu hal yang membosankan namun menentukan — <b>data yang bisa dipertanggungjawabkan</b>: kerugian yang terdokumentasi, emisi yang terlacak, klaim yang bisa diaudit. Di situlah pekerjaan Glyiv bermula. Keadilan iklim tak berhenti pada kesepakatan di ruang sidang; ia diuji pada apakah rupiahnya benar-benar sampai ke tangan yang membutuhkannya."}], "story": [{"kind": "cover", "title": "Siapa membayar bencana iklim?", "text": "Loss and Damage Fund yang disepakati di COP membantu negara paling rentan menanggung dampak iklim yang tak lagi bisa dicegah — keadilan yang lama tertunda."}, {"kind": "hook", "title": "Pulau tenggelam. Panen gagal. Rob berulang.", "text": "Pertanyaannya bukan lagi bagaimana menghindarinya, tapi siapa yang menanggung tagihannya."}, {"kind": "point", "title": "Di luar batas adaptasi", "text": "Ada kerugian iklim yang tak bisa lagi dicegah atau disesuaikan — hanya bisa ditanggung. Itulah 'kerugian dan kerusakan'."}, {"kind": "point", "title": "Lahir di COP27, cair di COP28", "text": "2022: dana disepakati. 2023: resmi beroperasi, dikelola sementara oleh Bank Dunia. Janji awal >US$700 juta ⚠︎."}, {"kind": "stat", "title": "Skala yang rentan", "big": "3,3–3,6 miliar", "label": "orang di wilayah sangat rentan iklim", "source": "IPCC AR6 WGII, 2022"}, {"kind": "quote", "title": "Soal keadilan", "text": "Yang paling sedikit menyebabkan krisis, paling berat menanggungnya. Ini soal keadilan — bukan amal."}, {"kind": "end", "title": "Keadilan yang diuji pada datanya", "text": "Baca ulasan lengkapnya, dan telusuri jejak karbon yang bisa dipertanggungjawabkan bersama Glyiv."}], "sources": [{"a": "UNFCCC (2023). Operationalisation of the new funding arrangements & the Fund for responding to Loss and Damage (Keputusan COP28/CMA.5).", "u": "https://unfccc.int/loss-and-damage"}, {"a": "IPCC (2022). AR6 Working Group II — Summary for Policymakers (3,3–3,6 miliar orang di konteks sangat rentan).", "u": "https://www.ipcc.ch/report/ar6/wg2/"}, {"a": "Markandya, A. & González-Eguino, M. (2019). Integrated Assessment for Identifying Climate Finance Needs for Loss and Damage. Dalam Mechler dkk. (ed.), Loss and Damage from Climate Change, Springer (akses terbuka).", "u": "https://link.springer.com/book/10.1007/978-3-319-72026-5"}]}, {"slug": "harga-karbon-dunia-beragam", "topic": "Global", "mood": "#C6A15B", "title": "Satu ton, banyak harga: peta harga karbon dunia.", "dek": "Bank Dunia mencatat puluhan skema harga karbon dengan rentang menganga — dari kurang dari satu dolar hingga sekitar US$150⚠︎ per ton — pertanda pasar yang sudah ada, tapi belum menyatu.", "hook": "Satu ton CO2 yang sama bisa berharga US$150 di satu negara dan hampir gratis di negara lain. Kok bisa?", "cover": "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan World Bank State and Trends of Carbon Pricing 2025", "read": 4, "blocks": [{"t": "lead", "x": "Bayangkan satu ton karbon dioksida yang sama — hasil pembakaran yang identik di mana pun di bumi. Di Uruguay, ton itu bisa berharga sekitar US$150. Di Polandia, kurang dari sepuluh sen dolar. Angka yang sama, planet yang sama, tapi harga yang berjauhan. Itulah potret pasar karbon dunia hari ini: sudah ada, tapi belum menyatu."}, {"t": "p", "x": "Laporan <b>State and Trends of Carbon Pricing 2025</b> Bank Dunia mencatat puluhan skema harga karbon yang aktif — kira-kira 43 pajak karbon dan 37 sistem perdagangan emisi (ETS)⚠︎ — yang kini menutup sekitar <b>28% emisi gas rumah kaca global</b>. Bersama-sama, skema itu mengumpulkan lebih dari US$100 miliar penerimaan negara pada 2024 <a href=\"https://www.worldbank.org/en/publication/state-and-trends-of-carbon-pricing\">(World Bank, 2025)</a>."}, {"t": "p", "x": "Yang mencolok bukan jumlahnya, tapi rentangnya. Harga per ton membentang dari kurang dari US$1 hingga sekitar US$150⚠︎ — jurang yang mencerminkan beda ambisi, sektor yang dicakup, dan kondisi ekonomi tiap negara. Rata-ratanya pun masih rendah: sekitar <b>US$19 per ton</b> pada 2025, naik dari kira-kira US$10 satu dekade lalu."}, {"t": "bars", "h": [0.01, 0.04, 0.09, 0.2, 0.4, 0.55, 1], "cap": "Ilustrasi rentang harga per ton CO2e — dari mendekati nol hingga yang tertinggi (Uruguay ~US$150). Sumber: World Bank, State and Trends of Carbon Pricing 2025."}, {"t": "pull", "x": "Selama satu ton bisa berharga seratus lima puluh dolar di satu tempat dan hampir gratis di tempat lain, karbon belum benar-benar punya satu harga."}, {"t": "h2", "x": "Kenapa harganya bisa sejauh itu"}, {"t": "p", "x": "Sebagian karena mekanismenya berbeda. Sebuah ETS membiarkan pasar menemukan harga dari kuota yang tersedia; pajak karbon menetapkannya dari atas. Cakupannya juga tak seragam — banyak skema hanya menyentuh sektor listrik atau industri berat, dan sebagian besar memberi pengecualian luas. Akibatnya, menurut Bank Dunia, <b>kurang dari 1%⚠︎</b> emisi dunia dihargai pada tingkat yang sejalan dengan target Paris — kisaran yang direkomendasikan <a href=\"https://www.carbonpricingleadership.org/report-of-the-highlevel-commission-on-carbon-prices\">High-Level Commission on Carbon Prices</a> sebesar US$50–100 per ton pada 2030."}, {"t": "h2", "x": "Di mana posisi Indonesia"}, {"t": "p", "x": "Indonesia sudah memasang fondasinya. <b>Bursa Karbon (IDXCarbon)</b> resmi diluncurkan pada September 2023 di bawah OJK, dan UU HPP 2021 memuat pajak karbon sebesar Rp30.000 per ton (sekitar US$2)⚠︎. Namun pemberlakuan pajak itu berkali-kali ditunda dan hingga awal 2026 belum berjalan penuh⚠︎. Sisi baiknya: harga yang belum tinggi memberi ruang bersiap sebelum tekanan datang — termasuk dari CBAM Uni Eropa yang menagih selisih karbon di perbatasan."}, {"t": "p", "x": "Untuk sebuah bisnis, pelajaran dari peta yang berwarna-warni ini sederhana. Harga karbon adalah sinyal, bukan sekadar tarif — dan sinyal itu hanya berguna bila jejak karbon Anda <b>terlacak</b> dengan metodologi yang bisa diaudit. Yang mengukur lebih dulu tidak menunggu harga; ia sudah siap ketika harga akhirnya tiba."}], "story": [{"kind": "cover", "title": "Satu ton, banyak harga", "text": "Bank Dunia mencatat puluhan skema harga karbon dengan rentang menganga — dari kurang dari satu dolar hingga sekitar US$150⚠︎ per ton — pertanda pasar yang sudah ada, tapi belum menyatu."}, {"kind": "hook", "title": "Satu ton CO2 yang sama bisa berharga US$150 di satu negara dan hampir gratis di negara lain.", "text": "Kok bisa?"}, {"kind": "point", "title": "Rentang yang menganga", "text": "~43 pajak karbon + 37 ETS menutup 28% emisi global. Harga per ton: dari <US$1 sampai ~US$150⚠︎. Rata-rata cuma ~US$19."}, {"kind": "stat", "title": "Nyaris tak ada yang Paris-aligned", "big": "<1%⚠︎", "label": "emisi dunia dihargai sesuai target Paris (US$50–100/ton pada 2030)", "source": "World Bank, 2025"}, {"kind": "point", "title": "Indonesia bersiap", "text": "Bursa Karbon (IDXCarbon) resmi 2023. Pajak karbon Rp30.000/ton masih tertunda⚠︎ — ada ruang bersiap sebelum CBAM menekan."}, {"kind": "quote", "title": "Intinya", "text": "Selama satu ton bisa berharga seratus lima puluh dolar di satu tempat dan hampir gratis di tempat lain, karbon belum punya satu harga."}, {"kind": "end", "title": "Ukur dulu, siap kemudian", "text": "Harga karbon adalah sinyal, bukan sekadar tarif. Baca selengkapnya di Glyiv Kabar — wawasan karbon yang jujur & bisa dipertanggungjawabkan."}], "sources": [{"a": "World Bank (2025). State and Trends of Carbon Pricing 2025.", "u": "https://www.worldbank.org/en/publication/state-and-trends-of-carbon-pricing"}, {"a": "World Bank. Carbon Pricing Dashboard (harga & cakupan per instrumen).", "u": "https://carbonpricingdashboard.worldbank.org/"}, {"a": "High-Level Commission on Carbon Prices — Stern & Stiglitz (2017). Report of the High-Level Commission on Carbon Prices.", "u": "https://www.carbonpricingleadership.org/report-of-the-highlevel-commission-on-carbon-prices"}, {"a": "International Carbon Action Partnership (ICAP). Indonesian Economic Value of Carbon (Nilai Ekonomi Karbon) Trading Scheme.", "u": "https://icapcarbonaction.com/en/ets/indonesian-economic-value-carbon-nilai-ekonomi-karbon-trading-scheme"}]}, {"slug": "cop30-belem-hutan-hujan", "topic": "Global", "mood": "#4F7A3A", "title": "COP30 di Belém: KTT iklim di jantung Amazon.", "dek": "Pada November 2025, untuk pertama kalinya konferensi iklim PBB digelar di tepi Amazon — dan gagasan besarnya, membayar negara yang menjaga hutannya tetap berdiri, menempatkan Indonesia tepat di tengah perundingan.", "hook": "Bayangkan sebuah hutan lebih bernilai saat dibiarkan berdiri ketimbang ditebang. Itulah taruhan Indonesia di COP30 Belém.", "cover": "https://images.unsplash.com/photo-1511497584788-876760111969?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber publik (UNFCCC, Presidensi COP30, FAO)", "read": 5, "blocks": [{"t": "lead", "x": "Untuk pertama kalinya dalam tiga dekade, konferensi iklim PBB digelar tepat di tepi hutan hujan yang selama ini menjadi taruhan terbesarnya. Pada November 2025, Brasil menjadi tuan rumah COP30 di Belém — kota pelabuhan di muara Sungai Amazon, gerbang menuju hamparan hutan tropis terbesar dunia. Pemilihan lokasinya bukan kebetulan; ia sebuah pesan."}, {"t": "p", "x": "Selama bertahun-tahun perundingan iklim berlangsung di kota-kota nyaman berpendingin — Paris, Glasgow, Dubai. Kali ini ribuan delegasi diterbangkan ke jantung Amazon, ke tempat di mana deforestasi bukan sekadar grafik melainkan pemandangan sehari-hari. Presiden COP30, diplomat <b>André Corrêa do Lago</b>, menyebutnya 'COP hutan' — momen ketika hutan tropis, penyimpan karbon dalam jumlah raksasa, ditempatkan di pusat meja perundingan, bukan di pinggirannya."}, {"t": "p", "x": "Simbolismenya kuat, dan tidak selalu nyaman. Menggelar KTT di kota yang infrastrukturnya terbatas memaksa dunia menatap langsung realitas kawasan yang selama ini hanya dibahas dari jauh — biaya hidup melonjak, logistik menegang, dan pertanyaan lama kembali mengemuka: siapa yang sebenarnya menanggung biaya menjaga hutan tetap berdiri?"}, {"t": "h2", "x": "Mengapa ini penting bagi Indonesia"}, {"t": "p", "x": "Bagi Indonesia, ini bukan berita luar negeri. Kita memiliki salah satu dari <a href=\"https://www.fao.org/forest-resources-assessment/2020\">tiga hamparan hutan hujan tropis terbesar</a> di planet ini — bersama Amazon dan Cekungan Kongo. Apa pun yang diputuskan soal nilai sebuah hutan yang dibiarkan berdiri akan menyentuh langsung nasib jutaan hektar hutan di Kalimantan, Papua, dan Sumatra."}, {"t": "p", "x": "Ujung tombak COP30 adalah gagasan tuan rumah bernama <a href=\"https://cop30.br\">Tropical Forests Forever Facility (TFFF)</a> — dana global yang membalik logika lama. Alih-alih membayar setelah pohon ditebang lalu ditanam ulang, TFFF berniat memberi <b>imbalan tahunan</b> kepada negara yang menjaga hutan tropisnya tetap utuh, dihitung per hektar dan diverifikasi lewat pemantauan satelit. Indonesia termasuk segelintir negara yang paling berpotensi menerima — sekaligus ikut menyumbang dana awalnya."}, {"t": "stat", "n": "US$125 miliar", "l": "Target dana TFFF untuk mengganjar negara penjaga hutan tropis ⚠︎ komitmen awal yang masuk masih jauh di bawah angka ini", "s": "Presidensi COP30 Brasil, 2025"}, {"t": "pull", "x": "Untuk pertama kalinya, hutan yang dibiarkan berdiri diperlakukan sebagai aset yang bernilai — bukan sekadar lahan yang menunggu dibuka."}, {"t": "p", "x": "Namun antusiasme perlu disertai kejujuran. Saat diluncurkan, komitmen dana yang benar-benar masuk masih jauh di bawah target ⚠︎, dan mekanisme pembayaran per hektar belum teruji dalam skala penuh. Sejarah pasar karbon hutan penuh janji yang menguap — kredit yang tak jelas asal-usulnya, klaim yang sulit diaudit. TFFF menjanjikan pendekatan berbasis hasil yang terpantau, tapi buktinya baru akan terlihat beberapa tahun ke depan."}, {"t": "p", "x": "Yang jelas berubah adalah kerangka berpikirnya. Nilai sebuah hutan tak lagi diukur hanya dari kayu atau lahan sawit yang bisa menggantikannya, melainkan dari karbon yang tetap tersimpan selama ia berdiri. Bagi Indonesia, tantangan berikutnya bersifat teknis sekaligus mendasar: mampukah kita membuktikan — dengan data yang tertelusur dan bisa diaudit — bahwa sebuah hutan benar-benar terjaga? Di sanalah nilai berpindah dari retorika ke bukti."}], "story": [{"kind": "cover", "title": "COP30 di Belém: iklim di jantung Amazon", "text": "November 2025, untuk pertama kalinya KTT iklim PBB digelar di tepi hutan hujan — dan Indonesia punya kepentingan besar di sana."}, {"kind": "hook", "title": "KTT iklim akhirnya pindah ke tepi hutan hujan.", "text": "Belém, gerbang Amazon. Lokasinya bukan kebetulan — ia sebuah pesan."}, {"kind": "point", "title": "'COP hutan'", "text": "Untuk pertama kali, hutan tropis ditaruh di pusat meja perundingan, bukan di pinggirannya."}, {"kind": "point", "title": "Kenapa Indonesia?", "text": "Kita pemilik salah satu dari tiga hutan hujan tropis terbesar dunia. Yang diputuskan di Belém menyentuh Kalimantan, Papua, Sumatra."}, {"kind": "point", "title": "Ide besarnya: TFFF", "text": "Dana global yang memberi imbalan tahunan bagi negara yang menjaga hutannya tetap berdiri — dihitung per hektar, dipantau satelit."}, {"kind": "stat", "title": "Angka yang jadi sorotan", "big": "US$125 miliar", "label": "Target dana TFFF ⚠︎ komitmen awal masih jauh di bawahnya", "source": "Presidensi COP30 Brasil, 2025"}, {"kind": "end", "title": "Nilai berpindah dari retorika ke bukti.", "text": "Baca ulasan lengkapnya di Glyiv Kabar — dan ikuti bagaimana karbon hutan Indonesia menjadi aset yang bisa diaudit."}], "sources": [{"a": "UNFCCC (2025). COP30 — UN Climate Change Conference, Belém, Brazil.", "u": "https://unfccc.int/cop30"}, {"a": "Presidência da COP30 / Governo do Brasil (2025). Tropical Forests Forever Facility (TFFF).", "u": "https://cop30.br"}, {"a": "FAO (2020). Global Forest Resources Assessment 2020 — Indonesia di antara negara berhutan tropis terbesar dunia.", "u": "https://www.fao.org/forest-resources-assessment/2020"}, {"a": "World Resources Institute — Global Forest Watch (2024). Tropical primary forest loss.", "u": "https://www.globalforestwatch.org"}]}, {"slug": "batas-planet-bukan-hanya-iklim", "topic": "Global", "mood": "#1F7A6B", "title": "Batas planet: iklim hanyalah satu dari sembilan garis.", "dek": "Kerangka 'batas planet' menilai sembilan sistem penjaga stabilitas Bumi. Per 2023, enam sudah terlampaui — karbon hanya salah satunya, dan bukan yang paling jauh dilanggar.", "hook": "Kita ribut soal karbon. Padahal Bumi punya sembilan garis pengaman — dan enam sudah kita lewati.", "cover": "https://images.unsplash.com/photo-1505142468610-359e7d316be0?auto=format&fit=crop&w=1400&q=70", "author": "Redaksi Glyiv", "role": "Ditinjau redaksi · berdasarkan sumber ilmiah publik", "read": 4, "blocks": [{"t": "lead", "x": "Percakapan soal krisis lingkungan hampir selalu berhenti di satu kata: karbon. Padahal para ilmuwan Bumi sudah lama memperingatkan bahwa iklim hanyalah satu dari sembilan 'batas planet' — pagar pengaman yang, bila dilewati, membuat kondisi Bumi yang selama ini ramah bagi peradaban tak lagi bisa diandalkan."}, {"t": "p", "x": "Kerangka <b>planetary boundaries</b> pertama kali diperkenalkan tim Johan Rockström pada 2009 <a href=\"https://www.nature.com/articles/461472a\">1</a>. Idenya sederhana namun kuat: ada sembilan sistem yang menjaga stabilitas Bumi — iklim, keutuhan biosfer, perubahan tata guna lahan, air tawar, aliran nitrogen dan fosfor, pengasaman laut, aerosol atmosfer, lapisan ozon, dan 'entitas baru' seperti plastik serta bahan kimia sintetis — dan masing-masing punya ambang aman yang bisa diperkirakan."}, {"t": "p", "x": "Penilaian terlengkap muncul pada 2023, saat untuk pertama kalinya kesembilan batas diukur secara kuantitatif sekaligus. Hasilnya mengkhawatirkan: <b>enam dari sembilan sudah terlampaui</b> — bukan hanya iklim, tetapi juga keutuhan biosfer, perubahan lahan, air tawar, aliran biogeokimia (nitrogen & fosfor), dan entitas baru <a href=\"https://www.science.org/doi/10.1126/sciadv.adh2458\">2</a>."}, {"t": "pull", "x": "Karbon adalah garis yang paling ramai dibicarakan — tapi bukan satu-satunya yang sudah kita lewati."}, {"t": "stat", "n": "6 / 9", "l": "batas planet yang sudah terlampaui per penilaian 2023", "s": "Richardson dkk., Science Advances, 2023"}, {"t": "h2", "x": "Kenapa ini penting bagi kerja karbon"}, {"t": "p", "x": "Yang jarang disadari: batas yang paling jauh dilampaui justru bukan iklim, melainkan <b>aliran nitrogen dan fosfor</b> — sebagian besar berasal dari pupuk pertanian yang bocor ke sungai dan laut. Ini pengingat bahwa menekan satu angka (ton CO₂) tanpa melihat sistem lain bisa menyesatkan. Solusi karbon yang justru memperparah pencemaran air atau menggerus keanekaragaman hayati bukanlah kemenangan."}, {"t": "p", "x": "Ada pula garis yang statusnya masih diperdebatkan: pengasaman laut kini dinilai berada tepat di ambang, dan sejumlah penilaian terbaru menyebutnya sudah terlampaui ⚠︎. Tetapi ada satu kabar baik yang layak diingat — lapisan ozon justru bergerak kembali ke zona aman berkat Protokol Montreal 1987 yang menghapus bahan perusak ozon <a href=\"https://www.unep.org/ozonaction/who-we-are/about-montreal-protocol\">3</a>. Buktinya: aksi terkoordinasi bisa membalik kerusakan, asal terlacak dan disepakati bersama."}, {"t": "p", "x": "Bagi Glyiv, ini bukan alasan untuk mengecilkan karbon, melainkan untuk menaruhnya dalam konteks. Karbon adalah lensa yang paling bisa dilacak dan dihitung hari ini — pintu masuk yang praktis menuju aksi. Tapi kerja iklim yang jujur mengakui bahwa Bumi punya lebih dari satu garis, dan setiap keputusan sebaiknya tidak sekadar memindahkan beban dari satu batas ke batas lain."}], "story": [{"kind": "cover", "title": "Iklim hanyalah satu dari sembilan garis", "text": "Kerangka 'batas planet' menilai sembilan sistem penjaga stabilitas Bumi. Per 2023, enam sudah terlampaui — karbon hanya salah satunya."}, {"kind": "hook", "title": "Kita ribut soal karbon. Padahal Bumi punya sembilan garis pengaman — dan enam sudah kita lewati."}, {"kind": "point", "title": "Sembilan garis, bukan satu", "text": "Sejak 2009, ilmuwan memetakan 9 batas planet: iklim, biosfer, lahan, air tawar, nitrogen-fosfor, laut, aerosol, ozon, entitas baru."}, {"kind": "point", "title": "Enam sudah terlampaui", "text": "Penilaian 2023: iklim, keutuhan biosfer, perubahan lahan, air tawar, aliran nitrogen & fosfor, dan entitas baru (plastik, kimia sintetis)."}, {"kind": "stat", "title": "Skor Bumi hari ini", "big": "6 / 9", "label": "batas planet yang sudah terlampaui", "source": "Richardson dkk., Science Advances, 2023"}, {"kind": "point", "title": "Karbon penting, tapi bukan satu-satunya", "text": "Batas paling jauh dilanggar justru nitrogen & fosfor dari pupuk. Solusi karbon yang merusak air atau hayati bukan kemenangan."}, {"kind": "end", "title": "Baca versi lengkapnya di Glyiv Kabar", "text": "Wawasan karbon yang jujur & bisa dipertanggungjawabkan — dalam konteks yang lebih luas."}], "sources": [{"a": "Rockström, J. dkk. (2009). A safe operating space for humanity. Nature 461, 472–475.", "u": "https://www.nature.com/articles/461472a"}, {"a": "Richardson, K. dkk. (2023). Earth beyond six of nine planetary boundaries. Science Advances 9, eadh2458.", "u": "https://www.science.org/doi/10.1126/sciadv.adh2458"}, {"a": "UNEP. About the Montreal Protocol (pemulihan lapisan ozon).", "u": "https://www.unep.org/ozonaction/who-we-are/about-montreal-protocol"}]}];
